def _is_env_managed_config_key(name: str) -> bool:
    normalized = str(name or "").strip().upper()
    if not normalized:
        return False
    if normalized in ENV_MANAGED_CONFIG_EXACT_KEYS:
        return True
    if normalized.startswith(ENV_MANAGED_CONFIG_PREFIXES):
        return True
    if normalized.endswith(ENV_MANAGED_CONFIG_SUFFIXES):
        return True
    return False


def _should_use_runtime_config_fallback(name: str) -> bool:
    if not runtime_config or not hasattr(runtime_config, name):
        return False
    if CONFIG_RESOLUTION_MODE == "hybrid":
        return True
    if CONFIG_RESOLUTION_MODE == "env_only":
        return False
    if LOADED_ENV_KEY_COUNT <= 0:
        return True
    return not _is_env_managed_config_key(name)


# ============ 配置读取工具 ============
def _cfg_get(name: str, default):
    # 生产环境可通过 INTUS_ 前缀变量覆盖（优先级最高）
    env_prefixed_val = os.environ.get(f"INTUS_{name}")
    if env_prefixed_val is not None:
        return env_prefixed_val

    # 兼容同名环境变量（次优先）
    env_val = os.environ.get(name)
    if env_val is not None:
        return env_val

    # 自动模式下，若已加载 .env，则环境接入/部署类配置不再回落 config.py，避免旧密钥或部署参数“偷生效”
    if _should_use_runtime_config_fallback(name):
        return getattr(runtime_config, name)
    return default


def _cfg_int(name: str, default: int) -> int:
    try:
        return int(_cfg_get(name, default))
    except Exception:
        return default


def _cfg_float(name: str, default: float) -> float:
    try:
        return float(_cfg_get(name, default))
    except Exception:
        return default


def _cfg_bool(name: str, default: bool) -> bool:
    value = _cfg_get(name, default)
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    if isinstance(value, str):
        v = value.strip().lower()
        if v in {"1", "true", "yes", "on", "y"}:
            return True
        if v in {"0", "false", "no", "off", "n"}:
            return False
    return default


def _cfg_text(name: str, default: str = "") -> str:
    return str(_cfg_get(name, default) or "").strip()


def summarize_error_for_log(error: object, limit: int = 240) -> str:
    """压缩异常文本，避免在日志中输出整段 HTML/长响应体。"""
    text = str(error or "").strip()
    if not text:
        return "未知错误"

    # 去除 HTML 标签（例如网关 504 的整页 HTML 错误页）
    stripped = re.sub(r"(?is)<script[^>]*>.*?</script>", " ", text)
    stripped = re.sub(r"(?is)<style[^>]*>.*?</style>", " ", stripped)
    stripped = re.sub(r"(?is)<[^>]+>", " ", stripped)
    stripped = re.sub(r"\s+", " ", stripped).strip()
    if stripped:
        text = stripped

    limit = max(32, int(limit or 240))
    if len(text) > limit:
        text = text[: limit - 1] + "…"

    return text


def _cfg_text_list(name: str, default: list[str]) -> list[str]:
    value = _cfg_get(name, default)
    if isinstance(value, (list, tuple, set)):
        cleaned = [str(item).strip() for item in value if str(item).strip()]
        return cleaned or list(default)
    if isinstance(value, str):
        text = value.strip()
        if not text:
            return list(default)
        if text.startswith("[") and text.endswith("]"):
            try:
                parsed = json.loads(text)
                if isinstance(parsed, list):
                    cleaned = [str(item).strip() for item in parsed if str(item).strip()]
                    return cleaned or list(default)
            except Exception:
                pass
        cleaned = [item.strip() for item in text.split(",") if item.strip()]
        return cleaned or list(default)
    return list(default)


def _cfg_numeric_map(name: str, default: dict[str, float], value_type: str = "float") -> dict[str, float]:
    value = _cfg_get(name, default)
    result = {}

    def _convert_number(raw_value):
        try:
            return int(raw_value) if value_type == "int" else float(raw_value)
        except Exception:
            return None

    if isinstance(value, dict):
        items = value.items()
    elif isinstance(value, str):
        text = value.strip()
        if not text:
            return dict(default)
        if text.startswith("{") and text.endswith("}"):
            try:
                parsed = json.loads(text)
                if isinstance(parsed, dict):
                    items = parsed.items()
                else:
                    items = []
            except Exception:
                items = []
        else:
            segments = [segment.strip() for segment in re.split(r"[;,]", text) if segment.strip()]
            pairs = []
            for segment in segments:
                if "=" not in segment:
                    continue
                key, raw_value = segment.split("=", 1)
                pairs.append((key, raw_value))
            items = pairs
    else:
        return dict(default)

    for key, raw_value in items:
        normalized_key = str(key or "").strip().lower()
        if not normalized_key:
            continue
        converted = _convert_number(raw_value)
        if converted is None:
            continue
        result[normalized_key] = converted

    merged = dict(default)
    merged.update(result)
    return merged


def _first_non_empty(*values: str) -> str:
    for value in values:
        text = str(value or "").strip()
        if text:
            return text
    return ""


def _is_bearer_gateway_url(url: str) -> bool:
    """判断网关是否默认使用 Authorization: Bearer。"""
    lowered = str(url or "").strip().lower()
    if not lowered:
        return False
    # aicodemirror 代理当前要求 Bearer 鉴权
    return "aicodemirror.com" in lowered


def _guess_bearer_auth_default() -> bool:
    """在未显式配置鉴权开关时，基于网关地址推断默认鉴权模式。"""
    candidates = [
        _cfg_text("QUESTION_BASE_URL", ""),
        _cfg_text("REPORT_BASE_URL", ""),
        _cfg_text("ANTHROPIC_BASE_URL", str(ANTHROPIC_BASE_URL or "").strip()),
    ]
    return any(_is_bearer_gateway_url(url) for url in candidates if str(url or "").strip())


