def _build_lane_signature(api_key: str, base_url: str, use_bearer_auth: bool) -> tuple[str, str, bool]:
    return (str(api_key or "").strip(), str(base_url or "").strip(), bool(use_bearer_auth))


def _is_dedicated_question_deep_gateway_configured() -> bool:
    return _build_lane_signature(
        QUESTION_DEEP_API_KEY,
        QUESTION_DEEP_BASE_URL,
        QUESTION_DEEP_USE_BEARER_AUTH,
    ) != _build_lane_signature(
        QUESTION_API_KEY,
        QUESTION_BASE_URL,
        QUESTION_USE_BEARER_AUTH,
    )


def _should_use_deep_question_gateway(model_name: str = "") -> bool:
    normalized_model = str(model_name or "").strip()
    deep_model = str(QUESTION_MODEL_NAME_DEEP or "").strip()
    if not normalized_model or not deep_model:
        return False
    if normalized_model != deep_model:
        return False
    return _is_dedicated_question_deep_gateway_configured()


def _resolve_lane_signature(lane: str) -> tuple[str, str, bool]:
    normalized_lane = str(lane or "").strip().lower()
    if normalized_lane == "question_deep":
        return _build_lane_signature(QUESTION_DEEP_API_KEY, QUESTION_DEEP_BASE_URL, QUESTION_DEEP_USE_BEARER_AUTH)
    if normalized_lane == "report_draft":
        return _build_lane_signature(REPORT_DRAFT_API_KEY, REPORT_DRAFT_BASE_URL, REPORT_DRAFT_USE_BEARER_AUTH)
    if normalized_lane == "report_review":
        return _build_lane_signature(REPORT_REVIEW_API_KEY, REPORT_REVIEW_BASE_URL, REPORT_REVIEW_USE_BEARER_AUTH)
    if normalized_lane == "report":
        return _build_lane_signature(REPORT_API_KEY, REPORT_BASE_URL, REPORT_USE_BEARER_AUTH)
    if normalized_lane == "summary":
        return _build_lane_signature(SUMMARY_API_KEY, SUMMARY_BASE_URL, SUMMARY_USE_BEARER_AUTH)
    if normalized_lane == "search_decision":
        return _build_lane_signature(
            SEARCH_DECISION_API_KEY,
            SEARCH_DECISION_BASE_URL,
            SEARCH_DECISION_USE_BEARER_AUTH,
        )
    if normalized_lane == "assessment":
        return _build_lane_signature(
            ASSESSMENT_API_KEY,
            ASSESSMENT_BASE_URL,
            ASSESSMENT_USE_BEARER_AUTH,
        )
    return _build_lane_signature(QUESTION_API_KEY, QUESTION_BASE_URL, QUESTION_USE_BEARER_AUTH)


def _is_report_draft_call_type(call_type: str = "") -> bool:
    lowered = str(call_type or "").strip().lower()
    return "report_v3_draft" in lowered


def _is_report_review_call_type(call_type: str = "") -> bool:
    lowered = str(call_type or "").strip().lower()
    return "report_v3_review" in lowered or "review_parse_repair" in lowered


def _resolve_lane_model_name(lane: str) -> str:
    """根据 lane 的实际网关签名选择模型，避免模型与网关供应商不匹配。"""
    normalized_lane = str(lane or "").strip().lower()

    if normalized_lane == "question_deep":
        return QUESTION_MODEL_NAME_DEEP or QUESTION_MODEL_NAME

    if normalized_lane == "report_draft":
        return REPORT_DRAFT_MODEL_NAME or REPORT_MODEL_NAME or QUESTION_MODEL_NAME

    if normalized_lane == "report_review":
        return REPORT_REVIEW_MODEL_NAME or REPORT_MODEL_NAME or QUESTION_MODEL_NAME

    if normalized_lane == "report":
        return REPORT_MODEL_NAME or REPORT_DRAFT_MODEL_NAME or REPORT_REVIEW_MODEL_NAME or QUESTION_MODEL_NAME

    if normalized_lane == "summary":
        default_model = SUMMARY_MODEL_NAME or QUESTION_MODEL_NAME
        summary_signature = _resolve_lane_signature("summary")
        report_signature = _resolve_lane_signature("report")
        if (
            summary_signature == report_signature
            and default_model == QUESTION_MODEL_NAME
            and REPORT_MODEL_NAME
            and REPORT_MODEL_NAME != default_model
        ):
            return REPORT_MODEL_NAME
        return default_model

    if normalized_lane == "search_decision":
        default_model = SEARCH_DECISION_MODEL_NAME or SUMMARY_MODEL_NAME or QUESTION_MODEL_NAME
        dedicated_model = (
            bool(SEARCH_DECISION_MODEL_NAME)
            and SEARCH_DECISION_MODEL_NAME not in {SUMMARY_MODEL_NAME, QUESTION_MODEL_NAME}
        )
        search_signature = _resolve_lane_signature("search_decision")
        summary_signature = _resolve_lane_signature("summary")
        if search_signature == summary_signature and not dedicated_model:
            return _resolve_lane_model_name("summary")
        report_signature = _resolve_lane_signature("report")
        if (
            search_signature == report_signature
            and not dedicated_model
            and default_model in {QUESTION_MODEL_NAME, SUMMARY_MODEL_NAME}
            and REPORT_MODEL_NAME
            and REPORT_MODEL_NAME != default_model
        ):
            return REPORT_MODEL_NAME
        return default_model

    if normalized_lane == "assessment":
        default_model = ASSESSMENT_MODEL_NAME or SEARCH_DECISION_MODEL_NAME or SUMMARY_MODEL_NAME or QUESTION_MODEL_NAME
        dedicated_model = (
            bool(ASSESSMENT_MODEL_NAME)
            and ASSESSMENT_MODEL_NAME not in {
                SEARCH_DECISION_MODEL_NAME,
                SUMMARY_MODEL_NAME,
                QUESTION_MODEL_NAME,
            }
        )
        assessment_signature = _resolve_lane_signature("assessment")
        search_signature = _resolve_lane_signature("search_decision")
        if assessment_signature == search_signature and not dedicated_model and default_model in {
            SEARCH_DECISION_MODEL_NAME,
            SUMMARY_MODEL_NAME,
            QUESTION_MODEL_NAME,
        }:
            return _resolve_lane_model_name("search_decision")
        summary_signature = _resolve_lane_signature("summary")
        if assessment_signature == summary_signature and not dedicated_model and default_model in {
            SUMMARY_MODEL_NAME,
            QUESTION_MODEL_NAME,
        }:
            return _resolve_lane_model_name("summary")
        return default_model

    return QUESTION_MODEL_NAME


def _resolve_report_phase_model_name(call_type: str = "", selected_lane: str = "") -> str:
    """在 report lane 下允许为草案/审稿阶段指定不同模型。"""
    normalized_lane = str(selected_lane or "").strip().lower()
    if normalized_lane == "report_draft":
        return REPORT_DRAFT_MODEL_NAME or REPORT_MODEL_NAME
    if normalized_lane == "report_review":
        return REPORT_REVIEW_MODEL_NAME or REPORT_MODEL_NAME
    if normalized_lane and normalized_lane != "report":
        return ""

    if _is_report_review_call_type(call_type):
        return REPORT_REVIEW_MODEL_NAME or REPORT_MODEL_NAME
    if _is_report_draft_call_type(call_type):
        return REPORT_DRAFT_MODEL_NAME or REPORT_MODEL_NAME
    return ""


def resolve_model_name(call_type: str = "", model_name: str = "") -> str:
    """根据调用类型选择模型；显式传入 model_name 时优先使用。"""
    explicit = str(model_name or "").strip()
    if explicit:
        return explicit

    lowered = (call_type or "").lower()
    if "assessment" in lowered:
        return _resolve_lane_model_name("assessment")
    if "search_decision" in lowered:
        return _resolve_lane_model_name("search_decision")
    if "summary" in lowered:
        return _resolve_lane_model_name("summary")
    report_phase_model = _resolve_report_phase_model_name(call_type=call_type)
    if report_phase_model:
        return report_phase_model
    if "report" in lowered:
        return _resolve_lane_model_name("report")
    return QUESTION_MODEL_NAME


def resolve_model_name_for_lane(call_type: str = "", model_name: str = "", selected_lane: str = "") -> str:
    """根据实际选中的 lane 选择模型，避免 fallback 时模型和网关不匹配。"""
    explicit = str(model_name or "").strip()
    if explicit:
        return explicit

    lane = str(selected_lane or "").strip().lower()
    report_phase_model = _resolve_report_phase_model_name(call_type=call_type, selected_lane=lane)
    if report_phase_model:
        return report_phase_model

    if lane in {"question", "report", "report_draft", "report_review", "summary", "search_decision", "assessment"}:
        lane_model = _resolve_lane_model_name(lane)
        if lane_model:
            return lane_model

    return resolve_model_name(call_type=call_type, model_name=model_name)


def _known_primary_model_fallback(explicit_model: str) -> str:
    normalized_model = str(explicit_model or "").strip()
    if not normalized_model:
        return ""
    known_pairs = [
        (QUESTION_MODEL_NAME_DEEP, QUESTION_MODEL_NAME_DEEP_FALLBACK),
        (QUESTION_MODEL_NAME, QUESTION_FALLBACK_MODEL_NAME),
        (REPORT_DRAFT_MODEL_NAME, REPORT_DRAFT_FALLBACK_MODEL_NAME),
        (REPORT_REVIEW_MODEL_NAME, REPORT_REVIEW_FALLBACK_MODEL_NAME),
        (SUMMARY_MODEL_NAME, SUMMARY_FALLBACK_MODEL_NAME),
        (SEARCH_DECISION_MODEL_NAME, SEARCH_DECISION_FALLBACK_MODEL_NAME),
        (ASSESSMENT_MODEL_NAME, ASSESSMENT_FALLBACK_MODEL_NAME),
    ]
    for primary_model, fallback_model in known_pairs:
        if normalized_model == str(primary_model or "").strip():
            return str(fallback_model or "").strip()
    return ""


def resolve_fallback_model_name_for_lane(call_type: str = "", selected_lane: str = "", model_name: str = "") -> str:
    """根据调用场景选择同 lane 内的备用模型。"""
    if not MODEL_FALLBACK_ENABLED:
        return ""

    explicit = str(model_name or "").strip()
    if explicit:
        return _known_primary_model_fallback(explicit)

    lane = str(selected_lane or "").strip().lower()
    lowered = str(call_type or "").strip().lower()
    if lane == "question_deep":
        return str(QUESTION_MODEL_NAME_DEEP_FALLBACK or "").strip()
    if _is_report_draft_call_type(call_type) or lane == "report_draft":
        return str(REPORT_DRAFT_FALLBACK_MODEL_NAME or "").strip()
    if _is_report_review_call_type(call_type) or lane == "report_review":
        return str(REPORT_REVIEW_FALLBACK_MODEL_NAME or "").strip()
    if "assessment" in lowered or lane == "assessment":
        return str(ASSESSMENT_FALLBACK_MODEL_NAME or "").strip()
    if "search_decision" in lowered or lane == "search_decision":
        return str(SEARCH_DECISION_FALLBACK_MODEL_NAME or "").strip()
    if "summary" in lowered or lane == "summary":
        return str(SUMMARY_FALLBACK_MODEL_NAME or "").strip()
    if explicit == str(QUESTION_MODEL_NAME_DEEP or "").strip():
        return str(QUESTION_MODEL_NAME_DEEP_FALLBACK or "").strip()
    return str(QUESTION_FALLBACK_MODEL_NAME or "").strip()


def resolve_model_fallback_candidates(call_type: str = "", model_name: str = "", selected_lane: str = "") -> list[str]:
    """返回主模型和可选备用模型，保持顺序并去重。"""
    primary_model = resolve_model_name_for_lane(
        call_type=call_type,
        model_name=model_name,
        selected_lane=selected_lane,
    )
    fallback_model = resolve_fallback_model_name_for_lane(
        call_type=call_type,
        selected_lane=selected_lane,
        model_name=model_name,
    )
    candidates = []
    seen = set()
    for item in [primary_model, fallback_model]:
        model = str(item or "").strip()
        if not model or model in seen:
            continue
        candidates.append(model)
        seen.add(model)
    return candidates


def resolve_call_lane(call_type: str = "", model_name: str = "") -> str:
    """根据调用类型判断应该优先使用的问题/报告网关。"""
    lowered = (call_type or "").lower()
    if "assessment" in lowered:
        return "assessment"
    if "search_decision" in lowered:
        return "search_decision"
    if "summary" in lowered:
        return "summary"
    if "report" in lowered:
        return "report"

    explicit = str(model_name or "").strip()
    if explicit and explicit == REPORT_MODEL_NAME and explicit != QUESTION_MODEL_NAME:
        return "report"

    return "question"


def resolve_report_v3_phase_lane(phase: str, pipeline_lane: str = "") -> str:
    """为 V3 不同阶段选择 lane；支持草案与审稿分离。"""
    normalized_phase = str(phase or "").strip().lower()
    if normalized_phase not in {"draft", "review"}:
        normalized_phase = "draft"

    normalized_pipeline_lane = str(pipeline_lane or "").strip().lower()
    if normalized_pipeline_lane not in {"question", "report"}:
        normalized_pipeline_lane = "report"

    if not REPORT_V3_DUAL_STAGE_ENABLED:
        return normalized_pipeline_lane

    # 备用网关重试时优先单 lane，避免跨网关抖动导致不稳定。
    if REPORT_V3_FAILOVER_FORCE_SINGLE_LANE and normalized_pipeline_lane != "report":
        return normalized_pipeline_lane

    if normalized_phase == "review":
        return REPORT_V3_REVIEW_PRIMARY_LANE
    return REPORT_V3_DRAFT_PRIMARY_LANE


