def get_admin_env_file_path() -> Path:
    explicit_env_files = list(ENV_LOAD_METADATA.get("explicit_env_files") or [])
    if explicit_env_files:
        env_path = Path(str(explicit_env_files[-1]).strip()).expanduser()
        if not env_path.is_absolute():
            env_path = (SKILL_DIR / env_path).resolve()
        return env_path
    if LOADED_ENV_FILES:
        return Path(LOADED_ENV_FILES[0]).resolve()
    return (WEB_DIR / ".env").resolve()


def get_admin_config_file_path() -> Path:
    return (WEB_DIR / "config.py").resolve()


def get_admin_site_config_file_path() -> Path:
    return (WEB_DIR / "site-config.js").resolve()


def _get_admin_nested_setting_value(container: Any, dotted_key: str) -> Any:
    current = container
    for segment in [part.strip() for part in str(dotted_key or "").split(".") if part.strip()]:
        if not isinstance(current, dict) or segment not in current:
            return None
        current = current.get(segment)
    return current


def _set_admin_nested_setting_value(container: dict[str, Any], dotted_key: str, value: Any) -> None:
    segments = [part.strip() for part in str(dotted_key or "").split(".") if part.strip()]
    if not segments:
        return
    current = container
    for segment in segments[:-1]:
        next_value = current.get(segment)
        if not isinstance(next_value, dict):
            next_value = {}
            current[segment] = next_value
        current = next_value
    current[segments[-1]] = value


def _read_env_file_map(env_path: Path) -> dict[str, str]:
    if not env_path.exists() or not env_path.is_file():
        return {}
    values: dict[str, str] = {}
    try:
        for raw_line in env_path.read_text(encoding="utf-8").splitlines():
            parsed = _parse_env_assignment(raw_line)
            if not parsed:
                continue
            key, value = parsed
            values[key] = value
    except Exception:
        return {}
    return values


def _read_admin_managed_config_values(config_path: Path) -> dict[str, Any]:
    if not config_path.exists() or not config_path.is_file():
        return {}
    try:
        content = config_path.read_text(encoding="utf-8")
    except Exception:
        return {}
    if ADMIN_CONFIG_MANAGED_BEGIN not in content or ADMIN_CONFIG_MANAGED_END not in content:
        return {}
    try:
        section = content.split(ADMIN_CONFIG_MANAGED_BEGIN, 1)[1].split(ADMIN_CONFIG_MANAGED_END, 1)[0]
        tree = ast.parse(section, mode="exec")
    except Exception:
        return {}

    values: dict[str, Any] = {}
    for node in getattr(tree, "body", []):
        if not isinstance(node, ast.Assign) or len(node.targets) != 1:
            continue
        target = node.targets[0]
        if not isinstance(target, ast.Name):
            continue
        key = str(target.id or "").strip()
        if not key:
            continue
        try:
            values[key] = ast.literal_eval(node.value)
        except Exception:
            continue
    return values


def _read_admin_site_config_values(site_config_path: Path, *, strict: bool = False) -> dict[str, Any]:
    if not site_config_path.exists() or not site_config_path.is_file():
        return {}
    node_script = (
        "const path = require('path');"
        "const file = process.argv[process.argv.length - 1];"
        "try {"
        "  const config = require(path.resolve(file));"
        "  process.stdout.write(JSON.stringify(config));"
        "} catch (error) {"
        "  console.error(error && error.stack ? error.stack : String(error));"
        "  process.exit(1);"
        "}"
    )
    try:
        result = subprocess.run(
            ["node", "-e", node_script, str(site_config_path)],
            cwd=str(WEB_DIR),
            capture_output=True,
            text=True,
            check=False,
        )
    except Exception as exc:
        if strict:
            raise ValueError("site-config.js 解析失败，请确认文件语法正确") from exc
        return {}
    if result.returncode != 0:
        if strict:
            raise ValueError("site-config.js 解析失败，请确认文件语法正确")
        return {}
    try:
        payload = json.loads(result.stdout or "{}")
    except Exception as exc:
        if strict:
            raise ValueError("site-config.js 解析失败，请确认文件语法正确") from exc
        return {}
    return payload if isinstance(payload, dict) else {}


def _normalize_site_config_payload(payload: Any) -> dict[str, Any]:
    return copy.deepcopy(payload) if isinstance(payload, dict) else {}


def _merge_site_config_defaults(default_values: dict[str, Any], override_values: dict[str, Any]) -> dict[str, Any]:
    merged = copy.deepcopy(default_values) if isinstance(default_values, dict) else {}
    overrides = override_values if isinstance(override_values, dict) else {}
    for key, value in overrides.items():
        if isinstance(value, dict) and isinstance(merged.get(key), dict):
            merged[key] = _merge_site_config_defaults(merged[key], value)
            continue
        merged[key] = copy.deepcopy(value)
    return merged


def _load_site_config_store_values(conn: Any) -> dict[str, Any]:
    row = conn.execute(
        """
        SELECT payload_json
        FROM site_config_store
        WHERE config_name = 'default'
        LIMIT 1
        """
    ).fetchone()
    if not row:
        return {}
    try:
        payload = json.loads(str(row["payload_json"] or "{}"))
    except Exception:
        return {}
    return _normalize_site_config_payload(payload)


def _upsert_site_config_store_values(conn: Any, values: dict[str, Any]) -> None:
    now_iso = datetime.now(timezone.utc).isoformat()
    conn.execute(
        """
        INSERT INTO site_config_store(config_name, payload_json, updated_at)
        VALUES (?, ?, ?)
        ON CONFLICT(config_name) DO UPDATE SET
            payload_json = excluded.payload_json,
            updated_at = excluded.updated_at
        """,
        (
            "default",
            json.dumps(_normalize_site_config_payload(values), ensure_ascii=False),
            now_iso,
        ),
    )


def _normalize_runtime_metrics_payload(payload: Any) -> dict[str, Any]:
    if not isinstance(payload, dict):
        return {}
    calls_raw = payload.get("calls", [])
    calls = [item for item in calls_raw if isinstance(item, dict)] if isinstance(calls_raw, list) else []
    summary_raw = payload.get("summary", {})
    summary = summary_raw if isinstance(summary_raw, dict) else {}
    return {
        "calls": calls,
        "summary": {
            "total_calls": int(summary.get("total_calls", 0) or 0),
            "total_timeouts": int(summary.get("total_timeouts", 0) or 0),
            "total_truncations": int(summary.get("total_truncations", 0) or 0),
            "total_cache_hits": int(summary.get("total_cache_hits", 0) or 0),
            "total_hedge_triggered": int(summary.get("total_hedge_triggered", 0) or 0),
            "total_model_fallbacks": int(summary.get("total_model_fallbacks", 0) or 0),
            "avg_response_time": float(summary.get("avg_response_time", 0) or 0),
            "avg_prompt_length": float(summary.get("avg_prompt_length", 0) or 0),
            "avg_queue_wait_ms": float(summary.get("avg_queue_wait_ms", 0) or 0),
        },
    }


def _load_runtime_store_payload(conn: Any, metric_key: str) -> dict[str, Any]:
    row = conn.execute(
        """
        SELECT payload_json
        FROM runtime_metrics_store
        WHERE metric_key = ?
        LIMIT 1
        """,
        (str(metric_key or "").strip(),),
    ).fetchone()
    if not row:
        return {}
    try:
        payload = json.loads(str(row["payload_json"] or "{}"))
    except Exception:
        return {}
    return payload if isinstance(payload, dict) else {}


def _upsert_runtime_store_payload(conn: Any, metric_key: str, payload: dict[str, Any]) -> None:
    now_iso = datetime.now(timezone.utc).isoformat()
    conn.execute(
        """
        INSERT INTO runtime_metrics_store(metric_key, payload_json, updated_at)
        VALUES (?, ?, ?)
        ON CONFLICT(metric_key) DO UPDATE SET
            payload_json = excluded.payload_json,
            updated_at = excluded.updated_at
        """,
        (
            str(metric_key or "").strip(),
            json.dumps(payload if isinstance(payload, dict) else {}, ensure_ascii=False),
            now_iso,
        ),
    )


def _load_runtime_metrics_store_payload(conn: Any, metric_key: str) -> dict[str, Any]:
    payload = _load_runtime_store_payload(conn, metric_key)
    return _normalize_runtime_metrics_payload(payload)


def _upsert_runtime_metrics_store_payload(conn: Any, metric_key: str, payload: dict[str, Any]) -> None:
    _upsert_runtime_store_payload(conn, metric_key, _normalize_runtime_metrics_payload(payload))


def _normalize_runtime_startup_payload(payload: Any) -> dict[str, Any]:
    if not isinstance(payload, dict):
        return {}
    phases: list[dict[str, object]] = []
    for item in payload.get("phases", []) if isinstance(payload.get("phases", []), list) else []:
        if not isinstance(item, dict):
            continue
        phases.append(
            {
                "name": str(item.get("name") or "").strip(),
                "elapsed_ms": round(float(item.get("elapsed_ms", 0) or 0), 2),
            }
        )
    return {
        "initialized": bool(payload.get("initialized", False)),
        "reason": str(payload.get("reason") or "").strip(),
        "started_at": str(payload.get("started_at") or "").strip(),
        "completed_at": str(payload.get("completed_at") or "").strip(),
        "total_ms": round(float(payload.get("total_ms", 0) or 0), 2),
        "phases": phases,
        "failed_phase": str(payload.get("failed_phase") or "").strip(),
        "error": str(payload.get("error") or "").strip(),
    }


def load_runtime_site_config_values() -> dict[str, Any]:
    default_values = _read_admin_site_config_values(get_admin_site_config_file_path())
    try:
        with get_meta_index_connection() as conn:
            stored = _load_site_config_store_values(conn)
    except Exception:
        stored = {}
    if stored:
        return _merge_site_config_defaults(default_values, stored)
    return default_values


def _mask_admin_sensitive_value(value: object) -> str:
    text = str(value or "")
    if not text:
        return "未设置"
    if len(text) <= 6:
        return "*" * len(text)
    return f"{text[:2]}{'*' * max(4, len(text) - 4)}{text[-2:]}"


def _format_admin_setting_form_value(setting_meta: dict[str, Any], value: object) -> str:
    field_type = str(setting_meta.get("type") or "text")
    value_codec = str(setting_meta.get("value_codec") or "")
    if value_codec == "json":
        if value is None:
            return ""
        return json.dumps(value, ensure_ascii=False, indent=2)
    if value_codec == "newline_list":
        if value is None:
            return ""
        if isinstance(value, (list, tuple, set)):
            return "\n".join(str(item).strip() for item in value if str(item).strip())
        return str(value)
    if value is None:
        return "false" if field_type == "boolean" else ""
    if field_type == "boolean":
        return "true" if bool(value) else "false"
    if field_type == "list":
        if isinstance(value, (list, tuple, set)):
            return ", ".join(str(item).strip() for item in value if str(item).strip())
        return str(value).strip()
    if field_type in {"integer", "float"}:
        return str(value)
    return str(value)


def _format_admin_setting_display_value(setting_meta: dict[str, Any], value: object, *, mask_secret: bool = False) -> str:
    field_type = str(setting_meta.get("type") or "text")
    value_codec = str(setting_meta.get("value_codec") or "")
    if value_codec == "json":
        if value is None:
            return "未设置"
        if isinstance(value, list):
            return f"{len(value)} 项"
        if isinstance(value, dict):
            return f"{len(value)} 个字段"
        serialized = json.dumps(value, ensure_ascii=False)
        return serialized if len(serialized) <= 120 else f"{serialized[:117]}..."
    if value_codec == "newline_list":
        if value is None:
            return "未设置"
        if isinstance(value, (list, tuple, set)):
            cleaned = [str(item).strip() for item in value if str(item).strip()]
        else:
            cleaned = [line.strip() for line in str(value).splitlines() if line.strip()]
        return f"{len(cleaned)} 项" if cleaned else "未设置"
    if field_type == "boolean":
        return "已开启" if bool(value) else "已关闭"
    if value is None:
        return "未设置"
    if field_type == "list":
        if isinstance(value, (list, tuple, set)):
            cleaned = [str(item).strip() for item in value if str(item).strip()]
        else:
            cleaned = [item.strip() for item in str(value).split(",") if item.strip()]
        return "，".join(cleaned) if cleaned else "未设置"
    if isinstance(value, Path):
        return str(value)
    text = str(value)
    if text == "":
        return "空值"
    if mask_secret and setting_meta.get("secret"):
        return _mask_admin_sensitive_value(text)
    return text


def _parse_admin_list_value(raw_value: object, list_value_kind: str = "text") -> list[Any]:
    if isinstance(raw_value, (list, tuple, set)):
        segments = [str(item).strip() for item in raw_value if str(item).strip()]
    else:
        text = str(raw_value or "").strip()
        if not text:
            return []
        segments = [item.strip() for item in re.split(r"[\n,]", text) if item.strip()]
    if list_value_kind == "int":
        parsed_ints = []
        for segment in segments:
            parsed_ints.append(int(segment))
        return parsed_ints
    return segments


def _coerce_admin_env_storage_value(setting_meta: dict[str, Any], raw_value: str) -> Any:
    field_type = str(setting_meta.get("type") or "text")
    if field_type == "boolean":
        parsed = _parse_bool_like(raw_value)
        return bool(parsed) if parsed is not None else False
    if field_type == "integer":
        if raw_value == "":
            return None
        return int(raw_value)
    if field_type == "float":
        if raw_value == "":
            return None
        return float(raw_value)
    if field_type == "list":
        return _parse_admin_list_value(raw_value, str(setting_meta.get("list_value_kind") or "text"))
    return raw_value


def _coerce_admin_request_value(setting_meta: dict[str, Any], raw_value: object) -> Any:
    field_type = str(setting_meta.get("type") or "text")
    value_codec = str(setting_meta.get("value_codec") or "")
    label = str(setting_meta.get("label") or setting_meta.get("key") or "配置项")

    if value_codec == "json":
        text = str(raw_value or "").strip()
        if not text:
            raise ValueError(f"{label} 不能为空")
        try:
            return json.loads(text)
        except Exception as exc:
            raise ValueError(f"{label} 必须为合法 JSON") from exc

    if value_codec == "newline_list":
        if isinstance(raw_value, (list, tuple, set)):
            return [str(item).strip() for item in raw_value if str(item).strip()]
        return [line.strip() for line in str(raw_value or "").splitlines() if line.strip()]

    if field_type == "boolean":
        parsed = _parse_bool_like(raw_value)
        if parsed is None:
            raise ValueError(f"{label} 必须为布尔值")
        return bool(parsed)

    if field_type == "integer":
        text = str(raw_value or "").strip()
        if not text:
            raise ValueError(f"{label} 不能为空")
        return int(text)

    if field_type == "float":
        text = str(raw_value or "").strip()
        if not text:
            raise ValueError(f"{label} 不能为空")
        return float(text)

    if field_type == "list":
        return _parse_admin_list_value(raw_value, str(setting_meta.get("list_value_kind") or "text"))

    return str(raw_value or "")


def _serialize_env_assignment_value(value: object) -> str:
    text = str(value or "")
    if text == "":
        return ""
    if re.fullmatch(r"[A-Za-z0-9_./:@,+\-]+", text):
        return text
    escaped = text.replace("\\", "\\\\").replace("\"", "\\\"")
    return f"\"{escaped}\""


def _serialize_admin_env_value(setting_meta: dict[str, Any], value: Any) -> str:
    field_type = str(setting_meta.get("type") or "text")
    if field_type == "boolean":
        return "true" if bool(value) else "false"
    if field_type == "list":
        if isinstance(value, (list, tuple, set)):
            return ",".join(str(item).strip() for item in value if str(item).strip())
        return str(value or "").strip()
    return str(value or "")


def _serialize_admin_python_value(value: Any) -> str:
    return repr(value)


def _write_admin_env_updates(updates: dict[str, Any]) -> Path:
    env_path = get_admin_env_file_path()
    env_path.parent.mkdir(parents=True, exist_ok=True)

    with ADMIN_SETTINGS_WRITE_LOCK:
        existing_lines = env_path.read_text(encoding="utf-8").splitlines() if env_path.exists() else []
        updated_keys: set[str] = set()
        result_lines: list[str] = []

        for line in existing_lines:
            parsed = _parse_env_assignment(line)
            if not parsed:
                result_lines.append(line)
                continue
            key, _ = parsed
            if key not in updates:
                result_lines.append(line)
                continue
            setting_meta = ADMIN_SETTINGS_FIELD_INDEX["env"].get(key)
            if not setting_meta:
                result_lines.append(line)
                continue
            rendered = _serialize_env_assignment_value(_serialize_admin_env_value(setting_meta, updates[key]))
            result_lines.append(f"{key}={rendered}")
            updated_keys.add(key)

        if result_lines and result_lines[-1].strip():
            result_lines.append("")

        for key, value in updates.items():
            if key in updated_keys:
                continue
            setting_meta = ADMIN_SETTINGS_FIELD_INDEX["env"].get(key)
            if not setting_meta:
                continue
            rendered = _serialize_env_assignment_value(_serialize_admin_env_value(setting_meta, value))
            result_lines.append(f"{key}={rendered}")

        content = "\n".join(result_lines).rstrip("\n")
        env_path.write_text(f"{content}\n" if content else "", encoding="utf-8")

    return env_path


def _render_admin_managed_config_block(values: dict[str, Any]) -> str:
    lines = [
        ADMIN_CONFIG_MANAGED_BEGIN,
        "# 本区块由管理员中心维护，若需手工调整，请修改区块外内容或在保存后重新覆盖。",
    ]
    for key in sorted(values.keys()):
        lines.append(f"{key} = {_serialize_admin_python_value(values[key])}")
    lines.append(ADMIN_CONFIG_MANAGED_END)
    return "\n".join(lines)


def _write_admin_config_updates(updates: dict[str, Any]) -> Path:
    config_path = get_admin_config_file_path()
    config_path.parent.mkdir(parents=True, exist_ok=True)

    with ADMIN_SETTINGS_WRITE_LOCK:
        existing_text = config_path.read_text(encoding="utf-8") if config_path.exists() else (
            "\"\"\"Intus 本地策略配置（由管理员中心可选覆盖）\"\"\"\n"
        )
        managed_values = _read_admin_managed_config_values(config_path)
        managed_values.update(updates)
        managed_block = _render_admin_managed_config_block(managed_values)

        if ADMIN_CONFIG_MANAGED_BEGIN in existing_text and ADMIN_CONFIG_MANAGED_END in existing_text:
            before, remainder = existing_text.split(ADMIN_CONFIG_MANAGED_BEGIN, 1)
            _, after = remainder.split(ADMIN_CONFIG_MANAGED_END, 1)
            merged = before.rstrip() + "\n\n" + managed_block + after
        else:
            merged = existing_text.rstrip() + "\n\n" + managed_block + "\n"

        config_path.write_text(merged.rstrip() + "\n", encoding="utf-8")

    return config_path


def _render_admin_site_config_file(values: dict[str, Any]) -> str:
    serialized = json.dumps(values, ensure_ascii=False, indent=2)
    return (
        "/**\n"
        " * Intus 前端配置文件\n"
        " *\n"
        " * 此文件由管理员中心维护。\n"
        " * 修改后请刷新浏览器页面生效。\n"
        " */\n\n"
        f"const SITE_CONFIG = {serialized};\n\n"
        "// 如果在 Node.js 环境中，导出配置\n"
        "if (typeof module !== \"undefined\" && module.exports) {\n"
        "  module.exports = SITE_CONFIG;\n"
        "}\n"
    )


def _write_admin_site_config_updates(updates: dict[str, Any]) -> Path:
    with ADMIN_SETTINGS_WRITE_LOCK:
        existing_values = load_runtime_site_config_values()
        merged_values = copy.deepcopy(existing_values) if isinstance(existing_values, dict) else {}
        for key, value in updates.items():
            _set_admin_nested_setting_value(merged_values, key, value)
        with get_meta_index_connection() as conn:
            _upsert_site_config_store_values(conn, merged_values)

    return Path(str(get_meta_index_db_target()))


def _get_admin_runtime_source_label(source: str, key: str) -> str:
    if source == "site":
        return "共享数据库 site_config_store（刷新页面后生效）"
    if os.environ.get(f"INTUS_{key}") is not None:
        return "INTUS_ 环境变量（保存配置文件不会覆盖当前运行值）"
    if os.environ.get(key) is not None:
        if key in LOADED_ENV_KEYS:
            return ".env 文件"
        return "进程环境变量（保存配置文件不会覆盖当前运行值）"
    if _should_use_runtime_config_fallback(key):
        return "config.py"
    return "内置默认"


def _get_admin_runtime_setting_value(source: str, key: str, *, site_values: Optional[dict[str, Any]] = None) -> Any:
    if source == "site":
        return _get_admin_nested_setting_value(site_values or {}, key)
    if key == "SECRET_KEY":
        return app.config.get("SECRET_KEY", "")
    if key == "AUTH_DB_PATH":
        return str(AUTH_DB_PATH)
    if key == "LICENSE_DB_PATH":
        return str(LICENSE_DB_PATH)
    if key == "META_INDEX_DB_PATH":
        return str(get_meta_index_db_target())
    if key == "ADMIN_USER_IDS":
        return sorted(int(item) for item in ADMIN_USER_IDS)
    if key == "ADMIN_PHONE_NUMBERS":
        return sorted(str(item) for item in ADMIN_PHONE_NUMBERS)
    value = globals().get(key)
    if isinstance(value, Path):
        return str(value)
    if isinstance(value, set):
        return sorted(str(item) for item in value)
    return value


