def get_meta_index_connection():
    ensure_meta_index_schema()
    return connect_db(get_meta_index_db_target())


def _decode_index_json(raw_text: str, default):
    text = str(raw_text or "").strip()
    if not text:
        return default
    try:
        parsed = json.loads(text)
        return parsed
    except Exception:
        return default


def _build_session_index_record(session_file: Path, session_data: dict) -> Optional[dict]:
    if not isinstance(session_data, dict):
        return None

    session_id = str(session_data.get("session_id") or "").strip()
    if not session_id:
        return None

    try:
        owner_user_id = int(session_data.get("owner_user_id"))
    except (TypeError, ValueError):
        return None
    if owner_user_id <= 0:
        return None

    signature = get_file_signature(session_file) or (0, 0)
    interview_log = session_data.get("interview_log", [])
    interview_count = len(interview_log) if isinstance(interview_log, list) else 0

    scenario_config = session_data.get("scenario_config")
    if isinstance(scenario_config, (dict, list)):
        scenario_config_json = json.dumps(scenario_config, ensure_ascii=False)
    else:
        scenario_config_json = "{}"

    dimensions_json = json.dumps(
        build_compact_dimensions(session_data.get("dimensions", {})),
        ensure_ascii=False,
    )
    current_report_name = normalize_solution_report_filename(session_data.get("current_report_name", ""))
    current_report_updated_at = str(session_data.get("current_report_updated_at") or "").strip()
    last_report_name = normalize_solution_report_filename(session_data.get("last_report_name", ""))
    last_report_quality_meta = session_data.get("last_report_quality_meta", {})
    if isinstance(last_report_quality_meta, dict):
        last_report_quality_meta_json = json.dumps(last_report_quality_meta, ensure_ascii=False)
    else:
        last_report_quality_meta_json = "{}"

    return {
        "session_id": session_id,
        "file_name": session_file.name,
        "owner_user_id": owner_user_id,
        "instance_scope_key": get_session_instance_scope_key(session_data),
        "topic": str(session_data.get("topic") or ""),
        "status": str(session_data.get("status") or "in_progress"),
        "created_at": str(session_data.get("created_at") or ""),
        "updated_at": str(session_data.get("updated_at") or ""),
        "interview_count": int(interview_count),
        "scenario_id": str(session_data.get("scenario_id") or ""),
        "scenario_config_json": scenario_config_json,
        "dimensions_json": dimensions_json,
        "current_report_name": current_report_name,
        "current_report_updated_at": current_report_updated_at,
        "last_report_name": last_report_name,
        "last_report_quality_meta_json": last_report_quality_meta_json,
        "file_mtime_ns": int(signature[0]),
        "file_size": int(signature[1]),
        "indexed_at": get_utc_now(),
    }


def _upsert_session_index_record(record: dict) -> None:
    if not isinstance(record, dict):
        return

    with get_meta_index_connection() as conn:
        conn.execute(
            "DELETE FROM session_index WHERE file_name = ? AND session_id <> ?",
            (record["file_name"], record["session_id"]),
        )
        conn.execute(
            """
            INSERT INTO session_index (
                session_id, file_name, owner_user_id, instance_scope_key, topic, status,
                created_at, updated_at, interview_count, scenario_id,
                scenario_config_json, dimensions_json, current_report_name, current_report_updated_at,
                last_report_name, last_report_quality_meta_json, file_mtime_ns,
                file_size, indexed_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(session_id) DO UPDATE SET
                file_name=excluded.file_name,
                owner_user_id=excluded.owner_user_id,
                instance_scope_key=excluded.instance_scope_key,
                topic=excluded.topic,
                status=excluded.status,
                created_at=excluded.created_at,
                updated_at=excluded.updated_at,
                interview_count=excluded.interview_count,
                scenario_id=excluded.scenario_id,
                scenario_config_json=excluded.scenario_config_json,
                dimensions_json=excluded.dimensions_json,
                current_report_name=excluded.current_report_name,
                current_report_updated_at=excluded.current_report_updated_at,
                last_report_name=excluded.last_report_name,
                last_report_quality_meta_json=excluded.last_report_quality_meta_json,
                file_mtime_ns=excluded.file_mtime_ns,
                file_size=excluded.file_size,
                indexed_at=excluded.indexed_at
            """,
            (
                record["session_id"],
                record["file_name"],
                record["owner_user_id"],
                record["instance_scope_key"],
                record["topic"],
                record["status"],
                record["created_at"],
                record["updated_at"],
                record["interview_count"],
                record["scenario_id"],
                record["scenario_config_json"],
                record["dimensions_json"],
                record["current_report_name"],
                record["current_report_updated_at"],
                record["last_report_name"],
                record["last_report_quality_meta_json"],
                record["file_mtime_ns"],
                record["file_size"],
                record["indexed_at"],
            ),
        )


def _write_text_atomic(file_path: Path, content: str, encoding: str = "utf-8") -> None:
    target = Path(file_path)
    target.parent.mkdir(parents=True, exist_ok=True)
    temp_path = target.with_name(f".{target.name}.{secrets.token_hex(6)}.tmp")
    try:
        temp_path.write_text(content, encoding=encoding)
        os.replace(temp_path, target)
    finally:
        if temp_path.exists():
            temp_path.unlink(missing_ok=True)


def _write_json_atomic(file_path: Path, payload: object) -> None:
    _write_text_atomic(
        file_path,
        json.dumps(payload, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )


def sync_session_index_and_bound_reports(session_file: Path, session_data: dict) -> None:
    record = _build_session_index_record(session_file, session_data)
    if record:
        _upsert_session_index_record(record)

    try:
        owner_user_id = int(session_data.get("owner_user_id") or 0)
    except (TypeError, ValueError):
        owner_user_id = 0
    if owner_user_id > 0:
        scope_key = get_session_instance_scope_key(session_data)
        binding_metadata = build_report_binding_metadata_from_session(session_data)
        for report_name in _collect_direct_bound_report_names(session_data):
            sync_report_index_for_filename(
                report_name,
                owner_user_id=owner_user_id,
                instance_scope_key=scope_key,
                binding_metadata=binding_metadata,
            )


def save_session_json_and_sync(session_file: Path, session_data: dict) -> tuple[int, int]:
    use_cloud_primary = _use_pure_cloud_session_storage()
    payload_text = _serialize_session_payload(session_data, compact=use_cloud_primary)
    signature = (int(_time.time_ns()), len(payload_text.encode("utf-8")))
    session_id = str(session_data.get("session_id") or "").strip()
    file_name = session_file.name
    if not use_cloud_primary:
        _write_text_atomic(session_file, payload_text, encoding="utf-8")
        signature = get_file_signature(session_file) or signature

    try:
        record = {
            "session_id": session_id,
            "file_name": file_name,
            "owner_user_id": _safe_int(session_data.get("owner_user_id"), 0),
            "instance_scope_key": get_session_instance_scope_key(session_data),
            "payload_json": payload_text,
            "created_at": str(session_data.get("created_at") or ""),
            "updated_at": str(session_data.get("updated_at") or ""),
            "payload_mtime_ns": int(signature[0]),
            "payload_size": int(signature[1]),
        }
        if not record["session_id"] or int(record["owner_user_id"]) <= 0:
            if use_cloud_primary:
                raise RuntimeError("会话缺少 session_id 或 owner_user_id，无法写入云端主存储")
        else:
            with get_meta_index_connection() as conn:
                _upsert_session_store_record(conn, record)
    except Exception as exc:
        if use_cloud_primary:
            raise
        if ENABLE_DEBUG_LOG:
            _safe_log(f"⚠️ 同步 session_store 失败: {session_file.name}, 错误: {exc}")

    try:
        sync_session_index_and_bound_reports(session_file, session_data)
    except Exception as exc:
        if use_cloud_primary:
            raise
        if ENABLE_DEBUG_LOG:
            _safe_log(f"⚠️ 同步 session_index 失败: {session_file.name}, 错误: {exc}")

    if session_id:
        _set_session_payload_cache(session_id, file_name, session_data, signature=signature)

    if use_cloud_primary and session_file.exists():
        session_file.unlink(missing_ok=True)
    return signature


def remove_session_index_record(session_id: str = "", file_name: str = "") -> None:
    sid = str(session_id or "").strip()
    fname = str(file_name or "").strip()
    if not sid and not fname:
        return

    with get_meta_index_connection() as conn:
        if sid and fname:
            conn.execute(
                "DELETE FROM session_index WHERE session_id = ? OR file_name = ?",
                (sid, fname),
            )
        elif sid:
            conn.execute("DELETE FROM session_index WHERE session_id = ?", (sid,))
        else:
            conn.execute("DELETE FROM session_index WHERE file_name = ?", (fname,))
    _delete_session_store_record(session_id=sid, file_name=fname)


def get_session_index_runtime_meta(session_id: str) -> dict:
    sid = str(session_id or "").strip()
    if not sid:
        return {}
    with get_meta_index_connection() as conn:
        row = conn.execute(
            """
            SELECT status, updated_at, current_report_name, current_report_updated_at,
                   last_report_name, last_report_quality_meta_json
            FROM session_index
            WHERE session_id = ?
            """,
            (sid,),
        ).fetchone()
    if not row:
        return {}
    return {
        "status": str(row["status"] or "").strip(),
        "updated_at": str(row["updated_at"] or "").strip(),
        "current_report_name": str(row["current_report_name"] or "").strip(),
        "current_report_updated_at": str(row["current_report_updated_at"] or "").strip(),
        "last_report_name": str(row["last_report_name"] or "").strip(),
        "last_report_quality_meta": _decode_index_json(row["last_report_quality_meta_json"], {}),
    }


def apply_session_index_runtime_meta(session_data: Optional[dict]) -> Optional[dict]:
    if not isinstance(session_data, dict):
        return session_data

    current_report_name = normalize_solution_report_filename(session_data.get("current_report_name", ""))
    if current_report_name:
        session_data["current_report_name"] = current_report_name
        report_reference = build_report_storage_reference(current_report_name)
        if report_reference:
            session_data["current_report_path"] = report_reference
        else:
            session_data.pop("current_report_path", None)

    last_report_name = normalize_solution_report_filename(session_data.get("last_report_name", ""))
    if last_report_name:
        session_data["last_report_name"] = last_report_name

    session_id = str(session_data.get("session_id") or "").strip()
    runtime_meta = get_session_index_runtime_meta(session_id)
    if not isinstance(runtime_meta, dict) or not runtime_meta:
        return session_data

    status = str(runtime_meta.get("status") or "").strip()
    if status:
        session_data["status"] = status
    updated_at = str(runtime_meta.get("updated_at") or "").strip()
    if updated_at:
        session_data["updated_at"] = updated_at
    current_report_name = normalize_solution_report_filename(runtime_meta.get("current_report_name", ""))
    if current_report_name:
        session_data["current_report_name"] = current_report_name
        report_reference = build_report_storage_reference(current_report_name)
        if report_reference:
            session_data["current_report_path"] = report_reference
        else:
            session_data.pop("current_report_path", None)
    current_report_updated_at = str(runtime_meta.get("current_report_updated_at") or "").strip()
    if current_report_updated_at:
        session_data["current_report_updated_at"] = current_report_updated_at
    last_report_name = normalize_solution_report_filename(runtime_meta.get("last_report_name", ""))
    if last_report_name:
        session_data["last_report_name"] = last_report_name
    quality_meta = runtime_meta.get("last_report_quality_meta")
    if isinstance(quality_meta, dict) and quality_meta:
        session_data["last_report_quality_meta"] = copy.deepcopy(quality_meta)
    return session_data


def rebuild_session_index_from_disk(*, full_reset: Optional[bool] = None) -> None:
    if full_reset is None:
        full_reset = not is_postgres_dsn(get_meta_index_db_target())

    records = []
    for session_file, session_data in _iter_session_payload_entries():
        record = _build_session_index_record(session_file, session_data)
        if record:
            records.append(record)

    if not full_reset:
        for record in records:
            _upsert_session_index_record(record)
        return

    with get_meta_index_connection() as conn:
        conn.execute("DELETE FROM session_index")
        if records:
            conn.executemany(
                """
                INSERT INTO session_index (
                    session_id, file_name, owner_user_id, instance_scope_key, topic, status,
                    created_at, updated_at, interview_count, scenario_id,
                    scenario_config_json, dimensions_json, file_mtime_ns,
                    file_size, indexed_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                [
                    (
                        record["session_id"],
                        record["file_name"],
                        record["owner_user_id"],
                        record["instance_scope_key"],
                        record["topic"],
                        record["status"],
                        record["created_at"],
                        record["updated_at"],
                        record["interview_count"],
                        record["scenario_id"],
                        record["scenario_config_json"],
                        record["dimensions_json"],
                        record["file_mtime_ns"],
                        record["file_size"],
                        record["indexed_at"],
                    )
                    for record in records
                ],
            )


def ensure_session_index_bootstrapped() -> None:
    ensure_meta_index_schema()
    is_pg_target = is_postgres_dsn(get_meta_index_db_target())

    with meta_index_state_lock:
        if meta_index_state.get("sessions_bootstrapped"):
            return
        meta_index_state["sessions_bootstrapped"] = True

    try:
        if is_pg_target:
            with get_meta_index_connection() as conn:
                if _meta_index_table_row_count(conn, "session_index") > 0:
                    rebuild_session_index_from_disk(full_reset=False)
                    return
        rebuild_session_index_from_disk(full_reset=not is_pg_target)
    except Exception as exc:
        with meta_index_state_lock:
            meta_index_state["sessions_bootstrapped"] = False
        raise RuntimeError(f"初始化 session_index 失败: {exc}") from exc


def query_session_index_for_user(owner_user_id: int, page: int, page_size: int) -> tuple[list[dict], int]:
    offset = (page - 1) * page_size
    with get_meta_index_connection() as conn:
        if is_instance_scope_enforced():
            scope_key = get_active_instance_scope_key()
            total_row = conn.execute(
                "SELECT COUNT(1) AS total FROM session_index WHERE owner_user_id = ? AND instance_scope_key = ?",
                (int(owner_user_id), scope_key),
            ).fetchone()
            total = int((total_row["total"] if total_row else 0) or 0)

            rows = conn.execute(
                """
                SELECT
                    session_id, topic, status, created_at, updated_at,
                    interview_count, scenario_id, scenario_config_json, dimensions_json
                FROM session_index
                WHERE owner_user_id = ? AND instance_scope_key = ?
                ORDER BY updated_at DESC
                LIMIT ? OFFSET ?
                """,
                (int(owner_user_id), scope_key, int(page_size), int(offset)),
            ).fetchall()
        else:
            total_row = conn.execute(
                "SELECT COUNT(1) AS total FROM session_index WHERE owner_user_id = ?",
                (int(owner_user_id),),
            ).fetchone()
            total = int((total_row["total"] if total_row else 0) or 0)

            rows = conn.execute(
                """
                SELECT
                    session_id, topic, status, created_at, updated_at,
                    interview_count, scenario_id, scenario_config_json, dimensions_json
                FROM session_index
                WHERE owner_user_id = ?
                ORDER BY updated_at DESC
                LIMIT ? OFFSET ?
                """,
                (int(owner_user_id), int(page_size), int(offset)),
            ).fetchall()

    result = []
    for row in rows:
        result.append({
            "session_id": row["session_id"],
            "topic": row["topic"],
            "status": row["status"],
            "created_at": row["created_at"],
            "updated_at": row["updated_at"],
            "interview_count": int(row["interview_count"] or 0),
            "scenario_id": row["scenario_id"],
            "scenario_config": _decode_index_json(row["scenario_config_json"], {}),
            "dimensions": _decode_index_json(row["dimensions_json"], {}),
        })
    return result, total


def empty_report_binding_metadata() -> dict:
    return {
        "session_id": "",
        "topic": "",
        "scenario_name": "",
        "report_template": "",
        "report_type": "",
        "report_profile": "",
        "source_report_name": "",
        "report_variant_label": "",
    }


def normalize_report_binding_metadata(metadata: Optional[dict] = None) -> dict:
    base = empty_report_binding_metadata()
    if not isinstance(metadata, dict):
        return base

    base["session_id"] = str(metadata.get("session_id") or "").strip()
    base["topic"] = str(metadata.get("topic") or "").strip()
    base["scenario_name"] = str(metadata.get("scenario_name") or "").strip()
    raw_report_type = str(metadata.get("report_type") or "").strip().lower()
    if raw_report_type not in {"standard", "assessment"}:
        raw_report_type = ""
    base["report_type"] = raw_report_type
    base["report_profile"] = normalize_report_profile_choice(metadata.get("report_profile", ""), fallback="")
    base["source_report_name"] = normalize_solution_report_filename(metadata.get("source_report_name", ""))
    variant_label = clean_solution_text(metadata.get("report_variant_label", ""), max_len=32)
    if not variant_label and base["report_profile"]:
        variant_label = "精审版" if base["report_profile"] == "quality" else "普通版"
    base["report_variant_label"] = variant_label
    base["report_template"] = normalize_report_template_name(
        metadata.get("report_template", ""),
        report_type=raw_report_type or "standard",
    ) if str(metadata.get("report_template") or "").strip() else ""
    return base


def build_report_binding_metadata_from_session(session_data: dict, report_name: str = "") -> dict:
    metadata = empty_report_binding_metadata()
    if not isinstance(session_data, dict):
        return metadata

    normalized_report_name = normalize_solution_report_filename(report_name)
    if normalized_report_name:
        direct_names = _collect_direct_bound_report_names(session_data)
        if normalized_report_name not in direct_names:
            return metadata

    scenario_config = session_data.get("scenario_config", {}) if isinstance(session_data.get("scenario_config", {}), dict) else {}
    report_cfg = scenario_config.get("report", {}) if isinstance(scenario_config.get("report", {}), dict) else {}
    report_type = str(report_cfg.get("type") or "standard").strip().lower()
    if report_type not in {"standard", "assessment"}:
        report_type = "standard"

    current_report_name = normalize_solution_report_filename(session_data.get("current_report_name", ""))
    inferred_report_profile = "balanced"
    inferred_source_report_name = ""
    inferred_variant_label = "普通版"
    if normalized_report_name and normalized_report_name.endswith("-quality.md"):
        inferred_report_profile = "quality"
        inferred_variant_label = "精审版"
        if current_report_name and current_report_name != normalized_report_name:
            inferred_source_report_name = current_report_name

    metadata.update({
        "session_id": str(session_data.get("session_id") or "").strip(),
        "topic": str(session_data.get("topic") or "").strip(),
        "scenario_name": str(scenario_config.get("name") or "").strip(),
        "report_type": report_type,
        "report_template": normalize_report_template_name(
            report_cfg.get("template", ""),
            report_type=report_type,
        ),
        "report_profile": inferred_report_profile,
        "source_report_name": inferred_source_report_name,
        "report_variant_label": inferred_variant_label,
    })
    return normalize_report_binding_metadata(metadata)


def collect_direct_bound_report_metadata_from_sessions() -> dict:
    metadata_map = {}
    expected_scope = get_active_instance_scope_key()
    for _session_file, session_data in _iter_session_payload_entries():
        if not isinstance(session_data, dict):
            continue
        if not is_instance_scope_visible(get_session_instance_scope_key(session_data), expected_scope=expected_scope):
            continue
        metadata = build_report_binding_metadata_from_session(session_data)
        if not any(metadata.values()):
            continue
        for report_name in _collect_direct_bound_report_names(session_data):
            normalized_report_name = normalize_solution_report_filename(report_name)
            if not normalized_report_name or normalized_report_name in metadata_map:
                continue
            metadata_map[normalized_report_name] = dict(metadata)
    return metadata_map


def _build_report_index_record(
    file_name: str,
    owner_user_id: int,
    deleted: bool,
    instance_scope_key: object = "",
    binding_metadata: Optional[dict] = None,
) -> Optional[dict]:
    name = str(file_name or "").strip()
    if not name or not name.endswith(".md"):
        return None
    if int(owner_user_id) <= 0:
        return None

    signature = _get_report_store_signature(name)
    if signature is None:
        return None

    normalized_binding = normalize_report_binding_metadata(binding_metadata)
    sidecar_binding = empty_report_binding_metadata()
    sidecar = read_solution_sidecar(name)
    if isinstance(sidecar, dict) and sidecar:
        normalized_snapshot = _normalize_solution_snapshot(sidecar)
        sidecar_binding = normalize_report_binding_metadata({
            "session_id": normalized_snapshot.get("session_id", ""),
            "topic": normalized_snapshot.get("topic", ""),
            "scenario_name": normalized_snapshot.get("scenario_name", ""),
            "report_template": normalized_snapshot.get("report_template", ""),
            "report_type": normalized_snapshot.get("report_type", ""),
            "report_profile": normalized_snapshot.get("report_profile", ""),
            "source_report_name": normalized_snapshot.get("source_report_name", ""),
            "report_variant_label": normalized_snapshot.get("report_variant_label", ""),
        })

    merged_binding = dict(normalized_binding)
    for key, value in sidecar_binding.items():
        if value:
            merged_binding[key] = value

    generated_at = _get_report_generated_at(name)
    created_at = generated_at.isoformat() if isinstance(generated_at, datetime) else ""
    return {
        "file_name": name,
        "owner_user_id": int(owner_user_id),
        "instance_scope_key": get_record_instance_scope_key(instance_scope_key),
        "deleted": 1 if deleted else 0,
        "size": int(signature[1]),
        "created_at": created_at,
        "session_id": merged_binding.get("session_id", ""),
        "topic": merged_binding.get("topic", ""),
        "scenario_name": merged_binding.get("scenario_name", ""),
        "report_template": merged_binding.get("report_template", ""),
        "report_type": merged_binding.get("report_type", ""),
        "report_profile": merged_binding.get("report_profile", ""),
        "source_report_name": merged_binding.get("source_report_name", ""),
        "report_variant_label": merged_binding.get("report_variant_label", ""),
        "file_mtime_ns": int(signature[0]),
        "file_size": int(signature[1]),
        "indexed_at": get_utc_now(),
    }


def _upsert_report_index_record(record: dict) -> None:
    if not isinstance(record, dict):
        return

    with get_meta_index_connection() as conn:
        conn.execute(
            """
            INSERT INTO report_index (
                file_name, owner_user_id, instance_scope_key, deleted, size, created_at,
                session_id, topic, scenario_name, report_template, report_type,
                report_profile, source_report_name, report_variant_label,
                file_mtime_ns, file_size, indexed_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(file_name) DO UPDATE SET
                owner_user_id=excluded.owner_user_id,
                instance_scope_key=excluded.instance_scope_key,
                deleted=excluded.deleted,
                size=excluded.size,
                created_at=excluded.created_at,
                session_id=excluded.session_id,
                topic=excluded.topic,
                scenario_name=excluded.scenario_name,
                report_template=excluded.report_template,
                report_type=excluded.report_type,
                report_profile=excluded.report_profile,
                source_report_name=excluded.source_report_name,
                report_variant_label=excluded.report_variant_label,
                file_mtime_ns=excluded.file_mtime_ns,
                file_size=excluded.file_size,
                indexed_at=excluded.indexed_at
            """,
            (
                record["file_name"],
                record["owner_user_id"],
                record["instance_scope_key"],
                record["deleted"],
                record["size"],
                record["created_at"],
                record["session_id"],
                record["topic"],
                record["scenario_name"],
                record["report_template"],
                record["report_type"],
                record["report_profile"],
                record["source_report_name"],
                record["report_variant_label"],
                record["file_mtime_ns"],
                record["file_size"],
                record["indexed_at"],
            ),
        )


def remove_report_index_record(file_name: str) -> None:
    name = str(file_name or "").strip()
    if not name:
        return
    with get_meta_index_connection() as conn:
        conn.execute("DELETE FROM report_index WHERE file_name = ?", (name,))


def sync_report_index_for_filename(
    file_name: str,
    owner_user_id: Optional[int] = None,
    deleted: Optional[bool] = None,
    instance_scope_key: Optional[object] = None,
    binding_metadata: Optional[dict] = None,
) -> None:
    name = str(file_name or "").strip()
    if not name:
        return

    if owner_user_id is None:
        owner_user_id = get_report_owner_id(name)
    owner_id = int(owner_user_id or 0)
    if owner_id <= 0:
        remove_report_index_record(name)
        return

    scope_key = get_report_scope_key(name) if instance_scope_key is None else get_record_instance_scope_key(instance_scope_key)
    is_deleted = bool(deleted) if deleted is not None else (name in get_deleted_reports())
    record = _build_report_index_record(name, owner_id, is_deleted, scope_key, binding_metadata=binding_metadata)
    if not record:
        remove_report_index_record(name)
        return
    _upsert_report_index_record(record)


def rebuild_report_index_from_sources(*, full_reset: Optional[bool] = None) -> None:
    if full_reset is None:
        full_reset = not is_postgres_dsn(get_meta_index_db_target())

    owner_map = load_report_owners()
    scope_map = load_report_scopes()
    deleted_set = get_deleted_reports()
    binding_map = collect_direct_bound_report_metadata_from_sessions()
    records = []
    for report_name, owner_id in owner_map.items():
        record = _build_report_index_record(
            report_name,
            int(owner_id),
            report_name in deleted_set,
            scope_map.get(report_name, ""),
            binding_metadata=binding_map.get(report_name),
        )
        if record:
            records.append(record)

    if not full_reset:
        for record in records:
            _upsert_report_index_record(record)
        return

    with get_meta_index_connection() as conn:
        conn.execute("DELETE FROM report_index")
        if records:
            conn.executemany(
                """
                INSERT INTO report_index (
                    file_name, owner_user_id, instance_scope_key, deleted, size, created_at,
                    session_id, topic, scenario_name, report_template, report_type,
                    report_profile, source_report_name, report_variant_label,
                    file_mtime_ns, file_size, indexed_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                [
                    (
                        record["file_name"],
                        record["owner_user_id"],
                        record["instance_scope_key"],
                        record["deleted"],
                        record["size"],
                        record["created_at"],
                        record["session_id"],
                        record["topic"],
                        record["scenario_name"],
                        record["report_template"],
                        record["report_type"],
                        record["report_profile"],
                        record["source_report_name"],
                        record["report_variant_label"],
                        record["file_mtime_ns"],
                        record["file_size"],
                        record["indexed_at"],
                    )
                    for record in records
                ],
            )


def ensure_report_index_bootstrapped() -> None:
    ensure_meta_index_schema()
    is_pg_target = is_postgres_dsn(get_meta_index_db_target())

    with meta_index_state_lock:
        if meta_index_state.get("reports_bootstrapped"):
            return
        meta_index_state["reports_bootstrapped"] = True

    try:
        if is_pg_target:
            with get_meta_index_connection() as conn:
                if _meta_index_table_row_count(conn, "report_index") > 0:
                    rebuild_report_index_from_sources(full_reset=False)
                    return
        rebuild_report_index_from_sources(full_reset=not is_pg_target)
    except Exception as exc:
        with meta_index_state_lock:
            meta_index_state["reports_bootstrapped"] = False
        raise RuntimeError(f"初始化 report_index 失败: {exc}") from exc


def query_report_index_for_user(owner_user_id: int, page: int, page_size: int) -> tuple[list[dict], int]:
    offset = (page - 1) * page_size
    with get_meta_index_connection() as conn:
        if is_instance_scope_enforced():
            scope_key = get_active_instance_scope_key()
            rows = conn.execute(
                """
                SELECT
                    file_name, size, created_at,
                    session_id, topic, scenario_name, report_template, report_type,
                    report_profile, source_report_name, report_variant_label
                FROM report_index
                WHERE owner_user_id = ? AND instance_scope_key = ? AND deleted = 0
                ORDER BY created_at DESC
                """,
                (int(owner_user_id), scope_key),
            ).fetchall()
        else:
            rows = conn.execute(
                """
                SELECT
                    file_name, size, created_at,
                    session_id, topic, scenario_name, report_template, report_type,
                    report_profile, source_report_name, report_variant_label
                FROM report_index
                WHERE owner_user_id = ? AND deleted = 0
                ORDER BY created_at DESC
                """,
                (int(owner_user_id),),
            ).fetchall()

    visible_rows = []
    stale_report_names = []
    owner_id = int(owner_user_id)
    for row in rows:
        report_name = str(row["file_name"] or "").strip()
        if not report_name:
            continue
        if not _report_exists(report_name) or not ensure_report_owner(report_name, owner_id):
            stale_report_names.append(report_name)
            continue
        visible_rows.append(row)

    if stale_report_names:
        unique_stale_report_names = list(dict.fromkeys(stale_report_names))
        for report_name in unique_stale_report_names:
            remove_report_index_record(report_name)

    total = len(visible_rows)
    page_rows = visible_rows[offset: offset + page_size]
    return ([
        build_report_list_item(
            row["file_name"],
            int(row["size"] or 0),
            str(row["created_at"] or ""),
            binding_metadata={
                "session_id": row["session_id"],
                "topic": row["topic"],
                "scenario_name": row["scenario_name"],
                "report_template": row["report_template"],
                "report_type": row["report_type"],
                "report_profile": row["report_profile"],
                "source_report_name": row["source_report_name"],
                "report_variant_label": row["report_variant_label"],
            },
        )
        for row in page_rows
    ], total)


