def normalize_user_level_key(value: object, fallback: str = DEFAULT_USER_LEVEL_KEY) -> str:
    normalized_fallback = str(fallback or DEFAULT_USER_LEVEL_KEY).strip().lower() or DEFAULT_USER_LEVEL_KEY
    if normalized_fallback not in USER_LEVEL_DEFINITIONS:
        normalized_fallback = DEFAULT_USER_LEVEL_KEY
    normalized_value = str(value or "").strip().lower()
    if not normalized_value:
        return normalized_fallback
    if normalized_value not in USER_LEVEL_DEFINITIONS:
        return normalized_fallback
    return normalized_value


def parse_user_level_key(
    value: object,
    *,
    field_name: str = "level_key",
    fallback: str = DEFAULT_USER_LEVEL_KEY,
    allow_empty: bool = True,
) -> str:
    normalized_value = str(value or "").strip().lower()
    if not normalized_value:
        if allow_empty:
            return normalize_user_level_key(fallback)
        raise ValueError(f"{field_name} 不能为空")
    if normalized_value not in USER_LEVEL_DEFINITIONS:
        raise ValueError(f"{field_name} 无效，仅支持：experience、standard、professional")
    return normalized_value


def get_user_level_meta(level_key: object) -> dict:
    normalized_level_key = normalize_user_level_key(level_key)
    meta = USER_LEVEL_DEFINITIONS.get(normalized_level_key) or USER_LEVEL_DEFINITIONS[DEFAULT_USER_LEVEL_KEY]
    return dict(meta)


def list_user_level_keys() -> list[str]:
    return [
        key
        for key, _meta in sorted(
            USER_LEVEL_DEFINITIONS.items(),
            key=lambda item: int((item[1] or {}).get("sort_order") or 0),
        )
    ]


def build_user_level_payload(level_key: object) -> dict:
    return get_user_level_meta(level_key)


def build_user_capabilities_for_level(level_key: object) -> dict:
    normalized_level_key = normalize_user_level_key(level_key)
    capability_map = USER_LEVEL_CAPABILITY_MAP.get(normalized_level_key) or USER_LEVEL_CAPABILITY_MAP[DEFAULT_USER_LEVEL_KEY]
    return {
        str(key): bool(value)
        for key, value in capability_map.items()
    }


def get_allowed_report_profiles_for_level(level_key: object) -> list[str]:
    normalized_level_key = normalize_user_level_key(level_key)
    profiles = USER_LEVEL_ALLOWED_REPORT_PROFILES.get(normalized_level_key) or USER_LEVEL_ALLOWED_REPORT_PROFILES["experience"]
    allowed: list[str] = []
    for item in profiles:
        normalized = normalize_report_profile_choice(item, fallback="balanced")
        if normalized and normalized not in allowed:
            allowed.append(normalized)
    return allowed or ["balanced"]


def get_allowed_interview_modes_for_level(level_key: object) -> list[str]:
    normalized_level_key = normalize_user_level_key(level_key)
    modes = USER_LEVEL_ALLOWED_INTERVIEW_MODES.get(normalized_level_key) or USER_LEVEL_ALLOWED_INTERVIEW_MODES["experience"]
    allowed: list[str] = []
    for item in modes:
        normalized = str(item or "").strip().lower()
        if normalized in {"quick", "standard", "deep"} and normalized not in allowed:
            allowed.append(normalized)
    return allowed or ["quick"]


def get_default_interview_mode_for_level(level_key: object, preferred_mode: object = None) -> str:
    allowed_modes = get_allowed_interview_modes_for_level(level_key)
    preferred = str(preferred_mode or "").strip().lower()
    if preferred in allowed_modes:
        return preferred
    configured_default = str(USER_LEVEL_DEFAULT_INTERVIEW_MODE.get(normalize_user_level_key(level_key)) or DEFAULT_INTERVIEW_MODE).strip().lower()
    if configured_default in allowed_modes:
        return configured_default
    return allowed_modes[0]


def get_required_user_level_for_interview_mode(mode: object) -> str:
    normalized_mode = str(mode or "").strip().lower()
    if normalized_mode not in {"quick", "standard", "deep"}:
        return "professional"
    for level_key in list_user_level_keys():
        if normalized_mode in get_allowed_interview_modes_for_level(level_key):
            return level_key
    return "professional"


def build_interview_mode_requirements() -> dict:
    requirements = {}
    for mode in ("quick", "standard", "deep"):
        required_level_key = get_required_user_level_for_interview_mode(mode)
        requirements[mode] = build_user_level_payload(required_level_key)
    return requirements


def get_default_report_profile_for_level(level_key: object, preferred_profile: object = None) -> str:
    allowed_profiles = get_allowed_report_profiles_for_level(level_key)
    preferred = normalize_report_profile_choice(preferred_profile or REPORT_V3_PROFILE, fallback="balanced")
    if preferred in allowed_profiles:
        return preferred
    return allowed_profiles[0]


def resolve_effective_user_level(
    user_row: Optional[sqlite3.Row],
    *,
    license_state: Optional[dict] = None,
) -> str:
    if not user_row:
        return "experience"
    resolved_license_state = license_state if isinstance(license_state, dict) else get_user_license_state(int(user_row["id"]))
    if not bool(resolved_license_state.get("enforcement_enabled")):
        if bool(resolved_license_state.get("has_valid_license")):
            license_summary = resolved_license_state.get("license") or {}
            license_level_key = normalize_user_level_key(license_summary.get("level_key"), fallback=DEFAULT_USER_LEVEL_KEY)
            if license_level_key != "experience":
                return license_level_key
        return "professional"
    if bool(resolved_license_state.get("has_valid_license")):
        license_summary = resolved_license_state.get("license") or {}
        return normalize_user_level_key(license_summary.get("level_key"), fallback=DEFAULT_USER_LEVEL_KEY)
    license_summary = resolved_license_state.get("license") or {}
    return normalize_user_level_key(license_summary.get("level_key"), fallback="experience")


def build_user_level_context_for_user(
    user_row: Optional[sqlite3.Row],
    *,
    license_state: Optional[dict] = None,
    prefer_bound_license_level: bool = False,
) -> dict:
    resolved_license_state = license_state if isinstance(license_state, dict) else (
        get_user_license_state(int(user_row["id"])) if user_row else {}
    )
    if prefer_bound_license_level and bool(resolved_license_state.get("has_valid_license")):
        license_summary = resolved_license_state.get("license") or {}
        level_key = normalize_user_level_key(license_summary.get("level_key"), fallback=DEFAULT_USER_LEVEL_KEY)
    else:
        level_key = resolve_effective_user_level(user_row, license_state=resolved_license_state)
    return {
        "level": build_user_level_payload(level_key),
        "capabilities": build_user_capabilities_for_level(level_key),
        "allowed_report_profiles": get_allowed_report_profiles_for_level(level_key),
        "report_profile_default": get_default_report_profile_for_level(level_key),
        "allowed_interview_modes": get_allowed_interview_modes_for_level(level_key),
        "interview_mode_default": get_default_interview_mode_for_level(level_key),
        "interview_mode_requirements": build_interview_mode_requirements(),
    }


def get_required_user_level_for_capability(capability_key: object) -> str:
    normalized_key = str(capability_key or "").strip()
    if normalized_key.startswith("interview.mode."):
        mode_key = normalized_key.split(".", 2)[-1]
        return get_required_user_level_for_interview_mode(mode_key)
    for level_key in list_user_level_keys():
        if bool(build_user_capabilities_for_level(level_key).get(normalized_key)):
            return level_key
    return "professional"


def user_has_level_capability(
    user_row: Optional[sqlite3.Row],
    capability_key: object,
    *,
    level_context: Optional[dict] = None,
    license_state: Optional[dict] = None,
) -> bool:
    normalized_key = str(capability_key or "").strip()
    if not normalized_key:
        return False
    context = level_context if isinstance(level_context, dict) else build_user_level_context_for_user(
        user_row,
        license_state=license_state,
    )
    capabilities = context.get("capabilities") or {}
    return bool(capabilities.get(normalized_key))


def build_level_capability_denied_response(
    user_row: Optional[sqlite3.Row],
    capability_key: object,
    *,
    level_context: Optional[dict] = None,
) -> tuple[Response, int]:
    normalized_key = str(capability_key or "").strip()
    context = level_context if isinstance(level_context, dict) else build_user_level_context_for_user(user_row)
    current_level = context.get("level") or build_user_level_payload("experience")
    required_level_key = get_required_user_level_for_capability(normalized_key)
    required_level = build_user_level_payload(required_level_key)
    if current_level.get("key") == required_level_key:
        upgrade_hint = "当前用户级别暂未开放该功能，请联系管理员确认权限配置"
    else:
        upgrade_hint = f"当前功能需升级到{required_level.get('name') or '更高等级'}后使用"
    return jsonify({
        "error": upgrade_hint,
        "error_code": "level_capability_denied",
        "capability_key": normalized_key,
        "current_level": current_level,
        "required_level": required_level,
        "upgrade_hint": upgrade_hint,
    }), 403


def ensure_auth_meta_table(conn: sqlite3.Connection) -> None:
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS auth_meta (
            meta_key TEXT PRIMARY KEY,
            meta_value TEXT NOT NULL,
            updated_at TEXT NOT NULL
        )
        """
    )


def ensure_license_tables(conn: sqlite3.Connection) -> None:
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS licenses (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            batch_id TEXT NOT NULL,
            code_hash TEXT NOT NULL UNIQUE,
            code_mask TEXT NOT NULL,
            status TEXT NOT NULL DEFAULT 'issued',
            level_key TEXT NOT NULL DEFAULT 'standard',
            not_before_at TEXT NOT NULL,
            expires_at TEXT NOT NULL,
            duration_days INTEGER NOT NULL DEFAULT 0,
            bound_user_id INTEGER,
            bound_at TEXT,
            replaced_by_license_id INTEGER,
            revoked_at TEXT,
            revoked_reason TEXT NOT NULL DEFAULT '',
            note TEXT NOT NULL DEFAULT '',
            created_at TEXT NOT NULL,
            updated_at TEXT NOT NULL
        )
        """
    )
    conn.execute("CREATE INDEX IF NOT EXISTS idx_licenses_batch_id ON licenses(batch_id)")
    conn.execute("CREATE INDEX IF NOT EXISTS idx_licenses_status ON licenses(status)")
    conn.execute("CREATE INDEX IF NOT EXISTS idx_licenses_bound_user_id ON licenses(bound_user_id)")
    conn.execute("CREATE INDEX IF NOT EXISTS idx_licenses_expires_at ON licenses(expires_at)")
    license_columns = {
        str(row[1]): True
        for row in conn.execute("PRAGMA table_info(licenses)").fetchall()
    }
    if "duration_days" not in license_columns:
        conn.execute("ALTER TABLE licenses ADD COLUMN duration_days INTEGER NOT NULL DEFAULT 0")
    if "level_key" not in license_columns:
        conn.execute("ALTER TABLE licenses ADD COLUMN level_key TEXT NOT NULL DEFAULT 'standard'")

    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS license_events (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            license_id INTEGER,
            actor_user_id INTEGER,
            event_type TEXT NOT NULL,
            payload_json TEXT NOT NULL DEFAULT '{}',
            created_at TEXT NOT NULL
        )
        """
    )
    conn.execute("CREATE INDEX IF NOT EXISTS idx_license_events_license_id ON license_events(license_id)")
    conn.execute("CREATE INDEX IF NOT EXISTS idx_license_events_actor_user_id ON license_events(actor_user_id)")
    conn.execute("CREATE INDEX IF NOT EXISTS idx_license_events_event_type ON license_events(event_type)")


def _migrate_legacy_license_data_to_license_db(conn: sqlite3.Connection) -> bool:
    auth_db_resolved = _resolve_auth_db_cache_path()
    license_db_resolved = _resolve_license_db_cache_path()
    if auth_db_resolved == license_db_resolved:
        return False

    has_existing_license_rows = conn.execute("SELECT 1 FROM licenses LIMIT 1").fetchone() is not None
    has_existing_license_events = conn.execute("SELECT 1 FROM license_events LIMIT 1").fetchone() is not None
    has_existing_license_meta = conn.execute(
        f"SELECT 1 FROM auth_meta WHERE meta_key IN ({','.join('?' for _ in LICENSE_META_KEYS)}) LIMIT 1",
        tuple(sorted(LICENSE_META_KEYS)),
    ).fetchone() is not None
    if has_existing_license_rows or has_existing_license_events or has_existing_license_meta:
        return False

    if not db_target_exists(AUTH_DB_PATH):
        return False

    migrated = False
    with get_auth_db_connection() as auth_conn:
        if _db_table_exists(auth_conn, "licenses"):
            auth_license_columns = {
                str(row[1]): True
                for row in auth_conn.execute("PRAGMA table_info(licenses)").fetchall()
            }
            has_level_key = "level_key" in auth_license_columns
            rows = auth_conn.execute(
                f"""
                SELECT id, batch_id, code_hash, code_mask, status,
                       {'level_key,' if has_level_key else ''}
                       not_before_at, expires_at, duration_days,
                       bound_user_id, bound_at, replaced_by_license_id, revoked_at,
                       revoked_reason, note, created_at, updated_at
                FROM licenses
                ORDER BY id ASC
                """
            ).fetchall()
            if rows:
                conn.executemany(
                    """
                    INSERT INTO licenses (
                        id, batch_id, code_hash, code_mask, status, level_key, not_before_at, expires_at, duration_days,
                        bound_user_id, bound_at, replaced_by_license_id, revoked_at,
                        revoked_reason, note, created_at, updated_at
                    )
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    """,
                    [
                        (
                            int(row["id"]),
                            str(row["batch_id"] or "").strip(),
                            str(row["code_hash"] or "").strip(),
                            str(row["code_mask"] or "").strip(),
                            str(row["status"] or "").strip(),
                            normalize_user_level_key(row["level_key"]) if has_level_key else DEFAULT_USER_LEVEL_KEY,
                            str(row["not_before_at"] or "").strip(),
                            str(row["expires_at"] or "").strip(),
                            int(row["duration_days"] or 0),
                            int(row["bound_user_id"] or 0) or None,
                            str(row["bound_at"] or "").strip() or None,
                            int(row["replaced_by_license_id"] or 0) or None,
                            str(row["revoked_at"] or "").strip() or None,
                            str(row["revoked_reason"] or "").strip(),
                            str(row["note"] or "").strip(),
                            str(row["created_at"] or "").strip(),
                            str(row["updated_at"] or "").strip(),
                        )
                        for row in rows
                    ],
                )
                migrated = True

        if _db_table_exists(auth_conn, "license_events"):
            rows = auth_conn.execute(
                """
                SELECT id, license_id, actor_user_id, event_type, payload_json, created_at
                FROM license_events
                ORDER BY id ASC
                """
            ).fetchall()
            if rows:
                conn.executemany(
                    """
                    INSERT INTO license_events (id, license_id, actor_user_id, event_type, payload_json, created_at)
                    VALUES (?, ?, ?, ?, ?, ?)
                    """,
                    [
                        (
                            int(row["id"]),
                            int(row["license_id"] or 0) or None,
                            int(row["actor_user_id"] or 0) or None,
                            str(row["event_type"] or "").strip(),
                            str(row["payload_json"] or "{}"),
                            str(row["created_at"] or "").strip(),
                        )
                        for row in rows
                    ],
                )
                migrated = True

        if _db_table_exists(auth_conn, "auth_meta"):
            meta_rows = auth_conn.execute(
                f"""
                SELECT meta_key, meta_value, updated_at
                FROM auth_meta
                WHERE meta_key IN ({','.join('?' for _ in LICENSE_META_KEYS)})
                """,
                tuple(sorted(LICENSE_META_KEYS)),
            ).fetchall()
            if meta_rows:
                conn.executemany(
                    """
                    INSERT INTO auth_meta (meta_key, meta_value, updated_at)
                    VALUES (?, ?, ?)
                    ON CONFLICT(meta_key) DO UPDATE SET
                        meta_value = excluded.meta_value,
                        updated_at = excluded.updated_at
                    """,
                    [
                        (
                            str(row["meta_key"] or "").strip(),
                            str(row["meta_value"] or "").strip(),
                            str(row["updated_at"] or "").strip() or datetime.now(timezone.utc).isoformat(),
                        )
                        for row in meta_rows
                    ],
                )
                migrated = True

    return migrated


def _clear_cached_license_signing_secret() -> None:
    with license_signing_secret_cache_lock:
        license_signing_secret_cache["db_path"] = ""
        license_signing_secret_cache["configured_seed"] = ""
        license_signing_secret_cache["value"] = ""


def _resolve_auth_db_cache_path() -> str:
    return normalize_db_cache_key(AUTH_DB_PATH)


def _resolve_license_db_cache_path() -> str:
    return normalize_db_cache_key(LICENSE_DB_PATH)


def _legacy_license_signing_secret() -> str:
    return _first_non_empty(
        CONFIG_SECRET_KEY,
        str(app.secret_key or ""),
        "intus-dev-license-secret",
    )


def _db_table_exists(conn, table_name: str) -> bool:
    table = str(table_name or "").strip()
    if not table:
        return False
    try:
        row = conn.execute(f"PRAGMA table_info({table})").fetchone()
        return bool(row)
    except Exception:
        return False


def _read_auth_meta_value(conn: sqlite3.Connection, meta_key: str) -> str:
    row = conn.execute(
        "SELECT meta_value FROM auth_meta WHERE meta_key = ? LIMIT 1",
        (str(meta_key or "").strip(),),
    ).fetchone()
    if not row:
        return ""
    return str(row["meta_value"] or "").strip()


def _write_auth_meta_value(conn: sqlite3.Connection, meta_key: str, meta_value: str) -> None:
    now_iso = datetime.now(timezone.utc).isoformat()
    conn.execute(
        """
        INSERT INTO auth_meta (meta_key, meta_value, updated_at)
        VALUES (?, ?, ?)
        ON CONFLICT(meta_key) DO UPDATE SET
            meta_value = excluded.meta_value,
            updated_at = excluded.updated_at
        """,
        (
            str(meta_key or "").strip(),
            str(meta_value or "").strip(),
            now_iso,
        ),
    )


def _ensure_license_signing_secret_in_auth_meta(conn: sqlite3.Connection) -> tuple[str, str]:
    ensure_auth_meta_table(conn)
    persisted_value = _read_auth_meta_value(conn, AUTH_META_LICENSE_SIGNING_SECRET_KEY)
    if persisted_value:
        return persisted_value, "auth_meta"

    configured_seed = str(LICENSE_CODE_SIGNING_SECRET or "").strip()
    if configured_seed:
        secret_value = configured_seed
        source = "env_seed"
    else:
        has_existing_licenses = conn.execute("SELECT 1 FROM licenses LIMIT 1").fetchone() is not None
        if has_existing_licenses:
            secret_value = _legacy_license_signing_secret()
            source = "legacy_migrated"
        else:
            secret_value = secrets.token_urlsafe(32)
            source = "generated"

    _write_auth_meta_value(conn, AUTH_META_LICENSE_SIGNING_SECRET_KEY, secret_value)
    return secret_value, source


def _parse_bool_like(value: object) -> Optional[bool]:
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)) and not isinstance(value, bool):
        if value == 1:
            return True
        if value == 0:
            return False
        return None
    text = str(value or "").strip().lower()
    if not text:
        return None
    if text in {"1", "true", "yes", "on", "enabled"}:
        return True
    if text in {"0", "false", "no", "off", "disabled"}:
        return False
    return None


def get_license_enforcement_default_state() -> dict[str, Any]:
    env_path = get_admin_env_file_path()
    env_values = _read_env_file_map(env_path)
    file_enabled = _parse_bool_like(env_values.get("LICENSE_ENFORCEMENT_ENABLED"))
    if file_enabled is not None:
        return {
            "enabled": bool(file_enabled),
            "source": "env_file",
            "source_label": ".env 默认值",
            "path": str(env_path),
            "value_in_file": True,
        }
    return {
        "enabled": bool(LICENSE_ENFORCEMENT_ENABLED),
        "source": "startup_default",
        "source_label": "启动默认值",
        "path": str(env_path),
        "value_in_file": False,
    }


def get_license_enforcement_state() -> dict:
    default_state = get_license_enforcement_default_state()
    default_enabled = bool(default_state.get("enabled"))
    override_enabled = None
    override_present = False
    updated_at = None
    updated_by_user_id = None
    try:
        with get_license_db_connection() as conn:
            ensure_auth_meta_table(conn)
            raw = _read_auth_meta_value(conn, AUTH_META_LICENSE_ENFORCEMENT_ENABLED_KEY)
            if raw:
                override_enabled = _parse_bool_like(raw)
                override_present = override_enabled is not None
            at_raw = _read_auth_meta_value(conn, AUTH_META_LICENSE_ENFORCEMENT_UPDATED_AT_KEY)
            if at_raw:
                updated_at = at_raw
            by_raw = _read_auth_meta_value(conn, AUTH_META_LICENSE_ENFORCEMENT_UPDATED_BY_KEY)
            if by_raw:
                try:
                    updated_by_user_id = int(by_raw)
                except (ValueError, TypeError):
                    pass
    except Exception:
        pass
    if override_present and override_enabled is not None:
        enabled = bool(override_enabled)
        source = "runtime_override"
        source_label = "管理员手动设置"
    else:
        enabled = default_enabled
        source = "env_default"
        source_label = str(default_state.get("source_label") or "启动默认值")
    message = "登录后必须绑定有效 License 才能继续使用。" if enabled else "License 验证已关闭，无需绑定即可使用。"
    return {
        "enabled": enabled,
        "default_enabled": default_enabled,
        "default_source": str(default_state.get("source") or "startup_default"),
        "default_source_label": str(default_state.get("source_label") or "启动默认值"),
        "default_path": str(default_state.get("path") or ""),
        "default_value_in_file": bool(default_state.get("value_in_file")),
        "override_enabled": override_enabled,
        "override_present": override_present,
        "source": source,
        "updated_at": updated_at,
        "updated_by_user_id": updated_by_user_id,
        "fixed": False,
        "message": message,
    }


def is_license_enforcement_enabled() -> bool:
    return bool(get_license_enforcement_state().get("enabled"))


def get_presentation_feature_default_state() -> dict[str, Any]:
    env_path = get_admin_env_file_path()
    env_values = _read_env_file_map(env_path)
    file_enabled = _parse_bool_like(env_values.get("PRESENTATION_GLOBAL_ENABLED"))
    if file_enabled is not None:
        return {
            "enabled": bool(file_enabled),
            "source": "env_file",
            "source_label": ".env 默认值",
            "path": str(env_path),
            "value_in_file": True,
        }
    return {
        "enabled": bool(PRESENTATION_GLOBAL_ENABLED),
        "source": "startup_default",
        "source_label": "启动默认值",
        "path": str(env_path),
        "value_in_file": False,
    }


def get_presentation_feature_state() -> dict:
    default_state = get_presentation_feature_default_state()
    default_enabled = bool(default_state.get("enabled"))
    with get_license_db_connection() as conn:
        ensure_auth_meta_table(conn)
        rows = conn.execute(
            """
            SELECT meta_key, meta_value
            FROM auth_meta
            WHERE meta_key IN (?, ?, ?)
            """,
            (
                AUTH_META_PRESENTATION_FEATURE_ENABLED_KEY,
                AUTH_META_PRESENTATION_FEATURE_UPDATED_BY_KEY,
                AUTH_META_PRESENTATION_FEATURE_UPDATED_AT_KEY,
            ),
        ).fetchall()

    meta_map = {
        str(row["meta_key"] or ""): str(row["meta_value"] or "")
        for row in rows
    }
    override_enabled = _parse_bool_like(meta_map.get(AUTH_META_PRESENTATION_FEATURE_ENABLED_KEY))
    updated_by_user_id = None
    raw_updated_by = str(meta_map.get(AUTH_META_PRESENTATION_FEATURE_UPDATED_BY_KEY) or "").strip()
    if raw_updated_by:
        try:
            updated_by_user_id = int(raw_updated_by)
        except (TypeError, ValueError):
            updated_by_user_id = None

    enabled = default_enabled if override_enabled is None else bool(override_enabled)
    return {
        "enabled": bool(enabled),
        "default_enabled": default_enabled,
        "default_source": str(default_state.get("source") or "startup_default"),
        "default_source_label": str(default_state.get("source_label") or "启动默认值"),
        "default_path": str(default_state.get("path") or ""),
        "default_value_in_file": bool(default_state.get("value_in_file")),
        "override_enabled": override_enabled,
        "override_present": override_enabled is not None,
        "source": "runtime_override" if override_enabled is not None else "env_default",
        "updated_at": str(meta_map.get(AUTH_META_PRESENTATION_FEATURE_UPDATED_AT_KEY) or "").strip() or None,
        "updated_by_user_id": updated_by_user_id,
    }


def is_presentation_feature_enabled() -> bool:
    return bool(get_presentation_feature_state().get("enabled"))


def set_presentation_feature_override(
    enabled: Optional[bool],
    actor_user_id: Optional[int] = None,
    *,
    sync_default: bool = False,
) -> dict:
    previous_state = get_presentation_feature_state()
    default_write_path = None
    next_default_enabled = bool(previous_state.get("default_enabled"))
    with get_license_db_connection() as conn:
        ensure_auth_meta_table(conn)
        now_iso = datetime.now(timezone.utc).isoformat()
        if enabled is None:
            conn.executemany(
                "DELETE FROM auth_meta WHERE meta_key = ?",
                [
                    (AUTH_META_PRESENTATION_FEATURE_ENABLED_KEY,),
                    (AUTH_META_PRESENTATION_FEATURE_UPDATED_BY_KEY,),
                    (AUTH_META_PRESENTATION_FEATURE_UPDATED_AT_KEY,),
                ],
            )
        else:
            updates = [
                (
                    AUTH_META_PRESENTATION_FEATURE_ENABLED_KEY,
                    "true" if bool(enabled) else "false",
                    now_iso,
                ),
                (
                    AUTH_META_PRESENTATION_FEATURE_UPDATED_AT_KEY,
                    now_iso,
                    now_iso,
                ),
            ]
            if actor_user_id is not None:
                updates.append(
                    (
                        AUTH_META_PRESENTATION_FEATURE_UPDATED_BY_KEY,
                        str(int(actor_user_id)),
                        now_iso,
                    )
                )
            else:
                conn.execute(
                    "DELETE FROM auth_meta WHERE meta_key = ?",
                    (AUTH_META_PRESENTATION_FEATURE_UPDATED_BY_KEY,),
                )
            conn.executemany(
                """
                INSERT INTO auth_meta (meta_key, meta_value, updated_at)
                VALUES (?, ?, ?)
                ON CONFLICT(meta_key) DO UPDATE SET
                    meta_value = excluded.meta_value,
                    updated_at = excluded.updated_at
                """,
                updates,
            )
            if sync_default:
                default_write_path = _write_admin_env_updates({
                    "PRESENTATION_GLOBAL_ENABLED": bool(enabled),
                })
                next_default_enabled = bool(enabled)
        _record_license_event(
            conn,
            license_id=None,
            actor_user_id=actor_user_id,
            event_type="presentation_feature_changed",
            payload={
                "previous_enabled": bool(previous_state.get("enabled")),
                "next_enabled": next_default_enabled if enabled is None else bool(enabled),
                "source": "env_default" if enabled is None else "runtime_override",
                "default_enabled": next_default_enabled,
                "default_synced": bool(sync_default and enabled is not None),
                "default_path": str(default_write_path) if default_write_path else None,
            },
            created_at=now_iso,
        )
        conn.commit()
    state = get_presentation_feature_state()
    if default_write_path:
        state["default_sync_written"] = True
        state["default_sync_path"] = str(default_write_path)
    else:
        state["default_sync_written"] = False
    return state


