def update_thinking_status(session_id: str, stage: str, has_search: bool = True):
    """更新思考进度状态（线程安全）"""
    stage_info = THINKING_STAGES.get(stage)
    if not stage_info:
        return

    # 始终使用原始的 stage_index，确保 index 和 message 一致
    # - 有搜索时：分析(0) -> 检索(1) -> 生成(2)
    # - 无搜索时：分析(0) -> 生成(2)，检索阶段被跳过
    index = stage_info["index"]

    status_payload = {
        "session_id": session_id,
        "stage": stage,
        "stage_index": index,
        "total_stages": 3,  # 总是3个阶段，无搜索时检索会被快速跳过
        "message": stage_info["message"],
        "updated_at": _time.time(),
    }

    with thinking_status_lock:
        thinking_status[session_id] = status_payload
    persist_thinking_status(session_id, status_payload)


def clear_thinking_status(session_id: str):
    """清除思考进度状态"""
    with thinking_status_lock:
        thinking_status.pop(session_id, None)
    delete_persisted_thinking_status(session_id)


def get_thinking_status_dir() -> Path:
    """返回跨 worker 共享的思考状态目录。"""
    return DATA_DIR / "runtime" / "thinking_status"


def get_thinking_status_file(session_id: str) -> Path:
    session_hash = hashlib.sha256(str(session_id or "").encode("utf-8")).hexdigest()
    return get_thinking_status_dir() / f"{session_hash}.json"


def persist_thinking_status(session_id: str, status_payload: dict):
    """把思考状态落盘，避免 Gunicorn 多 worker 读不到进程内状态。"""
    if not session_id or not isinstance(status_payload, dict):
        return
    try:
        status_dir = get_thinking_status_dir()
        status_dir.mkdir(parents=True, exist_ok=True)
        status_file = get_thinking_status_file(session_id)
        tmp_file = status_file.with_name(f".{status_file.name}.{os.getpid()}.tmp")
        tmp_file.write_text(json.dumps(status_payload, ensure_ascii=False), encoding="utf-8")
        tmp_file.replace(status_file)
    except Exception as exc:
        if ENABLE_DEBUG_LOG:
            print(f"⚠️ 写入思考状态失败: {exc}")


def read_persisted_thinking_status(session_id: str) -> Optional[dict]:
    """读取跨 worker 思考状态；过期或不匹配时返回空。"""
    if not session_id:
        return None
    status_file = get_thinking_status_file(session_id)
    try:
        if not status_file.exists():
            return None
        payload = json.loads(status_file.read_text(encoding="utf-8"))
    except Exception:
        return None
    if not isinstance(payload, dict) or payload.get("session_id") != session_id:
        return None
    updated_at = float(payload.get("updated_at") or 0)
    if updated_at <= 0 or (_time.time() - updated_at) > THINKING_STATUS_TTL_SECONDS:
        delete_persisted_thinking_status(session_id)
        return None
    return payload


def delete_persisted_thinking_status(session_id: str):
    if not session_id:
        return
    try:
        get_thinking_status_file(session_id).unlink(missing_ok=True)
    except Exception as exc:
        if ENABLE_DEBUG_LOG:
            print(f"⚠️ 删除思考状态失败: {exc}")


def update_report_generation_status(
    session_id: str,
    stage: str,
    message: Optional[str] = None,
    active: bool = True,
    detail_key: str = "",
    detail_label: str = "",
    next_hint: str = "",
    eta_hint: str = "",
    progress_override: Optional[int] = None,
):
    """更新报告生成进度状态（线程安全）"""
    stage_info = REPORT_GENERATION_STAGES.get(stage)
    if not stage_info:
        return
    detail_info = REPORT_GENERATION_DETAIL_STATES.get(str(detail_key or "").strip(), {})
    try:
        normalized_progress = int(progress_override) if progress_override is not None else int(stage_info["progress"])
    except Exception:
        normalized_progress = int(stage_info["progress"])
    normalized_progress = max(0, min(normalized_progress, 100))
    updated_at = datetime.now(timezone.utc).isoformat()

    with report_generation_status_lock:
        existing = report_generation_status.get(session_id)
        merged = dict(existing) if isinstance(existing, dict) else {}
        resolved_detail_key = str(detail_key or merged.get("detail_key", "") or "")
        resolved_detail_label = str(
            detail_label
            or detail_info.get("label", "")
            or merged.get("detail_label", "")
            or ""
        )
        resolved_next_hint = str(
            next_hint
            or detail_info.get("next_hint", "")
            or merged.get("next_hint", "")
            or ""
        )
        merged.update({
            "active": active,
            "state": stage,
            "stage_index": stage_info["index"],
            "total_stages": 6,
            "progress": normalized_progress,
            "message": message or stage_info["message"],
            "stage_label": str(stage_info.get("label", stage) or stage),
            "detail_key": resolved_detail_key,
            "detail_label": resolved_detail_label,
            "next_hint": resolved_next_hint,
            "eta_hint": str(eta_hint or merged.get("eta_hint", "") or ""),
            "updated_at": updated_at,
        })
        if active and not merged.get("started_at"):
            merged["started_at"] = updated_at
        phase_history = merged.get("phase_history", [])
        if not isinstance(phase_history, list):
            phase_history = []
        phase_entry = {
            "state": stage,
            "stage_label": str(stage_info.get("label", stage) or stage),
            "detail_key": resolved_detail_key,
            "detail_label": resolved_detail_label,
            "message": merged.get("message", ""),
            "progress": normalized_progress,
            "updated_at": updated_at,
        }
        if not phase_history or phase_history[-1] != phase_entry:
            phase_history.append(phase_entry)
        merged["phase_history"] = phase_history[-12:]
        report_generation_status[session_id] = merged


def set_report_generation_metadata(session_id: str, updates: Optional[dict] = None):
    """写入报告生成的扩展元信息（线程安全）。"""
    if not session_id or not isinstance(updates, dict):
        return

    with report_generation_status_lock:
        existing = report_generation_status.get(session_id)
        merged = dict(existing) if isinstance(existing, dict) else {}
        merged.update(updates)
        report_name = normalize_solution_report_filename(merged.get("report_name", ""))
        if report_name:
            merged["report_name"] = report_name
            report_reference = build_report_storage_reference(report_name)
            if report_reference:
                merged["report_path"] = report_reference
        merged["updated_at"] = datetime.now(timezone.utc).isoformat()
        report_generation_status[session_id] = merged


def get_report_generation_record(session_id: str) -> Optional[dict]:
    if not session_id:
        return None
    with report_generation_status_lock:
        status = report_generation_status.get(session_id)
        if not isinstance(status, dict):
            return None
        return dict(status)


def build_report_generation_payload(record: Optional[dict]) -> dict:
    if not isinstance(record, dict):
        return {"active": False}

    def _safe_int(value, default):
        try:
            return int(value)
        except Exception:
            return default

    report_name = normalize_solution_report_filename(record.get("report_name", ""))
    report_path = str(record.get("report_path", "") or "").strip()
    if report_name:
        report_reference = build_report_storage_reference(report_name)
        if report_reference:
            report_path = report_reference

    payload = {
        "active": bool(record.get("active", False)),
        "processing": bool(record.get("active", False)),
        "state": record.get("state", "queued"),
        "stage_index": _safe_int(record.get("stage_index", 0), 0),
        "total_stages": _safe_int(record.get("total_stages", 6), 6),
        "progress": _safe_int(record.get("progress", 0), 0),
        "message": record.get("message", "正在生成报告..."),
        "stage_label": record.get("stage_label", ""),
        "detail_key": record.get("detail_key", ""),
        "detail_label": record.get("detail_label", ""),
        "next_hint": record.get("next_hint", ""),
        "eta_hint": record.get("eta_hint", ""),
        "updated_at": record.get("updated_at"),
        "request_id": record.get("request_id", ""),
        "action": record.get("action", "generate"),
        "started_at": record.get("started_at", ""),
        "completed_at": record.get("completed_at", ""),
        "report_name": report_name,
        "report_path": report_path,
        "ai_generated": record.get("ai_generated"),
        "v3_enabled": record.get("v3_enabled"),
        "report_profile": normalize_report_profile_choice(record.get("report_profile", ""), fallback=REPORT_V3_PROFILE),
        "source_report_name": normalize_solution_report_filename(record.get("source_report_name", "")),
        "report_variant_label": clean_solution_text(record.get("report_variant_label", ""), max_len=32),
        "error": record.get("error", ""),
        "queue_position": _safe_int(record.get("queue_position", 0), 0),
        "queue_pending": _safe_int(record.get("queue_pending", 0), 0),
        "queue_running": _safe_int(record.get("queue_running", 0), 0),
        "estimated_wait_seconds": _safe_int(record.get("estimated_wait_seconds", 0), 0),
    }

    quality_meta = record.get("report_quality_meta")
    if isinstance(quality_meta, dict):
        payload["report_quality_meta"] = quality_meta
    runtime_timings = record.get("runtime_timings")
    if isinstance(runtime_timings, dict):
        payload["runtime_timings"] = runtime_timings
    runtime_summary = record.get("runtime_summary")
    if isinstance(runtime_summary, dict):
        payload["runtime_summary"] = runtime_summary
    phase_history = record.get("phase_history")
    if isinstance(phase_history, list):
        payload["phase_history"] = [dict(item) for item in phase_history if isinstance(item, dict)]
    if not payload["report_variant_label"] and payload["report_profile"]:
        payload["report_variant_label"] = "精审版" if payload["report_profile"] == "quality" else "普通版"

    return payload


def record_report_generation_queue_event(event: str, delta: int = 1) -> None:
    if event not in report_generation_queue_stats:
        return
    try:
        step = int(delta)
    except Exception:
        step = 1
    if step <= 0:
        return
    with report_generation_queue_stats_lock:
        report_generation_queue_stats[event] = int(report_generation_queue_stats.get(event, 0) or 0) + step


def estimate_report_generation_wait_seconds(
    queue_position: int,
    running: int,
    max_workers: int,
) -> int:
    try:
        normalized_position = max(0, int(queue_position or 0))
    except Exception:
        normalized_position = 0
    try:
        normalized_running = max(0, int(running or 0))
    except Exception:
        normalized_running = 0
    try:
        normalized_workers = max(1, int(max_workers or 0))
    except Exception:
        normalized_workers = 1
    if normalized_position <= 0:
        return 0

    available_now = max(0, normalized_workers - normalized_running)
    remaining_position = max(0, normalized_position - available_now)
    if remaining_position <= 0:
        return 0

    slot_seconds = max(1.0, float(REPORT_GENERATION_ESTIMATED_SLOT_SECONDS or 0.0))
    wait_rounds = math.ceil(float(remaining_position) / float(normalized_workers))
    return max(0, int(math.ceil(wait_rounds * slot_seconds)))


def release_report_generation_slot() -> None:
    try:
        report_generation_slots.release()
    except ValueError:
        # 兜底：避免异常场景重复释放导致线程报错
        pass


def get_report_generation_worker_snapshot(include_positions: bool = False) -> dict:
    running = 0
    pending_sessions = []
    stale_sessions = []

    with report_generation_workers_lock:
        for sid, future in list(report_generation_workers.items()):
            if not isinstance(future, Future):
                stale_sessions.append(sid)
                continue
            if future.done():
                stale_sessions.append(sid)
                continue
            if future.running():
                running += 1
            else:
                pending_sessions.append(sid)

        for sid in stale_sessions:
            report_generation_workers.pop(sid, None)

    in_flight = running + len(pending_sessions)

    with report_generation_queue_stats_lock:
        stats = dict(report_generation_queue_stats)

    snapshot = {
        "max_workers": int(REPORT_GENERATION_MAX_WORKERS),
        "max_pending": int(REPORT_GENERATION_MAX_PENDING),
        "in_flight": int(in_flight),
        "running": int(running),
        "pending": int(len(pending_sessions)),
        "available_slots": max(0, int(REPORT_GENERATION_MAX_PENDING) - int(in_flight)),
        "submitted": int(stats.get("submitted", 0) or 0),
        "rejected": int(stats.get("rejected", 0) or 0),
        "completed": int(stats.get("completed", 0) or 0),
        "failed": int(stats.get("failed", 0) or 0),
    }
    if include_positions:
        snapshot["queue_positions"] = {
            sid: idx + 1
            for idx, sid in enumerate(pending_sessions)
        }
    return snapshot


def sync_report_generation_queue_metadata(session_id: str, snapshot: Optional[dict] = None) -> dict:
    queue_snapshot = snapshot if isinstance(snapshot, dict) else get_report_generation_worker_snapshot(include_positions=True)
    if not session_id:
        return queue_snapshot

    with report_generation_status_lock:
        existing = report_generation_status.get(session_id)
        if not isinstance(existing, dict):
            return queue_snapshot

    queue_positions = queue_snapshot.get("queue_positions", {}) if isinstance(queue_snapshot, dict) else {}
    queue_position = 0
    if isinstance(queue_positions, dict):
        try:
            queue_position = int(queue_positions.get(session_id, 0) or 0)
        except Exception:
            queue_position = 0
    running_count = int(queue_snapshot.get("running", 0) or 0)
    pending_count = int(queue_snapshot.get("pending", 0) or 0)
    max_workers = int(queue_snapshot.get("max_workers", REPORT_GENERATION_MAX_WORKERS) or REPORT_GENERATION_MAX_WORKERS)
    estimated_wait_seconds = estimate_report_generation_wait_seconds(
        queue_position=queue_position,
        running=running_count,
        max_workers=max_workers,
    )

    set_report_generation_metadata(session_id, {
        "queue_position": queue_position,
        "queue_pending": pending_count,
        "queue_running": running_count,
        "estimated_wait_seconds": estimated_wait_seconds,
        "detail_key": "queue_wait" if queue_position > 0 else "",
        "detail_label": REPORT_GENERATION_DETAIL_STATES.get("queue_wait", {}).get("label", "") if queue_position > 0 else "",
        "next_hint": (
            f"当前前方还有 {queue_position} 个待执行任务"
            if queue_position > 0
            else ""
        ),
        "eta_hint": (
            f"预计还需等待约 {estimated_wait_seconds} 秒，当前 {running_count} 个正在执行，{pending_count} 个等待中"
            if queue_position > 0
            else ""
        ),
    })
    return queue_snapshot


def is_report_generation_worker_alive(session_id: str) -> bool:
    if not session_id:
        return False
    with report_generation_workers_lock:
        worker = report_generation_workers.get(session_id)
        if isinstance(worker, Future) and not worker.done():
            return True
        if worker is not None:
            report_generation_workers.pop(session_id, None)
    return False


def register_report_generation_worker(session_id: str, worker: Future) -> None:
    if not session_id or worker is None:
        return
    with report_generation_workers_lock:
        report_generation_workers[session_id] = worker


def cleanup_report_generation_worker(session_id: str, worker: Optional[Future] = None) -> None:
    if not session_id:
        return
    with report_generation_workers_lock:
        current = report_generation_workers.get(session_id)
        if worker is not None and current is not worker:
            return
        report_generation_workers.pop(session_id, None)


def clear_report_generation_status(session_id: str):
    """清除报告生成进度状态"""
    with report_generation_status_lock:
        report_generation_status.pop(session_id, None)
    cleanup_report_generation_worker(session_id)


def _cleanup_solution_payload_prewarm_job(report_name: str, future: Optional[Future] = None) -> None:
    normalized = normalize_solution_report_filename(report_name)
    if not normalized:
        return
    with solution_payload_prewarm_jobs_lock:
        current = solution_payload_prewarm_jobs.get(normalized)
        if future is not None and current is not future:
            return
        solution_payload_prewarm_jobs.pop(normalized, None)


def schedule_solution_payload_prewarm(report_name: str, report_content: str = "") -> bool:
    normalized = normalize_solution_report_filename(report_name)
    if not SOLUTION_PAYLOAD_PREWARM_ENABLED or not normalized:
        return False

    with solution_payload_prewarm_jobs_lock:
        existing = solution_payload_prewarm_jobs.get(normalized)
        if isinstance(existing, Future) and not existing.done():
            return False
        if existing is not None:
            solution_payload_prewarm_jobs.pop(normalized, None)

    future_holder = {}

    def do_prewarm():
        try:
            effective_content = str(report_content or "")
            if not effective_content.strip():
                effective_content = _load_report_content(normalized)
            if not effective_content.strip():
                return
            build_solution_payload_from_report(normalized, effective_content, allow_ai_enhancement=False)
            if ENABLE_DEBUG_LOG:
                print(f"✅ 方案缓存预热完成: report={normalized}")
        except Exception as exc:
            print(f"⚠️ 方案缓存预热失败: report={normalized}, error={exc}")
        finally:
            _cleanup_solution_payload_prewarm_job(normalized, future_holder.get("future"))

    future = solution_payload_prewarm_executor.submit(do_prewarm)
    future_holder["future"] = future
    with solution_payload_prewarm_jobs_lock:
        solution_payload_prewarm_jobs[normalized] = future
    return True


def ensure_solution_payload_ready(report_name: str, report_content: str = "", session_id: str = "") -> bool:
    normalized = normalize_solution_report_filename(report_name)
    if not normalized:
        return False

    effective_content = str(report_content or "")
    if not effective_content.strip():
        effective_content = _load_report_content(normalized)
    if not effective_content.strip():
        return False

    if session_id:
        update_report_generation_status(session_id, "saving", message="正在预热方案视图...")

    try:
        build_solution_payload_from_report(normalized, effective_content, allow_ai_enhancement=False)
        if ENABLE_DEBUG_LOG:
            print(f"✅ 方案缓存已就绪: report={normalized}")
        return True
    except Exception as exc:
        print(f"⚠️ 同步预热方案缓存失败，改为后台重试: report={normalized}, error={exc}")
        schedule_solution_payload_prewarm(normalized, effective_content)
        return False


# ============ 预生成缓存函数 ============

def _normalize_session_signature_value(value) -> Optional[tuple[int, int]]:
    if isinstance(value, tuple) and len(value) == 2:
        try:
            return int(value[0]), int(value[1])
        except (TypeError, ValueError):
            return None
    if isinstance(value, list) and len(value) == 2:
        try:
            return int(value[0]), int(value[1])
        except (TypeError, ValueError):
            return None
    return None


def _prefetch_entry_matches_signature(entry: Optional[dict], session_signature: Optional[tuple[int, int]]) -> bool:
    expected_signature = _normalize_session_signature_value(session_signature)
    if expected_signature is None:
        return True
    cached_signature = _normalize_session_signature_value((entry or {}).get("session_signature"))
    if cached_signature is None:
        return False
    return cached_signature == expected_signature


def _begin_question_prefetch_inflight(cache_key: str) -> tuple[Optional[threading.Event], bool]:
    key = str(cache_key or "").strip()
    if not key:
        return None, False
    with question_prefetch_inflight_lock:
        inflight = question_prefetch_inflight.get(key)
        event = inflight.get("event") if isinstance(inflight, dict) else None
        if isinstance(event, threading.Event):
            return event, False

        owner_event = threading.Event()
        question_prefetch_inflight[key] = {
            "event": owner_event,
            "started_at": _time.time(),
        }
        return owner_event, True


def _end_question_prefetch_inflight(cache_key: str, owner_event: Optional[threading.Event]) -> None:
    key = str(cache_key or "").strip()
    if not key or not isinstance(owner_event, threading.Event):
        return
    with question_prefetch_inflight_lock:
        inflight = question_prefetch_inflight.get(key)
        if isinstance(inflight, dict) and inflight.get("event") is owner_event:
            question_prefetch_inflight.pop(key, None)
    owner_event.set()


def _wait_for_question_prefetch_inflight(cache_key: str, wait_seconds: float) -> bool:
    key = str(cache_key or "").strip()
    if not key or wait_seconds <= 0:
        return False
    with question_prefetch_inflight_lock:
        inflight = question_prefetch_inflight.get(key)
        event = inflight.get("event") if isinstance(inflight, dict) else None
    if not isinstance(event, threading.Event):
        return False
    event.wait(wait_seconds)
    return True


def get_prefetch_result(session_id: str, dimension: str, session_signature: Optional[tuple[int, int]] = None) -> Optional[dict]:
    """获取预生成结果（线程安全），命中则消费（删除缓存）

    Args:
        session_id: 会话ID
        dimension: 维度名称

    Returns:
        命中则返回问题数据dict，否则返回None
    """
    with prefetch_cache_lock:
        session_cache = prefetch_cache.get(session_id, {})
        cached = session_cache.get(dimension)
        if cached and cached.get("valid"):
            if not _prefetch_entry_matches_signature(cached, session_signature):
                session_cache.pop(dimension, None)
                if ENABLE_DEBUG_LOG:
                    print(f"🧹 丢弃过期预生成缓存: session={session_id}, dim={dimension}")
                return None
            # 检查TTL
            if _time.time() - cached["created_at"] < PREFETCH_TTL:
                # 消费缓存（删除）
                session_cache.pop(dimension, None)
                if ENABLE_DEBUG_LOG:
                    print(f"🚀 预生成缓存命中: session={session_id}, dim={dimension}")
                return cached["question_data"]
            else:
                # 过期，清除
                session_cache.pop(dimension, None)
                if ENABLE_DEBUG_LOG:
                    print(f"⏰ 预生成缓存过期: session={session_id}, dim={dimension}")
    return None


def invalidate_prefetch(session_id: str, dimension: str = None):
    """使预生成缓存失效

    Args:
        session_id: 会话ID
        dimension: 维度名称，如果为None则清除整个会话的缓存
    """
    with prefetch_cache_lock:
        if dimension:
            prefetch_cache.get(session_id, {}).pop(dimension, None)
        else:
            prefetch_cache.pop(session_id, None)


def trigger_current_dimension_prefetch(session: dict, current_dimension: str, session_signature: Optional[tuple[int, int]] = None):
    """提交回答后预生成当前维度下一题，优先覆盖用户的下一次实时请求。"""
    session_id = str((session or {}).get("session_id") or "").strip()
    if not session_id:
        return

    dimension = str(current_dimension or "").strip()
    if not dimension:
        return

    dim_state = (session.get("dimensions") or {}).get(dimension)
    if not isinstance(dim_state, dict):
        return
    if float(dim_state.get("coverage", 0) or 0) >= 100 or bool(dim_state.get("user_completed", False)):
        return
    if evaluate_dimension_completion_v2(session, dimension).get("can_complete"):
        return

    normalized_signature = _normalize_session_signature_value(session_signature)
    if normalized_signature is None:
        session_file = SESSIONS_DIR / f"{session_id}.json"
        normalized_signature = get_file_signature(session_file)
        if normalized_signature is None:
            return

    question_cache_key = _build_question_result_cache_key(session_id, dimension, normalized_signature)
    cached_question_payload = _get_question_result_cache(question_cache_key)
    if isinstance(cached_question_payload, dict):
        return

    with prefetch_cache_lock:
        existing = prefetch_cache.get(session_id, {}).get(dimension)
        if existing and existing.get("valid") and _prefetch_entry_matches_signature(existing, normalized_signature):
            return

    owner_event, is_owner = _begin_question_prefetch_inflight(question_cache_key)
    if not is_owner:
        return

    def do_prefetch():
        question_generation_slot_acquired = False
        try:
            if ENABLE_DEBUG_LOG:
                print(f"🔮 开始预生成当前维度下一题: session={session_id}, dim={dimension}")

            if not _wait_for_prefetch_idle(PREFETCH_IDLE_WAIT_SECONDS):
                if ENABLE_DEBUG_LOG:
                    print(f"⏭️  跳过当前维度预生成（主链路繁忙）: session={session_id}, dim={dimension}")
                return

            session_file = SESSIONS_DIR / f"{session_id}.json"
            session_data = safe_load_session(session_file)
            if not isinstance(session_data, dict):
                return
            fresh_signature = get_file_signature(session_file)
            if fresh_signature is None:
                return
            if normalized_signature is not None and fresh_signature != normalized_signature:
                if ENABLE_DEBUG_LOG:
                    print(f"⏭️  放弃过期当前维度预生成: session={session_id}, dim={dimension}")
                return

            fresh_dim_state = (session_data.get("dimensions") or {}).get(dimension, {})
            if float(fresh_dim_state.get("coverage", 0) or 0) >= 100 or bool(fresh_dim_state.get("user_completed", False)):
                return
            if evaluate_dimension_completion_v2(session_data, dimension).get("can_complete"):
                return

            dim_logs = [
                log for log in session_data.get("interview_log", [])
                if log.get("dimension") == dimension
            ]

            if not try_acquire_question_generation_semaphore(record_overload=False):
                if ENABLE_DEBUG_LOG:
                    print(f"⏭️  跳过当前维度预生成（问题槽位繁忙）: session={session_id}, dim={dimension}")
                return
            question_generation_slot_acquired = True

            prepared_runtime = _prepare_question_generation_runtime(
                session_data,
                dimension,
                dim_logs,
                session_signature=fresh_signature,
                base_call_type="prefetch_current",
                allow_fast_path=True,
            )

            response, result, tier_used = generate_question_with_tiered_strategy(
                prepared_runtime["full_prompt"],
                truncated_docs=prepared_runtime["truncated_docs"],
                fast_truncated_docs=prepared_runtime.get("fast_truncated_docs"),
                debug=ENABLE_DEBUG_LOG,
                base_call_type="prefetch_current",
                allow_fast_path=bool(prepared_runtime["runtime_profile"].get("allow_fast_path", True)),
                fast_prompt=prepared_runtime["fast_prompt"],
                runtime_profile=prepared_runtime["runtime_profile"],
            )
            if ENABLE_DEBUG_LOG:
                print(f"⚙️ 当前维度预生成通道: {tier_used}")

            if response and result:
                result["dimension"] = dimension
                result["ai_generated"] = True
                selected_lane = tier_used.split(":", 1)[1] if ":" in tier_used else ""
                decision_meta = dict(prepared_runtime.get("decision_meta", {}) or {})
                decision_meta["tier_used"] = tier_used
                decision_meta["selected_lane"] = selected_lane
                result["decision_meta"] = decision_meta
                result["question_generation_tier"] = tier_used
                result["question_selected_lane"] = selected_lane
                result["question_runtime_profile"] = prepared_runtime.get("runtime_profile", {}).get("profile_name", "")

                with prefetch_cache_lock:
                    if session_id not in prefetch_cache:
                        prefetch_cache[session_id] = {}
                    prefetch_cache[session_id][dimension] = {
                        "question_data": result,
                        "created_at": _time.time(),
                        "topic": session_data.get("topic"),
                        "session_signature": fresh_signature,
                        "valid": True,
                    }
                _set_question_result_cache(question_cache_key, result)
                if ENABLE_DEBUG_LOG:
                    print(f"✅ 当前维度预生成完成: session={session_id}, dim={dimension}")
            else:
                if ENABLE_DEBUG_LOG:
                    print(f"⚠️ 当前维度预生成解析失败: session={session_id}, dim={dimension}")
        except Exception as e:
            print(f"⚠️ 当前维度预生成失败: {e}")
        finally:
            if question_generation_slot_acquired:
                try:
                    QUESTION_GENERATION_SEMAPHORE.release()
                except ValueError:
                    pass
            _end_question_prefetch_inflight(question_cache_key, owner_event)

    threading.Thread(target=do_prefetch, daemon=True).start()


def trigger_prefetch_if_needed(session: dict, current_dimension: str, session_signature: Optional[tuple[int, int]] = None):
    """判断是否需要预生成下一维度首题，如果需要则启动后台线程

    预生成触发条件：当前维度正式问题数 >= 2

    Args:
        session: 会话数据
        current_dimension: 当前维度
    """
    session_id = session.get("session_id")
    interview_log = session.get("interview_log", [])

    # 计算当前维度的正式问题数
    dim_logs = [l for l in interview_log if l.get("dimension") == current_dimension]
    formal_count = len([l for l in dim_logs if not l.get("is_follow_up", False)])

    current_mode_config = get_interview_mode_config(session)
    current_min_formal = current_mode_config.get("formal_questions_per_dim", 2)

    # 当前维度达到最低正式题后，预生成下一维度首题
    if formal_count < current_min_formal:
        return

    # 维度顺序（动态场景优先使用会话定义）
    dimension_order = get_dimension_order_for_session(session) or ['customer_needs', 'business_process', 'tech_constraints', 'project_constraints']
    current_idx = dimension_order.index(current_dimension) if current_dimension in dimension_order else -1

    # 找下一个未完成的维度
    next_dimension = None
    for i in range(1, len(dimension_order)):
        candidate = dimension_order[(current_idx + i) % len(dimension_order)]
        cand_logs = [l for l in interview_log if l.get("dimension") == candidate]
        cand_formal = len([l for l in cand_logs if not l.get("is_follow_up", False)])

        # 兼容动态场景：构造轻量 session 以读取该会话模式配置
        candidate_min_formal = get_interview_mode_config(session).get("formal_questions_per_dim", 3)
        if cand_formal < candidate_min_formal:
            next_dimension = candidate
            break

    if not next_dimension:
        return

    normalized_signature = _normalize_session_signature_value(session_signature)
    question_cache_key = (
        _build_question_result_cache_key(session_id, next_dimension, normalized_signature)
        if normalized_signature is not None else ""
    )

    # 检查缓存中是否已有
    with prefetch_cache_lock:
        existing = prefetch_cache.get(session_id, {}).get(next_dimension)
        if existing and existing.get("valid") and _prefetch_entry_matches_signature(existing, normalized_signature):
            return  # 已有有效缓存，不重复生成

    owner_event = None
    if question_cache_key:
        owner_event, is_owner = _begin_question_prefetch_inflight(question_cache_key)
        if not is_owner:
            return

    # 启动后台预生成线程
    def do_prefetch():
        try:
            if ENABLE_DEBUG_LOG:
                print(f"🔮 开始预生成: session={session_id}, next_dim={next_dimension}")

            if not _wait_for_prefetch_idle(PREFETCH_IDLE_WAIT_SECONDS):
                if ENABLE_DEBUG_LOG:
                    print(f"⏭️  跳过预生成（主链路繁忙）: session={session_id}, dim={next_dimension}")
                return

            # 重新读取会话数据（可能已更新）
            session_file = SESSIONS_DIR / f"{session_id}.json"
            session_data = safe_load_session(session_file)
            if not isinstance(session_data, dict) and isinstance(session, dict):
                session_data = copy.deepcopy(session)
            if not isinstance(session_data, dict):
                return
            fresh_signature = get_file_signature(session_file)
            if fresh_signature is None and normalized_signature is not None:
                fresh_signature = normalized_signature
            if fresh_signature is None:
                return
            if normalized_signature is not None and fresh_signature != normalized_signature:
                if ENABLE_DEBUG_LOG:
                    print(f"⏭️  放弃过期预生成: session={session_id}, dim={next_dimension}")
                return
            next_dim_logs = [l for l in session_data.get("interview_log", [])
                           if l.get("dimension") == next_dimension]

            prepared_runtime = _prepare_question_generation_runtime(
                session_data,
                next_dimension,
                next_dim_logs,
                session_signature=fresh_signature,
                base_call_type="prefetch",
                allow_fast_path=True,
            )

            response, result, tier_used = generate_question_with_tiered_strategy(
                prepared_runtime["full_prompt"],
                truncated_docs=prepared_runtime["truncated_docs"],
                fast_truncated_docs=prepared_runtime.get("fast_truncated_docs"),
                debug=ENABLE_DEBUG_LOG,
                base_call_type="prefetch",
                allow_fast_path=bool(prepared_runtime["runtime_profile"].get("allow_fast_path", True)),
                fast_prompt=prepared_runtime["fast_prompt"],
                runtime_profile=prepared_runtime["runtime_profile"],
            )
            if ENABLE_DEBUG_LOG:
                print(f"⚙️ 下一维度预生成通道: {tier_used}")

            if response and result:
                result["dimension"] = next_dimension
                result["ai_generated"] = True
                selected_lane = tier_used.split(":", 1)[1] if ":" in tier_used else ""
                decision_meta = dict(prepared_runtime.get("decision_meta", {}) or {})
                decision_meta["tier_used"] = tier_used
                decision_meta["selected_lane"] = selected_lane
                result["decision_meta"] = decision_meta
                result["question_generation_tier"] = tier_used
                result["question_selected_lane"] = selected_lane
                result["question_runtime_profile"] = prepared_runtime.get("runtime_profile", {}).get("profile_name", "")

                with prefetch_cache_lock:
                    if session_id not in prefetch_cache:
                        prefetch_cache[session_id] = {}
                    prefetch_cache[session_id][next_dimension] = {
                        "question_data": result,
                        "created_at": _time.time(),
                        "topic": session_data.get("topic"),
                        "session_signature": fresh_signature,
                        "valid": True,
                    }
                if ENABLE_DEBUG_LOG:
                    print(f"✅ 预生成完成: session={session_id}, dim={next_dimension}")
            else:
                if ENABLE_DEBUG_LOG:
                    print(f"⚠️ 预生成解析失败: session={session_id}, dim={next_dimension}")
        except Exception as e:
            print(f"⚠️ 预生成失败: {e}")
        finally:
            _end_question_prefetch_inflight(question_cache_key, owner_event)

    threading.Thread(target=do_prefetch, daemon=True).start()


def prefetch_first_question(session_id: str):
    """后台预生成会话的第一个问题

    在会话创建后调用，异步生成 customer_needs 维度的首题。

    Args:
        session_id: 会话ID
    """
    session_file = SESSIONS_DIR / f"{session_id}.json"
    initial_session_data = safe_load_session(session_file)
    if not isinstance(initial_session_data, dict):
        return

    initial_signature = get_file_signature(session_file)
    if initial_signature is None:
        return
    first_dim = get_dimension_order_for_session(initial_session_data)[0] if get_dimension_order_for_session(initial_session_data) else "customer_needs"
    question_cache_key = _build_question_result_cache_key(session_id, first_dim, initial_signature)
    owner_event, is_owner = _begin_question_prefetch_inflight(question_cache_key)
    if not is_owner:
        return

    def do_prefetch():
        try:
            if ENABLE_DEBUG_LOG:
                print(f"🔮 开始预生成首题: session={session_id}")

            priority_active = _is_first_question_prefetch_priority_active(session_id)
            if priority_active:
                if ENABLE_DEBUG_LOG:
                    print(f"⚡ 首题预生成优先窗口生效: session={session_id}")
            elif not _wait_for_prefetch_idle(PREFETCH_IDLE_WAIT_SECONDS):
                if ENABLE_DEBUG_LOG:
                    print(f"⏭️  跳过首题预生成（主链路繁忙）: session={session_id}")
                return

            session_data = safe_load_session(session_file)
            if not isinstance(session_data, dict):
                return
            fresh_signature = get_file_signature(session_file)
            if fresh_signature is None:
                return
            if fresh_signature != initial_signature:
                if ENABLE_DEBUG_LOG:
                    print(f"⏭️  放弃过期首题预生成: session={session_id}")
                return

            prepared_runtime = _prepare_question_generation_runtime(
                session_data,
                first_dim,
                [],
                session_signature=fresh_signature,
                base_call_type="prefetch_first",
                allow_fast_path=True,
            )

            response, result, tier_used = generate_question_with_tiered_strategy(
                prepared_runtime["full_prompt"],
                truncated_docs=prepared_runtime["truncated_docs"],
                fast_truncated_docs=prepared_runtime.get("fast_truncated_docs"),
                debug=ENABLE_DEBUG_LOG,
                base_call_type="prefetch_first",
                allow_fast_path=bool(prepared_runtime["runtime_profile"].get("allow_fast_path", True)),
                fast_prompt=prepared_runtime["fast_prompt"],
                runtime_profile=prepared_runtime["runtime_profile"],
            )
            if ENABLE_DEBUG_LOG:
                print(f"⚙️ 首题预生成通道: {tier_used}")

            if response and result:
                result["dimension"] = first_dim
                result["ai_generated"] = True
                selected_lane = tier_used.split(":", 1)[1] if ":" in tier_used else ""
                decision_meta = dict(prepared_runtime.get("decision_meta", {}) or {})
                decision_meta["tier_used"] = tier_used
                decision_meta["selected_lane"] = selected_lane
                result["decision_meta"] = decision_meta
                result["question_generation_tier"] = tier_used
                result["question_selected_lane"] = selected_lane
                result["question_runtime_profile"] = prepared_runtime.get("runtime_profile", {}).get("profile_name", "")

                with prefetch_cache_lock:
                    if session_id not in prefetch_cache:
                        prefetch_cache[session_id] = {}
                    prefetch_cache[session_id][first_dim] = {
                        "question_data": result,
                        "created_at": _time.time(),
                        "topic": session_data.get("topic"),
                        "session_signature": fresh_signature,
                        "valid": True,
                    }
                if ENABLE_DEBUG_LOG:
                    print(f"✅ 首题预生成完成: session={session_id}")
        except Exception as e:
            print(f"⚠️ 首题预生成失败: {e}")
        finally:
            _end_question_prefetch_inflight(question_cache_key, owner_event)
            _clear_first_question_prefetch_priority(session_id)

    threading.Thread(target=do_prefetch, daemon=True).start()


# ============ 性能监控系统 ============

class MetricsCollector:
    """API 性能指标收集器"""

    def __init__(self, metrics_key: str):
        self.metrics_key = str(metrics_key or "api_metrics").strip() or "api_metrics"
        self._pending_records = deque()
        self._pending_lock = threading.Lock()
        self._storage_lock = threading.RLock()
        self._store_ready = False
        self._flush_event = threading.Event()
        self._stop_event = threading.Event()
        self._closed = False
        self._flush_interval = float(METRICS_ASYNC_FLUSH_INTERVAL_SECONDS)
        self._flush_batch_size = int(METRICS_ASYNC_BATCH_SIZE)
        self._max_pending = int(METRICS_ASYNC_MAX_PENDING)
        self._flush_worker = threading.Thread(
            target=self._flush_loop,
            daemon=True,
            name="metrics-flush-worker",
        )
        self._flush_worker.start()
        try:
            atexit.register(self.close)
        except Exception:
            pass

    def _ensure_metrics_store(self):
        """确保共享指标存储存在。"""
        if self._store_ready:
            return
        payload = self._empty_payload()
        with self._storage_lock:
            if self._store_ready:
                return
            with get_meta_index_connection() as conn:
                existing = _load_runtime_metrics_store_payload(conn, self.metrics_key)
                if not existing:
                    _upsert_runtime_metrics_store_payload(conn, self.metrics_key, payload)
            self._store_ready = True

    def _empty_payload(self) -> dict:
        return {
            "calls": [],
            "summary": {
                "total_calls": 0,
                "total_timeouts": 0,
                "total_truncations": 0,
                "total_cache_hits": 0,
                "total_hedge_triggered": 0,
                "total_model_fallbacks": 0,
                "avg_response_time": 0,
                "avg_prompt_length": 0,
                "avg_queue_wait_ms": 0,
            },
        }

    def _load_metrics_data(self) -> dict:
        payload = self._empty_payload()
        try:
            self._ensure_metrics_store()
            with get_meta_index_connection() as conn:
                data = _load_runtime_metrics_store_payload(conn, self.metrics_key)
            return data or payload
        except Exception:
            return payload

    def _write_metrics_data(self, data: dict) -> None:
        self._ensure_metrics_store()
        with get_meta_index_connection() as conn:
            _upsert_runtime_metrics_store_payload(conn, self.metrics_key, data)

    def _apply_records_to_data(self, data: dict, records: list[dict]) -> dict:
        if not isinstance(data, dict):
            data = self._empty_payload()

        calls = data.get("calls", [])
        if not isinstance(calls, list):
            calls = []
        summary = data.get("summary", {})
        if not isinstance(summary, dict):
            summary = {}
        total_calls = int(summary.get("total_calls", 0) or 0)
        total_timeouts = int(summary.get("total_timeouts", 0) or 0)
        total_truncations = int(summary.get("total_truncations", 0) or 0)
        total_cache_hits = int(summary.get("total_cache_hits", 0) or 0)
        total_hedge_triggered = int(summary.get("total_hedge_triggered", 0) or 0)
        total_model_fallbacks = int(summary.get("total_model_fallbacks", 0) or 0)

        for record in records:
            if not isinstance(record, dict):
                continue
            calls.append(record)
            event_kind = str(record.get("event_kind", "api_call") or "api_call").strip().lower()
            if event_kind != "api_call":
                continue
            total_calls += 1
            if bool(record.get("timeout", False)):
                total_timeouts += 1
            total_truncations += len(record.get("truncated_docs", []) or [])
            if bool(record.get("cache_hit", False)):
                total_cache_hits += 1
            if bool(record.get("hedge_triggered", False)):
                total_hedge_triggered += 1
            if bool(record.get("fallback_model_used", False)):
                total_model_fallbacks += 1

        if len(calls) > 1000:
            calls = calls[-1000:]

        api_calls = [
            item for item in calls
            if isinstance(item, dict) and str(item.get("event_kind", "api_call") or "api_call").strip().lower() == "api_call"
        ]

        avg_response_time = 0.0
        avg_prompt_length = 0.0
        avg_queue_wait_ms = 0.0
        if api_calls:
            avg_response_time = round(
                sum(float(c.get("response_time_ms", 0) or 0) for c in api_calls) / len(api_calls), 2
            )
            avg_prompt_length = round(
                sum(float(c.get("prompt_length", 0) or 0) for c in api_calls) / len(api_calls), 2
            )
            queue_wait_values = [
                float(c.get("queue_wait_ms", 0) or 0)
                for c in api_calls
                if isinstance(c.get("queue_wait_ms", 0), (int, float))
            ]
            if queue_wait_values:
                avg_queue_wait_ms = round(sum(queue_wait_values) / len(queue_wait_values), 2)

        data["calls"] = calls
        data["summary"] = {
            "total_calls": total_calls,
            "total_timeouts": total_timeouts,
            "total_truncations": total_truncations,
            "total_cache_hits": total_cache_hits,
            "total_hedge_triggered": total_hedge_triggered,
            "total_model_fallbacks": total_model_fallbacks,
            "avg_response_time": avg_response_time,
            "avg_prompt_length": avg_prompt_length,
            "avg_queue_wait_ms": avg_queue_wait_ms,
        }
        return data

    def _drain_pending_records(self, max_items: Optional[int] = None) -> list[dict]:
        drained = []
        with self._pending_lock:
            if not self._pending_records:
                return drained
            if max_items is None or max_items >= len(self._pending_records):
                while self._pending_records:
                    drained.append(self._pending_records.popleft())
            else:
                for _ in range(max_items):
                    if not self._pending_records:
                        break
                    drained.append(self._pending_records.popleft())
        return drained

    def _flush_pending_records(self, force: bool = False) -> int:
        flushed = 0
        while True:
            batch_size = None if force else self._flush_batch_size
            records = self._drain_pending_records(max_items=batch_size)
            if not records:
                break
            try:
                with self._storage_lock:
                    data = self._load_metrics_data()
                    data = self._apply_records_to_data(data, records)
                    self._write_metrics_data(data)
                flushed += len(records)
            except Exception as exc:
                print(f"⚠️  刷新指标失败: {exc}")
                with self._pending_lock:
                    for record in reversed(records):
                        self._pending_records.appendleft(record)
                    while len(self._pending_records) > self._max_pending:
                        self._pending_records.popleft()
                break

            if not force:
                break

        if not force:
            with self._pending_lock:
                has_more = bool(self._pending_records)
            if has_more:
                self._flush_event.set()
        return flushed

    def _flush_loop(self) -> None:
        while not self._stop_event.is_set():
            self._flush_event.wait(timeout=self._flush_interval)
            self._flush_event.clear()
            self._flush_pending_records(force=False)

        # 退出前确保尽量落盘
        self._flush_pending_records(force=True)

    def close(self) -> None:
        if self._closed:
            return
        self._closed = True
        self._stop_event.set()
        self._flush_event.set()
        try:
            if self._flush_worker.is_alive():
                self._flush_worker.join(timeout=2.0)
        except Exception:
            pass
        self._flush_pending_records(force=True)

    def reset(self) -> None:
        with self._pending_lock:
            self._pending_records.clear()
        with self._storage_lock:
            self._write_metrics_data(self._empty_payload())

    def record_api_call(self, call_type: str, prompt_length: int, response_time: float,
                       success: bool, timeout: bool = False, error_msg: str = None,
                       truncated_docs: list = None, max_tokens: int = None,
                       queue_wait_ms: float = 0.0, hedge_triggered: bool = False,
                       cache_hit: bool = False, lane: str = "", model: str = "",
                       stage: str = "", event_kind: str = "api_call",
                       fallback_model_used: bool = False, fallback_reason: str = "",
                       primary_model: str = "", fallback_model: str = "",
                       model_attempt_index: int = 1):
        """记录 API 调用指标"""
        try:
            try:
                normalized_queue_wait_ms = max(0.0, float(queue_wait_ms or 0.0))
            except Exception:
                normalized_queue_wait_ms = 0.0
            normalized_lane = str(lane or "").strip().lower()
            normalized_model = str(model or "").strip()
            normalized_stage = str(stage or "").strip().lower()
            normalized_event_kind = str(event_kind or "api_call").strip().lower() or "api_call"
            normalized_primary_model = str(primary_model or "").strip()
            normalized_fallback_model = str(fallback_model or "").strip()
            normalized_fallback_reason = str(fallback_reason or "").strip().lower()
            try:
                normalized_model_attempt_index = max(1, int(model_attempt_index or 1))
            except Exception:
                normalized_model_attempt_index = 1
            call_record = {
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "type": call_type,  # "question" or "report"
                "event_kind": normalized_event_kind,
                "prompt_length": prompt_length,
                "response_time_ms": round(response_time * 1000, 2),
                "max_tokens": max_tokens,
                "success": success,
                "timeout": timeout,
                "error": error_msg,
                "truncated_docs": truncated_docs or [],
                "queue_wait_ms": round(normalized_queue_wait_ms, 2),
                "hedge_triggered": bool(hedge_triggered),
                "cache_hit": bool(cache_hit),
                "lane": normalized_lane,
                "model": normalized_model,
                "stage": normalized_stage,
                "fallback_model_used": bool(fallback_model_used),
                "fallback_reason": normalized_fallback_reason,
                "primary_model": normalized_primary_model,
                "fallback_model": normalized_fallback_model,
                "model_attempt_index": normalized_model_attempt_index,
            }

            with self._pending_lock:
                self._pending_records.append(call_record)
                while len(self._pending_records) > self._max_pending:
                    self._pending_records.popleft()
                pending_count = len(self._pending_records)

            if pending_count >= self._flush_batch_size:
                self._flush_event.set()

        except Exception as e:
            print(f"⚠️  记录指标失败: {e}")

    def get_statistics(self, last_n: int = None) -> dict:
        """获取统计信息"""
        empty_summary = {
            "total_calls": 0,
            "total_timeouts": 0,
            "total_truncations": 0,
            "total_cache_hits": 0,
            "total_hedge_triggered": 0,
            "total_model_fallbacks": 0,
            "avg_response_time": 0,
            "avg_prompt_length": 0,
            "avg_queue_wait_ms": 0,
        }
        try:
            self._flush_pending_records(force=True)
            with self._storage_lock:
                data = self._load_metrics_data()
            summary_data = data.get("summary", empty_summary)
            if not isinstance(summary_data, dict):
                summary_data = empty_summary
            calls_raw = data.get("calls", [])
            if not isinstance(calls_raw, list):
                calls_raw = []
            calls = [c for c in calls_raw if isinstance(c, dict)]

            if last_n:
                calls = calls[-last_n:]

            api_calls = [
                c for c in calls
                if str(c.get("event_kind", "api_call") or "api_call").strip().lower() == "api_call"
            ]
            stage_samples = [
                c for c in calls
                if str(c.get("stage", "") or "").strip()
            ]
            stage_profiles = _build_stage_latency_profiles(stage_samples)

            if not api_calls:
                return {
                    "period": f"最近 {last_n} 次调用" if last_n else "全部调用",
                    "total_calls": 0,
                    "successful_calls": 0,
                    "failed_calls": 0,
                    "timeout_calls": 0,
                    "timeout_rate": 0,
                    "truncation_events": 0,
                    "truncation_rate": 0,
                    "avg_response_time_ms": 0,
                    "max_response_time_ms": 0,
                    "min_response_time_ms": 0,
                    "avg_prompt_length": 0,
                    "max_prompt_length": 0,
                    "cache_hit_calls": 0,
                    "cache_hit_rate": 0,
                    "hedge_triggered_calls": 0,
                    "hedge_trigger_rate": 0,
                    "avg_queue_wait_ms": 0,
                    "max_queue_wait_ms": 0,
                    "recommendations": [{
                        "level": "info",
                        "message": "暂无数据"
                    }],
                    "summary": {
                        "total_calls": int(summary_data.get("total_calls", 0) or 0),
                        "total_timeouts": int(summary_data.get("total_timeouts", 0) or 0),
                        "total_truncations": int(summary_data.get("total_truncations", 0) or 0),
                        "total_cache_hits": int(summary_data.get("total_cache_hits", 0) or 0),
                        "total_hedge_triggered": int(summary_data.get("total_hedge_triggered", 0) or 0),
                        "total_model_fallbacks": int(summary_data.get("total_model_fallbacks", 0) or 0),
                        "avg_response_time": float(summary_data.get("avg_response_time", 0) or 0),
                        "avg_prompt_length": float(summary_data.get("avg_prompt_length", 0) or 0),
                        "avg_queue_wait_ms": float(summary_data.get("avg_queue_wait_ms", 0) or 0),
                    },
                    "stage_profiles": stage_profiles,
                    "calls": [],
                    "message": "暂无数据"
                }

            # 计算统计信息
            total_calls = len(api_calls)
            successful_calls = sum(1 for c in api_calls if bool(c.get("success")))
            timeout_calls = sum(1 for c in api_calls if c.get("timeout", False))
            truncation_events = sum(len(c.get("truncated_docs", [])) for c in api_calls)
            cache_hit_calls = sum(1 for c in api_calls if bool(c.get("cache_hit", False)))
            hedge_triggered_calls = sum(1 for c in api_calls if bool(c.get("hedge_triggered", False)))

            response_times = [
                float(c.get("response_time_ms", 0))
                for c in api_calls
                if bool(c.get("success")) and isinstance(c.get("response_time_ms", 0), (int, float))
            ]
            prompt_lengths = [
                float(c.get("prompt_length", 0))
                for c in api_calls
                if isinstance(c.get("prompt_length", 0), (int, float))
            ]
            queue_wait_values = [
                float(c.get("queue_wait_ms", 0))
                for c in api_calls
                if isinstance(c.get("queue_wait_ms", 0), (int, float))
            ]

            stats = {
                "period": f"最近 {last_n} 次调用" if last_n else "全部调用",
                "total_calls": total_calls,
                "successful_calls": successful_calls,
                "failed_calls": total_calls - successful_calls,
                "timeout_calls": timeout_calls,
                "timeout_rate": round(timeout_calls / total_calls * 100, 2) if total_calls > 0 else 0,
                "truncation_events": truncation_events,
                "truncation_rate": round(truncation_events / total_calls * 100, 2) if total_calls > 0 else 0,
                "avg_response_time_ms": round(sum(response_times) / len(response_times), 2) if response_times else 0,
                "max_response_time_ms": round(max(response_times), 2) if response_times else 0,
                "min_response_time_ms": round(min(response_times), 2) if response_times else 0,
                "avg_prompt_length": round(sum(prompt_lengths) / len(prompt_lengths), 2) if prompt_lengths else 0,
                "max_prompt_length": max(prompt_lengths) if prompt_lengths else 0,
                "cache_hit_calls": cache_hit_calls,
                "cache_hit_rate": round(cache_hit_calls / total_calls * 100, 2) if total_calls > 0 else 0,
                "hedge_triggered_calls": hedge_triggered_calls,
                "hedge_trigger_rate": round(hedge_triggered_calls / total_calls * 100, 2) if total_calls > 0 else 0,
                "avg_queue_wait_ms": round(sum(queue_wait_values) / len(queue_wait_values), 2) if queue_wait_values else 0,
                "max_queue_wait_ms": round(max(queue_wait_values), 2) if queue_wait_values else 0,
            }

            # 生成优化建议
            stats["recommendations"] = self._generate_recommendations(stats)
            stats["summary"] = {
                "total_calls": int(summary_data.get("total_calls", 0) or 0),
                "total_timeouts": int(summary_data.get("total_timeouts", 0) or 0),
                "total_truncations": int(summary_data.get("total_truncations", 0) or 0),
                "total_cache_hits": int(summary_data.get("total_cache_hits", 0) or 0),
                "total_hedge_triggered": int(summary_data.get("total_hedge_triggered", 0) or 0),
                "total_model_fallbacks": int(summary_data.get("total_model_fallbacks", 0) or 0),
                "avg_response_time": float(summary_data.get("avg_response_time", 0) or 0),
                "avg_prompt_length": float(summary_data.get("avg_prompt_length", 0) or 0),
                "avg_queue_wait_ms": float(summary_data.get("avg_queue_wait_ms", 0) or 0),
            }
            stats["stage_profiles"] = stage_profiles
            stats["calls"] = api_calls

            return stats

        except Exception as e:
            return {
                "period": f"最近 {last_n} 次调用" if last_n else "全部调用",
                "total_calls": 0,
                "successful_calls": 0,
                "failed_calls": 0,
                "timeout_calls": 0,
                "timeout_rate": 0,
                "truncation_events": 0,
                "truncation_rate": 0,
                "avg_response_time_ms": 0,
                "max_response_time_ms": 0,
                "min_response_time_ms": 0,
                "avg_prompt_length": 0,
                "max_prompt_length": 0,
                "cache_hit_calls": 0,
                "cache_hit_rate": 0,
                "hedge_triggered_calls": 0,
                "hedge_trigger_rate": 0,
                "avg_queue_wait_ms": 0,
                "max_queue_wait_ms": 0,
                "recommendations": [{
                    "level": "warning",
                    "message": "指标存储异常，已返回空统计"
                }],
                "summary": empty_summary,
                "calls": [],
                "message": f"获取统计信息失败: {e}",
            }

    def _generate_recommendations(self, stats: dict) -> list:
        """基于统计数据生成优化建议"""
        recommendations = []

        # 超时率过高
        if stats["timeout_rate"] > 10:
            recommendations.append({
                "level": "critical",
                "message": f"超时率过高 ({stats['timeout_rate']}%)，建议减少文档长度限制或实施智能摘要"
            })
        elif stats["timeout_rate"] > 5:
            recommendations.append({
                "level": "warning",
                "message": f"超时率偏高 ({stats['timeout_rate']}%)，需要关注"
            })

        # 截断率过高
        if stats["truncation_rate"] > 50:
            recommendations.append({
                "level": "warning",
                "message": f"文档截断频繁 ({stats['truncation_rate']}%)，建议实施智能摘要功能"
            })

        # Prompt 过长
        if stats["avg_prompt_length"] > 8000:
            recommendations.append({
                "level": "warning",
                "message": f"平均 Prompt 长度较大 ({stats['avg_prompt_length']} 字符)，可能影响响应速度"
            })

        # 响应时间过长
        if stats["avg_response_time_ms"] > 60000:
            recommendations.append({
                "level": "warning",
                "message": f"平均响应时间较长 ({stats['avg_response_time_ms']/1000:.1f} 秒)，建议优化 Prompt 长度"
            })
        if float(stats.get("avg_queue_wait_ms", 0) or 0) > 1200:
            recommendations.append({
                "level": "warning",
                "message": f"调度排队时间偏高 ({stats['avg_queue_wait_ms']:.0f} ms)，建议提升高优先级并发资源"
            })

        # 一切正常
        if not recommendations:
            if stats["timeout_rate"] < 5 and stats["truncation_rate"] < 30:
                recommendations.append({
                    "level": "info",
                    "message": "系统运行正常，可考虑适度增加文档长度限制以提升质量"
                })

        return recommendations


# 初始化指标收集器
metrics_collector = MetricsCollector("api_metrics")


def _record_cache_hit_metric(call_type: str) -> None:
    safe_call_type = str(call_type or "").strip() or "cache_hit"
    try:
        metrics_collector.record_api_call(
            call_type=safe_call_type,
            prompt_length=0,
            response_time=0.0,
            success=True,
            cache_hit=True,
        )
    except Exception:
        pass


def resolve_generation_stage(call_type: str = "") -> str:
    lowered = str(call_type or "").strip().lower()
    if not lowered:
        return ""
    if "report_v3_draft" in lowered:
        return "draft_gen"
    if "report_v3_review_round" in lowered:
        return "review_gen"
    if lowered.startswith(("question", "prefetch")):
        return "question_fast" if "_fast" in lowered else "question_full"
    return ""


def record_pipeline_stage_metric(
    stage: str,
    success: bool,
    elapsed_seconds: float,
    lane: str = "",
    model: str = "",
    error_msg: str = "",
) -> None:
    normalized_stage = str(stage or "").strip().lower()
    if not normalized_stage:
        return

    safe_elapsed_seconds = max(0.0, float(elapsed_seconds or 0.0))
    safe_lane = str(lane or "").strip().lower()
    safe_model = str(model or "").strip()
    safe_error = summarize_error_for_log(error_msg, limit=160) if error_msg else None

    try:
        metrics_collector.record_api_call(
            call_type=f"report_v3_stage_{normalized_stage}",
            prompt_length=0,
            response_time=safe_elapsed_seconds,
            success=bool(success),
            timeout=False,
            error_msg=safe_error if not success else None,
            truncated_docs=[],
            max_tokens=0,
            queue_wait_ms=0.0,
            hedge_triggered=False,
            cache_hit=False,
            lane=safe_lane,
            model=safe_model,
            stage=normalized_stage,
            event_kind="pipeline_stage",
        )
    except Exception:
        pass


# AI 客户端初始化（支持问题/报告分网关）
claude_client = None  # 历史兼容：默认指向可用的主客户端
question_ai_client = None
question_deep_ai_client = None
report_ai_client = None
report_draft_ai_client = None
report_review_ai_client = None
summary_ai_client = None
search_decision_ai_client = None
assessment_ai_client = None
AI_CLIENT_EAGER_INIT = _cfg_bool("AI_CLIENT_EAGER_INIT", False)
AI_CLIENT_INIT_CONNECTION_TEST = _cfg_bool("AI_CLIENT_INIT_CONNECTION_TEST", False)
GATEWAY_CIRCUIT_LANES = ("question", "report", "report_draft", "report_review", "summary", "search_decision", "assessment")
gateway_circuit_lock = threading.RLock()
ai_client_init_lock = threading.RLock()
ai_client_bootstrap_state = {
    "attempted": False,
    "initialized": False,
    "attempt_count": 0,
    "reason": "pending",
}


def _new_gateway_circuit_entry() -> dict:
    return {
        "fail_count": 0,
        "first_fail_at": 0.0,
        "cooldown_until": 0.0,
        "last_error_type": "",
    }


gateway_circuit_state = {lane: _new_gateway_circuit_entry() for lane in GATEWAY_CIRCUIT_LANES}


def _normalize_gateway_lane(lane: str) -> str:
    normalized = str(lane or "").strip().lower()
    if normalized in GATEWAY_CIRCUIT_LANES:
        return normalized
    return ""


def _gateway_circuit_guard_lanes(lane: str) -> list[str]:
    normalized = _normalize_gateway_lane(lane)
    if normalized == "report_draft":
        return ["report_draft", "report"]
    if normalized == "report_review":
        return ["report_review", "report"]
    if normalized:
        return [normalized]
    return []


def _cleanup_gateway_circuit_entry_locked(entry: dict, now_ts: float) -> None:
    cooldown_until = float(entry.get("cooldown_until", 0.0) or 0.0)
    first_fail_at = float(entry.get("first_fail_at", 0.0) or 0.0)
    if cooldown_until > 0 and now_ts >= cooldown_until:
        entry.update(_new_gateway_circuit_entry())
        return

    if first_fail_at > 0 and (now_ts - first_fail_at) > GATEWAY_CIRCUIT_FAILURE_WINDOW_SECONDS and cooldown_until <= 0:
        entry.update(_new_gateway_circuit_entry())


def reset_gateway_circuit_state(lanes: Optional[list[str]] = None) -> None:
    """重置网关熔断状态（测试与运维排障使用）。"""
    if lanes is None:
        normalized_lanes = list(GATEWAY_CIRCUIT_LANES)
    else:
        normalized_lanes = [
            lane_name
            for lane_name in (_normalize_gateway_lane(item) for item in lanes)
            if lane_name
        ]

    with gateway_circuit_lock:
        for lane_name in normalized_lanes:
            gateway_circuit_state[lane_name] = _new_gateway_circuit_entry()


def get_gateway_circuit_snapshot(lane: str) -> dict:
    lane_name = _normalize_gateway_lane(lane)
    if not lane_name:
        return {}

    now_ts = _time.time()
    with gateway_circuit_lock:
        entry = gateway_circuit_state.setdefault(lane_name, _new_gateway_circuit_entry())
        _cleanup_gateway_circuit_entry_locked(entry, now_ts)
        return {
            "fail_count": int(entry.get("fail_count", 0) or 0),
            "first_fail_at": float(entry.get("first_fail_at", 0.0) or 0.0),
            "cooldown_until": float(entry.get("cooldown_until", 0.0) or 0.0),
            "last_error_type": str(entry.get("last_error_type", "") or ""),
            "cooldown_remaining_seconds": max(0.0, float(entry.get("cooldown_until", 0.0) or 0.0) - now_ts),
        }


def _get_gateway_cooldown_lanes(lane: str, now_ts: float = None) -> list[str]:
    lane_name = _normalize_gateway_lane(lane)
    if not lane_name or not GATEWAY_CIRCUIT_BREAKER_ENABLED:
        return []

    current_ts = float(now_ts) if now_ts is not None else _time.time()
    blocked_lanes = []
    with gateway_circuit_lock:
        for guard_lane in _gateway_circuit_guard_lanes(lane_name):
            entry = gateway_circuit_state.setdefault(guard_lane, _new_gateway_circuit_entry())
            _cleanup_gateway_circuit_entry_locked(entry, current_ts)
            if float(entry.get("cooldown_until", 0.0) or 0.0) > current_ts:
                blocked_lanes.append(guard_lane)
    return blocked_lanes


def is_gateway_lane_in_cooldown(lane: str, now_ts: float = None) -> bool:
    return bool(_get_gateway_cooldown_lanes(lane, now_ts=now_ts))


def classify_gateway_failure_kind(raw_error_message: str) -> str:
    lowered = str(raw_error_message or "").strip().lower()
    if not lowered:
        return "unknown"
    if "timeout" in lowered or "timed out" in lowered:
        return "timeout"
    if "<html" in lowered or "<!doctype html" in lowered:
        return "html_payload"
    if re.search(r"\b5\d{2}\b", lowered) or "gateway time-out" in lowered or "gateway timeout" in lowered:
        return "http_5xx"
    return "other"


def _should_count_circuit_failure(error_kind: str) -> bool:
    return str(error_kind or "").strip().lower() in {"timeout", "http_5xx", "html_payload"}


def record_gateway_lane_failure(lane: str, error_kind: str, now_ts: float = None) -> dict:
    lane_name = _normalize_gateway_lane(lane)
    normalized_error = str(error_kind or "").strip().lower() or "unknown"
    if not lane_name:
        return {"counted": False, "lane": "", "error_kind": normalized_error}
    if not GATEWAY_CIRCUIT_BREAKER_ENABLED:
        return {"counted": False, "lane": lane_name, "error_kind": normalized_error}
    if not _should_count_circuit_failure(normalized_error):
        return {"counted": False, "lane": lane_name, "error_kind": normalized_error}

    current_ts = float(now_ts) if now_ts is not None else _time.time()
    with gateway_circuit_lock:
        entry = gateway_circuit_state.setdefault(lane_name, _new_gateway_circuit_entry())
        _cleanup_gateway_circuit_entry_locked(entry, current_ts)

        first_fail_at = float(entry.get("first_fail_at", 0.0) or 0.0)
        if first_fail_at <= 0 or (current_ts - first_fail_at) > GATEWAY_CIRCUIT_FAILURE_WINDOW_SECONDS:
            entry["first_fail_at"] = current_ts
            entry["fail_count"] = 0

        entry["fail_count"] = int(entry.get("fail_count", 0) or 0) + 1
        entry["last_error_type"] = normalized_error

        circuit_opened = False
        if entry["fail_count"] >= GATEWAY_CIRCUIT_FAIL_THRESHOLD:
            entry["cooldown_until"] = max(
                float(entry.get("cooldown_until", 0.0) or 0.0),
                current_ts + GATEWAY_CIRCUIT_COOLDOWN_SECONDS,
            )
            circuit_opened = True

        cooldown_until = float(entry.get("cooldown_until", 0.0) or 0.0)
        return {
            "counted": True,
            "lane": lane_name,
            "error_kind": normalized_error,
            "fail_count": int(entry.get("fail_count", 0) or 0),
            "cooldown_until": cooldown_until,
            "cooldown_remaining_seconds": max(0.0, cooldown_until - current_ts),
            "circuit_opened": circuit_opened,
        }


def record_gateway_lane_success(lane: str) -> None:
    lane_name = _normalize_gateway_lane(lane)
    if not lane_name:
        return
    with gateway_circuit_lock:
        for reset_lane in _gateway_circuit_guard_lanes(lane_name):
            gateway_circuit_state[reset_lane] = _new_gateway_circuit_entry()

# 检查 API Key 是否有效
def is_valid_api_key(api_key: str) -> bool:
    """检查 API Key 是否有效（不是默认占位符）"""
    if not api_key:
        return False
    placeholder_patterns = [
        "your-", "your_", "example", "test", "placeholder",
        "api-key", "apikey", "YOUR-", "YOUR_"
    ]
    api_key_lower = api_key.lower()
    for pattern in placeholder_patterns:
        if pattern in api_key_lower:
            return False
    return True


def _create_anthropic_client(api_key: str, base_url: str, use_bearer_auth: bool = False):
    kwargs = {
        "api_key": api_key,
        "max_retries": AI_CLIENT_MAX_RETRIES,
    }
    if base_url:
        kwargs["base_url"] = base_url
    if use_bearer_auth:
        kwargs["default_headers"] = {"Authorization": f"Bearer {api_key}"}
    return anthropic.Anthropic(**kwargs)


def _init_lane_client(
    lane_name: str,
    api_key: str,
    base_url: str,
    test_model: str,
    use_bearer_auth: bool = False,
    run_connection_test: bool = False,
):
    if not is_valid_api_key(api_key):
        print(f"⚠️  {lane_name} 网关 API Key 未配置或为占位值，跳过初始化")
        return None

    try:
        client = _create_anthropic_client(
            api_key=api_key,
            base_url=base_url,
            use_bearer_auth=use_bearer_auth,
        )
        endpoint = base_url or "(Anthropic 官方默认地址)"
        print(f"✅ {lane_name} 网关客户端已初始化")
        print(f"   模型: {test_model}")
        print(f"   Base URL: {endpoint}")
        print(f"   鉴权模式: {'Bearer Authorization' if use_bearer_auth else 'Anthropic x-api-key'}")

        if run_connection_test:
            # 连接测试失败不阻断服务，保留客户端以便后续重试
            try:
                client.messages.create(
                    model=test_model,
                    max_tokens=5,
                    messages=[{"role": "user", "content": "Hi"}]
                )
                print(f"✅ {lane_name} 网关连接测试成功")
            except Exception as e:
                print(f"⚠️  {lane_name} 网关连接测试失败: {e}")
                print("   客户端已保留，运行时会继续尝试请求")
        else:
            print("   连接探测: 已跳过（按需初始化）")

        return client
    except Exception as e:
        print(f"❌ {lane_name} 网关客户端初始化失败: {e}")
        return None


def _pick_reused_client(signature: tuple, lane_signatures: list[tuple]) -> tuple[Optional[object], str]:
    for lane_name, lane_signature, lane_client in lane_signatures:
        if signature == lane_signature and lane_client:
            return lane_client, lane_name
    return None, ""


def _any_ai_client_available() -> bool:
    return any([
        question_ai_client,
        question_deep_ai_client,
        report_ai_client,
        report_draft_ai_client,
        report_review_ai_client,
        summary_ai_client,
        search_decision_ai_client,
        assessment_ai_client,
    ])


def reset_ai_clients(force_reason: str = "reset") -> None:
    """重置 AI 客户端与懒加载状态（测试/运维排障使用）。"""
    global claude_client, question_ai_client, question_deep_ai_client, report_ai_client, report_draft_ai_client, report_review_ai_client, summary_ai_client, search_decision_ai_client, assessment_ai_client
    with ai_client_init_lock:
        claude_client = None
        question_ai_client = None
        question_deep_ai_client = None
        report_ai_client = None
        report_draft_ai_client = None
        report_review_ai_client = None
        summary_ai_client = None
        search_decision_ai_client = None
        assessment_ai_client = None
        ai_client_bootstrap_state.update({
            "attempted": False,
            "initialized": False,
            "reason": str(force_reason or "reset"),
        })


def get_ai_client_bootstrap_snapshot() -> dict:
    with ai_client_init_lock:
        snapshot = dict(ai_client_bootstrap_state)
        available_clients = [
            question_ai_client,
            question_deep_ai_client,
            report_ai_client,
            report_draft_ai_client,
            report_review_ai_client,
            summary_ai_client,
            search_decision_ai_client,
            assessment_ai_client,
        ]
        snapshot["available_client_count"] = int(len({id(item) for item in available_clients if item}))
        snapshot["question_ai_available"] = question_ai_client is not None
        snapshot["question_deep_ai_available"] = question_deep_ai_client is not None
        snapshot["report_ai_available"] = report_ai_client is not None
        snapshot["report_draft_ai_available"] = report_draft_ai_client is not None
        snapshot["report_review_ai_available"] = report_review_ai_client is not None
        snapshot["summary_ai_available"] = summary_ai_client is not None
        snapshot["search_decision_ai_available"] = search_decision_ai_client is not None
        snapshot["assessment_ai_available"] = assessment_ai_client is not None
        return snapshot


