def _lane_client_by_name(lane: str):
    if not _any_ai_client_available():
        ensure_ai_clients_initialized()
    lane_name = str(lane or "").strip().lower()
    if lane_name == "question":
        return question_ai_client
    if lane_name == "question_deep":
        return question_deep_ai_client or question_ai_client
    if lane_name == "report_draft":
        return report_draft_ai_client or report_ai_client or report_review_ai_client
    if lane_name == "report_review":
        return report_review_ai_client or report_ai_client or report_draft_ai_client
    if lane_name == "report":
        return report_ai_client or report_review_ai_client or report_draft_ai_client
    if lane_name == "summary":
        return summary_ai_client
    if lane_name == "search_decision":
        return search_decision_ai_client
    if lane_name == "assessment":
        return assessment_ai_client
    return None


def _resolve_client_for_lane_name(lane_name: str, model_name: str = ""):
    normalized_lane = str(lane_name or "").strip().lower()
    if normalized_lane == "question" and _should_use_deep_question_gateway(model_name):
        return question_deep_ai_client or question_ai_client
    return _lane_client_by_name(normalized_lane)


def _dedupe_lane_candidates(candidates: list[str]) -> list[str]:
    ordered = []
    seen = set()
    for lane_name in candidates:
        normalized = str(lane_name or "").strip().lower()
        if not normalized or normalized in seen:
            continue
        ordered.append(normalized)
        seen.add(normalized)
    return ordered


def _resolve_report_gateway_lane_candidates(call_type: str = "", primary_lane: str = "report") -> list[str]:
    normalized_primary_lane = str(primary_lane or "").strip().lower()
    if normalized_primary_lane not in {"question", "report", "report_draft", "report_review"}:
        normalized_primary_lane = "report"

    if normalized_primary_lane == "report_draft":
        return _dedupe_lane_candidates(["report_draft", "question", "report_review"])
    if normalized_primary_lane == "report_review":
        return _dedupe_lane_candidates(["report_review", "report_draft", "question"])

    if normalized_primary_lane == "question":
        if _is_report_review_call_type(call_type):
            return _dedupe_lane_candidates(["question", "report_review", "report_draft"])
        if _is_report_draft_call_type(call_type):
            return _dedupe_lane_candidates(["question", "report_draft", "report_review"])
        return _dedupe_lane_candidates(["question", "report_draft", "report_review"])

    if _is_report_review_call_type(call_type):
        return _dedupe_lane_candidates(["report_review", "report_draft", "question"])
    if _is_report_draft_call_type(call_type):
        return _dedupe_lane_candidates(["report_draft", "question", "report_review"])
    return _dedupe_lane_candidates(["report_draft", "report_review", "question"])


def _lane_candidates_for_client_resolution(
    call_type: str = "",
    model_name: str = "",
    preferred_lane: str = "",
    strict_preferred_lane: bool = False,
) -> list[str]:
    forced_lane = str(preferred_lane or "").strip().lower()
    if strict_preferred_lane and forced_lane:
        if forced_lane in {"report", "question", "report_draft", "report_review"} and "report" in str(call_type or "").lower():
            candidates = _resolve_report_gateway_lane_candidates(call_type=call_type, primary_lane=forced_lane)
            return candidates[:1]
        if forced_lane in {"assessment", "search_decision", "summary", "report", "question"}:
            return [forced_lane]
    if forced_lane in {"report", "question", "report_draft", "report_review"} and "report" in str(call_type or "").lower():
        return _resolve_report_gateway_lane_candidates(call_type=call_type, primary_lane=forced_lane)
    if forced_lane == "assessment":
        return ["assessment", "search_decision", "summary", "question", "report"]
    if forced_lane == "search_decision":
        return ["search_decision", "summary", "question", "report"]
    if forced_lane == "summary":
        return ["summary", "report", "question", "search_decision"]
    if forced_lane == "report":
        return ["report", "question"]
    if forced_lane == "question":
        return ["question", "report"]

    lane = resolve_call_lane(call_type=call_type, model_name=model_name)
    if lane == "report":
        return _resolve_report_gateway_lane_candidates(call_type=call_type, primary_lane=lane)
    if lane == "assessment":
        return ["assessment", "search_decision", "summary", "question", "report"]
    if lane == "search_decision":
        return ["search_decision", "summary", "question", "report"]
    if lane == "summary":
        return ["summary", "report", "question", "search_decision"]
    return ["question", "report", "summary", "search_decision", "assessment"]


def resolve_ai_client_with_lane(
    call_type: str = "",
    model_name: str = "",
    preferred_lane: str = "",
    respect_circuit_breaker: bool = True,
    strict_preferred_lane: bool = False,
) -> tuple[Optional[object], str, dict]:
    """按调用类型选择客户端，并返回命中的 lane 与熔断元信息。"""
    candidates = _lane_candidates_for_client_resolution(
        call_type=call_type,
        model_name=model_name,
        preferred_lane=preferred_lane,
        strict_preferred_lane=strict_preferred_lane,
    )
    requested_lane = candidates[0] if candidates else ""
    skip_open = bool(respect_circuit_breaker and GATEWAY_CIRCUIT_BREAKER_ENABLED)
    skipped_open_lanes = []
    fallback_pool = []

    for lane_name in candidates:
        client = _resolve_client_for_lane_name(lane_name, model_name=model_name)
        if not client:
            continue
        fallback_pool.append((lane_name, client))
        blocked_lanes = _get_gateway_cooldown_lanes(lane_name) if skip_open else []
        if blocked_lanes:
            for blocked_lane in blocked_lanes:
                if blocked_lane not in skipped_open_lanes:
                    skipped_open_lanes.append(blocked_lane)
            continue
        return client, lane_name, {
            "requested_lane": requested_lane,
            "skipped_open_lanes": skipped_open_lanes,
            "forced_open_lane": "",
            "strict_preferred_lane": bool(strict_preferred_lane),
        }

    if fallback_pool and not strict_preferred_lane:
        # 所有候选 lane 均处于冷却时，选择第一个可用客户端避免彻底不可用。
        lane_name, client = fallback_pool[0]
        return client, lane_name, {
            "requested_lane": requested_lane,
            "skipped_open_lanes": skipped_open_lanes,
            "forced_open_lane": lane_name if skipped_open_lanes else "",
            "strict_preferred_lane": bool(strict_preferred_lane),
        }

    return None, "", {
        "requested_lane": requested_lane,
        "skipped_open_lanes": skipped_open_lanes,
        "forced_open_lane": "",
        "strict_preferred_lane": bool(strict_preferred_lane),
    }


def resolve_ai_client(
    call_type: str = "",
    model_name: str = "",
    preferred_lane: str = "",
    strict_preferred_lane: bool = False,
):
    """兼容历史接口，仅返回客户端对象。"""
    client, _, _ = resolve_ai_client_with_lane(
        call_type=call_type,
        model_name=model_name,
        preferred_lane=preferred_lane,
        strict_preferred_lane=strict_preferred_lane,
    )
    return client


def _content_block_field(block, field: str):
    """兼容对象/字典两种内容块结构读取字段。"""
    if isinstance(block, dict):
        return block.get(field)
    return getattr(block, field, None)


def _strip_reasoning_tags(text: str) -> str:
    """移除兼容网关把思考内容混入 text block 的 <think> 段。"""
    normalized = str(text or "")
    if not normalized:
        return ""

    cleaned = re.sub(r"<think>\s*[\s\S]*?\s*</think>", "", normalized, flags=re.IGNORECASE)
    return cleaned.strip()


def extract_message_text(message, allow_non_text_fallback: bool = False) -> str:
    """从模型响应中提取文本内容，优先提取 type=text，并剥离混入的思考标签。"""
    content = getattr(message, "content", None) or []
    if not content:
        return ""

    # 优先提取 type=text 的内容块，避免拿到 thinking 块导致空文本
    text_parts = []
    for block in content:
        if _content_block_field(block, "type") != "text":
            continue
        block_text = _content_block_field(block, "text")
        if isinstance(block_text, str):
            cleaned_text = _strip_reasoning_tags(block_text)
            if cleaned_text:
                text_parts.append(cleaned_text)

    if text_parts:
        return "\n".join(text_parts).strip()

    # 默认不回退到非 text 块，避免把 thinking 当作最终输出
    if not allow_non_text_fallback:
        return ""

    # 兜底：极少数兼容实现可能未标记 type，但有 text 字段
    fallback_parts = []
    for block in content:
        block_text = _content_block_field(block, "text")
        if isinstance(block_text, str):
            cleaned_text = _strip_reasoning_tags(block_text)
            if cleaned_text:
                fallback_parts.append(cleaned_text)

    return "\n".join(fallback_parts).strip()


def _collect_json_candidates(raw_text: str) -> list:
    """提取可能的 JSON 候选字符串（直出、代码块、花括号配对）。"""
    candidates = []
    text = (raw_text or "").strip()
    if not text:
        return candidates

    candidates.append(text)

    # 代码块候选
    for match in re.finditer(r"```(?:json)?\s*([\s\S]*?)```", text, re.IGNORECASE):
        block = (match.group(1) or "").strip()
        if block:
            candidates.append(block)

    # 花括号配对提取第一个完整 JSON 对象
    json_start = text.find("{")
    if json_start >= 0:
        brace_count = 0
        in_string = False
        escape_next = False
        json_end = -1

        for idx in range(json_start, len(text)):
            char = text[idx]
            if escape_next:
                escape_next = False
                continue
            if char == "\\":
                escape_next = True
                continue
            if char == "\"":
                in_string = not in_string
                continue
            if in_string:
                continue
            if char == "{":
                brace_count += 1
            elif char == "}":
                brace_count -= 1
                if brace_count == 0:
                    json_end = idx + 1
                    break

        if json_end > json_start:
            candidates.append(text[json_start:json_end].strip())

    # 去重（保序）+ 处理 ```json 提取后残留的 json 前缀
    normalized = []
    seen = set()
    for candidate in candidates:
        item = candidate.strip()
        if item.lower().startswith("json"):
            item = item[4:].strip()
        if not item or item in seen:
            continue
        seen.add(item)
        normalized.append(item)
    return normalized


def parse_json_object_response(raw_text: str, required_keys: list = None) -> Optional[dict]:
    """从模型文本中容错解析 JSON 对象。"""
    required_keys = required_keys or []
    last_error = None

    for candidate in _collect_json_candidates(raw_text):
        try:
            parsed = json.loads(candidate)
        except Exception as exc:
            last_error = exc
            continue

        if not isinstance(parsed, dict):
            last_error = ValueError("JSON 不是对象")
            continue

        if any(key not in parsed for key in required_keys):
            last_error = ValueError(f"JSON 缺少必要字段: {required_keys}")
            continue

        return parsed

    if last_error:
        raise ValueError(f"JSON解析失败: {last_error}")
    raise ValueError("未找到可解析的 JSON 对象")


def parse_generated_scenario_response(raw_text: str) -> Optional[dict]:
    parse_meta = {}
    parsed = parse_structured_json_response(
        raw_text,
        required_keys=["name", "dimensions"],
        require_all_keys=True,
        parse_meta=parse_meta,
    )
    if isinstance(parsed, dict):
        return parsed

    partial = parse_structured_json_response(
        raw_text,
        required_keys=None,
    )
    if isinstance(partial, dict):
        return partial

    return parse_generated_scenario_text_fallback(raw_text)


def _pick_generated_scenario_text_value(source: dict, keys: list[str]) -> str:
    if not isinstance(source, dict):
        return ""
    for key in keys:
        value = source.get(key)
        if value is None:
            continue
        text = str(value).strip()
        if text:
            return text
    return ""


def _split_generated_scenario_aspects(raw_value: object) -> list[str]:
    candidates = []

    def _append_text(value: object) -> None:
        if value is None:
            return
        if isinstance(value, dict):
            text = _pick_generated_scenario_text_value(
                value,
                ["name", "title", "label", "text", "content", "description", "desc"],
            )
            if text:
                candidates.append(text)
            return
        text = str(value).strip()
        if text:
            candidates.append(text)

    if isinstance(raw_value, list):
        for item in raw_value:
            _append_text(item)
    else:
        _append_text(raw_value)

    aspects = []
    seen = set()
    for candidate in candidates:
        parts = re.split(r"[,，、；;\n]+", candidate)
        for part in parts:
            aspect = str(part or "").strip(" -•·\t")
            if not aspect or aspect in seen:
                continue
            seen.add(aspect)
            aspects.append(aspect[:30])
    return aspects


def _build_generated_dimension_payload(raw_dim: object, index: int) -> Optional[dict]:
    if isinstance(raw_dim, str):
        dim_name = str(raw_dim).strip()
        dim_description = ""
        key_aspects = []
    elif isinstance(raw_dim, dict):
        dim_name = _pick_generated_scenario_text_value(
            raw_dim,
            ["name", "title", "label", "dimension", "dimension_name", "section_name", "topic", "维度名称", "维度"],
        )
        dim_description = _pick_generated_scenario_text_value(
            raw_dim,
            ["description", "desc", "summary", "focus", "goal", "note", "说明", "描述"],
        )
        key_aspects = _split_generated_scenario_aspects(
            raw_dim.get("key_aspects")
            or raw_dim.get("keyPoints")
            or raw_dim.get("key_points")
            or raw_dim.get("aspects")
            or raw_dim.get("points")
            or raw_dim.get("keywords")
            or raw_dim.get("关注点")
            or raw_dim.get("关键点")
        )
    else:
        return None

    dim_name = str(dim_name or "").strip()
    if not dim_name:
        return None

    dim_description = str(dim_description or "").strip()
    if not dim_description and key_aspects:
        dim_description = f"围绕「{dim_name}」了解{ '、'.join(key_aspects[:2]) }等重点内容"

    return {
        "id": f"dim_{index}",
        "name": dim_name[:24],
        "description": dim_description[:120],
        "key_aspects": key_aspects[:6],
        "min_questions": 2,
        "max_questions": 4,
    }


def _extract_generated_dimension_header(line: str) -> tuple[str, str]:
    text = re.sub(r"^\s*(?:[-*•]+|#{1,6}\s*)", "", str(line or "").strip()).strip()
    if not text:
        return "", ""

    patterns = [
        r"^维度\s*[一二三四五六七八九十0-9]+\s*[:：\-、.]?\s*(.+)$",
        r"^[一二三四五六七八九十0-9]+\s*[.、:：-]\s*(.+)$",
    ]
    candidate = ""
    for pattern in patterns:
        match = re.match(pattern, text)
        if match:
            candidate = str(match.group(1) or "").strip()
            break
    if not candidate:
        return "", ""

    parts = re.split(r"\s*[:：]\s*", candidate, maxsplit=1)
    name = str(parts[0] or "").strip(" -•·\t")
    inline_description = str(parts[1] or "").strip() if len(parts) > 1 else ""
    return name, inline_description


def parse_generated_scenario_text_fallback(raw_text: str) -> Optional[dict]:
    text = re.sub(r"^\s*```(?:json)?\s*", "", str(raw_text or "").strip(), flags=re.IGNORECASE).strip()
    text = re.sub(r"\s*```\s*$", "", text).strip()
    if not text:
        return None

    def _extract_labeled_value(patterns: list[str]) -> str:
        for pattern in patterns:
            match = re.search(pattern, text, flags=re.IGNORECASE | re.MULTILINE)
            if match:
                return str(match.group(1) or "").strip()
        return ""

    name = _extract_labeled_value([
        r"^(?:场景名称|名称|Scenario Name)\s*[:：]\s*(.+)$",
    ])
    description = _extract_labeled_value([
        r"^(?:场景描述|描述|简介|Description)\s*[:：]\s*(.+)$",
    ])
    explanation = _extract_labeled_value([
        r"^(?:设计思路|设计说明|说明|解释|Explanation)\s*[:：]\s*(.+)$",
    ])

    inline_dimensions = []
    inline_match = re.search(
        r"^(?:访谈维度|维度列表|维度设计|维度)\s*[:：]\s*(.+)$",
        text,
        flags=re.IGNORECASE | re.MULTILINE,
    )
    if inline_match:
        inline_dimensions = [
            item.strip(" -•·\t")
            for item in re.split(r"[,，、/]+", str(inline_match.group(1) or "").strip())
            if item.strip(" -•·\t")
        ]

    dimension_blocks = []
    current_block = None

    def _flush_dimension() -> None:
        nonlocal current_block
        if current_block:
            dimension_blocks.append(current_block)
        current_block = None

    for raw_line in text.splitlines():
        line = str(raw_line or "").strip()
        if not line:
            continue

        line = re.sub(r"^\s*(?:[-*•]+|#{1,6}\s*)", "", line).strip()
        if not line:
            continue

        if re.match(r"^(?:场景名称|名称|场景描述|描述|简介|设计思路|设计说明|说明|解释)\s*[:：]", line, flags=re.IGNORECASE):
            continue

        dim_name, inline_desc = _extract_generated_dimension_header(line)
        if dim_name:
            _flush_dimension()
            current_block = {
                "name": dim_name,
                "description": inline_desc,
                "key_aspects": [],
            }
            continue

        if not current_block:
            continue

        aspects_match = re.match(
            r"^(?:关键点|关键方面|要点|关注点|Key Aspects?)\s*[:：]\s*(.+)$",
            line,
            flags=re.IGNORECASE,
        )
        if aspects_match:
            current_block["key_aspects"].extend(_split_generated_scenario_aspects(aspects_match.group(1)))
            continue

        desc_match = re.match(
            r"^(?:描述|说明|关注|重点|目的)\s*[:：]\s*(.+)$",
            line,
            flags=re.IGNORECASE,
        )
        if desc_match:
            detail = str(desc_match.group(1) or "").strip()
            if detail:
                merged = "；".join([part for part in [current_block.get("description", ""), detail] if part])
                current_block["description"] = merged[:120]
            continue

        if not current_block.get("description"):
            current_block["description"] = line[:120]
        else:
            current_block["key_aspects"].extend(_split_generated_scenario_aspects(line))

    _flush_dimension()

    raw_dimensions: object = dimension_blocks or inline_dimensions
    if not name or not raw_dimensions:
        return None

    payload = {
        "name": name,
        "description": description,
        "dimensions": raw_dimensions,
    }
    if explanation:
        payload["explanation"] = explanation
    return payload


def normalize_generated_scenario_payload(generated: dict) -> Optional[dict]:
    if not isinstance(generated, dict):
        return None

    name = _pick_generated_scenario_text_value(
        generated,
        ["name", "scenario_name", "scene_name", "title", "label", "场景名称", "名称"],
    )
    if not name:
        return None

    description = _pick_generated_scenario_text_value(
        generated,
        ["description", "desc", "summary", "scene_description", "场景描述", "描述", "简介"],
    )
    raw_dimensions = (
        generated.get("dimensions")
        or generated.get("dimension_list")
        or generated.get("dims")
        or generated.get("dimensionList")
        or generated.get("访谈维度")
        or []
    )
    if isinstance(raw_dimensions, dict):
        raw_dimensions = list(raw_dimensions.values())
    if isinstance(raw_dimensions, str):
        raw_dimensions = [
            item.strip(" -•·\t")
            for item in re.split(r"[,，、/;\n]+", raw_dimensions)
            if item.strip(" -•·\t")
        ]
    if not isinstance(raw_dimensions, list):
        raw_dimensions = []

    normalized_dimensions = []
    for index, raw_dim in enumerate(raw_dimensions, start=1):
        normalized_dim = _build_generated_dimension_payload(raw_dim, index)
        if normalized_dim:
            normalized_dimensions.append(normalized_dim)

    if not normalized_dimensions:
        return None

    normalized = {
        "name": name[:32],
        "description": description[:120],
        "dimensions": normalized_dimensions,
    }
    explanation = _pick_generated_scenario_text_value(
        generated,
        ["explanation", "design_thinking", "rationale", "设计思路", "设计说明", "说明"],
    )
    if explanation:
        normalized["explanation"] = explanation[:240]
    return normalized


