def _infer_scenario_generation_fallback_profile(user_description: str) -> str:
    text = str(user_description or "").lower()
    if any(keyword in text for keyword in ("评分", "打分", "评估", "评审", "比较", "对比", "风格", "偏好", "审美")):
        return "evaluation"
    if any(keyword in text for keyword in ("创建", "方案", "项目", "计划", "建设", "实施", "落地", "设计")):
        return "creation"
    return "generic"


def _build_generated_scenario_local_fallback(user_description: str) -> Optional[dict]:
    topic_text = str(user_description or "").strip()
    if not topic_text:
        return None

    primary_line = re.split(r"[。！？!?；;\n]+", topic_text, maxsplit=1)[0].strip()
    prefix_tokens = [
        "我想做一个", "我想做一套", "我想做个", "我想创建一个", "我想生成一个",
        "我想要", "我想做", "我想", "想要", "需要", "请帮我", "帮我",
        "请生成", "生成", "请创建", "创建", "做一个", "做一套", "做个", "做",
    ]
    changed = True
    while changed and primary_line:
        changed = False
        for token in prefix_tokens:
            if primary_line.startswith(token):
                primary_line = primary_line[len(token):].lstrip()
                changed = True
                break
    primary_line = re.sub(r"^(一个|一套|个)\s*", "", primary_line).strip()
    primary_line = re.sub(r"(的访谈场景|访谈场景|调研场景|访谈提纲|调研提纲|访谈|调研)$", "", primary_line).strip("，,。 ")
    if len(primary_line) > 12:
        primary_line = primary_line[:12].rstrip("，,。 ")
    name = primary_line or "通用访谈"

    profile = _infer_scenario_generation_fallback_profile(topic_text)
    preset = SCENARIO_GENERATION_FALLBACK_PRESETS.get(profile) or SCENARIO_GENERATION_FALLBACK_PRESETS["generic"]
    dimensions = []
    for index, (dim_name, dim_desc, key_aspects) in enumerate(preset, start=1):
        dimensions.append({
            "id": f"dim_{index}",
            "name": dim_name,
            "description": dim_desc,
            "key_aspects": list(key_aspects[:4]),
            "min_questions": 2,
            "max_questions": 4,
        })

    return {
        "name": name,
        "description": f"根据主题「{topic_text[:40]}」自动生成的初始访谈场景，可继续编辑调整。",
        "dimensions": dimensions,
        "explanation": "AI 返回结构异常，已根据主题生成可编辑草案，你可以继续调整维度和方案目录。",
    }


def parse_scenario_recognition_response(raw_text: str, valid_scenario_ids: set) -> Optional[dict]:
    """解析场景识别结果，支持 JSON 与半结构化兜底提取。"""
    try:
        parsed = parse_json_object_response(raw_text, required_keys=["scenario_id"])
        scenario_id = str(parsed.get("scenario_id", "")).strip()
        if scenario_id not in valid_scenario_ids:
            return None
        confidence = parsed.get("confidence", 0.8)
        try:
            confidence = float(confidence)
        except Exception:
            confidence = 0.8
        confidence = min(1.0, max(0.0, confidence))
        reason = str(parsed.get("reason", "") or "").strip()
        return {
            "scenario_id": scenario_id,
            "confidence": confidence,
            "reason": reason
        }
    except Exception:
        pass

    # 兜底：常见截断场景（如 reason 未闭合）时，尽量提取 scenario_id/confidence
    sid_match = re.search(r'"scenario_id"\s*:\s*"([^"]+)"', raw_text or "")
    if not sid_match:
        return None

    scenario_id = sid_match.group(1).strip()
    if scenario_id not in valid_scenario_ids:
        return None

    confidence = 0.8
    conf_match = re.search(r'"confidence"\s*:\s*([0-9]+(?:\.[0-9]+)?)', raw_text or "")
    if conf_match:
        try:
            confidence = float(conf_match.group(1))
        except Exception:
            confidence = 0.8
    confidence = min(1.0, max(0.0, confidence))

    reason = ""
    reason_match = re.search(r'"reason"\s*:\s*"([^"]*)"', raw_text or "")
    if reason_match:
        reason = reason_match.group(1).strip()

    return {
        "scenario_id": scenario_id,
        "confidence": confidence,
        "reason": reason
    }


def get_utc_now() -> str:
    return datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")


def generate_session_id() -> str:
    timestamp = datetime.now().strftime("%Y%m%d%H%M%S")
    random_suffix = secrets.token_hex(4)
    return f"dv-{timestamp}-{random_suffix}"


INSTANCE_SCOPE_FIELD = "instance_scope_key"


def normalize_instance_scope_key(raw_scope: object) -> str:
    value = str(raw_scope or "").strip().lower()
    if not value:
        return ""
    value = re.sub(r"[^a-z0-9._/-]+", "-", value)
    value = value.strip("-._/")
    value = value.replace("/", "--")
    return value[:96]


def get_active_instance_scope_key() -> str:
    return normalize_instance_scope_key(INSTANCE_SCOPE_KEY)


def get_instance_scope_short_tag() -> str:
    scope_key = get_active_instance_scope_key()
    if not scope_key:
        return ""
    return hashlib.sha1(scope_key.encode("utf-8")).hexdigest()[:8]


def get_record_instance_scope_key(raw_scope: object) -> str:
    return normalize_instance_scope_key(raw_scope)


def is_instance_scope_enforced() -> bool:
    return bool(INSTANCE_SCOPE_ENFORCEMENT_ENABLED)


def is_instance_scope_visible(record_scope: object, expected_scope: Optional[str] = None) -> bool:
    if not is_instance_scope_enforced():
        return True
    current_scope = normalize_instance_scope_key(
        get_active_instance_scope_key() if expected_scope is None else expected_scope
    )
    normalized_record_scope = get_record_instance_scope_key(record_scope)
    if current_scope:
        return normalized_record_scope == current_scope
    return normalized_record_scope == ""


def is_same_instance_scope(record_scope: object, expected_scope: object) -> bool:
    if not is_instance_scope_enforced():
        return True
    return get_record_instance_scope_key(record_scope) == get_record_instance_scope_key(expected_scope)


def get_session_instance_scope_key(session: dict) -> str:
    if not isinstance(session, dict):
        return ""
    return get_record_instance_scope_key(session.get(INSTANCE_SCOPE_FIELD))


def _use_postgres_shared_meta_storage() -> bool:
    return is_postgres_dsn(get_meta_index_db_target())


def load_report_scopes() -> dict:
    if _use_postgres_shared_meta_storage():
        rows = []
        try:
            with get_meta_index_connection() as conn:
                rows = conn.execute(
                    """
                    SELECT file_name, instance_scope_key
                    FROM report_meta_scopes
                    """
                ).fetchall()
        except Exception:
            rows = []

        normalized = {}
        for row in rows:
            name = str(row["file_name"] or "").strip()
            scope_key = normalize_instance_scope_key(row["instance_scope_key"])
            if not name or not scope_key:
                continue
            normalized[name] = scope_key
        record_list_cache_metric("report_scope", hit=False)
        return normalized

    with REPORT_SCOPES_LOCK:
        signature = get_file_signature(REPORT_SCOPES_FILE)
        cached_signature = report_scopes_cache.get("signature")
        cached_data = report_scopes_cache.get("data")
        if signature == cached_signature and isinstance(cached_data, dict):
            record_list_cache_metric("report_scope", hit=True)
            return dict(cached_data)

        record_list_cache_metric("report_scope", hit=False)
        if signature is None:
            report_scopes_cache["signature"] = None
            report_scopes_cache["data"] = {}
            return {}

        normalized = {}
        try:
            payload = json.loads(REPORT_SCOPES_FILE.read_text(encoding="utf-8"))
            if isinstance(payload, dict):
                for name, scope_key in payload.items():
                    if not isinstance(name, str):
                        continue
                    normalized_scope = normalize_instance_scope_key(scope_key)
                    if not normalized_scope:
                        continue
                    normalized[name] = normalized_scope
        except Exception:
            normalized = {}

        report_scopes_cache["signature"] = signature
        report_scopes_cache["data"] = dict(normalized)
        return dict(normalized)


def save_report_scopes(data: dict) -> None:
    normalized = {}
    if isinstance(data, dict):
        for name, scope_key in data.items():
            if not isinstance(name, str):
                continue
            normalized_scope = normalize_instance_scope_key(scope_key)
            if not normalized_scope:
                continue
            normalized[name] = normalized_scope

    if _use_postgres_shared_meta_storage():
        with get_meta_index_connection() as conn:
            conn.execute("DELETE FROM report_meta_scopes")
            if normalized:
                conn.executemany(
                    """
                    INSERT INTO report_meta_scopes(file_name, instance_scope_key, updated_at)
                    VALUES (?, ?, ?)
                    """,
                    [
                        (name, scope_key, get_utc_now())
                        for name, scope_key in normalized.items()
                    ],
                )
        with REPORT_SCOPES_LOCK:
            report_scopes_cache["signature"] = None
            report_scopes_cache["data"] = {}
        return

    with REPORT_SCOPES_LOCK:
        _write_json_atomic(REPORT_SCOPES_FILE, normalized)
        report_scopes_cache["signature"] = get_file_signature(REPORT_SCOPES_FILE)
        report_scopes_cache["data"] = dict(normalized)


def get_report_scope_key(filename: str) -> str:
    scopes = load_report_scopes()
    return get_record_instance_scope_key(scopes.get(filename, ""))


def set_report_scope_key(filename: str, scope_key: object) -> None:
    name = str(filename or "").strip()
    if not name:
        return

    normalized_scope = normalize_instance_scope_key(scope_key)
    if _use_postgres_shared_meta_storage():
        with get_meta_index_connection() as conn:
            if normalized_scope:
                conn.execute(
                    """
                    INSERT INTO report_meta_scopes(file_name, instance_scope_key, updated_at)
                    VALUES (?, ?, ?)
                    ON CONFLICT(file_name) DO UPDATE SET
                        instance_scope_key=excluded.instance_scope_key,
                        updated_at=excluded.updated_at
                    """,
                    (name, normalized_scope, get_utc_now()),
                )
            else:
                conn.execute("DELETE FROM report_meta_scopes WHERE file_name = ?", (name,))
        with REPORT_SCOPES_LOCK:
            report_scopes_cache["signature"] = None
            report_scopes_cache["data"] = {}
        return

    with REPORT_SCOPES_LOCK:
        with named_file_lock("sidecar", "report_scopes"):
            scopes = load_report_scopes()
            if normalized_scope:
                scopes[name] = normalized_scope
            else:
                scopes.pop(name, None)
            save_report_scopes(scopes)


def normalize_solution_share_token(raw_token: object) -> str:
    token = str(raw_token or "").strip()
    if not token:
        return ""
    if not re.fullmatch(r"[A-Za-z0-9_-]{16,160}", token):
        return ""
    return token


def load_solution_share_map() -> dict:
    if _use_postgres_shared_meta_storage():
        rows = []
        try:
            with get_meta_index_connection() as conn:
                rows = conn.execute(
                    """
                    SELECT share_token, report_name, owner_user_id, created_at, updated_at
                    FROM report_meta_solution_shares
                    """
                ).fetchall()
        except Exception:
            rows = []

        normalized = {}
        for row in rows:
            token = normalize_solution_share_token(row["share_token"])
            report_name = normalize_solution_report_filename(row["report_name"])
            owner_user_id = _safe_int(row["owner_user_id"], 0)
            if not token or not report_name or owner_user_id <= 0:
                continue
            normalized[token] = {
                "report_name": report_name,
                "owner_user_id": owner_user_id,
                "created_at": str(row["created_at"] or ""),
                "updated_at": str(row["updated_at"] or ""),
            }
        return normalized

    with REPORT_SOLUTION_SHARES_LOCK:
        signature = get_file_signature(REPORT_SOLUTION_SHARES_FILE)
        cached_signature = report_solution_shares_cache.get("signature")
        cached_data = report_solution_shares_cache.get("data")
        if signature is not None and signature == cached_signature and isinstance(cached_data, dict):
            return copy.deepcopy(cached_data)

        if signature is None:
            report_solution_shares_cache["signature"] = None
            report_solution_shares_cache["data"] = {}
            return {}

        normalized = {}
        try:
            payload = json.loads(REPORT_SOLUTION_SHARES_FILE.read_text(encoding="utf-8"))
            if isinstance(payload, dict):
                for raw_token, raw_record in payload.items():
                    token = normalize_solution_share_token(raw_token)
                    if not token or not isinstance(raw_record, dict):
                        continue
                    report_name = normalize_solution_report_filename(raw_record.get("report_name"))
                    if not report_name:
                        continue
                    try:
                        owner_user_id = int(raw_record.get("owner_user_id", 0))
                    except (TypeError, ValueError):
                        owner_user_id = 0
                    if owner_user_id <= 0:
                        continue
                    normalized[token] = {
                        "report_name": report_name,
                        "owner_user_id": owner_user_id,
                        "created_at": str(raw_record.get("created_at") or ""),
                        "updated_at": str(raw_record.get("updated_at") or ""),
                    }
        except Exception:
            normalized = {}

        report_solution_shares_cache["signature"] = signature
        report_solution_shares_cache["data"] = dict(normalized)
        return copy.deepcopy(normalized)


def save_solution_share_map(data: dict) -> None:
    normalized = {}
    if isinstance(data, dict):
        for raw_token, raw_record in data.items():
            token = normalize_solution_share_token(raw_token)
            if not token or not isinstance(raw_record, dict):
                continue
            report_name = normalize_solution_report_filename(raw_record.get("report_name"))
            if not report_name:
                continue
            try:
                owner_user_id = int(raw_record.get("owner_user_id", 0))
            except (TypeError, ValueError):
                owner_user_id = 0
            if owner_user_id <= 0:
                continue
            normalized[token] = {
                "report_name": report_name,
                "owner_user_id": owner_user_id,
                "created_at": str(raw_record.get("created_at") or ""),
                "updated_at": str(raw_record.get("updated_at") or ""),
            }

    if _use_postgres_shared_meta_storage():
        with get_meta_index_connection() as conn:
            conn.execute("DELETE FROM report_meta_solution_shares")
            if normalized:
                conn.executemany(
                    """
                    INSERT INTO report_meta_solution_shares(
                        share_token, report_name, owner_user_id, created_at, updated_at
                    ) VALUES (?, ?, ?, ?, ?)
                    """,
                    [
                        (
                            token,
                            record["report_name"],
                            int(record["owner_user_id"]),
                            str(record["created_at"] or ""),
                            str(record["updated_at"] or ""),
                        )
                        for token, record in normalized.items()
                    ],
                )
        with REPORT_SOLUTION_SHARES_LOCK:
            report_solution_shares_cache["signature"] = None
            report_solution_shares_cache["data"] = {}
        return

    with REPORT_SOLUTION_SHARES_LOCK:
        _write_json_atomic(REPORT_SOLUTION_SHARES_FILE, normalized)
        report_solution_shares_cache["signature"] = get_file_signature(REPORT_SOLUTION_SHARES_FILE)
        report_solution_shares_cache["data"] = dict(normalized)


def get_solution_share_record(token: str) -> Optional[dict]:
    normalized_token = normalize_solution_share_token(token)
    if not normalized_token:
        return None
    record = load_solution_share_map().get(normalized_token)
    if not isinstance(record, dict):
        return None
    result = copy.deepcopy(record)
    result["share_token"] = normalized_token
    return result


def create_or_get_solution_share(report_name: str, owner_user_id: int) -> dict:
    normalized_report_name = normalize_solution_report_filename(report_name)
    owner_id = int(owner_user_id)
    if not normalized_report_name or owner_id <= 0:
        raise ValueError("分享参数无效")

    if _use_postgres_shared_meta_storage():
        created_payload = None
        with get_meta_index_connection() as conn:
            existing = conn.execute(
                """
                SELECT share_token, created_at, updated_at
                FROM report_meta_solution_shares
                WHERE report_name = ? AND owner_user_id = ?
                LIMIT 1
                """,
                (normalized_report_name, owner_id),
            ).fetchone()
            if existing:
                return {
                    "share_token": str(existing["share_token"] or ""),
                    "report_name": normalized_report_name,
                    "owner_user_id": owner_id,
                    "created_at": str(existing["created_at"] or ""),
                    "updated_at": str(existing["updated_at"] or ""),
                }

            created_at = get_utc_now()
            for _attempt in range(8):
                share_token = normalize_solution_share_token(secrets.token_urlsafe(24))
                if not share_token:
                    continue
                try:
                    conn.execute(
                        """
                        INSERT INTO report_meta_solution_shares(
                            share_token, report_name, owner_user_id, created_at, updated_at
                        ) VALUES (?, ?, ?, ?, ?)
                        """,
                        (share_token, normalized_report_name, owner_id, created_at, created_at),
                    )
                    created_payload = {
                        "share_token": share_token,
                        "report_name": normalized_report_name,
                        "owner_user_id": owner_id,
                        "created_at": created_at,
                        "updated_at": created_at,
                    }
                    break
                except Exception:
                    continue
        if isinstance(created_payload, dict):
            return created_payload
        raise RuntimeError("生成分享链接失败，请稍后重试")

    with named_file_lock("sidecar", "solution_shares"):
        with REPORT_SOLUTION_SHARES_LOCK:
            shares = load_solution_share_map()
            for token, record in shares.items():
                if not isinstance(record, dict):
                    continue
                if record.get("report_name") != normalized_report_name:
                    continue
                if int(record.get("owner_user_id", 0) or 0) != owner_id:
                    continue
                result = copy.deepcopy(record)
                result["share_token"] = token
                return result

            created_at = get_utc_now()
            share_token = ""
            while not share_token or share_token in shares:
                share_token = normalize_solution_share_token(secrets.token_urlsafe(24))
            record = {
                "report_name": normalized_report_name,
                "owner_user_id": owner_id,
                "created_at": created_at,
                "updated_at": created_at,
            }
            shares[share_token] = record
            save_solution_share_map(shares)
            result = copy.deepcopy(record)
            result["share_token"] = share_token
            return result


def delete_solution_shares_for_report(report_name: str) -> None:
    normalized_report_name = normalize_solution_report_filename(report_name)
    if not normalized_report_name:
        return

    if _use_postgres_shared_meta_storage():
        with get_meta_index_connection() as conn:
            conn.execute(
                "DELETE FROM report_meta_solution_shares WHERE report_name = ?",
                (normalized_report_name,),
            )
        with REPORT_SOLUTION_SHARES_LOCK:
            report_solution_shares_cache["signature"] = None
            report_solution_shares_cache["data"] = {}
        return

    with named_file_lock("sidecar", "solution_shares"):
        with REPORT_SOLUTION_SHARES_LOCK:
            shares = load_solution_share_map()
            mutated = False
            for token in list(shares.keys()):
                record = shares.get(token, {})
                if isinstance(record, dict) and record.get("report_name") == normalized_report_name:
                    shares.pop(token, None)
                    mutated = True
            if mutated:
                save_solution_share_map(shares)


def build_solution_share_url(share_token: str) -> str:
    normalized_token = normalize_solution_share_token(share_token)
    if not normalized_token:
        return ""
    base_url = url_for("static_files", filename="solution.html", _external=True)
    separator = "&" if "?" in base_url else "?"
    return f"{base_url}{separator}share={quote(normalized_token)}"


def get_deleted_reports() -> set:
    """获取已删除报告的列表"""
    if _use_postgres_shared_meta_storage():
        try:
            with get_meta_index_connection() as conn:
                rows = conn.execute(
                    """
                    SELECT file_name
                    FROM report_meta_deleted_reports
                    """
                ).fetchall()
        except Exception:
            return set()
        return {
            str(row["file_name"] or "").strip()
            for row in rows
            if str(row["file_name"] or "").strip()
        }

    if not DELETED_REPORTS_FILE.exists():
        return set()
    try:
        data = json.loads(DELETED_REPORTS_FILE.read_text(encoding="utf-8"))
        return set(data.get("deleted", []))
    except Exception:
        return set()


def load_report_owners() -> dict:
    if _use_postgres_shared_meta_storage():
        rows = []
        try:
            with get_meta_index_connection() as conn:
                rows = conn.execute(
                    """
                    SELECT file_name, owner_user_id
                    FROM report_meta_owners
                    """
                ).fetchall()
        except Exception:
            rows = []

        normalized = {}
        for row in rows:
            name = str(row["file_name"] or "").strip()
            owner_id = _safe_int(row["owner_user_id"], 0)
            if not name or owner_id <= 0:
                continue
            normalized[name] = owner_id
        record_list_cache_metric("report_owner", hit=False)
        return normalized

    with REPORT_OWNERS_LOCK:
        signature = get_file_signature(REPORT_OWNERS_FILE)
        cached_signature = report_owners_cache.get("signature")
        cached_data = report_owners_cache.get("data")
        if signature == cached_signature and isinstance(cached_data, dict):
            record_list_cache_metric("report_owner", hit=True)
            return dict(cached_data)

        record_list_cache_metric("report_owner", hit=False)
        if signature is None:
            report_owners_cache["signature"] = None
            report_owners_cache["data"] = {}
            return {}

        normalized = {}
        try:
            payload = json.loads(REPORT_OWNERS_FILE.read_text(encoding="utf-8"))
            if isinstance(payload, dict):
                for name, owner in payload.items():
                    if not isinstance(name, str):
                        continue
                    try:
                        owner_id = int(owner)
                    except (TypeError, ValueError):
                        continue
                    if owner_id <= 0:
                        continue
                    normalized[name] = owner_id
        except Exception:
            normalized = {}

        report_owners_cache["signature"] = signature
        report_owners_cache["data"] = dict(normalized)
        return dict(normalized)


def save_report_owners(data: dict) -> None:
    normalized = {}
    if isinstance(data, dict):
        for name, owner in data.items():
            if not isinstance(name, str):
                continue
            try:
                owner_id = int(owner)
            except (TypeError, ValueError):
                continue
            if owner_id <= 0:
                continue
            normalized[name] = owner_id

    if _use_postgres_shared_meta_storage():
        with get_meta_index_connection() as conn:
            conn.execute("DELETE FROM report_meta_owners")
            if normalized:
                conn.executemany(
                    """
                    INSERT INTO report_meta_owners(file_name, owner_user_id, updated_at)
                    VALUES (?, ?, ?)
                    """,
                    [
                        (name, int(owner_id), get_utc_now())
                        for name, owner_id in normalized.items()
                    ],
                )
        with REPORT_OWNERS_LOCK:
            report_owners_cache["signature"] = None
            report_owners_cache["data"] = {}
        return

    with REPORT_OWNERS_LOCK:
        _write_json_atomic(REPORT_OWNERS_FILE, normalized)
        report_owners_cache["signature"] = get_file_signature(REPORT_OWNERS_FILE)
        report_owners_cache["data"] = dict(normalized)


def get_report_owner_id(filename: str) -> int:
    owners = load_report_owners()
    try:
        return int(owners.get(filename, 0))
    except (TypeError, ValueError):
        return 0


def set_report_owner_id(filename: str, owner_user_id: int) -> None:
    owner_id = int(owner_user_id)
    if _use_postgres_shared_meta_storage():
        with get_meta_index_connection() as conn:
            conn.execute(
                """
                INSERT INTO report_meta_owners(file_name, owner_user_id, updated_at)
                VALUES (?, ?, ?)
                ON CONFLICT(file_name) DO UPDATE SET
                    owner_user_id=excluded.owner_user_id,
                    updated_at=excluded.updated_at
                """,
                (filename, owner_id, get_utc_now()),
            )
        with REPORT_OWNERS_LOCK:
            report_owners_cache["signature"] = None
            report_owners_cache["data"] = {}
    else:
        with REPORT_OWNERS_LOCK:
            with named_file_lock("sidecar", "report_owners"):
                owners = load_report_owners()
                owners[filename] = owner_id
                save_report_owners(owners)
    set_report_scope_key(filename, get_active_instance_scope_key())
    try:
        sync_report_index_for_filename(filename, owner_user_id=owner_id)
    except Exception as exc:
        if ENABLE_DEBUG_LOG:
            _safe_log(f"⚠️ 同步 report_index 失败: {filename}, 错误: {exc}")


def ensure_report_owner(filename: str, owner_user_id: int) -> bool:
    owner = get_report_owner_id(filename)
    owner_id = int(owner_user_id)
    # 禁止自动认领无归属历史数据，需通过迁移脚本显式迁移
    if owner <= 0:
        return False
    if owner != owner_id:
        return False
    return is_instance_scope_visible(get_report_scope_key(filename))


def is_session_owned_by_user(session: dict, user_id: int) -> bool:
    if not isinstance(session, dict):
        return False
    owner = session.get("owner_user_id")
    try:
        owner_id = int(owner)
    except (TypeError, ValueError):
        return False
    return owner_id == int(user_id)


def ensure_session_owner(session: dict, user_id: int) -> bool:
    if not isinstance(session, dict):
        return False

    current_owner = session.get("owner_user_id")
    try:
        owner_id = int(current_owner)
    except (TypeError, ValueError):
        owner_id = 0

    # 禁止自动认领无归属历史数据，需通过迁移脚本显式迁移
    if owner_id <= 0:
        return False
    if owner_id != int(user_id):
        return False
    return is_instance_scope_visible(get_session_instance_scope_key(session))


def get_current_user_id_or_none() -> Optional[int]:
    user = get_current_user()
    if not user:
        return None
    try:
        return int(user["id"])
    except (TypeError, ValueError, KeyError):
        return None


def load_session_for_user(session_id: str, user_id: int, include_missing: bool = False):
    session_file = SESSIONS_DIR / f"{session_id}.json"
    session_data = safe_load_session(session_file)
    if session_data is None:
        if session_file.exists() and not _use_pure_cloud_session_storage():
            return None, "会话数据损坏", 500
        if include_missing:
            return None, None, "not_found"
        return None, "会话不存在", 404

    if not isinstance(session_data, dict):
        return None, "会话数据损坏", 500

    if not ensure_session_owner(session_data, user_id):
        return None, "会话不存在", 404

    if include_missing:
        return session_file, session_data, "ok"
    return session_file, session_data


def enforce_report_owner_or_404(filename: str, user_id: int) -> tuple[Optional[Path], Optional[tuple]]:
    normalized_name = normalize_solution_report_filename(filename)
    if not normalized_name or not _report_exists(normalized_name):
        return None, (jsonify({"error": "报告不存在"}), 404)

    if not ensure_report_owner(normalized_name, user_id):
        return None, (jsonify({"error": "报告不存在"}), 404)

    return REPORTS_DIR / normalized_name, None


def mark_report_as_deleted(filename: str):
    """标记报告为已删除（不真正删除文件）"""
    if _use_postgres_shared_meta_storage():
        with get_meta_index_connection() as conn:
            conn.execute(
                """
                INSERT INTO report_meta_deleted_reports(file_name, deleted_at)
                VALUES (?, ?)
                ON CONFLICT(file_name) DO UPDATE SET
                    deleted_at=excluded.deleted_at
                """,
                (str(filename or "").strip(), get_utc_now()),
            )
    else:
        with named_file_lock("sidecar", "deleted_reports"):
            deleted = get_deleted_reports()
            deleted.add(filename)
            _write_json_atomic(DELETED_REPORTS_FILE, {"deleted": sorted(deleted)})
    try:
        sync_report_index_for_filename(filename, deleted=True)
    except Exception as exc:
        if ENABLE_DEBUG_LOG:
            _safe_log(f"⚠️ 标记 report_index 删除失败: {filename}, 错误: {exc}")


def unmark_report_as_deleted(filename: str) -> None:
    """取消报告删除标记，用于重新生成后恢复可见性。"""
    name = str(filename or "").strip()
    if not name:
        return

    if _use_postgres_shared_meta_storage():
        with get_meta_index_connection() as conn:
            conn.execute("DELETE FROM report_meta_deleted_reports WHERE file_name = ?", (name,))
    else:
        with named_file_lock("sidecar", "deleted_reports"):
            deleted = get_deleted_reports()
            if name not in deleted:
                return

            deleted.discard(name)
            _write_json_atomic(DELETED_REPORTS_FILE, {"deleted": sorted(deleted)})
    try:
        sync_report_index_for_filename(name, deleted=False)
    except Exception as exc:
        if ENABLE_DEBUG_LOG:
            _safe_log(f"⚠️ 恢复 report_index 可见性失败: {name}, 错误: {exc}")


def normalize_topic_slug(topic: str) -> str:
    """按报告命名规则生成主题 slug。"""
    if not isinstance(topic, str):
        return ""
    topic = topic.strip()
    if not topic:
        return ""
    topic = re.sub(r"\s+", "-", topic)
    topic = sanitize_filename(topic).strip().strip(".")
    topic = re.sub(r"-{2,}", "-", topic)
    return topic[:30]


def build_session_report_filename(session: dict, now: Optional[datetime] = None) -> str:
    if not isinstance(session, dict):
        raise ValueError("session 无效")

    date_value = now if isinstance(now, datetime) else datetime.now()
    date_str = date_value.strftime("%Y%m%d")
    topic_slug = normalize_topic_slug(session.get("topic", "")) or "report"
    session_token = sanitize_filename(str(session.get("session_id") or "").strip()).replace(".", "-")
    if not session_token:
        raise ValueError("session_id 无效，无法生成报告文件名")

    parts = ["intus", date_str]
    scope_tag = get_instance_scope_short_tag()
    if scope_tag:
        parts.append(scope_tag)
    parts.append(session_token)
    parts.append(topic_slug)
    return "-".join(parts) + ".md"


def build_report_variant_filename(source_report_name: str, report_profile: str) -> str:
    normalized_source = normalize_solution_report_filename(source_report_name)
    normalized_profile = normalize_report_profile_choice(report_profile, fallback="")
    if not normalized_source or normalized_profile != "quality":
        return normalized_source
    source_path = Path(normalized_source)
    stem = source_path.stem
    if not stem.endswith("-quality"):
        stem = f"{stem}-quality"
    return f"{stem}{source_path.suffix or '.md'}"


def get_session_total_progress(session: dict) -> int:
    """计算会话总进度（各维度覆盖率平均值）。"""
    dimensions = session.get("dimensions")
    if not isinstance(dimensions, dict) or not dimensions:
        return 0

    values = []
    for value in dimensions.values():
        if not isinstance(value, dict):
            continue
        coverage = value.get("coverage", 0)
        try:
            coverage_value = int(coverage)
        except Exception:
            coverage_value = 0
        values.append(max(0, min(100, coverage_value)))

    if not values:
        return 0
    return round(sum(values) / len(values))


def get_effective_session_status(session: dict) -> str:
    """统一会话状态口径（与前端保持一致）。"""
    raw = session.get("status") or "in_progress"
    progress = get_session_total_progress(session)
    if raw == "in_progress" and progress >= 100:
        return "pending_review"
    return raw


def find_reports_by_session_topic(session: dict) -> list:
    """根据会话主题匹配同归属的关联报告文件。"""
    if not isinstance(session, dict):
        return []

    topic_slug = normalize_topic_slug(session.get("topic", ""))
    if not topic_slug:
        return []

    try:
        owner_user_id = int(session.get("owner_user_id"))
    except (TypeError, ValueError):
        return []
    if owner_user_id <= 0:
        return []

    suffix = f"-{topic_slug}.md"
    matched = []
    for report_name, report_owner_id in load_report_owners().items():
        if report_owner_id != owner_user_id:
            continue
        if not report_name.endswith(suffix):
            continue
        if not is_same_instance_scope(get_report_scope_key(report_name), get_session_instance_scope_key(session)):
            continue
        if not _report_exists(report_name):
            continue
        matched.append(report_name)
    return matched


def is_report_bound_to_session(filename: str, session: dict, user_id: int) -> bool:
    """校验报告是否可作为当前会话的绑定报告。"""
    name = str(filename or "").strip()
    if not name or not name.endswith(".md"):
        return False

    if not _report_exists(name):
        return False

    try:
        owner_user_id = int(user_id)
    except (TypeError, ValueError):
        return False

    if owner_user_id <= 0:
        return False
    if get_report_owner_id(name) != owner_user_id:
        return False
    if not is_same_instance_scope(get_report_scope_key(name), get_session_instance_scope_key(session)):
        return False
    return True


def resolve_session_bound_report_name(session: dict, user_id: int) -> str:
    """解析会话当前应复用的报告文件名。"""
    if not isinstance(session, dict):
        return ""

    direct_candidates = []
    current_report_name = str(session.get("current_report_name") or "").strip()
    if current_report_name:
        direct_candidates.append(current_report_name)

    current_report_path = str(session.get("current_report_path") or "").strip()
    if current_report_path:
        derived_name = Path(current_report_path).name.strip()
        if derived_name and derived_name not in direct_candidates:
            direct_candidates.append(derived_name)

    for report_name in direct_candidates:
        if is_report_bound_to_session(report_name, session, user_id):
            return report_name
    return ""


def get_bound_reports_for_session(session: dict) -> list[str]:
    """汇总会话已绑定的报告名，兼容新旧字段与主题兜底。"""
    if not isinstance(session, dict):
        return []

    try:
        owner_user_id = int(session.get("owner_user_id"))
    except (TypeError, ValueError):
        owner_user_id = 0

    bound_reports: list[str] = []
    seen: set[str] = set()
    direct_candidates: list[str] = []

    current_report_name = str(session.get("current_report_name") or "").strip()
    if current_report_name:
        direct_candidates.append(current_report_name)

    current_report_path = str(session.get("current_report_path") or "").strip()
    if current_report_path:
        derived_name = Path(current_report_path).name.strip()
        if derived_name and derived_name not in direct_candidates:
            direct_candidates.append(derived_name)

    last_report_name = normalize_solution_report_filename(session.get("last_report_name", ""))
    if last_report_name and last_report_name not in direct_candidates:
        direct_candidates.append(last_report_name)

    for report_name in direct_candidates:
        if not _report_exists(report_name):
            continue
        owner_ok = owner_user_id <= 0 or get_report_owner_id(report_name) == owner_user_id
        scope_ok = is_same_instance_scope(get_report_scope_key(report_name), get_session_instance_scope_key(session))
        if not owner_ok or not scope_ok or report_name in seen:
            continue
        bound_reports.append(report_name)
        seen.add(report_name)

    fallback_candidates = [name for name in find_reports_by_session_topic(session) if name not in seen]
    if len(fallback_candidates) == 1:
        bound_reports.append(fallback_candidates[0])
        seen.add(fallback_candidates[0])
    return bound_reports


def unique_non_empty_strings(items) -> list:
    """去重并过滤空字符串。"""
    if not isinstance(items, list):
        return []

    result = []
    seen = set()
    for item in items:
        if not isinstance(item, str):
            continue
        value = item.strip()
        if not value or value in seen:
            continue
        seen.add(value)
        result.append(value)
    return result


def get_deleted_docs() -> dict:
    """获取已删除文档的记录"""
    if _use_postgres_shared_meta_storage():
        try:
            with get_meta_index_connection() as conn:
                rows = conn.execute(
                    """
                    SELECT session_id, doc_name, doc_id, deleted_at
                    FROM report_meta_deleted_docs
                    ORDER BY updated_at DESC
                    """
                ).fetchall()
        except Exception:
            rows = []
        return {
            "reference_materials": [
                {
                    "session_id": str(row["session_id"] or ""),
                    "doc_name": str(row["doc_name"] or ""),
                    "doc_id": str(row["doc_id"] or ""),
                    "deleted_at": str(row["deleted_at"] or ""),
                }
                for row in rows
            ]
        }

    if not DELETED_DOCS_FILE.exists():
        return {"reference_materials": []}
    try:
        data = json.loads(DELETED_DOCS_FILE.read_text(encoding="utf-8"))
        # 兼容旧格式
        materials = data.get("reference_materials", [])
        materials.extend(data.get("reference_docs", []))
        materials.extend(data.get("research_docs", []))
        return {"reference_materials": materials}
    except Exception:
        return {"reference_materials": []}


def build_reference_material_doc_id(doc: dict, index: int = 0) -> str:
    if not isinstance(doc, dict):
        doc = {}
    seed = "|".join([
        str(doc.get("name") or "").strip(),
        str(doc.get("uploaded_at") or "").strip(),
        str(doc.get("source") or "").strip(),
        str(index),
        str(len(str(doc.get("content") or ""))),
    ])
    return hashlib.sha1(seed.encode("utf-8")).hexdigest()[:16]


def ensure_reference_material_doc_ids(materials) -> list:
    normalized = materials if isinstance(materials, list) else []
    for index, doc in enumerate(normalized):
        if not isinstance(doc, dict):
            continue
        if "source" not in doc:
            doc["source"] = "upload"
        if not str(doc.get("doc_id") or "").strip():
            doc["doc_id"] = build_reference_material_doc_id(doc, index=index)
    return normalized


def mark_doc_as_deleted(session_id: str, doc_name: str, doc_type: str = "reference_materials", doc_id: str = ""):
    """标记文档为已删除（软删除）

    Args:
        session_id: 会话 ID
        doc_name: 文档名称
        doc_type: 文档类型（默认 'reference_materials'）
        doc_id: 文档唯一标识
    """
    if _use_postgres_shared_meta_storage():
        sid = str(session_id or "").strip()
        name = str(doc_name or "").strip()
        token = str(doc_id or "").strip()
        if not sid or not name:
            return
        now_iso = get_utc_now()
        with get_meta_index_connection() as conn:
            conn.execute(
                """
                INSERT INTO report_meta_deleted_docs(
                    session_id, doc_name, doc_id, deleted_at, updated_at
                ) VALUES (?, ?, ?, ?, ?)
                ON CONFLICT(session_id, doc_name, doc_id) DO UPDATE SET
                    deleted_at=excluded.deleted_at,
                    updated_at=excluded.updated_at
                """,
                (sid, name, token, now_iso, now_iso),
            )
        return

    with named_file_lock("sidecar", "deleted_docs"):
        deleted = get_deleted_docs()
        record = {
            "session_id": session_id,
            "doc_name": doc_name,
            "doc_id": str(doc_id or "").strip(),
            "deleted_at": get_utc_now()
        }
        if "reference_materials" not in deleted:
            deleted["reference_materials"] = []
        deleted["reference_materials"].append(record)
        _write_json_atomic(DELETED_DOCS_FILE, deleted)


def migrate_session_docs(session: dict) -> dict:
    """迁移旧会话数据：将 reference_docs + research_docs 合并为 reference_materials

    Args:
        session: 会话数据字典

    Returns:
        迁移后的会话数据
    """
    # 如果已经有 reference_materials，检查是否还有旧字段需要迁移
    if "reference_materials" not in session:
        session["reference_materials"] = []

    # 迁移 reference_docs
    if "reference_docs" in session:
        for doc in session["reference_docs"]:
            if "source" not in doc:
                doc["source"] = "upload"
            session["reference_materials"].append(doc)
        del session["reference_docs"]

    # 迁移 research_docs
    if "research_docs" in session:
        for doc in session["research_docs"]:
            if "source" not in doc:
                doc["source"] = "auto"
            session["reference_materials"].append(doc)
        del session["research_docs"]

    session["reference_materials"] = ensure_reference_material_doc_ids(session.get("reference_materials", []))
    return session


# ============ 联网搜索功能 ============

class MCPClient:
    """智谱AI MCP客户端"""

    def __init__(self, api_key: str, base_url: str):
        self.api_key = api_key
        self.base_url = base_url
        self.session_id = None
        self.message_id = 0
        self.initialized = False
        self.available_tools = None

    def _get_next_id(self):
        """获取下一个消息ID"""
        self.message_id += 1
        return self.message_id

    def _build_headers(self) -> dict:
        headers = {
            "Content-Type": "application/json",
            "Accept": "application/json, text/event-stream",
            "Authorization": f"Bearer {self.api_key}"
        }

        if self.session_id:
            headers["Mcp-Session-Id"] = self.session_id

        return headers

    def _build_url(self) -> str:
        parsed = urlparse(self.base_url)
        query_items = dict(parse_qsl(parsed.query, keep_blank_values=True))
        query_items.setdefault("Authorization", self.api_key)
        return urlunparse(parsed._replace(query=urlencode(query_items)))

    def _parse_response_payload(self, response_text: str) -> dict:
        text = str(response_text or "").strip()
        if not text:
            return {}

        try:
            payload = json.loads(text)
            if isinstance(payload, dict):
                return payload
        except Exception:
            pass

        for line in text.splitlines():
            content = line.strip()
            if not content.startswith("data:"):
                continue
            json_str = content[5:].strip()
            if not json_str:
                continue
            try:
                payload = json.loads(json_str)
                if isinstance(payload, dict):
                    return payload
            except Exception:
                continue

        raise Exception(f"无法解析SSE响应: {text[:200]}")

    def _make_request(self, method: str, params: dict = None, expect_response: bool = True):
        """发送MCP JSON-RPC请求"""
        headers = self._build_headers()
        url = self._build_url()

        request_data = {
            "jsonrpc": "2.0",
            "method": method,
            "params": params or {}
        }
        if expect_response:
            request_data["id"] = self._get_next_id()

        if ENABLE_DEBUG_LOG:
            print(f"📤 MCP请求: {method}")
            print(f"   参数: {params}")

        response = requests.post(url, json=request_data, headers=headers, timeout=SEARCH_TIMEOUT)
        response.raise_for_status()

        # 检查响应头中的Session ID
        if "Mcp-Session-Id" in response.headers:
            self.session_id = response.headers["Mcp-Session-Id"]
            if ENABLE_DEBUG_LOG:
                print(f"   📝 获得Session ID: {self.session_id}")

        if not expect_response:
            return {}

        result_data = self._parse_response_payload(response.text)

        if "error" in result_data:
            raise Exception(f"MCP错误: {result_data['error']}")

        return result_data.get("result", {})

    def initialize(self):
        """初始化MCP连接"""
        try:
            result = self._make_request("initialize", {
                "protocolVersion": "2024-11-05",
                "capabilities": {},
                "clientInfo": {
                    "name": "intus",
                    "version": "1.0.0"
                }
            })
            self.initialized = True
            if ENABLE_DEBUG_LOG:
                print(f"✅ MCP初始化成功")
            return result
        except Exception as e:
            if ENABLE_DEBUG_LOG:
                print(f"❌ MCP初始化失败: {e}")
            raise

    def notify_initialized(self):
        """发送 initialized 通知，完成 MCP 握手"""
        try:
            self._make_request("notifications/initialized", {}, expect_response=False)
            if ENABLE_DEBUG_LOG:
                print("✅ MCP initialized 通知已发送")
        except Exception as e:
            if ENABLE_DEBUG_LOG:
                print(f"⚠️  MCP initialized 通知失败，继续尝试后续流程: {e}")

    def ensure_initialized(self):
        """确保 MCP 初始化和通知流程完成"""
        if self.initialized and self.session_id:
            return
        self.initialize()
        self.notify_initialized()

    def list_tools(self, force_refresh: bool = False) -> list:
        """获取 MCP 服务暴露的工具列表"""
        if self.available_tools is not None and not force_refresh:
            return self.available_tools

        self.ensure_initialized()
        result = self._make_request("tools/list", {})
        tools = result.get("tools") or []
        self.available_tools = tools

        if ENABLE_DEBUG_LOG:
            tool_names = [tool.get("name", "") for tool in tools if isinstance(tool, dict)]
            print(f"🧰 MCP可用工具: {tool_names}")

        return tools

    @staticmethod
    def _normalize_tool_name(name: str) -> str:
        return re.sub(r"[^a-z0-9]", "", str(name or "").lower())

    def resolve_tool_name(self, requested_name: str) -> str:
        """根据 tools/list 结果解析真实可用的工具名"""
        tools = self.list_tools()
        tool_names = [tool.get("name", "") for tool in tools if isinstance(tool, dict) and tool.get("name")]

        if not tool_names:
            return requested_name

        if requested_name in tool_names:
            return requested_name

        normalized_requested = self._normalize_tool_name(requested_name)
        exact_matches = [name for name in tool_names if self._normalize_tool_name(name) == normalized_requested]
        if len(exact_matches) == 1:
            return exact_matches[0]

        fuzzy_matches = [
            name for name in tool_names
            if normalized_requested in self._normalize_tool_name(name)
            or self._normalize_tool_name(name) in normalized_requested
        ]
        if len(fuzzy_matches) == 1:
            return fuzzy_matches[0]

        raise Exception(f"MCP工具不存在: {requested_name}，可用工具: {', '.join(tool_names)}")

    def call_tool(self, tool_name: str, arguments: dict):
        """调用MCP工具"""
        try:
            self.ensure_initialized()
            resolved_tool_name = self.resolve_tool_name(tool_name)

            if ENABLE_DEBUG_LOG and resolved_tool_name != tool_name:
                print(f"🔀 MCP工具名自动映射: {tool_name} -> {resolved_tool_name}")

            result = self._make_request("tools/call", {
                "name": resolved_tool_name,
                "arguments": arguments
            })

            return result
        except Exception as e:
            if ENABLE_DEBUG_LOG:
                print(f"❌ 工具调用失败: {e}")
            raise


def web_search(query: str) -> list:
    """使用智谱AI MCP web_search_prime 进行联网搜索"""
    global web_search_active

    if not ENABLE_WEB_SEARCH or not ZHIPU_API_KEY or ZHIPU_API_KEY == "your-zhipu-api-key-here":
        if ENABLE_DEBUG_LOG:
            print(f"⚠️  搜索功能未启用或 API Key 未配置，跳过搜索: {query}")
        return []

    normalized_query = re.sub(r"\s+", " ", str(query or "").strip())
    if not normalized_query:
        return []
    cache_key = _build_search_result_cache_key(normalized_query)

    cached_results = _get_search_result_cache(cache_key)
    if cached_results is not None:
        if ENABLE_DEBUG_LOG:
            print(f"📦 命中搜索结果缓存，跳过 MCP 调用: {normalized_query}")
        _record_cache_hit_metric("web_search_cache_hit")
        return cached_results

    owner_event, is_owner = _begin_search_inflight(cache_key)
    if not is_owner and isinstance(owner_event, threading.Event):
        wait_seconds = float(SEARCH_RESULT_INFLIGHT_WAIT_SECONDS)
        if ENABLE_DEBUG_LOG:
            print(f"⏳ 搜索请求去重生效，等待同查询结果: {normalized_query}")
        owner_event.wait(timeout=wait_seconds)
        cached_after_wait = _get_search_result_cache(cache_key)
        if cached_after_wait is not None:
            if ENABLE_DEBUG_LOG:
                print(f"✅ 复用并发搜索结果: {normalized_query}")
            _record_cache_hit_metric("web_search_cache_hit")
            return cached_after_wait

    is_owner_search = bool(is_owner)
    if not is_owner_search:
        owner_event, is_owner_search = _begin_search_inflight(cache_key)

    try:
        web_search_active = True
        mcp_url = "https://open.bigmodel.cn/api/mcp/web_search_prime/mcp"

        if ENABLE_DEBUG_LOG:
            print(f"🔍 开始MCP搜索: {normalized_query}")

        client = MCPClient(ZHIPU_API_KEY, mcp_url)
        result = client.call_tool("webSearchPrime", {
            "search_query": normalized_query,
            "search_recency_filter": "noLimit",
            "content_size": "medium"
        })

        results = []
        content_list = result.get("content", [])
        for item in content_list:
            if item.get("type") != "text":
                continue
            text = item.get("text", "")
            try:
                import json as json_module
                if text.startswith('"') and text.endswith('"'):
                    text = json_module.loads(text)
                search_data = json_module.loads(text)

                if isinstance(search_data, list):
                    for entry in search_data[:SEARCH_MAX_RESULTS]:
                        title = entry.get("title", "")
                        content = entry.get("content", "")
                        url = entry.get("link", entry.get("url", ""))
                        if title or content:
                            results.append({
                                "type": "result",
                                "title": title[:100] if title else "搜索结果",
                                "content": content[:300],
                                "url": url
                            })
                elif isinstance(search_data, dict):
                    title = search_data.get("title", "")
                    content = search_data.get("content", text[:300])
                    url = search_data.get("link", search_data.get("url", ""))
                    results.append({
                        "type": "result",
                        "title": title[:100] if title else "搜索结果",
                        "content": content[:300],
                        "url": url
                    })
            except Exception as parse_error:
                if ENABLE_DEBUG_LOG:
                    print(f"⚠️  解析搜索结果失败: {parse_error}")
                    print(f"   原始文本前200字符: {text[:200]}")
                results.append({
                    "type": "result",
                    "title": "搜索结果",
                    "content": text[:300],
                    "url": ""
                })

        if ENABLE_DEBUG_LOG:
            print(f"✅ MCP搜索成功，找到 {len(results)} 条结果")

        _set_search_result_cache(cache_key, results)
        return results
    except requests.exceptions.Timeout:
        print(f"⏱️  搜索超时: {normalized_query}")
        return []
    except Exception as e:
        print(f"❌ MCP搜索失败: {e}")
        if ENABLE_DEBUG_LOG:
            import traceback
            traceback.print_exc()
        return []
    finally:
        web_search_active = False
        _end_search_inflight(cache_key, owner_event if is_owner_search else None)


def should_search(topic: str, dimension: str, context: dict) -> bool:
    """
    规则预判：快速判断是否可能需要联网搜索（兜底规则）
    返回 True 表示"可能需要"，后续会交给 AI 做最终判断
    """
    if not ENABLE_WEB_SEARCH:
        return False

    # ========== 扩展的关键词库 ==========

    # 技术关键词
    tech_keywords = [
        "技术", "系统", "平台", "框架", "工具", "软件", "应用", "架构",
        "AI", "人工智能", "机器学习", "深度学习", "大模型", "LLM", "GPT",
        "云", "SaaS", "PaaS", "IaaS", "微服务", "容器", "Docker", "K8s", "Kubernetes",
        "数据库", "中间件", "API", "集成", "部署", "运维", "DevOps",
        "前端", "后端", "全栈", "移动端", "App", "小程序"
    ]

    # 垂直行业关键词（新增）
    industry_keywords = [
        # 医疗健康
        "医院", "医疗", "HIS", "LIS", "PACS", "EMR", "电子病历", "DRG", "医保",
        "诊所", "药房", "处方", "挂号", "门诊", "住院", "护理", "CDSS",
        # 金融
        "银行", "保险", "证券", "基金", "信托", "支付", "清算", "风控",
        "反洗钱", "征信", "资管", "理财", "贷款", "信用卡",
        # 教育
        "学校", "教育", "培训", "课程", "教学", "学生", "考试", "招生",
        "在线教育", "网课", "双减", "新课标",
        # 制造
        "工厂", "制造", "生产", "车间", "MES", "ERP", "PLM", "SCM", "WMS",
        "工业互联网", "智能制造", "数字孪生", "质检", "设备", "产线",
        # 零售电商
        "零售", "电商", "门店", "商城", "订单", "库存", "物流", "配送",
        "会员", "营销", "促销", "CRM", "POS",
        # 政务
        "政府", "政务", "审批", "办事", "公共服务", "智慧城市", "数字政府",
        # 能源
        "电力", "能源", "电网", "新能源", "光伏", "风电", "储能", "充电桩",
        # 交通物流
        "交通", "物流", "运输", "仓储", "TMS", "调度", "车队"
    ]

    # 合规政策关键词（新增）
    compliance_keywords = [
        "合规", "标准", "规范", "认证", "等保", "ISO", "GDPR", "隐私",
        "安全", "审计", "法规", "政策", "监管", "资质", "许可证"
    ]

    # 时效性关键词
    time_sensitive_keywords = [
        "最新", "当前", "现在", "近期", "今年", "明年",
        "2024", "2025", "2026", "2027",
        "趋势", "未来", "发展", "动态", "变化", "更新",
        "市场", "行情", "竞品", "对手", "现状"
    ]

    # 不确定性/专业性关键词（新增）
    uncertainty_keywords = [
        "怎么选", "如何选择", "哪个好", "推荐", "建议", "比较",
        "最佳实践", "业界", "头部", "领先", "主流", "标杆"
    ]

    all_keywords = (tech_keywords + industry_keywords + compliance_keywords +
                   time_sensitive_keywords + uncertainty_keywords)

    # 如果主题包含任何关键词，标记为"可能需要搜索"
    for keyword in all_keywords:
        if keyword.lower() in topic.lower():
            return True

    # 技术约束维度通常需要搜索
    if dimension == "tech_constraints":
        return True

    return False


def ai_evaluate_search_need(topic: str, dimension: str, context: dict, recent_qa: list) -> dict:
    """
    AI 自主判断：让 AI 评估是否需要联网搜索
    返回: { "need_search": bool, "reason": str, "search_query": str }
    """
    ai_client = resolve_ai_client(call_type="search_decision")
    if not ENABLE_WEB_SEARCH or not ai_client:
        return {"need_search": False, "reason": "搜索功能未启用", "search_query": ""}

    cache_key = _build_search_decision_cache_key(topic, dimension, recent_qa or [])
    cached = _get_search_decision_cache(cache_key)
    if isinstance(cached, dict):
        if ENABLE_DEBUG_LOG:
            print("📦 命中搜索决策缓存，跳过 AI 决策调用")
        _record_cache_hit_metric("search_decision_cache_hit")
        record_search_decision_event("cache_hit")
        return cached

    owner_event = None
    owner_mode = False
    search_decision_slot_acquired = False
    if cache_key:
        owner_event, owner_mode = _begin_search_decision_inflight(cache_key)
        if not owner_mode and isinstance(owner_event, threading.Event):
            wait_seconds = float(SEARCH_DECISION_INFLIGHT_WAIT_SECONDS)
            if ENABLE_DEBUG_LOG:
                print(f"⏳ 搜索决策去重生效，等待首个结果: dim={dimension}")
            owner_event.wait(timeout=wait_seconds)
            cached_after_wait = _get_search_decision_cache(cache_key)
            if isinstance(cached_after_wait, dict):
                if ENABLE_DEBUG_LOG:
                    print("✅ 复用并发搜索决策结果")
                _record_cache_hit_metric("search_decision_cache_hit")
                record_search_decision_event("cache_hit")
                return cached_after_wait

    try:
        if not try_acquire_search_decision_semaphore():
            record_search_decision_event("degraded", reason="overloaded")
            return {"need_search": False, "reason": "搜索决策繁忙，已降级跳过", "search_query": ""}
        search_decision_slot_acquired = True

        search_dim_info = get_dimension_info_for_session(context) if context else DIMENSION_INFO
        dim_info = search_dim_info.get(dimension, {})
        dim_name = dim_info.get("name", dimension)

        # 构建最近的问答上下文
        recent_context = ""
        if recent_qa:
            recent_context = "\n".join([
                f"Q: {qa.get('question', '')}\nA: {qa.get('answer', '')}"
                for qa in recent_qa[-3:]  # 只取最近3条
            ])

        prompt = f"""你是一个智能搜索决策助手。请判断在当前访谈场景下，是否需要联网搜索来获取更准确、更专业的信息。

## 当前访谈信息
- 访谈主题：{topic}
- 当前维度：{dim_name}
- 最近问答：
{recent_context if recent_context else "（尚未开始问答）"}

## 判断标准
请评估以下几个方面，判断是否需要联网搜索：

1. **知识时效性**：是否涉及近1-2年的政策、市场、技术变化？
2. **专业领域深度**：是否涉及你可能不够熟悉的垂直行业细节（如医疗编码规则、金融监管要求、行业标准参数等）？
3. **竞品/市场信息**：是否需要了解市场现状、竞争对手、行业头部产品？
4. **最佳实践参考**：是否需要了解业界的最新做法、成功案例？
5. **数据/指标参考**：是否需要了解行业基准数据、常见参数范围？

## 输出格式
请严格按以下JSON格式输出，不要有其他内容：
{{
    "need_search": true或false,
    "reason": "简要说明判断理由（20字以内）",
    "search_query": "如果需要搜索，给出最佳搜索词（要精准、具体，15字以内）；不需要搜索则留空"
}}"""

        result = None
        last_error = None
        attempts = [
            {
                "max_tokens": SEARCH_DECISION_FIRST_MAX_TOKENS,
                "timeout": 10.0,
                "extra_instruction": "",
            },
            {
                "max_tokens": SEARCH_DECISION_RETRY_MAX_TOKENS,
                "timeout": 18.0,
                "extra_instruction": "只输出一行 JSON，不要 markdown 代码块，不要额外解释，不要换行。",
            },
        ]

        for idx, attempt in enumerate(attempts, start=1):
            try:
                attempt_prompt = prompt
                if attempt["extra_instruction"]:
                    attempt_prompt = f"{prompt}\n\n【额外要求】{attempt['extra_instruction']}"

                _response, result_text, _call_meta = create_ai_message_with_model_fallback(
                    ai_client,
                    call_type="search_decision",
                    selected_lane="search_decision",
                    max_tokens=attempt["max_tokens"],
                    timeout=attempt["timeout"],
                    messages=[{"role": "user", "content": attempt_prompt}],
                    prompt_length=len(attempt_prompt),
                    require_text=True,
                )
                if not result_text:
                    raise ValueError("模型响应中未包含可用文本内容")

                result = parse_json_object_response(
                    result_text,
                    required_keys=["need_search", "reason", "search_query"]
                )
                break
            except Exception as retry_error:
                last_error = retry_error
                if _is_upstream_rate_limit_error(retry_error):
                    if ENABLE_DEBUG_LOG:
                        print(f"⚠️  AI搜索决策触发上游限流，停止重试: {retry_error}")
                    break
                if ENABLE_DEBUG_LOG and idx < len(attempts):
                    print(f"ℹ️  AI搜索决策第{idx}次解析失败，准备重试: {retry_error}")

        if result is None:
            raise ValueError(f"AI 搜索决策结果解析失败: {last_error}" if last_error else "AI 搜索决策结果解析失败")

        if ENABLE_DEBUG_LOG:
            print(f"🤖 AI搜索决策: need_search={result.get('need_search')}, reason={result.get('reason')}")

        need_search = result.get("need_search", False)
        if isinstance(need_search, str):
            need_search = need_search.strip().lower() in ["true", "1", "yes", "y"]

        normalized_result = {
            "need_search": bool(need_search),
            "reason": str(result.get("reason", "") or ""),
            "search_query": str(result.get("search_query", "") or "")
        }
        _set_search_decision_cache(cache_key, normalized_result)
        record_search_decision_event("ai_success")
        return normalized_result

    except Exception as e:
        degrade_reason = "rate_limited" if _is_upstream_rate_limit_error(e) else "exception"
        record_search_decision_event("degraded", reason=degrade_reason)
        if ENABLE_DEBUG_LOG:
            print(f"⚠️  AI搜索决策失败: {e}")
        # 失败时返回不搜索，避免阻塞流程
        return {"need_search": False, "reason": f"决策降级: {e}", "search_query": ""}
    finally:
        if search_decision_slot_acquired:
            try:
                SEARCH_DECISION_SEMAPHORE.release()
            except ValueError:
                pass
        if owner_mode:
            _end_search_decision_inflight(cache_key, owner_event)


def smart_search_decision(
    topic: str,
    dimension: str,
    context: dict,
    recent_qa: list = None,
    decision_mode: str = "default",
) -> tuple:
    """
    智能搜索决策：规则预判 + AI 最终判断
    返回: (need_search: bool, search_query: str, reason: str)
    """
    if not ENABLE_WEB_SEARCH:
        return (False, "", "搜索功能未启用")

    normalized_mode = _normalize_search_decision_mode(decision_mode)

    # 第一步：规则预判
    rule_suggests_search = should_search(topic, dimension, context)

    if normalized_mode == "rule_only":
        record_search_decision_event("rule_only")
        if rule_suggests_search:
            return (False, "", "预取降级：规则触发但后台跳过联网")
        return (False, "", "预取降级：规则未触发搜索")

    if not rule_suggests_search:
        # 规则判断不需要搜索，但让 AI 做二次确认（可能漏掉的场景）
        ai_result = ai_evaluate_search_need(topic, dimension, context, recent_qa or [])
        if ai_result["need_search"]:
            if ENABLE_DEBUG_LOG:
                print(f"🔍 规则未触发，但AI建议搜索: {ai_result['reason']}")
            return (True, ai_result["search_query"], f"AI建议: {ai_result['reason']}")
        else:
            return (False, "", "规则和AI均判断不需要搜索")

    # 第二步：规则建议搜索，让 AI 生成精准搜索词
    ai_result = ai_evaluate_search_need(topic, dimension, context, recent_qa or [])

    if ai_result["need_search"] and ai_result["search_query"]:
        # AI 确认需要搜索，使用 AI 生成的搜索词
        return (True, ai_result["search_query"], ai_result["reason"])
    elif ai_result["need_search"]:
        # AI 确认需要但没给搜索词，使用兜底模板
        fallback_query = generate_search_query(topic, dimension, context)
        return (True, fallback_query, "AI确认需要，使用模板搜索词")
    else:
        # AI 判断实际不需要搜索（规则误触发）
        if ENABLE_DEBUG_LOG:
            print(f"🔍 规则触发但AI判断不需要: {ai_result['reason']}")
        return (False, "", f"AI判断不需要: {ai_result['reason']}")


def generate_search_query(topic: str, dimension: str, context: dict) -> str:
    """生成搜索查询（兜底模板，当 AI 未生成搜索词时使用）"""
    gen_query_dim_info = get_dimension_info_for_session(context) if context else DIMENSION_INFO
    dim_info = gen_query_dim_info.get(dimension, {})
    dim_name = dim_info.get("name", dimension)

    # 构建搜索查询 - 对于非默认维度使用通用模板
    if dimension == "tech_constraints":
        return f"{topic} 技术选型 最佳实践 2026"
    elif dimension == "customer_needs":
        return f"{topic} 用户需求 行业痛点 2026"
    elif dimension == "business_process":
        return f"{topic} 业务流程 最佳实践"
    elif dimension == "project_constraints":
        return f"{topic} 项目实施 成本预算 周期"
    else:
        # 非默认维度，使用维度名称构建通用搜索词
        return f"{topic} {dim_name}"


# ============ Intus AI 核心逻辑 ============

DIMENSION_INFO = {
    "customer_needs": {
        "name": "客户需求",
        "description": "核心痛点、期望价值、使用场景、用户角色",
        "key_aspects": ["核心痛点", "期望价值", "使用场景", "用户角色"]
    },
    "business_process": {
        "name": "业务流程",
        "description": "关键流程节点、角色分工、触发事件、异常处理",
        "key_aspects": ["关键流程", "角色分工", "触发事件", "异常处理"]
    },
    "tech_constraints": {
        "name": "技术约束",
        "description": "现有技术栈、集成接口要求、性能指标、安全合规",
        "key_aspects": ["部署方式", "系统集成", "性能要求", "安全合规"]
    },
    "project_constraints": {
        "name": "项目约束",
        "description": "预算范围、时间节点、资源限制、其他约束",
        "key_aspects": ["预算范围", "时间节点", "资源限制", "优先级"]
    }
}


def normalize_scenario_dimensions(raw_dimensions) -> list[dict]:
    """规范化场景维度，过滤无效项，避免历史脏数据导致接口 500。"""
    normalized: list[dict] = []
    seen_ids: set[str] = set()

    if not isinstance(raw_dimensions, list):
        return normalized

    for dim in raw_dimensions:
        if not isinstance(dim, dict):
            continue

        dim_id = str(dim.get("id") or "").strip()
        if not dim_id or dim_id in seen_ids:
            continue

        safe_dim = dict(dim)
        safe_dim["id"] = dim_id

        dim_name = safe_dim.get("name")
        if not isinstance(dim_name, str) or not dim_name.strip():
            safe_dim["name"] = dim_id

        key_aspects = safe_dim.get("key_aspects")
        if isinstance(key_aspects, list):
            safe_dim["key_aspects"] = [str(item).strip() for item in key_aspects if str(item).strip()]
        else:
            safe_dim["key_aspects"] = []

        seen_ids.add(dim_id)
        normalized.append(safe_dim)

    return normalized


def build_default_dimension_entries() -> list[dict]:
    """构造可用的默认维度配置（最终兜底）。"""
    entries: list[dict] = []
    for dim_id, dim_info in DIMENSION_INFO.items():
        key_aspects = dim_info.get("key_aspects", [])
        entries.append({
            "id": dim_id,
            "name": dim_info.get("name", dim_id),
            "description": dim_info.get("description", ""),
            "key_aspects": key_aspects if isinstance(key_aspects, list) else [],
            "min_questions": 2,
            "max_questions": 4,
        })
    return entries


def get_dimension_info_for_session(session: dict) -> dict:
    """
    获取会话的维度信息（支持动态场景）

    优先从会话的 scenario_config 中获取，
    如果不存在则使用默认的 DIMENSION_INFO。

    Args:
        session: 会话数据

    Returns:
        维度信息字典 {dim_id: {name, description, key_aspects}}
    """
    scenario_config = session.get("scenario_config")
    if isinstance(scenario_config, dict):
        scenario_dimensions = normalize_scenario_dimensions(scenario_config.get("dimensions", []))
    else:
        scenario_dimensions = []

    if scenario_dimensions:
        return {
            dim["id"]: {
                "name": dim.get("name", dim["id"]),
                "description": dim.get("description", ""),
                "key_aspects": dim.get("key_aspects", []),
                "weight": dim.get("weight"),
                "scoring_criteria": dim.get("scoring_criteria")
            }
            for dim in scenario_dimensions
        }

    # 向后兼容：返回默认维度
    return DIMENSION_INFO


def get_dimension_order_for_session(session: dict) -> list:
    """
    获取会话的维度顺序列表

    Args:
        session: 会话数据

    Returns:
        维度 ID 列表
    """
    scenario_config = session.get("scenario_config")
    if isinstance(scenario_config, dict):
        scenario_dimensions = normalize_scenario_dimensions(scenario_config.get("dimensions", []))
    else:
        scenario_dimensions = []

    if scenario_dimensions:
        return [dim["id"] for dim in scenario_dimensions]

    # 向后兼容：返回默认顺序
    return list(DIMENSION_INFO.keys())


