def get_mode_identifier(session: dict) -> str:
    """获取会话模式ID（做容错）。"""
    if not isinstance(session, dict):
        return DEFAULT_INTERVIEW_MODE
    return normalize_interview_mode_key(session.get("interview_mode", DEFAULT_INTERVIEW_MODE))


def get_mode_saturation_thresholds(session: dict) -> dict:
    """获取当前模式的饱和度阈值。"""
    mode_config = get_interview_mode_config(session)
    quality = mode_config.get("quality_thresholds") or {}
    return {
        "high": quality.get("high", SATURATION_THRESHOLDS["high"]),
        "medium": quality.get("medium", SATURATION_THRESHOLDS["medium"]),
        "low": quality.get("low", SATURATION_THRESHOLDS["low"]),
    }


def get_interview_mode_config(session: dict) -> dict:
    """获取会话的访谈模式配置"""
    mode = get_mode_identifier(session)
    base_config = dict(INTERVIEW_MODES.get(mode, INTERVIEW_MODES[DEFAULT_INTERVIEW_MODE]))
    v2_override = INTERVIEW_MODES_V2.get(mode, {})
    return {**base_config, **v2_override}


def get_interview_mode_display_config(mode: str) -> dict:
    """获取某个模式的展示配置（用于前端UI渲染）。"""
    base = dict(INTERVIEW_MODES.get(mode, INTERVIEW_MODES[DEFAULT_INTERVIEW_MODE]))
    v2_override = INTERVIEW_MODES_V2.get(mode, {})
    return {**base, **v2_override}


def calculate_dimension_coverage(session: dict, dimension: str) -> int:
    """计算维度覆盖度（只统计正式问题）"""
    formal_count = len([log for log in session.get("interview_log", [])
                       if log.get("dimension") == dimension and not log.get("is_follow_up", False)])
    mode_config = get_interview_mode_config(session)
    required_questions = mode_config.get("max_formal_questions_per_dim", mode_config.get("formal_questions_per_dim", 3))
    if required_questions <= 0:
        return 100
    return min(100, int(formal_count / required_questions * 100))


def get_follow_up_budget_status(session: dict, dimension: str) -> dict:
    """
    计算追问预算使用情况

    Returns:
        {
            "total_used": int,           # 已使用的总追问次数
            "total_budget": int,         # 总预算
            "dimension_used": int,       # 当前维度已使用追问次数
            "dimension_budget": int,     # 当前维度预算
            "current_question_used": int, # 当前正式问题已追问次数
            "current_question_budget": int, # 当前正式问题追问预算
            "can_follow_up": bool,       # 是否还能追问
            "budget_exhausted_reason": str or None  # 预算耗尽原因
        }
    """
    mode_config = get_interview_mode_config(session)
    interview_log = session.get("interview_log", [])

    # 计算总追问次数
    total_follow_ups = len([log for log in interview_log if log.get("is_follow_up", False)])
    total_budget = mode_config["total_follow_up_budget"]

    # 计算当前维度的追问次数
    dim_logs = [log for log in interview_log if log.get("dimension") == dimension]
    dim_follow_ups = len([log for log in dim_logs if log.get("is_follow_up", False)])
    dim_budget = mode_config["follow_up_budget_per_dim"]

    # 计算当前正式问题的追问次数
    # 找到最后一个正式问题的索引
    formal_indices = [i for i, log in enumerate(dim_logs) if not log.get("is_follow_up", False)]
    if formal_indices:
        last_formal_idx = formal_indices[-1]
        # 统计这个正式问题之后的追问数
        current_question_follow_ups = len([
            log for log in dim_logs[last_formal_idx + 1:]
            if log.get("is_follow_up", False)
        ])
    else:
        current_question_follow_ups = 0
    current_question_budget = mode_config["max_questions_per_formal"]

    # 判断是否能继续追问
    can_follow_up = True
    budget_exhausted_reason = None

    if total_follow_ups >= total_budget:
        can_follow_up = False
        budget_exhausted_reason = "total_budget_exhausted"
    elif dim_follow_ups >= dim_budget:
        can_follow_up = False
        budget_exhausted_reason = "dimension_budget_exhausted"
    elif current_question_follow_ups >= current_question_budget:
        can_follow_up = False
        budget_exhausted_reason = "question_budget_exhausted"

    return {
        "total_used": total_follow_ups,
        "total_budget": total_budget,
        "dimension_used": dim_follow_ups,
        "dimension_budget": dim_budget,
        "current_question_used": current_question_follow_ups,
        "current_question_budget": current_question_budget,
        "can_follow_up": can_follow_up,
        "budget_exhausted_reason": budget_exhausted_reason
    }


def calculate_dimension_saturation(session: dict, dimension: str) -> dict:
    """
    计算维度的信息饱和度

    Returns:
        {
            "saturation_score": float,   # 0-1 饱和度分数
            "coverage_score": float,     # 关键方面覆盖度
            "depth_score": float,        # 信息深度
            "volume_score": float,       # 信息量
            "covered_aspects": list,     # 已覆盖的关键方面
            "level": str                 # "high", "medium", "low"
        }
    """
    interview_log = session.get("interview_log", [])
    dim_logs = [log for log in interview_log if log.get("dimension") == dimension]

    if not dim_logs:
        return {
            "saturation_score": 0,
            "coverage_score": 0,
            "depth_score": 0,
            "volume_score": 0,
            "covered_aspects": [],
            "level": "low"
        }

    session_dim_info = get_dimension_info_for_session(session)
    dim_info = session_dim_info.get(dimension, {})
    key_aspects = dim_info.get("key_aspects", [])

    # 1. 信息覆盖度：检查关键方面是否被提及
    all_answers = " ".join([log.get("answer", "") for log in dim_logs])
    all_questions = " ".join([log.get("question", "") for log in dim_logs])
    combined_text = all_answers + all_questions

    covered_aspects = []
    for aspect in key_aspects:
        # 检查关键词是否出现在问答中
        if aspect in combined_text:
            covered_aspects.append(aspect)
        else:
            # 检查相关词
            aspect_keywords = {
                "核心痛点": ["痛点", "问题", "困难", "挑战", "困扰"],
                "期望价值": ["价值", "收益", "效果", "目标", "期望"],
                "使用场景": ["场景", "情况", "使用", "应用", "何时"],
                "用户角色": ["用户", "角色", "人员", "谁", "使用者"],
                "关键流程": ["流程", "步骤", "环节", "过程"],
                "角色分工": ["分工", "职责", "负责", "部门"],
                "触发事件": ["触发", "开始", "启动", "何时"],
                "异常处理": ["异常", "错误", "失败", "例外"],
                "部署方式": ["部署", "云", "本地", "服务器"],
                "系统集成": ["集成", "对接", "接口", "系统"],
                "性能要求": ["性能", "响应", "并发", "速度"],
                "安全合规": ["安全", "合规", "权限", "加密"],
                "预算范围": ["预算", "费用", "成本", "价格"],
                "时间节点": ["时间", "期限", "周期", "何时"],
                "资源限制": ["资源", "人力", "团队", "限制"],
                "优先级": ["优先", "重要", "紧急", "先后"]
            }
            for keyword in aspect_keywords.get(aspect, []):
                if keyword in combined_text:
                    covered_aspects.append(aspect)
                    break

    coverage_score = len(covered_aspects) / len(key_aspects) if key_aspects else 0

    # 2. 信息深度：检查是否有量化、具体场景、对比等深度信号
    depth_signals = 0
    # 检查数字（量化信息）
    if any(c.isdigit() for c in all_answers):
        depth_signals += 1
    # 检查具体场景描述（包含"比如"、"例如"、"当...时"等）
    scenario_keywords = ["比如", "例如", "当", "如果", "场景", "情况下"]
    if any(kw in all_answers for kw in scenario_keywords):
        depth_signals += 1
    # 检查对比或选择（"而不是"、"优先"、"相比"）
    comparison_keywords = ["而不是", "优先", "相比", "更重要", "首先"]
    if any(kw in all_answers for kw in comparison_keywords):
        depth_signals += 1
    # 检查原因说明（"因为"、"由于"、"所以"）
    reason_keywords = ["因为", "由于", "所以", "原因是"]
    if any(kw in all_answers for kw in reason_keywords):
        depth_signals += 1
    # 检查多点回答
    if "；" in all_answers or "、" in all_answers:
        depth_signals += 1

    depth_score = min(1.0, depth_signals / 5)

    # 3. 信息量：基于总字符数
    total_chars = sum(len(log.get("answer", "")) for log in dim_logs)
    # 期望每个维度至少收集 300 字符的有效信息
    volume_score = min(1.0, total_chars / 300)

    # 综合饱和度
    saturation_score = coverage_score * 0.4 + depth_score * 0.3 + volume_score * 0.3

    thresholds = get_mode_saturation_thresholds(session)

    # 确定饱和度级别
    if saturation_score >= thresholds["high"]:
        level = "high"
    elif saturation_score >= thresholds["medium"]:
        level = "medium"
    else:
        level = "low"

    return {
        "saturation_score": round(saturation_score, 2),
        "coverage_score": round(coverage_score, 2),
        "depth_score": round(depth_score, 2),
        "volume_score": round(volume_score, 2),
        "covered_aspects": covered_aspects,
        "level": level
    }


def calculate_user_fatigue(session: dict, dimension: str) -> dict:
    """
    计算用户疲劳度

    Returns:
        {
            "fatigue_score": float,      # 0-1 疲劳度分数
            "detected_signals": list,    # 检测到的疲劳信号
            "sensitivity_modifier": float, # 追问敏感度调整系数 (0.5-1.0)
            "should_force_progress": bool  # 是否应该强制推进
        }
    """
    interview_log = session.get("interview_log", [])
    dim_logs = [log for log in interview_log if log.get("dimension") == dimension]

    detected_signals = []
    fatigue_score = 0

    # 1. 检查连续简短回答
    recent_answers = [log.get("answer", "") for log in interview_log[-5:]]
    short_count = sum(1 for ans in recent_answers if len(ans.strip()) < 30)
    if short_count >= FATIGUE_SIGNALS["consecutive_short"]["threshold"]:
        detected_signals.append("consecutive_short")
        fatigue_score += FATIGUE_SIGNALS["consecutive_short"]["weight"]

    # 2. 检查连续只选选项
    recent_logs = interview_log[-5:]
    option_only_count = 0
    for log in recent_logs:
        options = log.get("options", [])
        answer = log.get("answer", "")
        if options and answer in options and len(answer) < 40:
            option_only_count += 1
    if option_only_count >= FATIGUE_SIGNALS["option_only_streak"]["threshold"]:
        detected_signals.append("option_only_streak")
        fatigue_score += FATIGUE_SIGNALS["option_only_streak"]["weight"]

    # 3. 检查同一维度问题过多
    if len(dim_logs) >= FATIGUE_SIGNALS["same_dimension_too_long"]["threshold"]:
        detected_signals.append("same_dimension_too_long")
        fatigue_score += FATIGUE_SIGNALS["same_dimension_too_long"]["weight"]

    # 4. 检查总问题数
    if len(interview_log) >= FATIGUE_SIGNALS["total_questions_high"]["threshold"]:
        detected_signals.append("total_questions_high")
        fatigue_score += FATIGUE_SIGNALS["total_questions_high"]["weight"]

    fatigue_score = min(1.0, fatigue_score)

    # 计算敏感度调整系数（疲劳度越高，追问敏感度越低）
    # 当 fatigue_score = 0 时，modifier = 1.0
    # 当 fatigue_score = 1 时，modifier = 0.5
    sensitivity_modifier = 1.0 - (fatigue_score * 0.5)

    # 判断是否应该强制推进
    should_force_progress = fatigue_score >= 0.8

    return {
        "fatigue_score": round(fatigue_score, 2),
        "detected_signals": detected_signals,
        "sensitivity_modifier": round(sensitivity_modifier, 2),
        "should_force_progress": should_force_progress
    }


def get_dimension_missing_aspects(session: dict, dimension: str) -> list:
    """获取当前维度尚未覆盖的关键方面。"""
    saturation = calculate_dimension_saturation(session, dimension)
    covered = set(saturation.get("covered_aspects", []))
    dim_info = get_dimension_info_for_session(session).get(dimension, {})
    key_aspects = dim_info.get("key_aspects", [])
    return [aspect for aspect in key_aspects if aspect and aspect not in covered]


def get_follow_up_round_for_dimension_logs(dim_logs: list) -> int:
    """计算当前维度最后一个正式问题的追问轮次。"""
    formal_indices = [i for i, log in enumerate(dim_logs) if not log.get("is_follow_up", False)]
    if not formal_indices:
        return 0

    last_formal_idx = formal_indices[-1]
    chained = 0
    for log in dim_logs[last_formal_idx + 1:]:
        if log.get("is_follow_up", False):
            chained += 1
        else:
            break
    return chained


def has_pending_forced_follow_up(session: dict, dimension: str) -> bool:
    """判断当前维度是否存在待执行的强制追问。"""
    dim_logs = [log for log in session.get("interview_log", []) if log.get("dimension") == dimension]
    if not dim_logs:
        return False

    last_log = dim_logs[-1]
    if last_log.get("is_follow_up", False):
        return False

    if last_log.get("hard_triggered") and not last_log.get("user_skip_follow_up", False):
        return True

    return False


QUESTION_ANSWER_MODES = {"pick_only", "pick_with_reason"}
QUESTION_EVIDENCE_INTENTS = {"low", "medium", "high"}
AI_RECOMMENDATION_CONFIDENCE_LEVELS = {"low": 1, "medium": 2, "high": 3}


def normalize_question_answer_mode(answer_mode: str, fallback: str = "pick_only") -> str:
    normalized = str(answer_mode or "").strip().lower()
    if normalized in QUESTION_ANSWER_MODES:
        return normalized
    fallback_mode = str(fallback or "").strip().lower()
    if fallback_mode in QUESTION_ANSWER_MODES:
        return fallback_mode
    return "pick_only"


def normalize_question_evidence_intent(evidence_intent: str, fallback: str = "low") -> str:
    normalized = str(evidence_intent or "").strip().lower()
    if normalized in QUESTION_EVIDENCE_INTENTS:
        return normalized
    fallback_intent = str(fallback or "").strip().lower()
    if fallback_intent in QUESTION_EVIDENCE_INTENTS:
        return fallback_intent
    return "low"


def normalize_ai_recommendation_confidence(value: str, fallback: str = "") -> str:
    normalized = str(value or "").strip().lower()
    if normalized in AI_RECOMMENDATION_CONFIDENCE_LEVELS:
        return normalized
    fallback_value = str(fallback or "").strip().lower()
    if fallback_value in AI_RECOMMENDATION_CONFIDENCE_LEVELS:
        return fallback_value
    return ""


def ai_recommendation_confidence_meets_threshold(confidence: str, threshold: str) -> bool:
    normalized_confidence = normalize_ai_recommendation_confidence(confidence)
    normalized_threshold = normalize_ai_recommendation_confidence(threshold)
    if not normalized_threshold:
        return True
    if not normalized_confidence:
        return False
    return AI_RECOMMENDATION_CONFIDENCE_LEVELS[normalized_confidence] >= AI_RECOMMENDATION_CONFIDENCE_LEVELS[normalized_threshold]


def build_question_capture_contract(
    *,
    should_follow_up: bool,
    hard_triggered: bool,
    missing_aspects: Optional[list] = None,
    formal_questions_count: int = 0,
    dimension: str = "",
) -> dict:
    """根据当前访谈上下文决定问题的采集契约。"""
    missing_count = len(list(missing_aspects or []))
    normalized_dimension = str(dimension or "").strip().lower()

    answer_mode = "pick_only"
    requires_rationale = False
    evidence_intent = "low"

    if should_follow_up or hard_triggered or missing_count > 0:
        answer_mode = "pick_with_reason"
        requires_rationale = True
        evidence_intent = "high"
    elif formal_questions_count >= 2 or normalized_dimension in {"tech_constraints", "project_constraints"}:
        answer_mode = "pick_with_reason"
        requires_rationale = True
        evidence_intent = "medium"

    return {
        "answer_mode": answer_mode,
        "requires_rationale": requires_rationale,
        "evidence_intent": evidence_intent,
    }


EVIDENCE_LEDGER_PREFLIGHT_INTERVAL = 4
EVIDENCE_LEDGER_MIN_GAP_SCORE = 0.45
EVIDENCE_LEDGER_MAX_FOCUS_SLOTS = 2
EVIDENCE_LEDGER_PREFLIGHT_COOLDOWN_FORMAL_GAP = 2
EVIDENCE_LEDGER_PREFLIGHT_PRIORITY_WINDOW = 2

DIMENSION_EVIDENCE_PROBE_TEMPLATES = {
    "customer_needs": ["使用场景", "影响范围", "用户角色", "主要原因"],
    "business_process": ["角色分工", "触发事件", "异常处理", "协作瓶颈"],
    "tech_constraints": ["系统边界", "性能口径", "安全要求", "集成方式"],
    "project_constraints": ["时间节点", "资源边界", "优先级", "验收标准"],
}

FOLLOW_UP_SIGNAL_PROBE_MAP = {
    "too_short": ["主要原因", "使用场景"],
    "vague_expression": ["边界条件", "责任角色"],
    "generic_answer": ["主要原因", "影响范围"],
    "option_only": ["主要原因", "影响范围"],
    "no_quantification": ["发生频次", "量化口径"],
    "single_selection": ["其他并存因素", "影响范围"],
    "contradiction_detected": ["冲突边界", "确认口径"],
}

SHADOW_DRAFT_SECTION_DIMENSIONS = {
    "needs": ("customer_needs",),
    "solutions": ("business_process", "tech_constraints"),
    "actions": ("business_process", "project_constraints"),
    "evidence_index": ("customer_needs", "business_process", "tech_constraints", "project_constraints"),
}

SHADOW_DRAFT_SECTION_SKIP_IDS = {"overview", "appendix", "risks"}
SHADOW_DRAFT_SECTION_KEYWORDS = {
    "needs": {"need", "needs", "customer", "pain", "current", "state", "profile", "scenario", "usage"},
    "solutions": {"solution", "solutions", "architecture", "target", "tech", "selection", "comparison", "recommendation"},
    "actions": {"action", "actions", "roadmap", "implementation", "plan", "path", "milestone", "recommendation"},
    "evidence_index": {"evidence", "index", "appendix", "summary"},
}
SHADOW_DRAFT_DIMENSION_HINTS = {
    "current_state": {"needs", "current", "state", "pain", "current_state_analysis"},
    "target_architecture": {"solutions", "target", "architecture"},
    "tech_selection": {"solutions", "tech", "selection", "comparison", "recommendations"},
    "implementation_path": {"actions", "implementation", "roadmap", "path", "recommendations"},
}


def _derive_probe_slots_for_dimension(
    dimension: str,
    *,
    missing_aspects: Optional[list] = None,
    signals: Optional[list] = None,
) -> list:
    normalized_dimension = str(dimension or "").strip().lower()
    slots = []
    seen = set()

    def _append_slot(value: str) -> None:
        text = str(value or "").strip()
        if not text or text in seen:
            return
        slots.append(text)
        seen.add(text)

    for aspect in list(missing_aspects or []):
        _append_slot(aspect)
        if len(slots) >= EVIDENCE_LEDGER_MAX_FOCUS_SLOTS:
            return slots

    for signal in list(signals or []):
        for slot in FOLLOW_UP_SIGNAL_PROBE_MAP.get(str(signal or "").strip(), []):
            _append_slot(slot)
            if len(slots) >= EVIDENCE_LEDGER_MAX_FOCUS_SLOTS:
                return slots

    for slot in DIMENSION_EVIDENCE_PROBE_TEMPLATES.get(normalized_dimension, []):
        _append_slot(slot)
        if len(slots) >= EVIDENCE_LEDGER_MAX_FOCUS_SLOTS:
            return slots

    return slots


def _build_preflight_focus_fingerprint(
    dimension: str,
    *,
    target_aspect: str = "",
    probe_slots: Optional[list] = None,
    blocked_sections: Optional[list] = None,
) -> str:
    normalized_dimension = str(dimension or "").strip().lower()
    normalized_aspect = str(target_aspect or "").strip().lower()
    normalized_slots = sorted({
        str(item or "").strip().lower()
        for item in (probe_slots or [])
        if str(item or "").strip()
    })
    normalized_sections = sorted({
        str(item or "").strip().lower()
        for item in (blocked_sections or [])
        if str(item or "").strip()
    })
    payload = [normalized_dimension, normalized_aspect, "|".join(normalized_slots), "|".join(normalized_sections)]
    return "::".join(payload)


def _question_text_covers_probe_slots(question_text: str, target_aspect: str, probe_slots: Optional[list] = None) -> bool:
    normalized_question = str(question_text or "").strip().lower()
    if not normalized_question:
        return False
    tokens = [str(target_aspect or "").strip().lower()]
    tokens.extend(str(item or "").strip().lower() for item in (probe_slots or []))
    tokens = [token for token in tokens if token]
    if not tokens:
        return False
    matched = sum(1 for token in tokens if token and token in normalized_question)
    return matched >= 1


def _tokenize_shadow_draft_text(*values: str) -> set:
    tokens = set()
    for value in values:
        text = str(value or "").strip().lower()
        if not text:
            continue
        tokens.add(text)
        for part in re.split(r"[^a-z0-9\u4e00-\u9fff]+", text):
            normalized_part = str(part or "").strip().lower()
            if normalized_part:
                tokens.add(normalized_part)
    return tokens


def resolve_shadow_draft_section_dimensions(session: dict, dim_info_map: dict) -> dict:
    """根据默认规则和动态场景报告结构推导 shadow draft 段落与维度映射。"""
    mapping = {
        section: list(dimensions)
        for section, dimensions in SHADOW_DRAFT_SECTION_DIMENSIONS.items()
    }

    scenario_config = session.get("scenario_config", {}) if isinstance(session, dict) else {}
    report_config = scenario_config.get("report", {}) if isinstance(scenario_config, dict) else {}
    report_sections = report_config.get("sections", []) if isinstance(report_config, dict) else []
    if not isinstance(report_sections, list):
        report_sections = []

    if not dim_info_map:
        return mapping

    canonical_dimensions = {dim for dims in SHADOW_DRAFT_SECTION_DIMENSIONS.values() for dim in dims}
    dynamic_dimensions = [dim_id for dim_id in dim_info_map.keys() if dim_id not in canonical_dimensions]
    if not dynamic_dimensions:
        return mapping

    dimension_tokens = {}
    for dim_id, info in dim_info_map.items():
        key_aspects = info.get("key_aspects", []) if isinstance(info.get("key_aspects", []), list) else []
        tokens = _tokenize_shadow_draft_text(dim_id, info.get("name", ""), info.get("description", ""), " ".join(key_aspects))
        tokens.update(SHADOW_DRAFT_DIMENSION_HINTS.get(str(dim_id or "").strip().lower(), set()))
        dimension_tokens[dim_id] = tokens

    for section in report_sections:
        section_id = str(section or "").strip().lower()
        if not section_id or section_id in SHADOW_DRAFT_SECTION_SKIP_IDS:
            continue
        section_tokens = _tokenize_shadow_draft_text(section_id.replace("_", " "))
        for canonical, hints in SHADOW_DRAFT_SECTION_KEYWORDS.items():
            if section_id == canonical or section_tokens.intersection(hints):
                mapping.setdefault(canonical, [])
        matched_dims = []
        for dim_id, tokens in dimension_tokens.items():
            overlap = section_tokens.intersection(tokens)
            if overlap:
                matched_dims.append(dim_id)
                continue
            if any(hint in section_id for hint in SHADOW_DRAFT_DIMENSION_HINTS.get(str(dim_id or "").strip().lower(), set())):
                matched_dims.append(dim_id)

        if matched_dims:
            mapping[section_id] = sorted(set(matched_dims))
            for canonical, hints in SHADOW_DRAFT_SECTION_KEYWORDS.items():
                if section_tokens.intersection(hints):
                    target_dims = mapping.setdefault(canonical, [])
                    for dim_id in matched_dims:
                        if dim_id not in target_dims:
                            target_dims.append(dim_id)

    if report_sections:
        recommendations_dims = mapping.get("recommendations", [])
        if recommendations_dims:
            for canonical in ("solutions", "actions"):
                target_dims = mapping.setdefault(canonical, [])
                for dim_id in recommendations_dims:
                    if dim_id not in target_dims:
                        target_dims.append(dim_id)

    for key, dims in list(mapping.items()):
        ordered = []
        seen = set()
        for dim_id in dims:
            if dim_id in dim_info_map and dim_id not in seen:
                ordered.append(dim_id)
                seen.add(dim_id)
        mapping[key] = ordered

    return mapping


def build_session_evidence_ledger(session: dict) -> dict:
    """基于当前访谈记录构建轻量证据账本，用于访谈中途预检与追问规划。"""
    normalized_session = session if isinstance(session, dict) else {}
    interview_log = normalized_session.get("interview_log", [])
    if not isinstance(interview_log, list):
        interview_log = []

    dim_info_map = get_dimension_info_for_session(normalized_session)
    dimension_order = get_dimension_order_for_session(normalized_session) or list(dim_info_map.keys())
    mode_config = get_interview_mode_config(normalized_session)
    min_formal = max(1, int(mode_config.get("formal_questions_per_dim", 3) or 3))

    dimensions = {}
    total_formal = 0
    total_follow_up = 0
    total_weighted_evidence = 0.0
    total_pending_follow_up = 0

    for dim_key in dimension_order:
        dim_logs = [log for log in interview_log if log.get("dimension") == dim_key]
        formal_logs = [log for log in dim_logs if not log.get("is_follow_up", False)]
        follow_up_logs = [log for log in dim_logs if log.get("is_follow_up", False)]
        info = dim_info_map.get(dim_key, {})
        key_aspects = info.get("key_aspects", []) if isinstance(info.get("key_aspects", []), list) else []
        missing_aspects = get_dimension_missing_aspects(normalized_session, dim_key) if (dim_logs or key_aspects) else []

        evidence_counts = {"explicit": 0, "rich_option": 0, "weak_inferred": 0, "pending_follow_up": 0}
        quality_scores = []
        high_intent_count = 0
        follow_up_candidates = 0
        latest_formal = formal_logs[-1] if formal_logs else None

        for log in formal_logs:
            evidence_class = str(
                log.get("answer_evidence_class")
                or classify_answer_evidence_class_v3(
                    log.get("follow_up_signals", []),
                    log.get("quality_score", 0.0),
                    log.get("evidence_intent", "low"),
                )
            ).strip()
            if evidence_class not in evidence_counts:
                evidence_class = "weak_inferred"
            evidence_counts[evidence_class] += 1
            quality_scores.append(_safe_float(log.get("quality_score"), default=0.0))
            if normalize_question_evidence_intent(log.get("evidence_intent", ""), fallback="low") == "high":
                high_intent_count += 1
            if bool(log.get("needs_follow_up", False)) and not bool(log.get("user_skip_follow_up", False)):
                follow_up_candidates += 1

        weighted_evidence = (
            evidence_counts["explicit"] * 1.0
            + evidence_counts["rich_option"] * 0.75
            + evidence_counts["weak_inferred"] * 0.35
        )
        formal_count = len(formal_logs)
        evidence_density = weighted_evidence / formal_count if formal_count > 0 else 0.0
        pending_ratio = evidence_counts["pending_follow_up"] / formal_count if formal_count > 0 else 0.0
        missing_ratio = (len(missing_aspects) / len(key_aspects)) if key_aspects else (1.0 if formal_count == 0 else 0.0)
        quality_average = (sum(quality_scores) / len(quality_scores)) if quality_scores else 0.0

        gap_score = 0.0
        gap_score += min(0.5, missing_ratio * 0.5)
        gap_score += min(0.25, pending_ratio * 0.35)
        gap_score += min(0.2, max(0.0, 0.65 - evidence_density) * 0.4)
        if formal_count < min_formal:
            gap_score += min(0.2, (min_formal - formal_count) * 0.08)
        if latest_formal and latest_formal.get("hard_triggered"):
            gap_score += 0.12
        if latest_formal and latest_formal.get("needs_follow_up") and not latest_formal.get("user_skip_follow_up"):
            gap_score += 0.08
        gap_score = max(0.0, min(1.0, gap_score))

        latest_signals = list(latest_formal.get("follow_up_signals", []) or []) if isinstance(latest_formal, dict) else []
        probe_slots = _derive_probe_slots_for_dimension(
            dim_key,
            missing_aspects=missing_aspects,
            signals=latest_signals,
        )
        ready_for_report = (
            formal_count >= min_formal
            and not missing_aspects
            and evidence_density >= 0.55
            and pending_ratio <= 0.35
        )

        dimensions[dim_key] = {
            "dimension": dim_key,
            "name": info.get("name", dim_key),
            "formal_count": formal_count,
            "follow_up_count": len(follow_up_logs),
            "coverage": int(normalized_session.get("dimensions", {}).get(dim_key, {}).get("coverage", 0) or 0),
            "missing_aspects": missing_aspects,
            "key_aspects": key_aspects,
            "evidence_counts": evidence_counts,
            "evidence_density": round(evidence_density, 3),
            "pending_follow_up_ratio": round(pending_ratio, 3),
            "quality_average": round(quality_average, 3),
            "high_evidence_question_count": high_intent_count,
            "follow_up_candidates": follow_up_candidates,
            "latest_signals": latest_signals,
            "latest_probe_slots": probe_slots,
            "latest_question": str(latest_formal.get("question", "") or "") if isinstance(latest_formal, dict) else "",
            "latest_answer": str(latest_formal.get("answer", "") or "") if isinstance(latest_formal, dict) else "",
            "latest_needs_follow_up": bool(latest_formal.get("needs_follow_up", False)) if isinstance(latest_formal, dict) else False,
            "latest_user_skip_follow_up": bool(latest_formal.get("user_skip_follow_up", False)) if isinstance(latest_formal, dict) else False,
            "gap_score": round(gap_score, 3),
            "ready_for_report": bool(ready_for_report),
        }

        total_formal += formal_count
        total_follow_up += len(follow_up_logs)
        total_weighted_evidence += weighted_evidence
        total_pending_follow_up += evidence_counts["pending_follow_up"]

    priority_dimensions = sorted(
        dimensions.values(),
        key=lambda item: (
            -_safe_float(item.get("gap_score"), default=0.0),
            len(item.get("missing_aspects", []) or []),
            -_safe_float(item.get("pending_follow_up_ratio"), default=0.0),
        ),
    )

    shadow_draft = {}
    shadow_section_dimensions = resolve_shadow_draft_section_dimensions(normalized_session, dim_info_map)
    for section, section_dims in shadow_section_dimensions.items():
        blockers = []
        section_scores = []
        for dim_key in section_dims:
            dim_ledger = dimensions.get(dim_key)
            if not isinstance(dim_ledger, dict):
                continue
            section_scores.append(_safe_float(dim_ledger.get("gap_score"), default=0.0))
            if not dim_ledger.get("ready_for_report", False):
                blockers.append(dim_key)
        if not section_scores:
            continue
        readiness = 1.0 - (sum(section_scores) / len(section_scores))
        shadow_draft[section] = {
            "ready": bool(not blockers and readiness >= 0.45),
            "blocking_dimensions": blockers,
            "readiness_score": round(max(0.0, min(1.0, readiness)), 3),
        }

    overall_density = (total_weighted_evidence / total_formal) if total_formal > 0 else 0.0
    ledger = {
        "generated_at": get_utc_now(),
        "formal_questions_total": total_formal,
        "follow_up_total": total_follow_up,
        "pending_follow_up_total": total_pending_follow_up,
        "overall_evidence_density": round(overall_density, 3),
        "priority_dimensions": [item.get("dimension", "") for item in priority_dimensions if item.get("dimension")],
        "dimensions": dimensions,
        "shadow_draft": shadow_draft,
    }
    return ledger


def refresh_session_evidence_ledger(session: dict) -> dict:
    """刷新会话中的轻量证据账本。"""
    ledger = build_session_evidence_ledger(session)
    if isinstance(session, dict):
        session["evidence_ledger"] = ledger
    return ledger


def _get_question_hedge_budget_state(session: dict, dimension: str) -> dict:
    interview_log = session.get("interview_log", []) if isinstance(session, dict) else []
    if not isinstance(interview_log, list):
        interview_log = []
    normalized_dimension = str(dimension or "").strip()
    session_used = 0
    dimension_used = 0
    for log in interview_log:
        if not isinstance(log, dict):
            continue
        if not bool(log.get("question_hedge_triggered", False)):
            continue
        session_used += 1
        if str(log.get("dimension", "") or "").strip() == normalized_dimension:
            dimension_used += 1

    session_budget = max(0, int(QUESTION_SESSION_HEDGE_BUDGET or 0))
    dimension_budget = max(0, int(QUESTION_DIMENSION_HEDGE_BUDGET or 0))
    session_remaining = max(0, session_budget - session_used) if session_budget > 0 else 0
    dimension_remaining = max(0, dimension_budget - dimension_used) if dimension_budget > 0 else 0
    session_allowed = session_budget > 0 and session_remaining > 0
    dimension_allowed = dimension_budget > 0 and dimension_remaining > 0
    hedge_allowed = session_allowed and dimension_allowed
    return {
        "session_budget": session_budget,
        "session_used": session_used,
        "session_remaining": session_remaining,
        "dimension_budget": dimension_budget,
        "dimension_used": dimension_used,
        "dimension_remaining": dimension_remaining,
        "hedge_allowed": hedge_allowed,
    }


def _get_question_shadow_blocker_state(session: dict, dimension: str, ledger: Optional[dict] = None) -> dict:
    effective_ledger = ledger if isinstance(ledger, dict) else build_session_evidence_ledger(session)
    shadow_draft = effective_ledger.get("shadow_draft", {}) if isinstance(effective_ledger.get("shadow_draft", {}), dict) else {}
    normalized_dimension = str(dimension or "").strip()
    blocking_sections = []
    for section_id, meta in shadow_draft.items():
        if not isinstance(meta, dict):
            continue
        if bool(meta.get("ready", False)):
            continue
        blocking_dimensions = [
            str(item or "").strip()
            for item in (meta.get("blocking_dimensions", []) if isinstance(meta.get("blocking_dimensions", []), list) else [])
            if str(item or "").strip()
        ]
        if normalized_dimension in blocking_dimensions:
            blocking_sections.append(str(section_id or "").strip())
    return {
        "is_blocker": bool(blocking_sections),
        "blocking_sections": blocking_sections,
    }


def build_preflight_user_reason(
    missing_aspects: list,
    *,
    pending_ratio: float = 0.0,
    evidence_density: float = 0.0,
    blocked_sections: Optional[list] = None,
) -> str:
    """把内部证据指标转换为访谈页可展示的通俗提示。"""
    clean_aspects = [
        str(item or "").strip()
        for item in (missing_aspects or [])
        if str(item or "").strip()
    ]
    clean_sections = [
        str(item or "").strip()
        for item in (blocked_sections or [])
        if str(item or "").strip()
    ]

    parts = []
    if clean_aspects:
        focus = "、".join(clean_aspects[:2])
        parts.append(f"为了让报告更准确，请补充“{focus}”相关信息")
    if pending_ratio >= 0.35 or evidence_density < 0.55:
        parts.append("建议补一句具体原因、使用场景、角色影响或数字指标")
    if clean_sections:
        parts.append("这些信息会影响后续报告和方案建议")

    if not parts:
        return "当前信息还不够具体，请补充一个可写进报告的关键依据。"
    return "；".join(parts[:3]) + "。"


def plan_mid_interview_preflight(
    session: dict,
    dimension: str,
    *,
    ledger: Optional[dict] = None,
    rule_based_result: Optional[dict] = None,
) -> dict:
    """在访谈中途评估证据缺口，决定是否优先补证据而不是等到成稿阶段。"""
    normalized_dimension = str(dimension or "").strip()
    ledger = ledger if isinstance(ledger, dict) else build_session_evidence_ledger(session)
    dim_ledger = dict((ledger.get("dimensions", {}) or {}).get(normalized_dimension, {}) or {})
    total_formal = max(0, int(ledger.get("formal_questions_total", 0) or 0))

    gap_score = _safe_float(dim_ledger.get("gap_score"), default=0.0)
    missing_aspects = list(dim_ledger.get("missing_aspects", []) or [])
    probe_slots = list(dim_ledger.get("latest_probe_slots", []) or [])
    pending_ratio = _safe_float(dim_ledger.get("pending_follow_up_ratio"), default=0.0)
    evidence_density = _safe_float(dim_ledger.get("evidence_density"), default=0.0)
    latest_needs_follow_up = bool(dim_ledger.get("latest_needs_follow_up", False))
    user_skipped = bool(dim_ledger.get("latest_user_skip_follow_up", False))
    latest_signals = list(dim_ledger.get("latest_signals", []) or [])
    shadow_draft = ledger.get("shadow_draft", {}) if isinstance(ledger.get("shadow_draft", {}), dict) else {}

    blocked_sections = [
        section for section, meta in shadow_draft.items()
        if isinstance(meta, dict)
        and normalized_dimension in list(meta.get("blocking_dimensions", []) or [])
        and not bool(meta.get("ready", False))
    ]

    urgent_gap = (
        gap_score >= EVIDENCE_LEDGER_MIN_GAP_SCORE
        or (pending_ratio >= 0.45 and evidence_density < 0.65)
        or len(missing_aspects) >= 2
    )
    preflight_due = total_formal >= EVIDENCE_LEDGER_PREFLIGHT_INTERVAL and (
        total_formal % EVIDENCE_LEDGER_PREFLIGHT_INTERVAL == 0 or urgent_gap
    )
    should_intervene = bool(preflight_due and (urgent_gap or blocked_sections))

    force_follow_up = bool(
        should_intervene
        and latest_needs_follow_up
        and not user_skipped
    )
    planner_mode = "follow_up" if force_follow_up else ("gap_probe" if should_intervene else "observe")
    target_aspect = str((missing_aspects or probe_slots or [""])[0] or "").strip()
    if not probe_slots:
        probe_slots = _derive_probe_slots_for_dimension(
            normalized_dimension,
            missing_aspects=missing_aspects,
            signals=(rule_based_result or {}).get("signals", latest_signals),
        )

    priority_dimensions = [str(item or "").strip() for item in list(ledger.get("priority_dimensions", []) or []) if str(item or "").strip()]
    try:
        priority_rank = priority_dimensions.index(normalized_dimension)
    except ValueError:
        priority_rank = len(priority_dimensions)
    high_value_gap = bool(
        blocked_sections
        or priority_rank < EVIDENCE_LEDGER_PREFLIGHT_PRIORITY_WINDOW
        or gap_score >= 0.62
        or pending_ratio >= 0.55
    )

    focus_fingerprint = _build_preflight_focus_fingerprint(
        normalized_dimension,
        target_aspect=target_aspect,
        probe_slots=probe_slots,
        blocked_sections=blocked_sections,
    )

    recent_formal_logs = [
        log for log in list(session.get("interview_log", []) or [])
        if isinstance(log, dict)
        and log.get("dimension") == normalized_dimension
        and not bool(log.get("is_follow_up", False))
    ]
    cooldown_suppressed = False
    cooldown_reason = ""
    if recent_formal_logs:
        latest_formal_log = recent_formal_logs[-1]
        if _question_text_covers_probe_slots(
            latest_formal_log.get("question", ""),
            target_aspect,
            probe_slots,
        ):
            cooldown_suppressed = True
            cooldown_reason = "上一题已针对同类缺口补证据"

    if not cooldown_suppressed:
        for reverse_index, previous_log in enumerate(reversed(recent_formal_logs), 1):
            previous_fp = str(previous_log.get("preflight_fingerprint", "") or "").strip()
            if not bool(previous_log.get("preflight_intervened", False)):
                continue
            if focus_fingerprint and previous_fp and previous_fp == focus_fingerprint:
                if reverse_index <= EVIDENCE_LEDGER_PREFLIGHT_COOLDOWN_FORMAL_GAP:
                    cooldown_suppressed = True
                    cooldown_reason = "同类证据缺口刚刚追问过，先等待补答"
                break

    reason_text = build_preflight_user_reason(
        missing_aspects,
        pending_ratio=pending_ratio,
        evidence_density=evidence_density,
        blocked_sections=blocked_sections,
    )

    if should_intervene and not high_value_gap:
        should_intervene = False
        force_follow_up = False
        planner_mode = "observe"
        reason_text = "当前缺口收益较低，继续自然访谈"

    if should_intervene and cooldown_suppressed:
        should_intervene = False
        force_follow_up = False
        planner_mode = "observe"
        reason_text = cooldown_reason or "同类缺口近期已追问，先等待新证据"

    return {
        "preflight_due": bool(preflight_due),
        "should_intervene": bool(should_intervene),
        "force_follow_up": bool(force_follow_up),
        "planner_mode": planner_mode,
        "target_aspect": target_aspect,
        "probe_slots": probe_slots[:EVIDENCE_LEDGER_MAX_FOCUS_SLOTS],
        "reason": reason_text,
        "gap_score": round(gap_score, 3),
        "blocked_sections": blocked_sections,
        "priority_rank": priority_rank,
        "high_value_gap": bool(high_value_gap),
        "cooldown_suppressed": bool(cooldown_suppressed),
        "cooldown_reason": cooldown_reason,
        "fingerprint": focus_fingerprint,
        "boost_evidence_intent": bool(should_intervene and (force_follow_up or gap_score >= EVIDENCE_LEDGER_MIN_GAP_SCORE)),
    }


RICH_OPTION_CAUSE_KEYWORDS = (
    "导致", "影响", "因为", "所以", "瓶颈", "阻塞", "误拦截", "投诉", "风险", "失败", "延迟",
)
RICH_OPTION_CONTEXT_KEYWORDS = (
    "高峰期", "夜间", "白天", "审批", "接口", "流程", "场景", "订单", "工单", "客户", "用户",
)
RICH_OPTION_ROLE_KEYWORDS = (
    "客服", "销售", "运营", "风控", "研发", "产品", "实施", "财务", "法务", "商家",
)
RICH_OPTION_PROCESS_KEYWORDS = (
    "流转", "复核", "上线", "对接", "集成", "回访", "分配", "排查", "协作", "审核",
)


def _score_rich_option_answer(question: str, answer: str, options: list = None, dimension: str = "") -> dict:
    """识别“只点选项但选项本身信息密度足够高”的回答。"""
    answer_text = str(answer or "").strip()
    option_list = [str(item or "").strip() for item in (options or []) if str(item or "").strip()]
    if not answer_text or not option_list:
        return {"is_rich_option": False, "score": 0, "primary_option": "", "matched_options": [], "exact_option": False}

    exact_option = answer_text in option_list
    matched_options = [option for option in option_list if option and option in answer_text]
    if not exact_option and not matched_options:
        return {"is_rich_option": False, "score": 0, "primary_option": "", "matched_options": [], "exact_option": False}

    primary_option = answer_text if exact_option else max(matched_options, key=len)
    normalized_question = str(question or "").strip()
    normalized_dimension = str(dimension or "").strip().lower()
    score = 0

    if exact_option:
        score += 1
    if len(primary_option) >= 10:
        score += 1
    if len(primary_option) >= 16:
        score += 1
    if any(token in primary_option for token in ("（", ")", "：", ":", "/", "-", "，")):
        score += 1
    if any(token in primary_option for token in RICH_OPTION_CAUSE_KEYWORDS):
        score += 1
    if any(token in primary_option for token in RICH_OPTION_CONTEXT_KEYWORDS):
        score += 1
    if any(token in primary_option for token in RICH_OPTION_ROLE_KEYWORDS):
        score += 1
    if any(token in primary_option for token in RICH_OPTION_PROCESS_KEYWORDS):
        score += 1
    if any(char.isdigit() for char in primary_option):
        score += 1
    if any(token in normalized_question for token in ("原因", "场景", "影响", "频次", "角色", "流程", "瓶颈")):
        score += 1
    if normalized_dimension in {"tech_constraints", "project_constraints"} and any(
        token in primary_option for token in ("分钟", "小时", "天", "周", "月", "成本", "预算", "上线")
    ):
        score += 1

    is_rich_option = score >= 4 or (exact_option and score >= 3 and len(primary_option) >= 12)
    return {
        "is_rich_option": bool(is_rich_option),
        "score": score,
        "primary_option": primary_option,
        "matched_options": matched_options,
        "exact_option": exact_option,
    }


def evaluate_answer_quality(eval_result: dict, answer: str, is_follow_up: bool, follow_up_round: int) -> dict:
    """将回答评估结果映射为质量分数与标签。"""
    signals = eval_result.get("signals", [])
    hard_triggered = eval_result.get("hard_triggered", False)

    quality_score = 0.5
    answer_len = len((answer or "").strip())

    if answer_len >= 120:
        quality_score += 0.2
    elif answer_len >= 80:
        quality_score += 0.1

    if eval_result.get("has_numbers"):
        quality_score += 0.1

    scenario_keywords = ["比如", "例如", "当", "如果", "场景", "案例"]
    if any(keyword in (answer or "") for keyword in scenario_keywords):
        quality_score += 0.1
    if "rich_option_answer" in signals:
        quality_score += 0.12

    negative_penalty = {
        "too_short": 0.2,
        "vague_expression": 0.25,
        "generic_answer": 0.3,
        "option_only": 0.2,
        "no_quantification": 0.1,
        "single_selection": 0.1,
        "contradiction_detected": 0.25,
    }
    quality_score -= sum(negative_penalty.get(signal, 0.05) for signal in signals)

    if is_follow_up and follow_up_round >= 1 and not hard_triggered:
        quality_score += 0.05

    quality_score = max(0.0, min(1.0, quality_score))

    quality_signals = []
    if quality_score >= 0.75:
        quality_signals.append("high_quality")
    if eval_result.get("has_numbers"):
        quality_signals.append("quantified")
    if answer_len >= 80:
        quality_signals.append("detailed")
    if "rich_option_answer" in signals:
        quality_signals.append("rich_option")

    for signal in signals:
        if signal not in quality_signals:
            quality_signals.append(signal)

    return {
        "quality_score": round(quality_score, 2),
        "quality_signals": quality_signals,
        "hard_triggered": bool(hard_triggered),
    }


