def _compact_visible_question_text(text: object) -> str:
    return re.sub(r"[\s，。？！、；：,.?!;:（）()【】\[\]\"'“”‘’]", "", str(text or "").strip())


def _has_visible_context_marker(text: object) -> bool:
    raw = str(text or "")
    return any(marker in raw for marker in QUESTION_VISIBLE_CONTEXT_MARKERS)


def _is_placeholder_visible_option(text: object) -> bool:
    raw = str(text or "").strip()
    return bool(re.fullmatch(r"(选项|方案)?[A-D一二三四1234]", raw, flags=re.IGNORECASE))


def _is_generic_visible_option(text: object) -> bool:
    raw = str(text or "").strip()
    compact = _compact_visible_question_text(raw)
    if not compact:
        return True
    if _is_placeholder_visible_option(compact):
        return True
    if compact in QUESTION_VISIBLE_GENERIC_OPTION_TERMS:
        return True
    return len(compact) <= 4 and not _has_visible_context_marker(compact)


def evaluate_visible_question_quality_gate(
    payload: dict,
    session: Optional[dict] = None,
    dimension: str = "",
    source: str = "",
) -> dict:
    """用户可见问题质量闸门：拦截泛题、模板选项和占位符式问题。"""
    if not isinstance(payload, dict):
        return {"passed": False, "reasons": ["invalid_payload"], "source": str(source or "")}
    if payload.get("completed"):
        return {"passed": True, "reasons": [], "source": str(source or "")}

    question = str(payload.get("question") or "").strip()
    compact_question = _compact_visible_question_text(question)
    options = [
        str(option or "").strip()
        for option in (payload.get("options") or [])
        if str(option or "").strip()
    ]
    reasons = []

    if len(compact_question) < 12:
        reasons.append("short_question")

    generic_question = any(pattern in compact_question for pattern in QUESTION_VISIBLE_GENERIC_QUESTION_PATTERNS)
    if generic_question:
        reasons.append("generic_question")

    if len(options) < 2:
        reasons.append("insufficient_options")

    generic_options = [option for option in options if _is_generic_visible_option(option)]
    placeholder_options = [option for option in options if _is_placeholder_visible_option(option)]
    contextual_options = [option for option in options if _has_visible_context_marker(option)]
    generic_option_ratio = len(generic_options) / max(1, len(options))

    if len(placeholder_options) >= 2 or generic_option_ratio >= 0.75 or (generic_question and not contextual_options):
        reasons.append("generic_options")

    unique_reasons = []
    for reason in reasons:
        if reason not in unique_reasons:
            unique_reasons.append(reason)

    return {
        "passed": not unique_reasons,
        "reasons": unique_reasons,
        "source": str(source or ""),
        "dimension": str(dimension or ""),
        "question_length": len(compact_question),
        "option_count": len(options),
        "generic_option_ratio": round(generic_option_ratio, 4),
        "contextual_option_count": len(contextual_options),
        "interview_mode": get_mode_identifier(session) if isinstance(session, dict) else "",
    }


def evaluate_dimension_completion_v2(session: dict, dimension: str) -> dict:
    """维度完成门禁（V2）：题量 + 质量 + 强制追问。"""
    mode_config = get_interview_mode_config(session)
    dim_logs = [log for log in session.get("interview_log", []) if log.get("dimension") == dimension]
    formal_count = len([log for log in dim_logs if not log.get("is_follow_up", False)])
    min_formal = mode_config.get("formal_questions_per_dim", 3)
    max_formal = mode_config.get("max_formal_questions_per_dim", min_formal)

    budget_status = get_follow_up_budget_status(session, dimension)
    saturation = calculate_dimension_saturation(session, dimension)
    fatigue = calculate_user_fatigue(session, dimension)

    quality_thresholds = mode_config.get("quality_thresholds") or {}
    coverage_threshold = quality_thresholds.get("coverage", 0.8)
    depth_threshold = quality_thresholds.get("depth", 0.6)
    volume_threshold = quality_thresholds.get("volume", 0.45)

    missing_aspects = get_dimension_missing_aspects(session, dimension)
    follow_up_round = get_follow_up_round_for_dimension_logs(dim_logs)
    pending_forced_follow_up = has_pending_forced_follow_up(session, dimension)

    snapshot = {
        "formal_count": formal_count,
        "min_formal": min_formal,
        "max_formal": max_formal,
        "coverage": saturation.get("coverage_score", 0),
        "depth": saturation.get("depth_score", 0),
        "volume": saturation.get("volume_score", 0),
        "saturation": saturation.get("saturation_score", 0),
        "missing_aspects": missing_aspects,
        "follow_up_round": follow_up_round,
        "pending_forced_follow_up": pending_forced_follow_up,
        "budget_status": budget_status,
        "fatigue": fatigue,
    }

    # 1. 待执行强制追问
    if pending_forced_follow_up and follow_up_round < 1:
        return {
            "can_complete": False,
            "reason": "存在待执行的关键追问，需要至少追问1次",
            "action": "continue",
            "quality_warning": False,
            "snapshot": snapshot,
        }

    # 2. 最低正式题未达标
    if formal_count < min_formal:
        return {
            "can_complete": False,
            "reason": f"正式问题数量不足（{formal_count}/{min_formal}）",
            "action": "continue",
            "quality_warning": False,
            "snapshot": snapshot,
        }

    meets_quality = (
        saturation.get("coverage_score", 0) >= coverage_threshold
        and saturation.get("depth_score", 0) >= depth_threshold
        and saturation.get("volume_score", 0) >= volume_threshold
        and not missing_aspects
    )

    # 3. 达到质量门槛可完成
    if meets_quality and not pending_forced_follow_up:
        return {
            "can_complete": True,
            "reason": "达到维度质量门槛",
            "action": "complete",
            "quality_warning": False,
            "snapshot": snapshot,
        }

    # 4. 达到上限保护或预算耗尽，强制完成
    budget_exhausted = not budget_status.get("can_follow_up", True)
    reached_upper_bound = formal_count >= max_formal
    is_deep_mode = normalize_interview_mode_key(session.get("interview_mode", DEFAULT_INTERVIEW_MODE)) == "deep"
    if (
        QUESTION_DEEP_QUALITY_GATE_BLOCKS_FORCE_COMPLETE
        and is_deep_mode
        and not meets_quality
        and reached_upper_bound
        and not budget_exhausted
    ):
        return {
            "can_complete": False,
            "reason": "深度模式质量门槛未达成，需要补齐证据缺口",
            "action": "evidence_gap_confirm",
            "quality_warning": True,
            "snapshot": snapshot,
        }
    if reached_upper_bound or budget_exhausted:
        return {
            "can_complete": True,
            "reason": "预算耗尽且质量仍不足，允许带质量警告完成" if budget_exhausted and not meets_quality else "达到上限保护，允许强制完成",
            "action": "blocked_by_budget_with_quality_gap" if budget_exhausted and not meets_quality else "force_complete",
            "quality_warning": not meets_quality,
            "snapshot": snapshot,
        }

    # 5. 继续提问
    return {
        "can_complete": False,
        "reason": "质量门槛未达成，继续提问",
        "action": "continue",
        "quality_warning": False,
        "snapshot": snapshot,
    }


def should_follow_up_comprehensive(session: dict, dimension: str,
                                    rule_based_result: dict,
                                    preflight_plan: Optional[dict] = None) -> dict:
    """
    综合决策是否应该追问

    整合：规则评估 + 预算检查 + 饱和度 + 疲劳度

    Returns:
        {
            "should_follow_up": bool,
            "reason": str,
            "budget_status": dict,
            "saturation": dict,
            "fatigue": dict,
            "decision_factors": list  # 影响决策的因素
        }
    """
    decision_factors = []
    normalized_preflight = dict(preflight_plan or {})

    # 1. 检查预算
    budget_status = get_follow_up_budget_status(session, dimension)
    if not budget_status["can_follow_up"]:
        reason_map = {
            "total_budget_exhausted": "会话追问预算已用完",
            "dimension_budget_exhausted": "当前维度追问预算已用完",
            "question_budget_exhausted": "当前问题追问次数已达上限"
        }
        return {
            "should_follow_up": False,
            "reason": reason_map.get(budget_status["budget_exhausted_reason"], "预算已用完"),
            "budget_status": budget_status,
            "saturation": {},
            "fatigue": {},
            "decision_factors": ["budget_exhausted"]
        }

    fatigue = calculate_user_fatigue(session, dimension)

    if normalized_preflight.get("force_follow_up") and fatigue.get("fatigue_score", 0) < 0.9:
        return {
            "should_follow_up": True,
            "reason": normalized_preflight.get("reason") or "证据预检发现关键缺口，需要优先补齐",
            "budget_status": budget_status,
            "saturation": calculate_dimension_saturation(session, dimension),
            "fatigue": fatigue,
            "decision_factors": ["mid_interview_preflight"]
        }

    # V2: 硬触发信号优先（在疲劳保护之外）
    hard_triggered = bool(rule_based_result.get("hard_triggered", False))
    if hard_triggered and fatigue.get("fatigue_score", 0) < 0.9:
        return {
            "should_follow_up": True,
            "reason": rule_based_result.get("reason") or "检测到关键模糊/冲突，需要至少追问一次",
            "budget_status": budget_status,
            "saturation": calculate_dimension_saturation(session, dimension),
            "fatigue": fatigue,
            "decision_factors": ["hard_signal_forced_follow_up"]
        }

    # 2. 检查饱和度
    saturation = calculate_dimension_saturation(session, dimension)
    if saturation["level"] == "high":
        decision_factors.append("high_saturation")
        return {
            "should_follow_up": False,
            "reason": f"信息已充分（饱和度 {saturation['saturation_score']:.0%}）",
            "budget_status": budget_status,
            "saturation": saturation,
            "fatigue": None,
            "decision_factors": decision_factors
        }

    # 3. 检查疲劳度
    if fatigue["should_force_progress"]:
        decision_factors.append("user_fatigue")
        return {
            "should_follow_up": False,
            "reason": "检测到用户疲劳，暂停追问",
            "budget_status": budget_status,
            "saturation": saturation,
            "fatigue": fatigue,
            "decision_factors": decision_factors
        }

    # 4. 基于规则评估结果，但应用疲劳度调整
    original_needs_follow_up = rule_based_result.get("needs_follow_up", False)

    if not original_needs_follow_up:
        if normalized_preflight.get("should_intervene") and fatigue.get("fatigue_score", 0) < 0.9:
            return {
                "should_follow_up": False,
                "reason": normalized_preflight.get("reason") or "证据预检建议优先补当前缺口",
                "budget_status": budget_status,
                "saturation": saturation,
                "fatigue": fatigue,
                "decision_factors": ["mid_interview_preflight_probe"]
            }
        return {
            "should_follow_up": False,
            "reason": "回答已充分",
            "budget_status": budget_status,
            "saturation": saturation,
            "fatigue": fatigue,
            "decision_factors": ["sufficient_answer"]
        }

    # 中等饱和度时限制追问
    if saturation["level"] == "medium":
        # 检查是否已经追问过
        if budget_status["current_question_used"] >= 1:
            decision_factors.append("medium_saturation_limit")
            return {
                "should_follow_up": False,
                "reason": "信息接近充分，不再追问",
                "budget_status": budget_status,
                "saturation": saturation,
                "fatigue": fatigue,
                "decision_factors": decision_factors
            }

    # 疲劳度较高时，提高追问门槛
    if fatigue["fatigue_score"] >= 0.5:
        decision_factors.append("elevated_threshold")
        # 只有非常明显需要追问的情况才追问
        if len(rule_based_result.get("signals", [])) < 2:
            return {
                "should_follow_up": False,
                "reason": "用户可能疲劳，跳过非关键追问",
                "budget_status": budget_status,
                "saturation": saturation,
                "fatigue": fatigue,
                "decision_factors": decision_factors
            }

    # 通过所有检查，可以追问
    decision_factors.append("rule_based_follow_up")
    return {
        "should_follow_up": True,
        "reason": rule_based_result.get("reason", "需要进一步了解"),
        "budget_status": budget_status,
        "saturation": saturation,
        "fatigue": fatigue,
        "decision_factors": decision_factors
    }


def score_assessment_answer(session: dict, dimension: str, question: str, answer: str) -> Optional[float]:
    """
    为评估场景的回答打分（1-5分）

    Args:
        session: 会话数据
        dimension: 维度ID
        question: 问题
        answer: 回答

    Returns:
        float: 1.0-5.0 的分数，失败返回 None
    """
    ai_client = resolve_ai_client(call_type="assessment_score")
    if not ai_client:
        return None

    # 获取维度配置
    scenario_config = session.get("scenario_config", {})
    dim_config = None
    for dim in scenario_config.get("dimensions", []):
        if dim.get("id") == dimension:
            dim_config = dim
            break

    if not dim_config:
        return None

    # 构建评分标准文本
    scoring_criteria = dim_config.get("scoring_criteria", {})
    criteria_text = "\n".join(
        f"  {score}分: {desc}"
        for score, desc in sorted(scoring_criteria.items(), key=lambda x: int(x[0]), reverse=True)
    )

    if not criteria_text:
        criteria_text = """  5分: 回答非常优秀，展现深厚专业能力
  4分: 回答良好，有清晰的思路和见解
  3分: 回答基本合格，但缺乏深度
  2分: 回答有明显不足或偏差
  1分: 回答很差，无法展现相关能力"""

    prompt = f"""你是一位专业面试官。请根据以下评分标准，对候选人的回答进行评分。

【评估维度】{dim_config.get("name", dimension)}
【维度说明】{dim_config.get("description", "")}

【评分标准】
{criteria_text}

【面试问题】
{question}

【候选人回答】
{answer}

    请严格按照评分标准打分，只返回一个数字（1-5之间的整数或小数，如 3.5），不要有任何其他文字："""

    try:
        _response, raw, _call_meta = create_ai_message_with_model_fallback(
            ai_client,
            call_type="assessment_score",
            selected_lane="assessment",
            max_tokens=ASSESSMENT_SCORE_MAX_TOKENS,  # 低 token 容易只返回 thinking，保留可调默认值
            timeout=15.0,
            messages=[{"role": "user", "content": prompt}],
            prompt_length=len(prompt),
            require_text=True,
        )
        if not raw:
            raise ValueError("模型响应中未包含评分文本")
        # 提取数字
        import re
        match = re.search(r'(\d+\.?\d*)', raw)
        if match:
            score = float(match.group(1))
            return max(1.0, min(5.0, score))  # 限制在 1-5 范围
    except Exception as e:
        if ENABLE_DEBUG_LOG:
            print(f"⚠️ 评分失败: {e}")

    return None


def evaluate_answer_depth(question: str, answer: str, dimension: str,
                          options: list = None, is_follow_up: bool = False,
                          multi_select: bool = False,
                          answer_mode: str = "",
                          requires_rationale: bool = False,
                          evidence_intent: str = "") -> dict:
    """
    评估回答深度，判断是否需要追问

    三层判断：
    1. 明确需要追问（回答太弱）
    2. 明确不需要追问（回答已充分）
    3. 建议AI评估（交给AI在生成下一题时判断）

    Returns:
        {
            "needs_follow_up": bool,       # 规则层判断结果
            "suggest_ai_eval": bool,       # 是否建议AI再次评估
            "reason": str or None,         # 追问原因
            "signals": list                # 检测到的信号
        }
    """
    signals = []
    answer_stripped = answer.strip()
    answer_len = len(answer_stripped)
    sensitivity = DIMENSION_FOLLOW_UP_SENSITIVITY.get(dimension, 0.5)
    normalized_answer_mode = normalize_question_answer_mode(
        answer_mode,
        fallback="pick_with_reason" if requires_rationale else "pick_only",
    )
    normalized_requires_rationale = bool(requires_rationale or normalized_answer_mode == "pick_with_reason")
    normalized_evidence_intent = normalize_question_evidence_intent(
        evidence_intent,
        fallback="high" if normalized_requires_rationale else "low",
    )
    pick_only_mode = normalized_answer_mode == "pick_only" and not normalized_requires_rationale
    rich_option_meta = _score_rich_option_answer(question, answer_stripped, options=options, dimension=dimension)
    is_rich_option_answer = bool(rich_option_meta.get("is_rich_option", False))

    # ---- 第一层：明确需要追问的情况 ----

    # 1. 回答过短（根据维度敏感度调整阈值）
    short_threshold = int(20 + sensitivity * 20)  # 客户需求36字符，项目约束28字符
    if options:
        if pick_only_mode:
            short_threshold = min(short_threshold, 10 if multi_select else 6)
        else:
            short_threshold = min(short_threshold, 18 if multi_select else 12)
    if answer_len < short_threshold and not is_rich_option_answer:
        signals.append("too_short")

    # 2. 模糊表达检测（扩展词库）
    vague_indicators = [
        # 不确定类
        "看情况", "不一定", "可能", "或许", "大概", "差不多", "到时候",
        "再说", "还没想好", "不确定", "看具体", "根据情况", "待定",
        "以后再说", "暂时不清楚", "目前还不好说",
        # 笼统类
        "都可以", "都行", "随便", "无所谓", "差不多", "一般",
        # 回避类
        "不太了解", "没想过", "不知道", "说不好", "很难说",
    ]
    matched_vague = [v for v in vague_indicators if v in answer_stripped]
    if matched_vague:
        signals.append("vague_expression")

    # 3. 完全匹配泛泛回答
    generic_answers = [
        "好的", "是的", "可以", "没问题", "需要", "应该要",
        "对", "嗯", "行", "同意", "没有", "不需要",
    ]
    if answer_stripped in generic_answers:
        signals.append("generic_answer")

    # 4. 仅选择了预设选项没有补充（答案等于某个选项原文）
    if options:
        is_exact_option = bool(rich_option_meta.get("exact_option", False))
        informative_option = (
            answer_len >= 10
            or is_rich_option_answer
            or any(token in answer_stripped for token in ("（", ")", "：", ":", "如", "例如", "比如", "因为"))
        )
        # 只有非常短的“机械选项回填”才视为 option_only；收敛型问题不处罚。
        if not pick_only_mode and is_exact_option and answer_len < 16 and not informative_option:
            signals.append("option_only")
        if is_rich_option_answer:
            signals.append("rich_option_answer")

    # 5. 缺乏量化信息（对某些维度重要）
    has_numbers = any(c.isdigit() for c in answer_stripped)
    quantitative_dimensions = ["tech_constraints", "project_constraints"]
    if dimension in quantitative_dimensions and not has_numbers and answer_len < 60:
        signals.append("no_quantification")

    # 6. 多选但只选了一个（可能需要补充）
    if multi_select and options and "；" not in answer_stripped and len(options) >= 3 and not is_rich_option_answer:
        # 检查是否是多选题但只选了一个
        selected_count = sum(1 for opt in options if opt in answer_stripped)
        if selected_count <= 1 and answer_len < 30:
            signals.append("single_selection")

    # 7. 轻量矛盾检测
    contradiction_pairs = [
        ("需要", "不需要"),
        ("可以", "不可以"),
        ("支持", "不支持"),
        ("已经", "还没"),
        ("有", "没有"),
        ("必须", "可选"),
    ]
    contradiction_detected = any(
        left in answer_stripped and right in answer_stripped
        for left, right in contradiction_pairs
    )
    if contradiction_detected:
        signals.append("contradiction_detected")

    # ---- 第二层：判断是否明确不需要追问 ----

    # 回答足够详细，不需要追问
    sufficient_signals = []
    if answer_len > 80:
        sufficient_signals.append("detailed_answer")
    if "；" in answer_stripped and answer_len > 40:
        sufficient_signals.append("multi_point_answer")
    if has_numbers and answer_len > 30:
        sufficient_signals.append("quantified_answer")
    if is_rich_option_answer:
        sufficient_signals.append("rich_option_answer")

    # ---- 第三层：综合判断 ----

    # 计算追问得分（信号越多越需要追问）
    signal_weights = {
        "too_short": 0.4,
        "vague_expression": 0.5,
        "generic_answer": 0.8,
        "option_only": 0.3,
        "no_quantification": 0.2,
        "single_selection": 0.2,
        "contradiction_detected": 0.6,
    }
    follow_up_score = sum(signal_weights.get(s, 0.1) for s in signals)
    follow_up_score *= sensitivity  # 应用维度敏感度

    # 减去充分度信号
    sufficient_weights = {
        "detailed_answer": 0.5,
        "multi_point_answer": 0.3,
        "quantified_answer": 0.2,
        "rich_option_answer": 0.25 if normalized_evidence_intent == "high" else 0.18,
    }
    sufficient_score = sum(sufficient_weights.get(s, 0) for s in sufficient_signals)
    follow_up_score -= sufficient_score

    hard_triggered = any(signal in HARD_FOLLOW_UP_SIGNALS for signal in signals)

    # 判断结果
    if follow_up_score >= 0.4:
        # 明确需要追问
        reason = _build_follow_up_reason(signals)
        return {"needs_follow_up": True, "suggest_ai_eval": False,
                "reason": reason, "signals": signals,
                "hard_triggered": hard_triggered,
                "has_numbers": has_numbers,
                "follow_up_score": round(follow_up_score, 2)}
    elif follow_up_score >= 0.15 and not sufficient_signals:
        # 边界情况，建议让AI评估
        reason = _build_follow_up_reason(signals)
        return {"needs_follow_up": False, "suggest_ai_eval": True,
                "reason": reason, "signals": signals,
                "hard_triggered": hard_triggered,
                "has_numbers": has_numbers,
                "follow_up_score": round(follow_up_score, 2)}
    else:
        # 不需要追问
        return {"needs_follow_up": False, "suggest_ai_eval": False,
                "reason": None, "signals": signals,
                "hard_triggered": hard_triggered,
                "has_numbers": has_numbers,
                "follow_up_score": round(follow_up_score, 2)}


def _build_follow_up_reason(signals: list) -> str:
    """根据检测到的信号构建追问原因"""
    reason_map = {
        "too_short": "回答过于简短，需要补充具体细节",
        "vague_expression": "回答包含模糊表述，需要明确具体要求",
        "generic_answer": "回答过于笼统，需要深入了解具体需求",
        "option_only": "当前答案方向明确，但仍需补一个关键依据以支撑后续结论",
        "no_quantification": "缺少量化指标，需要明确具体数据要求",
        "single_selection": "只选择了单一选项，需要了解是否还有其他需求",
        "contradiction_detected": "回答中存在前后冲突，需要澄清真实约束",
    }
    reasons = [reason_map.get(s, "") for s in signals if s in reason_map]
    return reasons[0] if reasons else "需要进一步了解详细需求"


def _infer_legacy_log_capture_contract(log: dict, prior_dim_logs: list) -> dict:
    """为历史会话中缺失的问题采集契约做近似推断。"""
    if not isinstance(log, dict):
        return {
            "answer_mode": "pick_only",
            "requires_rationale": False,
            "evidence_intent": "low",
        }

    dimension = str(log.get("dimension", "") or "").strip()
    question = str(log.get("question", "") or "").strip()
    options = log.get("options", []) if isinstance(log.get("options", []), list) else []
    is_follow_up = bool(log.get("is_follow_up", False) or int(log.get("follow_up_round", 0) or 0) > 0)
    hard_triggered = bool(log.get("hard_triggered", False))
    formal_questions_count = len([item for item in (prior_dim_logs or []) if not item.get("is_follow_up", False)])

    contract = build_question_capture_contract(
        should_follow_up=is_follow_up,
        hard_triggered=hard_triggered,
        missing_aspects=[],
        formal_questions_count=formal_questions_count,
        dimension=dimension,
    )

    question_markers = (
        "原因", "为什么", "场景", "影响", "频次", "角色", "流程", "主要是因为", "哪种情况",
    )
    option_markers = RICH_OPTION_CAUSE_KEYWORDS + RICH_OPTION_CONTEXT_KEYWORDS + RICH_OPTION_ROLE_KEYWORDS + RICH_OPTION_PROCESS_KEYWORDS
    asks_for_evidence = any(marker in question for marker in question_markers)
    options_are_rich = any(
        len(str(option or "").strip()) >= 10 and any(marker in str(option or "") for marker in option_markers)
        for option in options
    )

    if asks_for_evidence or options_are_rich:
        contract["answer_mode"] = "pick_with_reason"
        contract["requires_rationale"] = True
        current_intent = normalize_question_evidence_intent(contract.get("evidence_intent", ""), fallback="low")
        if is_follow_up or asks_for_evidence:
            contract["evidence_intent"] = "high"
        elif current_intent == "low":
            contract["evidence_intent"] = "medium"

    return {
        "answer_mode": normalize_question_answer_mode(contract.get("answer_mode", ""), fallback="pick_only"),
        "requires_rationale": bool(contract.get("requires_rationale", False)),
        "evidence_intent": normalize_question_evidence_intent(contract.get("evidence_intent", ""), fallback="low"),
    }


def backfill_session_interview_log_evidence_annotations(
    session: dict,
    *,
    refresh_quality: bool = True,
    overwrite_contract: bool = False,
) -> dict:
    """按当前证据规则为历史 interview_log 回填契约、质量与证据分类。"""
    if not isinstance(session, dict):
        return {"changed": False, "logs_total": 0, "logs_updated": 0, "field_updates": {}}

    interview_log = session.get("interview_log", [])
    if not isinstance(interview_log, list):
        return {"changed": False, "logs_total": 0, "logs_updated": 0, "field_updates": {}}

    changed = False
    logs_updated = 0
    field_updates = {}
    dim_history = {}

    for log in interview_log:
        if not isinstance(log, dict):
            continue

        dimension = str(log.get("dimension", "") or "").strip()
        prior_dim_logs = dim_history.setdefault(dimension, [])
        inferred_contract = _infer_legacy_log_capture_contract(log, prior_dim_logs)

        raw_answer_mode = str(log.get("answer_mode", "") or "").strip().lower()
        raw_evidence_intent = str(log.get("evidence_intent", "") or "").strip().lower()
        current_answer_mode = normalize_question_answer_mode(raw_answer_mode, fallback=inferred_contract["answer_mode"])
        has_explicit_contract = raw_answer_mode in QUESTION_ANSWER_MODES and raw_evidence_intent in QUESTION_EVIDENCE_INTENTS

        answer_mode = current_answer_mode if (has_explicit_contract and not overwrite_contract) else inferred_contract["answer_mode"]
        requires_rationale = bool(log.get("requires_rationale", False) or answer_mode == "pick_with_reason")
        if overwrite_contract or not has_explicit_contract:
            requires_rationale = bool(inferred_contract["requires_rationale"] or answer_mode == "pick_with_reason")
        evidence_intent = normalize_question_evidence_intent(
            log.get("evidence_intent", "") if (has_explicit_contract and not overwrite_contract) else inferred_contract["evidence_intent"],
            fallback="high" if requires_rationale else ("medium" if answer_mode == "pick_with_reason" else "low"),
        )

        original_snapshot = {
            "answer_mode": log.get("answer_mode"),
            "requires_rationale": log.get("requires_rationale"),
            "evidence_intent": log.get("evidence_intent"),
            "follow_up_signals": copy.deepcopy(log.get("follow_up_signals")),
            "quality_score": log.get("quality_score"),
            "quality_signals": copy.deepcopy(log.get("quality_signals")),
            "hard_triggered": log.get("hard_triggered"),
            "needs_follow_up": log.get("needs_follow_up"),
            "answer_evidence_class": log.get("answer_evidence_class"),
        }

        log["answer_mode"] = answer_mode
        log["requires_rationale"] = requires_rationale
        log["evidence_intent"] = evidence_intent

        eval_result = evaluate_answer_depth(
            question=str(log.get("question", "") or ""),
            answer=str(log.get("answer", "") or ""),
            dimension=dimension,
            options=log.get("options", []) if isinstance(log.get("options", []), list) else [],
            is_follow_up=bool(log.get("is_follow_up", False)),
            multi_select=bool(log.get("question_multi_select", log.get("multi_select", False))),
            answer_mode=answer_mode,
            requires_rationale=requires_rationale,
            evidence_intent=evidence_intent,
        )
        quality_result = evaluate_answer_quality(
            eval_result=eval_result,
            answer=str(log.get("answer", "") or ""),
            is_follow_up=bool(log.get("is_follow_up", False)),
            follow_up_round=int(log.get("follow_up_round", 0) or 0),
        )
        answer_evidence_class = classify_answer_evidence_class_v3(
            eval_result.get("signals", []),
            quality_result.get("quality_score", 0.0),
            evidence_intent,
        )

        if refresh_quality or "follow_up_signals" not in log:
            log["follow_up_signals"] = list(eval_result.get("signals", []) or [])
            log["needs_follow_up"] = bool(eval_result.get("needs_follow_up", False))
        if refresh_quality or "quality_score" not in log:
            log["quality_score"] = quality_result.get("quality_score", 0.0)
            log["quality_signals"] = list(quality_result.get("quality_signals", []) or [])
            log["hard_triggered"] = bool(quality_result.get("hard_triggered", False))
        log["answer_evidence_class"] = answer_evidence_class

        updated_snapshot = {
            "answer_mode": log.get("answer_mode"),
            "requires_rationale": log.get("requires_rationale"),
            "evidence_intent": log.get("evidence_intent"),
            "follow_up_signals": log.get("follow_up_signals"),
            "quality_score": log.get("quality_score"),
            "quality_signals": log.get("quality_signals"),
            "hard_triggered": log.get("hard_triggered"),
            "needs_follow_up": log.get("needs_follow_up"),
            "answer_evidence_class": log.get("answer_evidence_class"),
        }

        if original_snapshot != updated_snapshot:
            changed = True
            logs_updated += 1
            for key, value in updated_snapshot.items():
                if original_snapshot.get(key) != value:
                    field_updates[key] = field_updates.get(key, 0) + 1

        prior_dim_logs.append(log)

    return {
        "changed": changed,
        "logs_total": len([log for log in interview_log if isinstance(log, dict)]),
        "logs_updated": logs_updated,
        "field_updates": field_updates,
    }


def build_interview_prompt(
    session: dict,
    dimension: str,
    all_dim_logs: list,
    session_id: str = None,
    session_signature: Optional[tuple[int, int]] = None,
    output_mode: str = "full",
    search_mode: str = "default",
    runtime_probe: bool = False,
) -> tuple[str, list, dict]:
    return run_interview_runtime_with_bindings(
        _sync_interview_runtime_bindings(),
        module_build_interview_prompt,
        session,
        dimension,
        all_dim_logs,
        session_id=session_id,
        session_signature=session_signature,
        output_mode=output_mode,
        search_mode=search_mode,
        runtime_probe=runtime_probe,
    )


def build_assessment_report_prompt(session: dict) -> str:
    """构建面试评估报告 prompt"""
    topic = session.get("topic", "候选人评估")
    description = session.get("description", "")
    interview_log = session.get("interview_log", [])
    dimensions = session.get("dimensions", {})
    scenario_config = session.get("scenario_config", {})
    assessment_config = scenario_config.get("assessment", {})

    # 获取维度配置
    dim_configs = {d["id"]: d for d in scenario_config.get("dimensions", [])}

    # 计算综合评分
    total_score = 0.0
    total_weight = 0.0
    dim_scores_info = []
    for dim_id, dim_data in dimensions.items():
        dim_config = dim_configs.get(dim_id, {})
        weight = dim_config.get("weight", 0.25)
        score = dim_data.get("score")
        if score is not None:
            total_score += score * weight
            total_weight += weight
            dim_scores_info.append({
                "id": dim_id,
                "name": dim_config.get("name", dim_id),
                "score": score,
                "weight": weight,
                "criteria": dim_config.get("scoring_criteria", {})
            })

    final_score = round(total_score / total_weight, 2) if total_weight > 0 else 0

    # 确定推荐等级
    recommendation_levels = assessment_config.get("recommendation_levels", [])
    recommendation = {"level": "D", "name": "不推荐", "color": "#ef4444"}
    for level in sorted(recommendation_levels, key=lambda x: x.get("threshold", 0), reverse=True):
        if final_score >= level.get("threshold", 0):
            recommendation = level
            break

    # 构建评分表格文本
    score_table = "| 维度 | 得分 | 权重 | 加权得分 |\n|:---|:---:|:---:|:---:|\n"
    for info in dim_scores_info:
        weighted = round(info["score"] * info["weight"], 2)
        score_table += f"| {info['name']} | {info['score']:.1f} | {info['weight']*100:.0f}% | {weighted:.2f} |\n"
    score_table += f"| **综合得分** | **{final_score:.2f}** | 100% | **{final_score:.2f}** |"

    # 按维度整理问答和评分
    qa_sections = ""
    for dim_info in dim_scores_info:
        dim_id = dim_info["id"]
        qa_list = [log for log in interview_log if log.get("dimension") == dim_id]
        qa_sections += f"\n### {dim_info['name']}（得分: {dim_info['score']:.1f}/5.0）\n"
        for qa in qa_list:
            qa_sections += f"**Q**: {qa['question']}\n"
            qa_sections += f"**A**: {qa['answer']}\n"
            if qa.get("score"):
                qa_sections += f"*单题评分: {qa['score']:.1f}*\n"
            qa_sections += "\n"

    prompt = f"""你是一位资深的面试官和人才评估专家，需要基于以下访谈记录生成一份专业的面试评估报告。

## 评估主题
{topic}
"""

    if description:
        prompt += f"""
## 背景说明
{description}
"""

    prompt += f"""
## 各维度得分

{score_table}

## 访谈记录与评分
{qa_sections}

## 报告要求

请生成一份专业的面试评估报告，包含以下章节：

### 1. 候选人概览
- 评估主题
- 评估时间
- 综合得分：**{final_score:.2f}/5.0**
- 推荐等级：**{recommendation.get('name', '待定')}** ({recommendation.get('level', 'C')})

### 2. 能力雷达图
使用 Mermaid 雷达图展示各维度得分（如果 Mermaid 不支持雷达图，可用其他可视化方式替代）：

**注意**：由于 Mermaid 不原生支持雷达图，请使用以下替代方案：

```mermaid
xychart-beta
    title "能力评估雷达"
    x-axis [{', '.join([f'"{d["name"]}"' for d in dim_scores_info])}]
    y-axis "得分" 0 --> 5
    bar [{', '.join([str(d["score"]) for d in dim_scores_info])}]
```

### 3. 各维度详细分析
对每个评估维度进行详细分析：
- 该维度的得分和表现
- 具体的优势体现
- 存在的不足或待提升点
- 关键证据（引用访谈内容）

### 4. 核心优势
总结候选人的 2-3 个核心优势，用具体事例支撑

### 5. 待提升领域
指出 1-2 个需要提升的方面，给出具体建议

### 6. 推荐意见
基于综合评分 **{final_score:.2f}** 给出：
- 推荐等级：**{recommendation.get('name', '待定')}**
- 等级说明：{recommendation.get('description', '')}
- 录用建议（详细说明录用/不录用的理由，以及如果录用的注意事项）

### 7. 后续建议
- 如需进一步评估的问题
- 入职后的培养建议（如果推荐录用）

## 重要提醒
- 所有分析必须严格基于访谈记录中的实际内容
- 评分已由 AI 在访谈过程中逐题打分，请基于这些评分进行分析
- 客观公正，既要指出优势也要指出不足
- 报告要专业、结构清晰、有理有据
- 使用 Markdown 格式
- 报告末尾使用署名：*此报告由 Intus 见真生成*

请生成完整的评估报告："""

    return prompt


def build_report_prompt(session: dict) -> str:
    """构建报告生成 prompt"""
    return build_report_prompt_with_options(session)


def _normalize_report_prompt_excerpt(value: object, max_len: int = 420, placeholder: str = "暂无数据") -> str:
    text = re.sub(r"\s+", " ", str(value or "").strip())
    if not text:
        return placeholder
    if len(text) <= max(40, int(max_len or 40)):
        return text
    normalized_limit = max(40, int(max_len or 40))
    return text[: normalized_limit - 1].rstrip() + "…"


def _collect_report_reference_materials(session: dict) -> list[dict]:
    reference_materials = session.get("reference_materials", [])
    if isinstance(reference_materials, list) and reference_materials:
        return reference_materials
    legacy_docs = session.get("reference_docs", [])
    research_docs = session.get("research_docs", [])
    merged_docs = []
    if isinstance(legacy_docs, list):
        merged_docs.extend(legacy_docs)
    if isinstance(research_docs, list):
        merged_docs.extend(research_docs)
    return merged_docs


def _build_compact_report_reference_block(session: dict, max_docs: int = 3, max_chars: int = 420) -> str:
    reference_materials = _collect_report_reference_materials(session)
    normalized_docs = [item for item in reference_materials if isinstance(item, dict)]
    if not normalized_docs:
        return "- 无参考资料"

    lines = []
    for doc in normalized_docs[: max(1, int(max_docs or 1))]:
        doc_name = _normalize_report_prompt_excerpt(doc.get("name", "文档"), max_len=48, placeholder="文档")
        source_marker = "自动抓取" if doc.get("source") == "auto" else "用户上传"
        if doc.get("chunk_manifest_ref"):
            selected_content, _selection_meta = select_reference_material_context(
                doc,
                query_text=str(session.get("topic", "") or ""),
                max_chars=max_chars,
                chunk_limit=2,
            )
        else:
            selected_content = str(doc.get("content", "") or "")
        content = _normalize_report_prompt_excerpt(selected_content, max_len=max_chars, placeholder="内容缺失")
        lines.append(f"- {doc_name}（{source_marker}）：{content}")
    return "\n".join(lines) if lines else "- 无参考资料"


def build_compact_report_prompt(session: dict, evidence_pack: Optional[dict] = None) -> str:
    """构建紧凑版报告 prompt，用于 V3 失败后的快速回退。"""
    effective_evidence_pack = evidence_pack if isinstance(evidence_pack, dict) and evidence_pack else build_report_evidence_pack(session)
    template_name = resolve_report_template_for_session(session, evidence_pack=effective_evidence_pack)
    if template_name == REPORT_TEMPLATE_ASSESSMENT_V1:
        return build_assessment_report_prompt(session)

    topic = session.get("topic", "未知项目")
    description = str(session.get("description", "") or "").strip()
    report_cfg = (session.get("scenario_config", {}) or {}).get("report", {})
    if not isinstance(report_cfg, dict):
        report_cfg = {}

    dimension_lines = []
    raw_dimension_coverage = effective_evidence_pack.get("dimension_coverage", {})
    if isinstance(raw_dimension_coverage, dict):
        for dim_key, dim_meta in raw_dimension_coverage.items():
            if not isinstance(dim_meta, dict):
                continue
            missing = "、".join((dim_meta.get("missing_aspects", []) if isinstance(dim_meta.get("missing_aspects", []), list) else [])[:3]) or "无"
            dimension_lines.append(
                f"- {dim_meta.get('name', dim_key)}：覆盖{int(dim_meta.get('coverage_percent', 0) or 0)}%，"
                f"正式题{int(dim_meta.get('formal_count', 0) or 0)}，追问{int(dim_meta.get('follow_up_count', 0) or 0)}，盲区：{missing}"
            )
    dimension_text = "\n".join(dimension_lines) if dimension_lines else "- 暂无维度覆盖数据"

    selected_facts = select_slimmed_facts_for_prompt(effective_evidence_pack, facts_limit=14)
    fact_lines = []
    for fact in selected_facts:
        fact_lines.append(
            f"- {fact.get('q_id')} [{fact.get('dimension_name', '未分类')}] "
            f"Q: {_normalize_report_prompt_excerpt(fact.get('question', ''), max_len=60)} | "
            f"A: {_normalize_report_prompt_excerpt(fact.get('answer', ''), max_len=120)}"
        )
    facts_text = "\n".join(fact_lines) if fact_lines else "- 暂无高价值问答证据"

    contradiction_lines = []
    for item in (effective_evidence_pack.get("contradictions", []) if isinstance(effective_evidence_pack.get("contradictions", []), list) else [])[:5]:
        if not isinstance(item, dict):
            continue
        refs = "、".join(_normalize_evidence_refs(item.get("evidence_refs", []))[:4]) or "-"
        contradiction_lines.append(f"- {_normalize_report_prompt_excerpt(item.get('detail', ''), max_len=120)}（证据：{refs}）")
    contradiction_text = "\n".join(contradiction_lines) if contradiction_lines else "- 未发现明显冲突"

    unknown_lines = []
    for item in (effective_evidence_pack.get("unknowns", []) if isinstance(effective_evidence_pack.get("unknowns", []), list) else [])[:5]:
        if not isinstance(item, dict):
            continue
        unknown_lines.append(
            f"- {item.get('q_id', '-')}/{_normalize_report_prompt_excerpt(item.get('dimension', ''), max_len=18)}："
            f"{_normalize_report_prompt_excerpt(item.get('reason', ''), max_len=90)}"
        )
    unknown_text = "\n".join(unknown_lines) if unknown_lines else "- 未发现明显模糊回答"

    blindspot_lines = []
    for item in (effective_evidence_pack.get("blindspots", []) if isinstance(effective_evidence_pack.get("blindspots", []), list) else [])[:6]:
        if not isinstance(item, dict):
            continue
        blindspot_lines.append(
            f"- {_normalize_report_prompt_excerpt(item.get('dimension', ''), max_len=20)}："
            f"{_normalize_report_prompt_excerpt(item.get('aspect', ''), max_len=48)}"
        )
    blindspot_text = "\n".join(blindspot_lines) if blindspot_lines else "- 暂无明显盲区"

    reference_text = _build_compact_report_reference_block(session, max_docs=3, max_chars=320)

    if template_name == REPORT_TEMPLATE_CUSTOM_V1:
        normalized_schema, schema_issues = normalize_custom_report_schema(
            report_cfg.get("schema"),
            fallback_sections=report_cfg.get("sections"),
        )
        section_blueprint = summarize_custom_report_schema_for_prompt(normalized_schema)
        schema_issue_notice = ""
        if schema_issues:
            schema_issue_notice = "\n- 原始模板存在异常配置，已回退为可解析章节。"
        return f"""你是一名资深咨询顾问。请仅基于以下证据快照，生成一份紧凑但可交付的 Markdown 报告。

## 主题
- 主题：{topic}
{f"- 描述：{description}" if description else ""}

## 维度覆盖快照
{dimension_text}

## 高价值证据
{facts_text}

## 冲突 / 未决 / 盲区
### 冲突
{contradiction_text}
### 未决
{unknown_text}
### 盲区
{blindspot_text}

## 参考资料摘录（辅助，不得压过访谈证据）
{reference_text}

## 用户自定义章节蓝图（必须按顺序输出）
{section_blueprint}

## 输出要求
1. 只输出 Markdown，不要输出解释、致歉、工具话术。
2. 必须严格按蓝图顺序输出章节，不新增或省略章节标题。
3. 结论优先引用 Q 编号；信息不足时明确写“暂无数据”或“待补充”。
4. component 为 `table` 时输出 Markdown 表格；为 `list` 时输出列表；为 `mermaid` 时输出 ```mermaid 代码块。
5. 内容要紧凑、结论先行，避免大段空话和重复表述。
6. 报告末尾使用署名：*此报告由 Intus 见真生成*{schema_issue_notice}

请直接生成完整报告："""

    return f"""你是一名资深咨询顾问。请仅基于以下证据快照，生成一份紧凑但可交付的 Markdown 访谈报告。

## 主题
- 主题：{topic}
{f"- 描述：{description}" if description else ""}

## 维度覆盖快照
{dimension_text}

## 高价值证据
{facts_text}

## 冲突 / 未决 / 盲区
### 冲突
{contradiction_text}
### 未决
{unknown_text}
### 盲区
{blindspot_text}

## 参考资料摘录（辅助，不得压过访谈证据）
{reference_text}

## 输出要求
1. 仅输出 Markdown 报告，不要输出 JSON、前言或工具确认话术。
2. 按以下章节输出：访谈概述、需求摘要、详细需求分析、可视化分析、方案建议、风险评估、下一步行动。
3. 需求摘要、方案建议、风险评估、下一步行动优先使用 Markdown 表格。
4. 可视化分析可包含 Mermaid，但仅保留 1-2 个最有价值的图，不要堆砌。
5. 所有关键结论尽量引用 Q 编号；信息不足时明确写“暂无数据”。
6. 内容要紧凑、结论先行，避免大段空话和重复表述。
7. 报告末尾使用署名：*此报告由 Intus 见真生成*

请直接生成完整报告："""


def build_report_prompt_with_options(session: dict, evidence_pack: Optional[dict] = None, compact_mode: bool = False) -> str:
    """构建报告生成 prompt，可按需要切换紧凑回退模式。"""
    scenario_config = session.get("scenario_config", {}) if isinstance(session.get("scenario_config", {}), dict) else {}
    report_cfg = scenario_config.get("report", {}) if isinstance(scenario_config.get("report", {}), dict) else {}
    template_name = resolve_report_template_for_session(session, evidence_pack=evidence_pack if isinstance(evidence_pack, dict) else None)

    if template_name == REPORT_TEMPLATE_ASSESSMENT_V1:
        return build_assessment_report_prompt(session)
    if compact_mode:
        return build_compact_report_prompt(session, evidence_pack=evidence_pack)

    topic = session.get("topic", "未知项目")
    description = session.get("description")  # 获取主题描述
    interview_log = session.get("interview_log", [])
    # 兼容旧数据：优先使用 reference_materials，否则合并旧字段
    reference_materials = _collect_report_reference_materials(session)

    # 获取会话的动态维度信息
    report_dim_info = get_dimension_info_for_session(session)

    # 按维度整理问答
    qa_by_dim = {}
    for dim_key in report_dim_info:
        qa_by_dim[dim_key] = [log for log in interview_log if log.get("dimension") == dim_key]

    prompt = f"""你是一个专业的需求分析师，需要基于以下访谈记录生成一份专业的访谈报告。

## 访谈主题
{topic}
"""

    # 如果有主题描述，添加到 prompt 中
    if description:
        prompt += f"""
## 主题描述
{description}
"""

    prompt += """
## 参考资料
"""

    if reference_materials:
        prompt += "以下是用户提供的参考资料，请在生成报告时参考这些内容：\n\n"
        for doc in reference_materials:
            doc_name = doc.get('name', '文档')
            # 根据 source 添加标记
            source_marker = "🔄 " if doc.get("source") == "auto" else ""
            prompt += f"### {source_marker}{doc_name}\n"
            if doc.get("content"):
                reference_selection_meta = {}
                if doc.get("chunk_manifest_ref"):
                    content, reference_selection_meta = select_reference_material_context(
                        doc,
                        query_text=f"{topic}\n{description}",
                        max_chars=MAX_DOC_LENGTH,
                        chunk_limit=REFERENCE_MATERIAL_CONTEXT_CHUNK_LIMIT,
                    )
                else:
                    content = doc["content"]
                original_length = len(content)

                # 使用智能摘要处理长文档
                if original_length > SMART_SUMMARY_THRESHOLD and ENABLE_SMART_SUMMARY:
                    processed_content, is_summarized = summarize_document(content, doc_name, topic)
                    if is_summarized:
                        prompt += f"{processed_content}\n"
                        prompt += f"*[原文档 {original_length} 字符，已通过AI生成摘要保留关键信息]*\n\n"
                    elif len(processed_content) > MAX_DOC_LENGTH:
                        prompt += f"{processed_content[:MAX_DOC_LENGTH]}\n"
                        prompt += f"*[文档内容过长，已截取前 {MAX_DOC_LENGTH} 字符]*\n\n"
                    else:
                        prompt += f"{processed_content}\n\n"
                elif original_length > MAX_DOC_LENGTH:
                    prompt += f"{content[:MAX_DOC_LENGTH]}\n"
                    prompt += f"*[文档内容过长，已截取前 {MAX_DOC_LENGTH} 字符]*\n\n"
                else:
                    prompt += f"{content}\n\n"
                if isinstance(reference_selection_meta, dict) and reference_selection_meta.get("mode") == "chunk_selection":
                    prompt += (
                        f"*[已从全文索引 {reference_selection_meta.get('chunk_count', 0)} 个片段中选取相关内容]*\n\n"
                    )
            else:
                prompt += "*[文档内容为空]*\n\n"
    else:
        prompt += "无参考资料\n"

    prompt += "\n## 访谈记录\n"

    for dim_key, dim_info in report_dim_info.items():
        prompt += f"\n### {dim_info['name']}\n"
        qa_list = qa_by_dim.get(dim_key, [])
        if qa_list:
            for qa in qa_list:
                prompt += f"**Q**: {qa['question']}\n"
                prompt += f"**A**: {qa['answer']}\n\n"
        else:
            prompt += "*该维度暂无收集数据*\n"

    if template_name == REPORT_TEMPLATE_CUSTOM_V1:
        normalized_schema, schema_issues = normalize_custom_report_schema(
            report_cfg.get("schema"),
            fallback_sections=report_cfg.get("sections"),
        )
        section_blueprint = summarize_custom_report_schema_for_prompt(normalized_schema)
        schema_issue_notice = ""
        if schema_issues:
            schema_issue_notice = "\n- 原始模板存在异常配置，已自动回退为可解析章节。"

        prompt += f"""
## 报告要求

请根据用户的自定义模板输出完整 Markdown 报告（不包含附录，附录会由系统自动追加）。

### 用户自定义章节蓝图（必须按顺序输出）
{section_blueprint}

### 输出约束
1. 必须按蓝图顺序输出章节，不新增或省略章节标题。
2. component 为 `paragraph` 时输出结构化段落；为 `table` 时输出 Markdown 表格；为 `list` 时输出列表；为 `mermaid` 时输出 ```mermaid 代码块。
3. 关键结论优先引用问答证据（Q数字），不得编造访谈事实。
4. 若某章节信息不足，明确写出“暂无数据”或“待补充”，不得空章节。
5. flowchart 连接线标签必须使用 `A -->|标签| B` 语法。
6. 报告末尾使用署名：*此报告由 Intus 见真生成*{schema_issue_notice}

请生成完整的报告："""
    else:
        prompt += """
## 报告要求

请生成一份专业的访谈报告，包含以下章节：

1. **访谈概述** - 基本信息、访谈背景
2. **需求摘要** - 核心需求列表、优先级矩阵
3. **详细需求分析**
   - 客户/用户需求（痛点、期望、场景、角色）
   - 业务流程（关键流程、决策节点）
   - 技术约束（部署、集成、安全）
   - 项目约束（预算、时间、资源）
4. **可视化分析** - 使用 Mermaid 图表展示关键信息
5. **方案建议** - 基于需求的可行建议
6. **风险评估** - 潜在风险和应对策略
7. **下一步行动** - 具体的行动项

**注意**：不需要包含"附录"章节，完整的访谈记录会在报告生成后自动追加。

## Mermaid 图表规范

请在报告中包含以下类型的 Mermaid 图表。**除 quadrantChart 外，所有图表都应使用中文标签**。

### 1. 优先级矩阵（必须，两种形式都要）

#### 1.1 象限图（Mermaid）
使用 quadrantChart 展示需求在重要性-紧急性坐标中的位置：

```mermaid
quadrantChart
    title Priority Matrix
    x-axis Low Urgency --> High Urgency
    y-axis Low Importance --> High Importance
    quadrant-1 Do First
    quadrant-2 Schedule
    quadrant-3 Delegate
    quadrant-4 Eliminate

    Requirement1: [0.8, 0.9]
    Requirement2: [0.3, 0.7]
```

**象限图中文图例说明**（必须在象限图下方添加）：
- **横轴**：紧急程度（左低右高）
- **纵轴**：重要程度（下低上高）
- **Do First（立即执行）**：右上象限，重要且紧急
- **Schedule（计划执行）**：左上象限，重要但不紧急
- **Delegate（可委派）**：右下象限，紧急但不重要
- **Eliminate（低优先级）**：左下象限，不重要不紧急
- 然后列出每个数据点对应的中文需求名称，如：`Requirement1 = 需求名称1`

**quadrantChart 规则（必须遵守）：**
- title、x-axis、y-axis、quadrant 标签**必须用英文**（技术限制）
- 数据点名称用英文或拼音，格式：`Name: [x, y]`，x和y范围0-1
- 不要使用特殊符号
- **必须在图表下方添加中文图例说明**

#### 1.2 优先级清单（Markdown表格）
紧接着图例说明，用中文表格详细说明每个需求的优先级：

| 优先级 | 需求项 | 说明 |
|:---:|:---|:---|
| 🔴 P0 立即执行 | 需求1、需求2 | 重要且紧急，必须优先处理 |
| 🟡 P1 计划执行 | 需求3 | 重要但不紧急，需要规划 |
| 🟢 P2 可委派 | 需求4 | 紧急但不重要，可分配他人 |
| ⚪ P3 低优先级 | 需求5 | 不重要不紧急，可延后 |

**两种形式配合使用**：象限图直观展示位置分布，中文图例解释英文标签，表格详细说明优先级和理由。

### 2. 业务流程图（推荐）
使用 flowchart 展示关键业务流程，**使用中文标签**：

```mermaid
flowchart TD
    A[开始] --> B{判断条件}
    B -->|条件满足| C[处理流程1]
    B -->|条件不满足| D[处理流程2]
    C --> E[结束]
    D --> E
```

**注意**：带标签的连接线格式为 `-->|标签|`，标签写在箭头后面的竖线之间。

**flowchart 规则（必须遵守）：**
- 节点ID使用英文字母（如 A、B、C），节点标签使用中文（如 `A[中文标签]`）
- subgraph 标题使用中文（如 `subgraph 子流程名称`）
- **每个 subgraph 必须有对应的 end 关闭**
- 节点标签中**严禁使用以下特殊字符**：
  - 半角冒号 `:` - 用短横线 `-` 或空格替代
  - 半角引号 `"` - 用全角引号 "" 或书名号 《》 替代
  - 半角括号 `()` - 用全角括号 （） 替代
  - HTML 标签如 `<br>` - 用空格或换行替代
- 菱形判断节点使用 `{中文}` 格式
- **不要在同一个 flowchart 中嵌套过多层级（最多2层 subgraph）**
- **连接线语法规则（严格遵守）**：
  - 无标签连接：`A --> B`
  - 带标签连接：`A -->|标签文字| B`（标签在箭头后面，竖线包围）
  - 虚线带标签连接：`A -.->|标签文字| B`
  - **禁止使用**：`A --|标签|--> B`（这是错误语法）
  - **禁止使用**：`A -->|标签|--> B`（不能有双箭头）
  - **禁止使用**：`A -.标签. B`（虚线标签不能省略箭头）
  - **禁止使用**：`A --- B`（虚线无箭头）

### 3. 需求分类饼图（可选）
使用中文标签：
```mermaid
pie title 需求分布
    "功能需求" : 45
    "性能需求" : 25
    "安全需求" : 20
    "易用性" : 10
```

### 4. 部署架构图（如涉及技术约束）
如果访谈中涉及部署模式、系统架构等技术话题，可使用 flowchart 展示部署架构：

```mermaid
flowchart LR
    subgraph 前端
        A[客户端]
    end
    subgraph 后端
        B[负载均衡]
        C[应用服务器]
    end
    subgraph 存储
        D[(数据库)]
    end
    A -->|请求| B
    B --> C
    C -->|读写数据| D
```

**部署架构图规则：**
- 使用 flowchart LR（从左到右）或 flowchart TD（从上到下）
- 节点ID使用英文字母，标签使用中文
- 保持结构简洁，避免过度复杂的嵌套
- 带标签的连接线使用 `-->|标签文字|` 格式（标签在箭头后面）
- 虚线带标签连接使用 `-.->|标签文字|` 格式，不要写成 `-.标签.`

### 5. 图表配色与视觉层次（必须）
- 禁止整张图仅使用单一颜色或同色浅深渐变，至少使用 3 种语义色。
- flowchart/架构图必须包含 `classDef` + `class`，并按语义分层：
  - `核心链路`：蓝色系（如 `#1D4ED8`）
  - `决策节点`：橙色系（如 `#D97706`）
  - `风险/异常`：红色系（如 `#DC2626`）
  - `支撑/辅助`：绿色系（如 `#16A34A`）
- 可直接参考以下写法（示例）：
```mermaid
flowchart TD
    A[核心入口] --> B{决策判断}
    B -->|通过| C[核心流程]
    B -->|阻塞| D[风险处理]
    classDef dvCore fill:#DBEAFE,stroke:#1D4ED8,color:#1E3A8A,stroke-width:1.4px
    classDef dvDecision fill:#FEF3C7,stroke:#D97706,color:#7C2D12,stroke-width:1.4px
    classDef dvRisk fill:#FEE2E2,stroke:#DC2626,color:#7F1D1D,stroke-width:1.4px
    classDef dvSupport fill:#DCFCE7,stroke:#16A34A,color:#14532D,stroke-width:1.4px
    class A,C dvCore
    class B dvDecision
    class D dvRisk
```

## 重要提醒
- 所有内容必须严格基于访谈记录，不得编造
- 使用 Markdown 格式，Mermaid 代码块使用 ```mermaid 标记
- **优先级矩阵必须同时包含：quadrantChart象限图 + Markdown表格**
- **flowchart、pie 等图表使用中文标签**，quadrantChart 因技术限制必须用英文
- 报告要专业、结构清晰、可操作
- **Mermaid 语法要求严格，请仔细检查每个图表的语法正确性**
- **flowchart 连接线带标签语法必须是 `A -->|标签| B`，禁止使用 `A --|标签|--> B`**
- 报告末尾使用署名：*此报告由 Intus 见真生成*

请生成完整的报告："""

    return prompt


def _extract_first_json_object(raw_text: str) -> Optional[str]:
    """从文本中提取第一个完整 JSON 对象。"""
    if not raw_text:
        return None

    json_start = raw_text.find('{')
    if json_start < 0:
        return None

    brace_count = 0
    in_string = False
    escape_next = False

    for i in range(json_start, len(raw_text)):
        char = raw_text[i]

        if escape_next:
            escape_next = False
            continue
        if char == '\\':
            escape_next = True
            continue
        if char == '"' and not escape_next:
            in_string = not in_string
            continue

        if in_string:
            continue

        if char == '{':
            brace_count += 1
        elif char == '}':
            brace_count -= 1
            if brace_count == 0:
                return raw_text[json_start:i + 1]

    return None


def _repair_json_candidate(candidate: str) -> tuple[str, bool]:
    """尝试修复常见 JSON 格式问题，返回 (修复后文本, 是否应用修复)。"""
    text = str(candidate or "").strip()
    if not text:
        return "", False

    repaired = False
    normalized = text.replace("\ufeff", "").strip()
    quote_fixed = (
        normalized
        .replace("“", "\"")
        .replace("”", "\"")
        .replace("‘", "'")
        .replace("’", "'")
    )
    if quote_fixed != normalized:
        normalized = quote_fixed
        repaired = True

    # 移除 markdown 代码块包裹残留
    fenced = re.sub(r"^\s*```(?:json)?\s*", "", normalized, flags=re.IGNORECASE).strip()
    fenced = re.sub(r"\s*```\s*$", "", fenced).strip()
    if fenced != normalized:
        normalized = fenced
        repaired = True

    # 删除常见尾逗号
    trailing_fixed = re.sub(r",\s*([}\]])", r"\1", normalized)
    if trailing_fixed != normalized:
        normalized = trailing_fixed
        repaired = True

    # 修复字符串内部未转义控制字符（常见于模型直接输出多行文本字段）
    control_fixed_parts = []
    in_string = False
    escape_next = False
    control_fixed = False
    for ch in normalized:
        if escape_next:
            control_fixed_parts.append(ch)
            escape_next = False
            continue

        if ch == "\\":
            control_fixed_parts.append(ch)
            escape_next = True
            continue

        if ch == "\"":
            control_fixed_parts.append(ch)
            in_string = not in_string
            continue

        if in_string and ord(ch) < 0x20:
            control_fixed = True
            if ch == "\n":
                control_fixed_parts.append("\\n")
            elif ch == "\r":
                control_fixed_parts.append("\\r")
            elif ch == "\t":
                control_fixed_parts.append("\\t")
            else:
                # 其它控制字符统一替换为空格，避免破坏 JSON 语法
                control_fixed_parts.append(" ")
            continue

        control_fixed_parts.append(ch)

    if control_fixed:
        normalized = "".join(control_fixed_parts)
        repaired = True

    # 兜底修复：截断响应常见于长 JSON，尝试补齐字符串与括号闭合。
    if normalized.startswith("{"):
        stack = []
        in_string = False
        escape_next = False
        for ch in normalized:
            if escape_next:
                escape_next = False
                continue
            if ch == "\\":
                escape_next = True
                continue
            if ch == '"':
                in_string = not in_string
                continue
            if in_string:
                continue
            if ch in "[{":
                stack.append(ch)
            elif ch == "]" and stack and stack[-1] == "[":
                stack.pop()
            elif ch == "}" and stack and stack[-1] == "{":
                stack.pop()

        suffix = []
        if in_string:
            suffix.append('"')
        while stack:
            opener = stack.pop()
            suffix.append('}' if opener == '{' else ']')
        if suffix:
            normalized = normalized + "".join(suffix)
            normalized = re.sub(r",\s*([}\]])", r"\1", normalized)
            repaired = True

    # 若候选中仍混有额外文本，尝试提取首个 JSON 对象
    if not (normalized.startswith("{") and normalized.endswith("}")):
        extracted = _extract_first_json_object(normalized)
        if extracted:
            normalized = extracted.strip()
            repaired = True

    return normalized, repaired


def parse_structured_json_response(
    raw_text: str,
    required_keys: Optional[list] = None,
    require_all_keys: bool = True,
    parse_meta: Optional[dict] = None,
) -> Optional[dict]:
    """解析结构化 JSON 响应（兼容代码块与混杂文本，并支持修复常见格式问题）。"""
    if not raw_text:
        return None

    if isinstance(parse_meta, dict):
        parse_meta.clear()
        parse_meta.update({
            "candidate_count": 0,
            "parse_attempts": 0,
            "repair_applied": False,
            "selected_source": "",
            "missing_keys": [],
            "last_error": "",
        })

    text = raw_text.strip()
    candidates = []
    seen_candidates = set()

    def _append_candidate(value: str, source: str) -> None:
        candidate = str(value or "").strip()
        if not candidate:
            return
        dedup_key = candidate[:4096]
        if dedup_key in seen_candidates:
            return
        seen_candidates.add(dedup_key)
        candidates.append((candidate, source))

    if text.startswith('{'):
        _append_candidate(text, "raw_text")

    if "```json" in text:
        try:
            json_start = text.find("```json") + 7
            json_end = text.find("```", json_start)
            if json_end > json_start:
                _append_candidate(text[json_start:json_end].strip(), "json_fence")
        except Exception:
            pass

    if "```" in text:
        try:
            blocks = re.findall(r"```(?:json)?\s*([\s\S]*?)```", text)
            for block in blocks:
                _append_candidate(block.strip(), "generic_fence")
        except Exception:
            pass

    extracted = _extract_first_json_object(text)
    if extracted:
        _append_candidate(extracted, "extract_first_object")

    if isinstance(parse_meta, dict):
        parse_meta["candidate_count"] = len(candidates)

    for candidate, source in candidates:
        attempts = [(candidate, False, source)]
        repaired_candidate, repaired = _repair_json_candidate(candidate)
        if repaired and repaired_candidate and repaired_candidate != candidate:
            attempts.append((repaired_candidate, True, f"{source}:repaired"))

        for attempt_text, repaired_flag, attempt_source in attempts:
            if isinstance(parse_meta, dict):
                parse_meta["parse_attempts"] = int(parse_meta.get("parse_attempts", 0) or 0) + 1

            try:
                parsed = json.loads(attempt_text)
                if not isinstance(parsed, dict):
                    continue

                if required_keys:
                    if require_all_keys:
                        missing_keys = [key for key in required_keys if key not in parsed]
                        if missing_keys:
                            if isinstance(parse_meta, dict):
                                parse_meta["missing_keys"] = missing_keys
                            continue
                    elif not any(key in parsed for key in required_keys):
                        if isinstance(parse_meta, dict):
                            parse_meta["missing_keys"] = list(required_keys)
                        continue

                if isinstance(parse_meta, dict):
                    parse_meta["repair_applied"] = bool(repaired_flag)
                    parse_meta["selected_source"] = attempt_source
                    parse_meta["missing_keys"] = []
                    parse_meta["last_error"] = ""
                return parsed
            except Exception as parse_error:
                if isinstance(parse_meta, dict):
                    parse_meta["last_error"] = str(parse_error)[:200]
                continue

    return None


def _normalize_evidence_refs(raw_refs) -> list:
    """标准化证据引用，统一为 Q数字 格式。"""
    refs = []
    if isinstance(raw_refs, str):
        refs.extend(re.findall(r"Q\d+", raw_refs.upper()))
    elif isinstance(raw_refs, list):
        for item in raw_refs:
            if isinstance(item, str):
                refs.extend(re.findall(r"Q\d+", item.upper()))

    dedup = sorted(set(refs), key=lambda ref: int(ref[1:]) if ref[1:].isdigit() else 10**9)
    return dedup


_INLINE_EVIDENCE_MARKER_PATTERN = re.compile(
    r"(?:\[\s*证据\s*[：:][^\]\n]*\]|[（(]\s*证据\s*[：:][^）)\n]*[）)])"
)
_PAREN_Q_REF_LIST_PATTERN = re.compile(
    r"[（(]\s*Q\d+(?:\s*[,，、/]\s*Q\d+)*\s*[）)]",
    flags=re.IGNORECASE,
)
_BRACKET_Q_REF_LIST_PATTERN = re.compile(
    r"\[\s*Q\d+(?:\s*[,，、/]\s*Q\d+)*\s*\]",
    flags=re.IGNORECASE,
)


def strip_inline_evidence_markers(text: str) -> str:
    """移除正文中的行内证据编号标记（如 [证据:Q1,Q2]、（证据:Q3）、(Q1,Q2)）。"""
    value = str(text or "")
    if not value:
        return ""

    cleaned = _INLINE_EVIDENCE_MARKER_PATTERN.sub("", value)
    cleaned = _PAREN_Q_REF_LIST_PATTERN.sub("", cleaned)
    cleaned = _BRACKET_Q_REF_LIST_PATTERN.sub("", cleaned)
    cleaned = re.sub(r"[ \t]{2,}", " ", cleaned)
    cleaned = re.sub(r"\s+([，。！？；：,.!?;:])", r"\1", cleaned)
    cleaned = re.sub(r"\n{3,}", "\n\n", cleaned)
    return cleaned.strip()


def classify_answer_evidence_class_v3(signals: list, quality_score: float, evidence_intent: str) -> str:
    normalized_signals = {str(item or "").strip().lower() for item in (signals or []) if str(item or "").strip()}
    normalized_intent = normalize_question_evidence_intent(evidence_intent, fallback="low")
    normalized_quality = max(0.0, min(1.0, _safe_float(quality_score, default=0.0)))

    if "rich_option_answer" in normalized_signals:
        return "rich_option"
    if any(signal in normalized_signals for signal in {"vague_expression", "generic_answer", "contradiction_detected"}):
        return "pending_follow_up" if normalized_intent in {"medium", "high"} else "weak_inferred"
    if any(signal in normalized_signals for signal in {"too_short", "option_only", "no_quantification", "single_selection"}):
        return "pending_follow_up" if normalized_intent == "high" else "weak_inferred"
    if normalized_quality < 0.35 and normalized_intent in {"medium", "high"}:
        return "weak_inferred"
    return "explicit"


def build_report_evidence_pack(session: dict) -> dict:
    """构建报告 V3 证据包。"""
    normalized_session = copy.deepcopy(session) if isinstance(session, dict) else {}
    backfill_session_interview_log_evidence_annotations(normalized_session, refresh_quality=True, overwrite_contract=False)
    interview_log = normalized_session.get("interview_log", [])
    dim_info = get_dimension_info_for_session(normalized_session)
    mode_config = get_interview_mode_config(normalized_session)

    vague_terms = ["看情况", "不确定", "都可以", "不知道", "可能", "暂时不清楚", "以后再说", "差不多"]
    unknown_signals = {"vague_expression", "generic_answer"}

    contradiction_patterns = [
        ("need", "需要", "不需要", "需求取向冲突"),
        ("support", "支持", "不支持", "支持立场冲突"),
        ("available", "有", "没有", "资源现状冲突"),
        ("must", "必须", "可选", "约束优先级冲突"),
        ("ready", "已经", "还没", "准备状态冲突"),
    ]

    facts = []
    unknowns = []
    contradictions = []
    blindspots = []
    contradiction_state = {}
    contradiction_keys = set()
    unknown_keys = set()
    answer_mode_distribution = {mode: 0 for mode in QUESTION_ANSWER_MODES}
    evidence_intent_distribution = {intent: 0 for intent in QUESTION_EVIDENCE_INTENTS}
    answer_evidence_class_distribution = {
        "explicit": 0,
        "rich_option": 0,
        "weak_inferred": 0,
        "pending_follow_up": 0,
    }

    for idx, log in enumerate(interview_log, 1):
        q_id = f"Q{idx}"
        dimension_key = log.get("dimension", "")
        dim_name = dim_info.get(dimension_key, {}).get("name", dimension_key or "未分类")
        question = str(log.get("question", "")).strip()
        answer = str(log.get("answer", "")).strip()
        signals = log.get("follow_up_signals") if isinstance(log.get("follow_up_signals"), list) else []
        try:
            quality_score = float(log.get("quality_score", 0) or 0)
        except Exception:
            quality_score = 0.0
        quality_score = max(0.0, min(1.0, quality_score))
        answer_mode = normalize_question_answer_mode(log.get("answer_mode", ""), fallback="pick_only")
        requires_rationale = bool(log.get("requires_rationale", False) or answer_mode == "pick_with_reason")
        evidence_intent = normalize_question_evidence_intent(
            log.get("evidence_intent", ""),
            fallback="high" if requires_rationale else ("medium" if answer_mode == "pick_with_reason" else "low"),
        )
        answer_mode_distribution[answer_mode] = answer_mode_distribution.get(answer_mode, 0) + 1
        evidence_intent_distribution[evidence_intent] = evidence_intent_distribution.get(evidence_intent, 0) + 1
        answer_evidence_class = classify_answer_evidence_class_v3(signals, quality_score, evidence_intent)
        answer_evidence_class_distribution[answer_evidence_class] = answer_evidence_class_distribution.get(answer_evidence_class, 0) + 1

        fact = {
            "q_id": q_id,
            "dimension": dimension_key,
            "dimension_name": dim_name,
            "question": question,
            "answer": answer,
            "is_follow_up": bool(log.get("is_follow_up", False)),
            "follow_up_round": int(log.get("follow_up_round", 0) or 0),
            "quality_score": quality_score,
            "quality_signals": log.get("quality_signals", []) if isinstance(log.get("quality_signals"), list) else [],
            "follow_up_signals": signals,
            "hard_triggered": bool(log.get("hard_triggered", False)),
            "answer_mode": answer_mode,
            "requires_rationale": requires_rationale,
            "evidence_intent": evidence_intent,
            "answer_evidence_class": answer_evidence_class,
        }
        facts.append(fact)

        unknown_reasons = []
        if answer_evidence_class != "rich_option" and any(signal in unknown_signals for signal in signals):
            unknown_reasons.append("命中模糊回答信号")
        if any(term in answer for term in vague_terms):
            unknown_reasons.append("回答存在模糊表述")
        if answer_evidence_class != "rich_option" and quality_score > 0 and quality_score < 0.45:
            unknown_reasons.append("回答质量偏低")
        if unknown_reasons:
            unknown_key = f"{q_id}:{'|'.join(sorted(set(unknown_reasons)))}"
            if unknown_key not in unknown_keys:
                unknown_keys.add(unknown_key)
                unknowns.append({
                    "q_id": q_id,
                    "dimension": dim_name,
                    "reason": "；".join(sorted(set(unknown_reasons))),
                    "answer_excerpt": answer[:120],
                })

        for pair_id, positive, negative, description in contradiction_patterns:
            has_positive = positive in answer
            has_negative = negative in answer

            if has_positive and has_negative:
                key = f"self:{pair_id}:{q_id}"
                if key not in contradiction_keys:
                    contradiction_keys.add(key)
                    contradictions.append({
                        "type": "same_answer_conflict",
                        "pair_id": pair_id,
                        "description": description,
                        "dimension": dim_name,
                        "evidence_refs": [q_id],
                        "detail": f"{q_id} 同时出现「{positive}」与「{negative}」",
                    })

            if not (has_positive or has_negative):
                continue

            state = "positive" if has_positive else "negative"
            state_key = (dimension_key, pair_id)
            previous = contradiction_state.get(state_key)
            if previous and previous.get("state") != state:
                key = f"cross:{pair_id}:{previous.get('q_id')}:{q_id}:{dimension_key}"
                if key not in contradiction_keys:
                    contradiction_keys.add(key)
                    contradictions.append({
                        "type": "cross_answer_conflict",
                        "pair_id": pair_id,
                        "description": description,
                        "dimension": dim_name,
                        "evidence_refs": [previous.get("q_id"), q_id],
                        "detail": f"{previous.get('q_id')} 与 {q_id} 对「{positive}/{negative}」存在冲突",
                    })
            contradiction_state[state_key] = {"state": state, "q_id": q_id}

    dimension_coverage = {}
    coverage_values = []
    question_count_coverage_values = []
    for dim_key, info in dim_info.items():
        dim_logs = [log for log in interview_log if log.get("dimension") == dim_key]
        dim_facts = [fact for fact in facts if fact.get("dimension") == dim_key]
        formal_count = len([log for log in dim_logs if not log.get("is_follow_up", False)])
        follow_up_count = len([log for log in dim_logs if log.get("is_follow_up", False)])
        dim_state = session.get("dimensions", {}).get(dim_key, {})
        question_count_coverage_percent = int(dim_state.get("coverage", 0) or 0)
        question_count_ratio = max(0, min(100, question_count_coverage_percent)) / 100.0
        missing_aspects = get_dimension_missing_aspects(session, dim_key)
        key_aspects = info.get("key_aspects", []) if isinstance(info.get("key_aspects", []), list) else []
        if key_aspects:
            aspect_total = len(key_aspects)
            aspect_missing = min(aspect_total, len(missing_aspects))
            coverage_ratio = max(0.0, min(1.0, (aspect_total - aspect_missing) / aspect_total))
            coverage_percent = int(round(coverage_ratio * 100))
        else:
            coverage_percent = question_count_coverage_percent
            coverage_ratio = question_count_ratio
        dim_quality_scores = [
            max(0.0, min(1.0, _safe_float(fact.get("quality_score", 0.0), default=0.0)))
            for fact in dim_facts
        ]
        dim_raw_average_quality = (sum(dim_quality_scores) / len(dim_quality_scores)) if dim_quality_scores else 0.0
        quality_adjusted_coverage = max(0.0, min(1.0, coverage_ratio * (0.35 + 0.65 * dim_raw_average_quality)))
        coverage_values.append(quality_adjusted_coverage)
        question_count_coverage_values.append(question_count_ratio)

        for aspect in missing_aspects:
            blindspots.append({
                "dimension": info.get("name", dim_key),
                "aspect": aspect,
            })

        dimension_coverage[dim_key] = {
            "name": info.get("name", dim_key),
            "coverage_percent": max(0, min(100, coverage_percent)),
            "coverage_ratio": round(coverage_ratio, 2),
            "question_count_coverage_percent": max(0, min(100, question_count_coverage_percent)),
            "question_count_coverage_ratio": round(question_count_ratio, 2),
            "quality_adjusted_coverage": round(quality_adjusted_coverage, 3),
            "raw_average_quality_score": round(dim_raw_average_quality, 3),
            "formal_count": formal_count,
            "follow_up_count": follow_up_count,
            "minimum_formal": mode_config.get("formal_questions_per_dim", 3),
            "maximum_formal": mode_config.get("max_formal_questions_per_dim", mode_config.get("formal_questions_per_dim", 3)),
            "missing_aspects": missing_aspects,
            "key_aspects": key_aspects,
        }

    raw_quality_scores = [
        max(0.0, min(1.0, _safe_float(fact.get("quality_score", 0.0), default=0.0)))
        for fact in facts
    ]
    valid_quality_scores = [score for score in raw_quality_scores if score > 0]
    average_quality = sum(raw_quality_scores) / len(raw_quality_scores) if raw_quality_scores else 0.0
    positive_only_average_quality = sum(valid_quality_scores) / len(valid_quality_scores) if valid_quality_scores else 0.0
    overall_coverage = sum(coverage_values) / len(coverage_values) if coverage_values else 0.0
    question_count_overall_coverage = sum(question_count_coverage_values) / len(question_count_coverage_values) if question_count_coverage_values else 0.0

    total_formal = len([fact for fact in facts if not fact.get("is_follow_up", False)])
    total_follow_up = len([fact for fact in facts if fact.get("is_follow_up", False)])

    report_template = resolve_report_template_for_session(session)
    report_cfg = (session.get("scenario_config", {}) or {}).get("report", {})
    if not isinstance(report_cfg, dict):
        report_cfg = {}
    report_schema = {}
    if report_template == REPORT_TEMPLATE_CUSTOM_V1:
        normalized_schema, _schema_issues = normalize_custom_report_schema(
            report_cfg.get("schema"),
            fallback_sections=report_cfg.get("sections"),
        )
        report_schema = normalized_schema

    return {
        "topic": session.get("topic", "未知主题"),
        "report_type": session.get("scenario_config", {}).get("report", {}).get("type", "standard"),
        "report_template": report_template,
        "report_schema": report_schema,
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "facts": facts,
        "contradictions": contradictions,
        "unknowns": unknowns,
        "blindspots": blindspots,
        "dimension_coverage": dimension_coverage,
        "overall_coverage": round(overall_coverage, 3),
        "question_count_overall_coverage": round(question_count_overall_coverage, 3),
        "quality_snapshot": {
            "average_quality_score": round(average_quality, 3),
            "raw_average_quality_score": round(average_quality, 3),
            "positive_only_average_quality_score": round(positive_only_average_quality, 3),
            "hard_triggered_count": len([fact for fact in facts if fact.get("hard_triggered")]),
            "total_questions": len(facts),
            "total_formal_questions": total_formal,
            "total_follow_up_questions": total_follow_up,
            "follow_up_ratio": round(total_follow_up / len(facts), 3) if facts else 0.0,
            "answer_mode_distribution": answer_mode_distribution,
            "evidence_intent_distribution": evidence_intent_distribution,
            "answer_evidence_class_distribution": answer_evidence_class_distribution,
        },
    }


def summarize_evidence_pack_for_debug(evidence_pack: dict) -> dict:
    """提炼证据包摘要，用于会话内调试留痕。"""
    if not isinstance(evidence_pack, dict):
        return {}

    facts = evidence_pack.get("facts", [])
    contradictions = evidence_pack.get("contradictions", [])
    unknowns = evidence_pack.get("unknowns", [])
    blindspots = evidence_pack.get("blindspots", [])

    dimension_summary = {}
    raw_dimension_coverage = evidence_pack.get("dimension_coverage", {})
    if isinstance(raw_dimension_coverage, dict):
        for dim_key, dim_meta in raw_dimension_coverage.items():
            if not isinstance(dim_meta, dict):
                continue
            dimension_summary[dim_key] = {
                "name": dim_meta.get("name", dim_key),
                "coverage_percent": int(dim_meta.get("coverage_percent", 0) or 0),
                "question_count_coverage_percent": int(dim_meta.get("question_count_coverage_percent", dim_meta.get("coverage_percent", 0)) or 0),
                "quality_adjusted_coverage": float(dim_meta.get("quality_adjusted_coverage", 0.0) or 0.0),
                "formal_count": int(dim_meta.get("formal_count", 0) or 0),
                "follow_up_count": int(dim_meta.get("follow_up_count", 0) or 0),
                "missing_aspects": (dim_meta.get("missing_aspects", []) if isinstance(dim_meta.get("missing_aspects", []), list) else [])[:8],
            }

    quality_snapshot = evidence_pack.get("quality_snapshot", {})
    if not isinstance(quality_snapshot, dict):
        quality_snapshot = {}

    return {
        "overall_coverage": float(evidence_pack.get("overall_coverage", 0) or 0),
        "question_count_overall_coverage": float(evidence_pack.get("question_count_overall_coverage", 0) or 0),
        "facts_count": len(facts) if isinstance(facts, list) else 0,
        "contradictions_count": len(contradictions) if isinstance(contradictions, list) else 0,
        "unknowns_count": len(unknowns) if isinstance(unknowns, list) else 0,
        "blindspots_count": len(blindspots) if isinstance(blindspots, list) else 0,
        "quality_snapshot": {
            "average_quality_score": float(quality_snapshot.get("average_quality_score", 0) or 0),
            "raw_average_quality_score": float(quality_snapshot.get("raw_average_quality_score", quality_snapshot.get("average_quality_score", 0)) or 0),
            "positive_only_average_quality_score": float(quality_snapshot.get("positive_only_average_quality_score", 0) or 0),
            "hard_triggered_count": int(quality_snapshot.get("hard_triggered_count", 0) or 0),
            "total_questions": int(quality_snapshot.get("total_questions", 0) or 0),
            "total_formal_questions": int(quality_snapshot.get("total_formal_questions", 0) or 0),
            "total_follow_up_questions": int(quality_snapshot.get("total_follow_up_questions", 0) or 0),
            "follow_up_ratio": float(quality_snapshot.get("follow_up_ratio", 0) or 0),
            "answer_mode_distribution": dict(quality_snapshot.get("answer_mode_distribution", {}) or {}),
            "evidence_intent_distribution": dict(quality_snapshot.get("evidence_intent_distribution", {}) or {}),
            "answer_evidence_class_distribution": dict(quality_snapshot.get("answer_evidence_class_distribution", {}) or {}),
        },
        "dimension_coverage": dimension_summary,
    }


def _safe_float(value: object, default: float = 0.0) -> float:
    try:
        return float(value)
    except Exception:
        return default


def _fact_sort_key_for_prompt(fact: dict) -> int:
    q_id = str(fact.get("q_id", "")).upper().strip()
    if re.fullmatch(r"Q\d+", q_id):
        try:
            return int(q_id[1:])
        except Exception:
            pass
    return 10 ** 9


def _fact_signature_for_prompt(fact: dict) -> str:
    dimension = str(fact.get("dimension", "")).strip().lower()
    question = re.sub(r"\s+", " ", str(fact.get("question", "")).strip().lower())
    answer = re.sub(r"\s+", " ", str(fact.get("answer", "")).strip().lower())
    question = question[:80]
    answer = answer[:120]
    return f"{dimension}|{question}|{answer}"


def select_slimmed_facts_for_prompt(evidence_pack: dict, facts_limit: int) -> list[dict]:
    """按质量和信息密度选择证据，减少冗余输入。"""
    raw_facts = evidence_pack.get("facts", [])
    if not isinstance(raw_facts, list):
        return []

    normalized_limit = max(1, int(facts_limit or 1))
    normalized_facts = [item for item in raw_facts if isinstance(item, dict)]
    if not normalized_facts:
        return []

    if not REPORT_V3_EVIDENCE_SLIM_ENABLED:
        return normalized_facts[:normalized_limit]

    contradiction_refs = set()
    for item in evidence_pack.get("contradictions", []):
        if not isinstance(item, dict):
            continue
        contradiction_refs.update(_normalize_evidence_refs(item.get("evidence_refs", [])))

    unknown_refs = set()
    for item in evidence_pack.get("unknowns", []):
        if not isinstance(item, dict):
            continue
        q_id = str(item.get("q_id", "")).upper().strip()
        if re.fullmatch(r"Q\d+", q_id):
            unknown_refs.add(q_id)

    score_items = []
    for idx, fact in enumerate(normalized_facts):
        quality = max(0.0, min(1.0, _safe_float(fact.get("quality_score", 0.0), 0.0)))
        q_id = str(fact.get("q_id", "")).upper().strip()
        is_contradiction_ref = q_id in contradiction_refs
        is_unknown_ref = q_id in unknown_refs
        is_hard_triggered = bool(fact.get("hard_triggered", False))
        is_follow_up = bool(fact.get("is_follow_up", False))

        score = quality * 100.0
        if is_hard_triggered:
            score += 24.0
        if is_contradiction_ref:
            score += 22.0
        if is_unknown_ref:
            score += 12.0
        if is_follow_up:
            score += 8.0

        score_items.append({
            "idx": idx,
            "fact": fact,
            "q_id": q_id,
            "score": score,
            "quality": quality,
            "is_mandatory": is_contradiction_ref or (REPORT_V3_EVIDENCE_KEEP_HARD_TRIGGERED and is_hard_triggered),
            "signature": _fact_signature_for_prompt(fact),
            "dimension": str(fact.get("dimension", "") or "__unknown__").strip().lower() or "__unknown__",
        })

    score_items.sort(key=lambda item: (-item["score"], item["idx"]))

    selected = []
    selected_signatures = set()
    dimension_counter = {}
    dim_quota = max(1, int(REPORT_V3_EVIDENCE_DIM_QUOTA))

    def try_take(item: dict, bypass_quota: bool = False, bypass_quality: bool = False) -> bool:
        if len(selected) >= normalized_limit:
            return False
        if REPORT_V3_EVIDENCE_DEDUP_ENABLED and item["signature"] in selected_signatures:
            return False
        if not bypass_quality and not item.get("is_mandatory", False):
            if float(item.get("quality", 0.0) or 0.0) < REPORT_V3_EVIDENCE_MIN_QUALITY:
                return False

        dim_key = item.get("dimension", "__unknown__")
        if not bypass_quota:
            if int(dimension_counter.get(dim_key, 0) or 0) >= dim_quota:
                return False

        selected.append(item)
        selected_signatures.add(item["signature"])
        dimension_counter[dim_key] = int(dimension_counter.get(dim_key, 0) or 0) + 1
        return True

    # 第一轮：保留强信号事实（冲突/硬触发）
    for item in score_items:
        if not item.get("is_mandatory", False):
            continue
        if len(selected) >= normalized_limit:
            break
        try_take(item, bypass_quota=True, bypass_quality=True)

    # 第二轮：按分数补齐，兼顾维度配额与最小质量。
    for item in score_items:
        if len(selected) >= normalized_limit:
            break
        try_take(item, bypass_quota=False, bypass_quality=False)

    # 第三轮：若仍不足，放宽配额与质量门槛兜底补齐。
    if len(selected) < normalized_limit:
        for item in score_items:
            if len(selected) >= normalized_limit:
                break
            try_take(item, bypass_quota=True, bypass_quality=True)

    selected_facts = [item["fact"] for item in selected]
    selected_facts.sort(key=_fact_sort_key_for_prompt)
    return selected_facts


def build_report_draft_prompt_assessment_v1(
    session: dict,
    evidence_pack: dict,
    facts_limit: int = 48,
    contradiction_limit: int = 12,
    unknown_limit: int = 12,
    blindspot_limit: int = 12,
) -> str:
    """assessment_v1 草案提示词：强调候选人能力评估与录用建议。"""
    topic = session.get("topic", "候选人评估")
    description = session.get("description", "")
    selected_facts = select_slimmed_facts_for_prompt(evidence_pack, facts_limit=max(8, int(facts_limit or 8)))
    facts_lines = []
    for fact in selected_facts:
        question_text = (fact.get("question", "") or "").replace("\n", " ").strip()[:90]
        answer_text = (fact.get("answer", "") or "").replace("\n", " ").strip()[:150]
        facts_lines.append(
            f"- {fact.get('q_id')} [{fact.get('dimension_name', '未分类')}] "
            f"Q: {question_text} | A: {answer_text} | quality={fact.get('quality_score', 0):.2f} | evidence={fact.get('answer_evidence_class', 'explicit')}"
        )
    facts_text = "\n".join(facts_lines) if facts_lines else "- 无有效问答证据"

    dimension_lines = []
    for dim_key, dim_meta in (evidence_pack.get("dimension_coverage", {}) or {}).items():
        missing = "、".join(dim_meta.get("missing_aspects", [])[:4]) if dim_meta.get("missing_aspects") else "无"
        dimension_lines.append(
            f"- {dim_meta.get('name', dim_key)}: 覆盖{dim_meta.get('coverage_percent', 0)}%，"
            f"正式题 {dim_meta.get('formal_count', 0)}，追问 {dim_meta.get('follow_up_count', 0)}，未覆盖方面：{missing}"
        )
    dimension_text = "\n".join(dimension_lines) if dimension_lines else "- 暂无维度覆盖数据"

    contradictions = evidence_pack.get("contradictions", [])
    contradiction_lines = [
        f"- {item.get('detail')}（证据: {', '.join(item.get('evidence_refs', []))}）"
        for item in contradictions[:max(5, int(contradiction_limit or 5))]
    ]
    contradiction_text = "\n".join(contradiction_lines) if contradiction_lines else "- 未发现明显冲突"

    unknowns = evidence_pack.get("unknowns", [])
    unknown_lines = [
        f"- {item.get('q_id')} [{item.get('dimension')}] {item.get('reason')}"
        for item in unknowns[:max(5, int(unknown_limit or 5))]
    ]
    unknown_text = "\n".join(unknown_lines) if unknown_lines else "- 未发现明显模糊回答"

    blindspots = evidence_pack.get("blindspots", [])
    blindspot_lines = [
        f"- {item.get('dimension')}: {item.get('aspect')}"
        for item in blindspots[:max(5, int(blindspot_limit or 5))]
    ]
    blindspot_text = "\n".join(blindspot_lines) if blindspot_lines else "- 暂无盲区"

    schema_example = {
        "overview": "候选人概览（1-2段）",
        "needs": [
            {
                "name": "能力项结论（如问题拆解能力）",
                "priority": "P0",
                "description": "该能力项的表现结论与证据摘要",
                "evidence_refs": ["Q1", "Q3"]
            }
        ],
        "analysis": {
            "customer_needs": "能力优势分析",
            "business_flow": "思维结构与推理链分析",
            "tech_constraints": "经验边界与风险意识分析",
            "project_constraints": "录用约束、岗位匹配与团队协作分析"
        },
        "visualizations": {
            "priority_quadrant_mermaid": "可选，能力优先矩阵",
            "business_flow_mermaid": "可选，思维流程图",
            "demand_pie_mermaid": "可选，能力分布图",
            "architecture_mermaid": "可选，胜任力结构图"
        },
        "solutions": [
            {
                "title": "录用/培养建议",
                "description": "建议说明",
                "owner": "用人经理",
                "timeline": "试用期1个月/3个月",
                "metric": "阶段性能力达成指标",
                "evidence_refs": ["Q2", "Q8"]
            }
        ],
        "risks": [
            {
                "risk": "录用风险项",
                "impact": "风险影响",
                "mitigation": "缓解措施",
                "evidence_refs": ["Q6"]
            }
        ],
        "actions": [
            {
                "action": "后续评估/培养行动",
                "owner": "面试官/导师",
                "timeline": "短期+中期里程碑",
                "metric": "可量化验收标准",
                "evidence_refs": ["Q4"]
            }
        ],
        "open_questions": [
            {
                "question": "需补充验证的问题",
                "reason": "为何未决",
                "impact": "影响范围",
                "suggested_follow_up": "建议补充追问",
                "evidence_refs": ["Q7"]
            }
        ],
        "evidence_index": [
            {
                "claim": "关键评估结论",
                "confidence": "high",
                "evidence_refs": ["Q1", "Q5"]
            }
        ]
    }

    return f"""你是一名资深面试评估顾问。请基于证据包输出结构化草案 JSON，不要输出 JSON 之外任何文字。

## 任务类型
- 报告类型：面试评估
- 主题：{topic}
{f"- 背景：{description}" if description else ""}

## 维度覆盖快照
{dimension_text}

## 关键证据（问答编号）
{facts_text}

## 冲突信号
{contradiction_text}

## 模糊与不确定信号
{unknown_text}

## 盲区清单
{blindspot_text}

## 输出要求
1. 顶层字段必须严格为：overview/needs/analysis/visualizations/solutions/risks/actions/open_questions/evidence_index。
2. 关键结论必须绑定 evidence_refs（Q数字）。
3. solutions/actions 必须包含 owner、timeline、metric。
4. actions 至少 2 条，且覆盖短期与中期里程碑。
5. 内容风格偏“评估结论+培养建议”，避免需求文案口吻。
6. 禁止输出工具执行话术、markdown代码块与额外前后缀文本。

## JSON 模板（字段必须完整）
{json.dumps(schema_example, ensure_ascii=False, indent=2)}
"""


def build_report_draft_prompt_custom_v1(
    session: dict,
    evidence_pack: dict,
    facts_limit: int = 56,
    contradiction_limit: int = 16,
    unknown_limit: int = 16,
    blindspot_limit: int = 16,
) -> str:
    """custom_v1 草案提示词：按用户章节蓝图约束表达焦点。"""
    report_cfg = (session.get("scenario_config", {}) or {}).get("report", {})
    schema_raw = report_cfg.get("schema") if isinstance(report_cfg, dict) else {}
    normalized_schema, _issues = normalize_custom_report_schema(schema_raw, fallback_sections=report_cfg.get("sections") if isinstance(report_cfg, dict) else None)
    section_blueprint = summarize_custom_report_schema_for_prompt(normalized_schema)

    topic = session.get("topic", "未知主题")
    description = session.get("description", "")
    selected_facts = select_slimmed_facts_for_prompt(evidence_pack, facts_limit=max(10, int(facts_limit or 10)))
    facts_lines = []
    for fact in selected_facts:
        question_text = (fact.get("question", "") or "").replace("\n", " ").strip()[:90]
        answer_text = (fact.get("answer", "") or "").replace("\n", " ").strip()[:150]
        facts_lines.append(
            f"- {fact.get('q_id')} [{fact.get('dimension_name', '未分类')}] "
            f"Q: {question_text} | A: {answer_text} | quality={fact.get('quality_score', 0):.2f} | evidence={fact.get('answer_evidence_class', 'explicit')}"
        )
    facts_text = "\n".join(facts_lines) if facts_lines else "- 无有效问答证据"

    contradictions = evidence_pack.get("contradictions", [])
    contradiction_lines = [
        f"- {item.get('detail')}（证据: {', '.join(item.get('evidence_refs', []))}）"
        for item in contradictions[:max(5, int(contradiction_limit or 5))]
    ]
    contradiction_text = "\n".join(contradiction_lines) if contradiction_lines else "- 未发现明显冲突"

    unknowns = evidence_pack.get("unknowns", [])
    unknown_lines = [
        f"- {item.get('q_id')} [{item.get('dimension')}] {item.get('reason')}"
        for item in unknowns[:max(5, int(unknown_limit or 5))]
    ]
    unknown_text = "\n".join(unknown_lines) if unknown_lines else "- 未发现明显模糊回答"

    blindspots = evidence_pack.get("blindspots", [])
    blindspot_lines = [
        f"- {item.get('dimension')}: {item.get('aspect')}"
        for item in blindspots[:max(5, int(blindspot_limit or 5))]
    ]
    blindspot_text = "\n".join(blindspot_lines) if blindspot_lines else "- 暂无盲区"

    schema_example = {
        "overview": "执行摘要",
        "needs": [],
        "analysis": {
            "customer_needs": "",
            "business_flow": "",
            "tech_constraints": "",
            "project_constraints": ""
        },
        "visualizations": {
            "priority_quadrant_mermaid": "",
            "business_flow_mermaid": "",
            "demand_pie_mermaid": "",
            "architecture_mermaid": ""
        },
        "solutions": [],
        "risks": [],
        "actions": [],
        "open_questions": [],
        "evidence_index": []
    }

    return f"""你是一名企业咨询顾问，需要基于证据包输出结构化草案 JSON。

## 任务类型
- 报告类型：用户自定义模板
- 主题：{topic}
{f"- 背景：{description}" if description else ""}

## 用户定义章节蓝图（渲染时会按此输出）
{section_blueprint}

## 关键证据（问答编号）
{facts_text}

## 冲突信号
{contradiction_text}

## 模糊与不确定信号
{unknown_text}

## 盲区清单
{blindspot_text}

## 输出要求
1. 只输出合法 JSON，禁止任何前后缀文本。
2. 顶层字段必须严格为：overview/needs/analysis/visualizations/solutions/risks/actions/open_questions/evidence_index。
3. 关键结论必须绑定 evidence_refs（Q数字）。
4. solutions/actions 必须包含 owner、timeline、metric。
5. open_questions 要优先覆盖盲区与冲突。
6. 文案需简洁可交付，避免口语化、避免空泛叙述。

## JSON 模板（字段必须完整）
{json.dumps(schema_example, ensure_ascii=False, indent=2)}
"""


def build_report_draft_prompt_v3(
    session: dict,
    evidence_pack: dict,
    facts_limit: int = 60,
    contradiction_limit: int = 20,
    unknown_limit: int = 20,
    blindspot_limit: int = 20,
    compact_mode: bool = False,
) -> str:
    """构建 V3 报告草案生成 Prompt（结构化 JSON）。"""
    template_name = resolve_report_template_for_session(session, evidence_pack=evidence_pack)
    if template_name == REPORT_TEMPLATE_ASSESSMENT_V1:
        return build_report_draft_prompt_assessment_v1(
            session,
            evidence_pack,
            facts_limit=facts_limit,
            contradiction_limit=contradiction_limit,
            unknown_limit=unknown_limit,
            blindspot_limit=blindspot_limit,
        )
    if template_name == REPORT_TEMPLATE_CUSTOM_V1:
        return build_report_draft_prompt_custom_v1(
            session,
            evidence_pack,
            facts_limit=facts_limit,
            contradiction_limit=contradiction_limit,
            unknown_limit=unknown_limit,
            blindspot_limit=blindspot_limit,
        )

    topic = session.get("topic", "未知主题")
    description = session.get("description", "")
    report_type = evidence_pack.get("report_type", "standard")
    report_type_label = "面试评估" if report_type == "assessment" else "需求访谈"

    dimension_lines = []
    max_dimension_lines = 4 if compact_mode else 8
    for dim_key, dim_meta in list((evidence_pack.get("dimension_coverage", {}) or {}).items())[:max_dimension_lines]:
        missing = "、".join(dim_meta.get("missing_aspects", [])[:4]) if dim_meta.get("missing_aspects") else "无"
        dimension_lines.append(
            f"- {dim_meta.get('name', dim_key)}: 覆盖{dim_meta.get('coverage_percent', 0)}%，"
            f"正式题 {dim_meta.get('formal_count', 0)}，追问 {dim_meta.get('follow_up_count', 0)}，未覆盖方面：{missing}"
        )
    dimension_text = "\n".join(dimension_lines) if dimension_lines else "- 暂无维度覆盖数据"

    facts_limit = max(8 if compact_mode else 10, int(facts_limit or (8 if compact_mode else 10)))
    contradiction_limit = max(4 if compact_mode else 5, int(contradiction_limit or (4 if compact_mode else 5)))
    unknown_limit = max(4 if compact_mode else 5, int(unknown_limit or (4 if compact_mode else 5)))
    blindspot_limit = max(4 if compact_mode else 5, int(blindspot_limit or (4 if compact_mode else 5)))

    selected_facts = select_slimmed_facts_for_prompt(evidence_pack, facts_limit=facts_limit)
    facts_lines = []
    for fact in selected_facts:
        question_max = 54 if compact_mode else 90
        answer_max = 96 if compact_mode else 150
        question_text = (fact.get("question", "") or "").replace("\n", " ").strip()[:question_max]
        answer_text = (fact.get("answer", "") or "").replace("\n", " ").strip()[:answer_max]
        facts_lines.append(
            f"- {fact.get('q_id')} [{fact.get('dimension_name', '未分类')}] "
            f"Q: {question_text} | A: {answer_text} | quality={fact.get('quality_score', 0):.2f} | evidence={fact.get('answer_evidence_class', 'explicit')}"
        )
    facts_text = "\n".join(facts_lines) if facts_lines else "- 无有效问答证据"
    facts_source_count = len(evidence_pack.get("facts", [])) if isinstance(evidence_pack.get("facts", []), list) else 0

    contradictions = evidence_pack.get("contradictions", [])
    if compact_mode:
        contradiction_limit = min(contradiction_limit, 6)
        unknown_limit = min(unknown_limit, 6)
        blindspot_limit = min(blindspot_limit, 6)

    contradiction_lines = [
        f"- {item.get('detail')}（证据: {', '.join(item.get('evidence_refs', []))}）"
        for item in contradictions[:contradiction_limit]
    ]
    contradiction_text = "\n".join(contradiction_lines) if contradiction_lines else "- 未发现明显冲突"

    unknowns = evidence_pack.get("unknowns", [])
    unknown_lines = [
        f"- {item.get('q_id')} [{item.get('dimension')}] {item.get('reason')}"
        for item in unknowns[:unknown_limit]
    ]
    unknown_text = "\n".join(unknown_lines) if unknown_lines else "- 未发现明显模糊回答"

    blindspots = evidence_pack.get("blindspots", [])
    blindspot_lines = [
        f"- {item.get('dimension')}: {item.get('aspect')}"
        for item in blindspots[:blindspot_limit]
    ]
    blindspot_text = "\n".join(blindspot_lines) if blindspot_lines else "- 暂无盲区"
    action_strategy = _derive_action_generation_strategy_v3(evidence_pack)
    action_strategy_text = (
        f"- facts={action_strategy.get('facts_count', 0)}，盲区={action_strategy.get('blindspots_count', 0)}，"
        f"unknown_ratio={float(action_strategy.get('unknown_ratio', 0.0)):.0%}，平均质量={float(action_strategy.get('average_quality_score', 0.0)):.0%}，"
        f"pick_only={float(action_strategy.get('pick_only_ratio', 0.0)):.0%}，low_intent={float(action_strategy.get('low_intent_ratio', 0.0)):.0%}"
    )
    if int(action_strategy.get("min_actions", 2) or 2) <= 1:
        action_constraint = "actions 至少 1 条，但只保留高证据或高可验证的近期动作；若缺少强 evidence_refs，宁可转为 open_questions，不得为了凑条数硬写行动项。"
    elif int(action_strategy.get("min_actions", 2) or 2) == 2:
        if action_strategy.get("prefer_open_questions"):
            action_constraint = "actions 至少 2 条，优先选择高证据动作；证据不足时，不要扩写到 3 条，应把不确定内容写进 open_questions，timeline 以近期/中期验证为主。"
        else:
            action_constraint = "actions 至少 2 条，并尽量覆盖短期与中期里程碑。"
    else:
        action_constraint = "actions 至少 3 条（证据不足时至少 2 条），且 timeline 需覆盖短期与中期里程碑。"

    schema_example = {
        "overview": "访谈概述（2-4段）",
        "needs": [
            {
                "name": "核心需求名称",
                "priority": "P0",
                "description": "需求描述",
                "evidence_refs": ["Q1", "Q3"]
            }
        ],
        "analysis": {
            "customer_needs": "客户/用户需求分析",
            "business_flow": "业务流程分析",
            "tech_constraints": "技术约束分析",
            "project_constraints": "项目约束分析"
        },
        "visualizations": {
            "priority_quadrant_mermaid": "可选，quadrantChart ...",
            "business_flow_mermaid": "可选，flowchart TD ...",
            "demand_pie_mermaid": "可选，pie title ...",
            "architecture_mermaid": "可选，flowchart LR ..."
        },
        "solutions": [
            {
                "title": "方案建议标题",
                "description": "方案说明",
                "owner": "负责角色",
                "timeline": "时间计划",
                "metric": "验收指标",
                "evidence_refs": ["Q2", "Q8"]
            }
        ],
        "risks": [
            {
                "risk": "风险项",
                "impact": "影响",
                "mitigation": "缓解措施",
                "evidence_refs": ["Q6"]
            }
        ],
        "actions": [
            {
                "action": "下一步行动",
                "owner": "负责人角色",
                "timeline": "预计时间",
                "metric": "完成标准",
                "evidence_refs": ["Q4"]
            }
        ],
        "open_questions": [
            {
                "question": "未决问题",
                "reason": "为何未决",
                "impact": "影响范围",
                "suggested_follow_up": "建议补充追问",
                "evidence_refs": ["Q7"]
            }
        ],
        "evidence_index": [
            {
                "claim": "关键结论",
                "confidence": "high",
                "evidence_refs": ["Q1", "Q5"]
            }
        ]
    }

    if compact_mode:
        schema_example = {
            "overview": "访谈概述",
            "needs": [{"name": "需求", "priority": "P0", "description": "描述", "evidence_refs": ["Q1"]}],
            "analysis": {
                "customer_needs": "客户需求分析",
                "business_flow": "业务流程分析",
                "tech_constraints": "技术约束分析",
                "project_constraints": "项目约束分析"
            },
            "solutions": [{"title": "方案", "description": "说明", "owner": "角色", "timeline": "短期", "metric": "指标", "evidence_refs": ["Q2"]}],
            "risks": [{"risk": "风险", "impact": "影响", "mitigation": "缓解", "evidence_refs": ["Q3"]}],
            "actions": [{"action": "行动", "owner": "角色", "timeline": "短期/中期", "metric": "验收口径", "evidence_refs": ["Q4"]}],
            "open_questions": [{"question": "待补问题", "reason": "原因", "impact": "影响", "suggested_follow_up": "追问方向", "evidence_refs": ["Q5"]}],
            "evidence_index": [{"claim": "关键结论", "confidence": "high", "evidence_refs": ["Q1", "Q2"]}],
        }

    return f"""你是一名资深分析顾问。请基于给定证据包生成一份结构化报告草案 JSON，禁止输出任何 JSON 之外的文字。

## 任务类型
- 报告类型：{report_type_label}
- 主题：{topic}
{f"- 主题描述：{description}" if description else ""}

## 维度覆盖快照
{dimension_text}

## 关键证据（按问答编号）
（原始 {facts_source_count} 条，已筛选 {len(selected_facts)} 条高价值证据）
{facts_text}

## 冲突信号
{contradiction_text}

## 模糊与不确定信号
{unknown_text}

## 盲区清单（必须优先补齐）
{blindspot_text}

## 证据密度策略
{action_strategy_text}

## 输出硬性约束
1. 输出必须是合法 JSON 对象，首字符是 {{，末字符是 }}。
2. 所有关键结论都要携带 evidence_refs（格式必须是 Q数字）。
3. solutions/actions 每一项必须包含 owner、timeline、metric。
4. 若存在冲突信号，必须在 risks 或 open_questions 中显式处理。
5. 若存在盲区，必须在 open_questions 中体现对应补问。
6. visualizations 字段可选；即使填写也仅作为补充参考，最终图表由后端按结构化数据渲染。
7. 不得编造证据编号，不得引用不存在的 Q 编号。
8. 禁止输出任何工具流程话术：如“请确认是否继续”“需要先征得同意”“我会创建文件”等。
9. 禁止输出 markdown 代码块、注释、额外解释或前后缀文本。
10. 顶层字段必须仅包含：overview/needs/analysis/visualizations/solutions/risks/actions/open_questions/evidence_index。
11. 草案采用“咨询交付风格”：描述简洁、结论先行、避免口语与空泛表述。
12. {action_constraint}
13. 证据稀疏、盲区偏多或低信号占比高时，优先把不确定内容写进 open_questions；没有强 evidence_refs 时不要为了凑条数硬写行动项。
14. needs/solutions/risks/actions 要满足表格化呈现：每项字段完整，单项表达尽量控制在 70 字内。

## 风格锁定模板（审稿会按此门禁）
- 2.需求摘要：needs 必须可直接渲染为表格（优先级/需求项/描述/证据）。
- 5.方案建议：solutions 必须可直接渲染为表格（标题/说明/owner/timeline/metric/证据）。
- 6.风险评估：risks 必须可直接渲染为表格（风险/影响/缓解/证据）。
- 7.下一步行动：actions 必须可直接渲染为表格（行动/owner/timeline/metric/证据），并体现里程碑层次。
- open_questions 必须对齐盲区或冲突，避免泛化问题。

## JSON 模板（字段必须完整）
{json.dumps(schema_example, ensure_ascii=False, indent=2)}
"""


def resolve_custom_report_source_value_v3(draft: dict, source: str) -> object:
    source_key = str(source or "").strip()
    if not source_key:
        return ""

    if source_key == "overview":
        return draft.get("overview", "")
    if source_key in {"needs", "solutions", "risks", "actions", "open_questions", "evidence_index"}:
        value = draft.get(source_key, [])
        return value if isinstance(value, list) else []
    if source_key == "priority_list":
        value = draft.get("needs", [])
        return value if isinstance(value, list) else []
    if source_key == "priority_matrix":
        visuals = draft.get("visualizations", {})
        if isinstance(visuals, dict):
            return str(visuals.get("priority_quadrant_mermaid", "") or "").strip()
        return ""

    if source_key.startswith("analysis."):
        _, _, field = source_key.partition(".")
        analysis = draft.get("analysis", {})
        if isinstance(analysis, dict):
            return analysis.get(field, "")
        return ""

    if source_key.startswith("visualizations."):
        _, _, field = source_key.partition(".")
        visuals = draft.get("visualizations", {})
        if isinstance(visuals, dict):
            return visuals.get(field, "")
        return ""

    return ""


def is_custom_report_source_empty_v3(value: object) -> bool:
    if value is None:
        return True
    if isinstance(value, str):
        return not str(value or "").strip()
    if isinstance(value, list):
        return len(value) == 0
    if isinstance(value, dict):
        return len(value) == 0
    return False


def validate_report_draft_v3(draft: dict, evidence_pack: dict) -> tuple[dict, list]:
    """校验并标准化 V3 报告草案。"""
    issues = []
    template_name = normalize_report_template_name(
        (evidence_pack or {}).get("report_template", ""),
        report_type=(evidence_pack or {}).get("report_type", "standard"),
    )

    def sanitize_text(value) -> str:
        return strip_inline_evidence_markers(str(value or "").strip())

    def add_issue(issue_type: str, severity: str, message: str, target: str):
        issues.append({
            "type": issue_type,
            "severity": severity,
            "message": message,
            "target": target,
        })

    if not isinstance(draft, dict):
        add_issue("structure_error", "high", "草案不是 JSON 对象", "root")
        return {}, issues

    normalized = {
        "overview": sanitize_text(draft.get("overview", "")),
        "needs": [],
        "analysis": {
            "customer_needs": "",
            "business_flow": "",
            "tech_constraints": "",
            "project_constraints": "",
        },
        "visualizations": {
            "priority_quadrant_mermaid": "",
            "business_flow_mermaid": "",
            "demand_pie_mermaid": "",
            "architecture_mermaid": "",
        },
        "solutions": [],
        "risks": [],
        "actions": [],
        "open_questions": [],
        "evidence_index": [],
    }

    valid_q_refs = {
        str(item.get("q_id", "")).upper().strip()
        for item in evidence_pack.get("facts", [])
        if isinstance(item, dict) and re.fullmatch(r"Q\d+", str(item.get("q_id", "")).upper().strip())
    }

    def normalize_evidence_refs_for_target(raw_refs, target: str) -> list:
        refs = _normalize_evidence_refs(raw_refs)
        if not refs:
            return []
        if not valid_q_refs:
            add_issue("invalid_evidence_ref", "high", "证据包缺少可用问答编号，无法验证证据引用", target)
            return []

        invalid_refs = [ref for ref in refs if ref not in valid_q_refs]
        if invalid_refs:
            add_issue(
                "invalid_evidence_ref",
                "high",
                f"包含无效证据引用：{', '.join(invalid_refs)}",
                target
            )

        return [ref for ref in refs if ref in valid_q_refs]

    analysis = draft.get("analysis", {})
    if isinstance(analysis, dict):
        for key in normalized["analysis"]:
            normalized["analysis"][key] = sanitize_text(analysis.get(key, ""))

    visualizations = draft.get("visualizations", {})
    if isinstance(visualizations, dict):
        for key in normalized["visualizations"]:
            normalized["visualizations"][key] = str(visualizations.get(key, "")).strip()

    if not normalized["overview"]:
        add_issue("structure_error", "high", "overview 不能为空", "overview")

    needs = draft.get("needs", [])
    if isinstance(needs, list):
        for idx, item in enumerate(needs):
            if not isinstance(item, dict):
                add_issue("structure_error", "medium", "needs 项必须是对象", f"needs[{idx}]")
                continue
            refs = normalize_evidence_refs_for_target(item.get("evidence_refs", []), f"needs[{idx}].evidence_refs")
            normalized_item = {
                "name": sanitize_text(item.get("name", "")),
                "priority": str(item.get("priority", "P1")).strip().upper() or "P1",
                "description": sanitize_text(item.get("description", "")),
                "evidence_refs": refs,
                "evidence_binding_mode": str(item.get("evidence_binding_mode", "") or "").strip().lower(),
            }
            if refs and not normalized_item["evidence_binding_mode"]:
                normalized_item["evidence_binding_mode"] = "strong_explicit"
            if not normalized_item["name"]:
                add_issue("structure_error", "medium", "needs.name 不能为空", f"needs[{idx}].name")
            if not refs:
                add_issue("no_evidence", "high", "核心需求缺少证据引用", f"needs[{idx}]")
            normalized["needs"].append(normalized_item)

    for field, id_field in [("solutions", "title"), ("risks", "risk"), ("actions", "action"), ("open_questions", "question"), ("evidence_index", "claim")]:
        values = draft.get(field, [])
        if not isinstance(values, list):
            add_issue("structure_error", "medium", f"{field} 必须是数组", field)
            continue
        for idx, item in enumerate(values):
            if not isinstance(item, dict):
                add_issue("structure_error", "medium", f"{field} 项必须是对象", f"{field}[{idx}]")
                continue
            refs = normalize_evidence_refs_for_target(item.get("evidence_refs", []), f"{field}[{idx}].evidence_refs")
            normalized_item = dict(item)
            normalized_item[id_field] = sanitize_text(item.get(id_field, ""))
            normalized_item["evidence_refs"] = refs
            normalized_item["evidence_binding_mode"] = str(item.get("evidence_binding_mode", "") or "").strip().lower()
            if refs and not normalized_item["evidence_binding_mode"]:
                normalized_item["evidence_binding_mode"] = "strong_explicit"

            if field in {"solutions", "actions"}:
                normalized_item["owner"] = sanitize_text(item.get("owner", ""))
                normalized_item["timeline"] = sanitize_text(item.get("timeline", ""))
                normalized_item["metric"] = sanitize_text(item.get("metric", ""))
                if not (normalized_item["owner"] and normalized_item["timeline"] and normalized_item["metric"]):
                    add_issue("not_actionable", "medium", f"{field} 缺少 owner/timeline/metric", f"{field}[{idx}]")

            if field == "risks":
                normalized_item["impact"] = sanitize_text(item.get("impact", ""))
                normalized_item["mitigation"] = sanitize_text(item.get("mitigation", ""))

            if field == "open_questions":
                normalized_item["reason"] = sanitize_text(item.get("reason", ""))
                normalized_item["impact"] = sanitize_text(item.get("impact", ""))
                normalized_item["suggested_follow_up"] = sanitize_text(item.get("suggested_follow_up", ""))

            if field == "evidence_index":
                confidence = str(item.get("confidence", "medium")).strip().lower()
                if confidence not in {"high", "medium", "low"}:
                    confidence = "medium"
                normalized_item["confidence"] = confidence

            if not normalized_item.get(id_field):
                add_issue("structure_error", "medium", f"{field}.{id_field} 不能为空", f"{field}[{idx}].{id_field}")
            if field == "open_questions" and not refs:
                if normalized_item.get("evidence_binding_mode") != "weak_inferred":
                    normalized_item["evidence_binding_mode"] = "pending_follow_up"
            elif not refs:
                add_issue("no_evidence", "high", f"{field} 缺少证据引用", f"{field}[{idx}]")

            normalized[field].append(normalized_item)

    contradictions = evidence_pack.get("contradictions", [])
    contradiction_ref_pool = set()
    for field in ["risks", "open_questions", "actions", "solutions", "evidence_index"]:
        values = normalized.get(field, [])
        if not isinstance(values, list):
            continue
        for item in values:
            if not isinstance(item, dict):
                continue
            contradiction_ref_pool.update(_normalize_evidence_refs(item.get("evidence_refs", [])))

    unresolved_conflicts = 0
    for item in contradictions:
        refs = _normalize_evidence_refs(item.get("evidence_refs", []))
        if refs and not any(ref in contradiction_ref_pool for ref in refs):
            unresolved_conflicts += 1
    if unresolved_conflicts > 0:
        add_issue(
            "unresolved_contradiction",
            "high",
            f"存在 {unresolved_conflicts} 条冲突证据未在草案中处理",
            "risks/open_questions"
        )

    blindspot_text_segments = []
    blindspot_text_segments.extend(str(value or "") for value in normalized.get("analysis", {}).values())
    for field in ["open_questions", "actions", "solutions", "risks"]:
        values = normalized.get(field, [])
        if not isinstance(values, list):
            continue
        for item in values:
            if not isinstance(item, dict):
                continue
            blindspot_text_segments.extend([
                str(item.get("question", "") or ""),
                str(item.get("reason", "") or ""),
                str(item.get("impact", "") or ""),
                str(item.get("suggested_follow_up", "") or ""),
                str(item.get("action", "") or ""),
                str(item.get("description", "") or ""),
                str(item.get("risk", "") or ""),
                str(item.get("mitigation", "") or ""),
            ])
    blindspot_corpus = " ".join(blindspot_text_segments).lower()

    blindspots = evidence_pack.get("blindspots", [])
    unresolved_blindspots = []
    for item in blindspots:
        aspect = str(item.get("aspect", "")).strip()
        if aspect and aspect.lower() not in blindspot_corpus:
            unresolved_blindspots.append(aspect)
    if unresolved_blindspots:
        sample = "、".join(unresolved_blindspots[:5])
        add_issue(
            "blindspot",
            "medium",
            f"仍有未覆盖盲区未进入草案：{sample}",
            "open_questions"
        )

    if template_name == REPORT_TEMPLATE_CUSTOM_V1:
        report_schema = (evidence_pack or {}).get("report_schema", {})
        normalized_schema, schema_issues = normalize_custom_report_schema(report_schema)
        for item in schema_issues:
            add_issue("custom_schema_error", "high", str(item), "report_schema")
        for section in normalized_schema.get("sections", []):
            if not isinstance(section, dict):
                continue
            if not bool(section.get("required", False)):
                continue
            source = str(section.get("source", "")).strip()
            section_id = str(section.get("section_id", "") or source).strip() or "unknown"
            value = resolve_custom_report_source_value_v3(normalized, source)
            if is_custom_report_source_empty_v3(value):
                add_issue(
                    "custom_required_section_empty",
                    "high",
                    f"自定义模板必填章节缺少内容：{section.get('title', section_id)}",
                    f"custom_sections[{section_id}]",
                )

    return normalized, issues


def _report_review_response_schema_v3() -> dict:
    return {
        "passed": True,
        "issues": [
            {
                "type": "no_evidence",
                "severity": "high",
                "message": "问题描述",
                "target": "字段路径"
            }
        ],
        "revised_draft": {
            "overview": "修订后的 overview",
            "needs": [],
            "analysis": {},
            "visualizations": {},
            "solutions": [],
            "risks": [],
            "actions": [],
            "open_questions": [],
            "evidence_index": []
        }
    }


def build_report_review_prompt_v3(session: dict, evidence_pack: dict, draft: dict, issues: list) -> str:
    """构建 V3 审稿与修复 Prompt。"""
    topic = session.get("topic", "未知主题")
    contradiction_text = "\n".join(
        [f"- {item.get('detail')}（证据: {', '.join(item.get('evidence_refs', []))}）" for item in evidence_pack.get("contradictions", [])[:20]]
    ) or "- 无"
    blindspot_text = "\n".join(
        [f"- {item.get('dimension')}: {item.get('aspect')}" for item in evidence_pack.get("blindspots", [])[:20]]
    ) or "- 无"

    issue_text = "\n".join(
        [f"- [{item.get('severity', 'medium')}] {item.get('type')}: {item.get('message')} @ {item.get('target', 'unknown')}" for item in issues[:30]]
    ) or "- 无已知问题"

    response_schema = _report_review_response_schema_v3()

    return f"""你是报告质量审稿专家。请对草案执行一致性审稿并直接修复，输出 JSON。

## 访谈主题
{topic}

## 重点核查规则
1. no_evidence：关键结论或行动缺少 evidence_refs。
2. unresolved_contradiction：冲突证据没有被解释或处理。
3. not_actionable：行动建议缺少 owner/timeline/metric。
4. blindspot：盲区至少进入 open_questions；仅在证据充分时再进入 actions。
5. style_template_violation：章节模板偏离（数量不足、字段缺失、难以表格化）。
6. quality_gate_expression：表达结构不完整（概述、分析、建议、行动衔接弱）。
7. quality_gate_table：needs/solutions/risks/actions 的表格化可读性不足。
8. quality_gate_milestone：行动缺少短中期里程碑覆盖。

## 冲突证据
{contradiction_text}

## 盲区证据
{blindspot_text}

## 当前已知问题
{issue_text}

## 待审稿草案 JSON
{json.dumps(draft, ensure_ascii=False)}

## 输出要求
- 仅输出合法 JSON，禁止附加解释文字。
- 必须包含 passed、issues、revised_draft 三个字段。
- revised_draft 允许采用“增量修订”模式：
  - 未修改的顶层字段可以省略。
  - 若修改 needs/solutions/risks/actions/open_questions/evidence_index 任一数组字段，需返回该字段的完整数组。
  - analysis / visualizations 只返回被修改的子字段即可。
- 只有在多数顶层字段都被改动时，才返回完整 revised_draft。
- 若仍有问题，issues 需完整列出。
- 优先修复风格锁定问题：补齐可表格化字段，避免段落堆叠和口语化表述。
- actions 至少 3 条（证据不足可 2 条），timeline 需覆盖短期和中期。
- 对盲区项优先补齐 open_questions；若证据仍不足，可先以 pending_follow_up 标记并给出补采动作。
- 不要引入模板外新字段作为硬门槛（例如 needs.acceptance_criteria 不是必填）。
- 禁止输出“请确认是否继续”“我会创建文件”等工具执行话术。
- 禁止输出 markdown 代码块与额外说明，禁止前后缀文本。

## 输出模板
{json.dumps(response_schema, ensure_ascii=False, indent=2)}
"""


def build_report_review_repair_prompt_v3(raw_review: str, draft: dict, review_issues: list) -> str:
    """当审稿响应无法解析时，要求模型只做结构化转写与轻修复。"""
    issue_text = "\n".join(
        [f"- [{item.get('severity', 'medium')}] {item.get('type')}: {item.get('message')} @ {item.get('target', 'unknown')}" for item in review_issues[:20]]
    ) or "- 无已知问题"
    response_schema = _report_review_response_schema_v3()

    return f"""你是 JSON 修复助手。以下内容是上一轮审稿模型的原始输出，但当前系统无法解析。

你的任务不是重新长篇审稿，而是基于原始输出和当前草案，整理出一个合法 JSON。

## 当前已知问题
{issue_text}

## 当前草案 JSON
{json.dumps(draft, ensure_ascii=False)}

## 原始审稿输出
{str(raw_review or '')[:12000]}

## 修复要求
- 仅输出合法 JSON，禁止 markdown 代码块、解释文字、前后缀文本。
- 必须包含 passed、issues、revised_draft 三个字段。
- 若原始输出已表达“通过”，passed=true；否则按内容谨慎判断。
- revised_draft 可为空对象 {{}}，但必须是对象。
- issues 必须是数组；数组元素包含 type、severity、message、target。
- 不要新增模板外顶层字段。
- 如果原始输出信息不足，请保守返回 passed=false，并在 issues 中说明无法解析的关键问题。

## 输出模板
{json.dumps(response_schema, ensure_ascii=False, indent=2)}
"""


def parse_report_review_response_v3(raw_text: str, parse_meta: Optional[dict] = None) -> Optional[dict]:
    """解析 V3 审稿响应。"""
    parsed = parse_structured_json_response(
        raw_text,
        required_keys=["passed", "issues", "revised_draft"],
        require_all_keys=True,
        parse_meta=parse_meta,
    )
    if not parsed:
        return None

    issues = []
    raw_issues = parsed.get("issues", [])
    if isinstance(raw_issues, list):
        for item in raw_issues:
            if not isinstance(item, dict):
                continue
            issues.append({
                "type": str(item.get("type", "unknown")).strip(),
                "severity": str(item.get("severity", "medium")).strip().lower() or "medium",
                "message": str(item.get("message", "")).strip(),
                "target": str(item.get("target", "unknown")).strip(),
            })

    revised_draft = parsed.get("revised_draft", {})
    if not isinstance(revised_draft, dict):
        revised_draft = {}

    return {
        "passed": bool(parsed.get("passed", False)),
        "issues": issues,
        "revised_draft": revised_draft,
    }


def repair_report_review_response_v3(
    review_raw: str,
    current_draft: dict,
    review_issues: list,
    preferred_lane: str,
    review_round_no: int,
    call_type_suffix: str = "",
    max_tokens: int = 2200,
    timeout: float = 45.0,
) -> tuple[Optional[dict], dict, str]:
    """对无法解析的审稿输出发起一次严格 JSON 修复重试。"""
    if not REPORT_V3_REVIEW_REPAIR_RETRY_ENABLED or not review_raw:
        return None, {"attempted": False, "last_error": ""}, ""

    repair_prompt = build_report_review_repair_prompt_v3(review_raw, current_draft, review_issues)
    repair_call_type = f"report_v3_review_parse_repair_round_{max(1, int(review_round_no or 1))}{call_type_suffix}"
    repair_raw = call_claude(
        repair_prompt,
        max_tokens=max_tokens,
        call_type=repair_call_type,
        timeout=timeout,
        preferred_lane=preferred_lane,
    )
    repair_parse_meta = {
        "attempted": True,
        "repair_call_type": repair_call_type,
        "last_error": "",
    }
    if not repair_raw:
        repair_parse_meta["last_error"] = "repair_generation_failed"
        return None, repair_parse_meta, ""

    parsed_meta = {}
    repaired = parse_report_review_response_v3(repair_raw, parse_meta=parsed_meta)
    repair_parse_meta.update({
        "repair_applied": bool(parsed_meta.get("repair_applied", False)),
        "selected_source": str(parsed_meta.get("selected_source", "") or ""),
        "candidate_count": int(parsed_meta.get("candidate_count", 0) or 0),
        "parse_attempts": int(parsed_meta.get("parse_attempts", 0) or 0),
        "missing_keys": list(parsed_meta.get("missing_keys", []) or []),
        "last_error": str(parsed_meta.get("last_error", "") or repair_parse_meta.get("last_error", "")),
    })
    if not repaired and not repair_parse_meta.get("last_error"):
        repair_parse_meta["last_error"] = "repair_parse_failed"
    return repaired, repair_parse_meta, repair_raw or ""


def merge_report_draft_patch_v3(base_draft: dict, revised_patch: dict) -> dict:
    """将审稿阶段的增量 patch 合并回完整草案，减少长 JSON 输出压力。"""
    base = copy.deepcopy(base_draft) if isinstance(base_draft, dict) else {}
    patch = revised_patch if isinstance(revised_patch, dict) else {}
    if not patch:
        return base

    merged = copy.deepcopy(base)

    if "overview" in patch:
        merged["overview"] = patch.get("overview", "")

    for field in ("analysis", "visualizations"):
        if field in patch and isinstance(patch.get(field), dict):
            current_value = merged.get(field, {})
            if not isinstance(current_value, dict):
                current_value = {}
            current_value = dict(current_value)
            current_value.update(patch.get(field, {}))
            merged[field] = current_value

    for field in ("needs", "solutions", "risks", "actions", "open_questions", "evidence_index"):
        if field in patch and isinstance(patch.get(field), list):
            merged[field] = patch.get(field, [])

    return merged


def resolve_report_v3_alternate_lane(primary_lane: str) -> str:
    """为 V3 阶段选择可用且独立的备用 lane。"""
    primary = str(primary_lane or "").strip().lower()
    if primary not in {"question", "report"}:
        return ""
    alternate = "question" if primary == "report" else "report"
    primary_client = resolve_ai_client(preferred_lane=primary)
    alternate_client = resolve_ai_client(preferred_lane=alternate)
    if not primary_client or not alternate_client or primary_client is alternate_client:
        return ""
    return alternate


REVIEW_BLOCKING_ISSUE_TYPES_V3 = {
    "no_evidence",
    "unresolved_contradiction",
    "not_actionable",
    "blindspot",
    "structure_error",
    "invalid_evidence_ref",
}
REVIEW_GATE_MANAGED_ISSUE_PREFIXES_V3 = ("quality_gate_",)
REVIEW_GATE_MANAGED_ISSUE_TYPES_V3 = {"style_template_violation"}


def summarize_issue_types_v3(issues: list) -> list[str]:
    """提取问题类型列表并去重，保持原始顺序。"""
    if not isinstance(issues, list):
        return []
    output = []
    seen = set()
    for item in issues:
        if not isinstance(item, dict):
            continue
        issue_type = str(item.get("type", "") or "").strip().lower()
        if not issue_type or issue_type in seen:
            continue
        seen.add(issue_type)
        output.append(issue_type)
    return output


def _is_quality_gate_issue_type_v3(issue_type: str) -> bool:
    normalized = str(issue_type or "").strip().lower()
    return normalized.startswith(REVIEW_GATE_MANAGED_ISSUE_PREFIXES_V3) or normalized in REVIEW_GATE_MANAGED_ISSUE_TYPES_V3


def _extract_blindspot_aspect_from_text_v3(text: str) -> str:
    source = str(text or "").strip()
    if not source:
        return ""

    quoted = re.findall(r"[\"'“‘](.+?)[\"'”’]", source)
    if quoted:
        candidate = quoted[0]
        if ":" in candidate:
            candidate = candidate.split(":", 1)[1]
        if "：" in candidate:
            candidate = candidate.split("：", 1)[1]
        candidate = candidate.strip()
        if candidate:
            return candidate

    if "未覆盖盲区未进入草案" in source:
        tail = source.split("未覆盖盲区未进入草案", 1)[-1]
        tail = tail.lstrip("：: ").strip()
        if tail:
            return tail.split("、")[0].strip()
    return ""


def _collect_text_corpus_for_items_v3(items: list, keys: list[str]) -> str:
    if not isinstance(items, list):
        return ""
    seg = []
    for item in items:
        if not isinstance(item, dict):
            continue
        for key in keys:
            text = str(item.get(key, "") or "").strip()
            if text:
                seg.append(text.lower())
    return " ".join(seg)


def _is_evidence_sparse_v3(evidence_pack: Optional[dict]) -> bool:
    if not isinstance(evidence_pack, dict):
        return False
    facts = evidence_pack.get("facts", [])
    unknowns = evidence_pack.get("unknowns", [])
    quality_snapshot = evidence_pack.get("quality_snapshot", {})
    facts_count = len(facts) if isinstance(facts, list) else 0
    unknown_count = len(unknowns) if isinstance(unknowns, list) else 0
    unknown_ratio = (unknown_count / facts_count) if facts_count > 0 else 0.0
    avg_quality = _safe_float((quality_snapshot or {}).get("average_quality_score", 0.0), default=0.0)
    return unknown_ratio >= REPORT_V3_UNKNOWN_RATIO_TRIGGER or avg_quality <= 0.32


def _derive_action_generation_strategy_v3(evidence_pack: Optional[dict]) -> dict:
    """根据证据密度决定 actions 的最小数量与生成策略。"""
    strategy = {
        "facts_count": 0,
        "blindspots_count": 0,
        "unknown_count": 0,
        "unknown_ratio": 0.0,
        "average_quality_score": 0.0,
        "pick_only_ratio": 0.0,
        "low_intent_ratio": 0.0,
        "sparse_evidence": False,
        "low_signal_pressure": False,
        "prefer_open_questions": False,
        "min_actions": 2,
        "timeline_expectation": "short_and_mid",
    }
    if not isinstance(evidence_pack, dict):
        return strategy

    facts = evidence_pack.get("facts", [])
    blindspots = evidence_pack.get("blindspots", [])
    unknowns = evidence_pack.get("unknowns", [])
    quality_snapshot = evidence_pack.get("quality_snapshot", {})
    facts_count = len(facts) if isinstance(facts, list) else 0
    blindspots_count = len(blindspots) if isinstance(blindspots, list) else 0
    unknown_count = len(unknowns) if isinstance(unknowns, list) else 0
    unknown_ratio = (unknown_count / facts_count) if facts_count > 0 else 0.0
    avg_quality = max(0.0, min(1.0, _safe_float((quality_snapshot or {}).get("average_quality_score", 0.0), default=0.0)))

    total_formal = max(0, int((quality_snapshot or {}).get("total_formal_questions", 0) or 0))
    answer_mode_distribution = (quality_snapshot or {}).get("answer_mode_distribution", {})
    evidence_intent_distribution = (quality_snapshot or {}).get("evidence_intent_distribution", {})
    if not isinstance(answer_mode_distribution, dict):
        answer_mode_distribution = {}
    if not isinstance(evidence_intent_distribution, dict):
        evidence_intent_distribution = {}

    pick_only_ratio = (
        max(0, int(answer_mode_distribution.get("pick_only", 0) or 0)) / total_formal
        if total_formal > 0 else 0.0
    )
    low_intent_ratio = (
        max(0, int(evidence_intent_distribution.get("low", 0) or 0)) / total_formal
        if total_formal > 0 else 0.0
    )
    sparse_evidence = _is_evidence_sparse_v3(evidence_pack)
    low_signal_pressure = total_formal > 0 and (pick_only_ratio >= 0.55 or low_intent_ratio >= 0.55)

    min_actions = 3 if facts_count >= 10 else 2
    timeline_expectation = "short_and_mid"
    prefer_open_questions = bool(sparse_evidence or blindspots_count >= 8 or low_signal_pressure)

    if facts_count <= 3 and blindspots_count >= 8 and (unknown_ratio >= 0.25 or avg_quality <= 0.58 or low_signal_pressure):
        min_actions = 1
        timeline_expectation = "short_only"
        prefer_open_questions = True
    elif facts_count <= 6 and (blindspots_count >= 6 or unknown_ratio >= 0.40 or avg_quality <= 0.42 or low_signal_pressure):
        min_actions = min(min_actions, 2)
        timeline_expectation = "short_preferred"
        prefer_open_questions = True

    strategy.update({
        "facts_count": facts_count,
        "blindspots_count": blindspots_count,
        "unknown_count": unknown_count,
        "unknown_ratio": round(unknown_ratio, 3),
        "average_quality_score": round(avg_quality, 3),
        "pick_only_ratio": round(pick_only_ratio, 3),
        "low_intent_ratio": round(low_intent_ratio, 3),
        "sparse_evidence": bool(sparse_evidence),
        "low_signal_pressure": bool(low_signal_pressure),
        "prefer_open_questions": bool(prefer_open_questions),
        "min_actions": int(min_actions),
        "timeline_expectation": timeline_expectation,
    })
    return strategy


def _pick_evidence_refs_for_dimension_v3(evidence_pack: dict, dimension_hint: str = "", limit: int = 1) -> list[str]:
    if not isinstance(evidence_pack, dict):
        return []
    facts = evidence_pack.get("facts", [])
    if not isinstance(facts, list):
        return []

    normalized_hint = str(dimension_hint or "").strip().lower()
    picked = []
    for fact in facts:
        if not isinstance(fact, dict):
            continue
        q_id = str(fact.get("q_id", "") or "").upper().strip()
        if not re.fullmatch(r"Q\d+", q_id):
            continue
        if normalized_hint:
            fact_dim = str(fact.get("dimension", "") or "").strip().lower()
            fact_dim_name = str(fact.get("dimension_name", "") or "").strip().lower()
            if normalized_hint not in {fact_dim, fact_dim_name} and normalized_hint not in fact_dim_name and normalized_hint not in fact_dim:
                continue
        picked.append(q_id)
        if len(picked) >= max(1, int(limit or 1)):
            break
    return _normalize_evidence_refs(picked)


def _build_blindspot_open_question_v3(dimension: str, aspect: str, evidence_pack: dict) -> dict:
    dim_text = str(dimension or "相关维度").strip()
    aspect_text = str(aspect or "关键未覆盖点").strip()
    refs = _pick_evidence_refs_for_dimension_v3(evidence_pack, dimension_hint=dim_text, limit=1)
    return {
        "question": f"{dim_text}中的“{aspect_text}”缺少直接证据，是否需要补采访谈？",
        "reason": "该盲区会影响结论可信度，先记录为待验证问题并补采证据",
        "impact": f"{aspect_text}未澄清会影响行动优先级与方案可行性判断",
        "suggested_follow_up": f"围绕“{aspect_text}”补充角色、场景与量化口径，并确认责任边界",
        "evidence_refs": refs,
        "evidence_binding_mode": "pending_follow_up" if not refs else "weak_inferred",
    }


def _normalize_dimension_hint_v3(dimension: str) -> str:
    text = str(dimension or "").strip().lower()
    if not text:
        return ""
    aliases = {
        "customer_needs": "customer_needs",
        "客户需求": "customer_needs",
        "business_process": "business_process",
        "business_flow": "business_process",
        "业务流程": "business_process",
        "tech_constraints": "tech_constraints",
        "技术约束": "tech_constraints",
        "技术限制": "tech_constraints",
        "project_constraints": "project_constraints",
        "项目约束": "project_constraints",
        "项目限制": "project_constraints",
    }
    if text in aliases:
        return aliases[text]
    for raw_key, normalized in aliases.items():
        if raw_key and raw_key in text:
            return normalized
    return text


def _infer_default_action_owner_v3(text: str, dimension: str = "") -> str:
    corpus = f"{str(text or '').strip().lower()} {str(dimension or '').strip().lower()}".strip()
    if not corpus:
        return "产品经理"

    if any(token in corpus for token in ("研发", "技术", "接口", "api", "系统", "架构", "数据", "稳定性", "性能", "开发", "上线")):
        return "技术负责人"
    if any(token in corpus for token in ("排期", "里程碑", "推进", "协调", "资源", "项目", "验收", "复盘")):
        return "项目经理"

    normalized_dimension = _normalize_dimension_hint_v3(dimension)
    if normalized_dimension == "business_process":
        return "业务负责人"
    if normalized_dimension == "tech_constraints":
        return "技术负责人"
    if normalized_dimension == "project_constraints":
        return "项目经理"
    if normalized_dimension == "customer_needs":
        return "产品经理"

    if any(token in corpus for token in ("访谈", "补采", "澄清", "确认", "需求", "客户", "分工", "流程", "规则")):
        return "产品经理"
    return "业务负责人"


def _infer_default_action_timeline_v3(text: str, field: str = "actions") -> str:
    corpus = str(text or "").strip().lower()
    if any(token in corpus for token in ("补采", "澄清", "确认", "梳理", "对齐", "盘点", "访谈", "分工", "职责", "边界")):
        return "1-2周内"
    if any(token in corpus for token in ("试点", "上线", "改造", "接入", "开发", "实施", "落地", "优化", "建设")):
        return "2-4周内"
    if field == "solutions":
        return "2-4周内"
    return "1-2周内"


def _is_action_timeline_specific_v3(value: str) -> bool:
    text = str(value or "").strip()
    if not text:
        return False
    vague_tokens = ("尽快", "近期", "后续", "择期", "适时", "后面", "后期", "待定", " asap", "soon")
    lower_text = text.lower()
    if any(token in lower_text for token in vague_tokens):
        return False
    specific_markers = ("天", "周", "月", "季度", "q1", "q2", "q3", "q4", "本周", "下周", "本月", "下月", "内")
    return any(marker in lower_text for marker in specific_markers) or bool(re.search(r"\d", text))


def _infer_default_action_metric_v3(text: str, dimension: str = "", field: str = "actions") -> str:
    corpus = f"{str(text or '').strip().lower()} {str(dimension or '').strip().lower()}".strip()
    if any(token in corpus for token in ("分工", "职责", "责任", "边界")):
        return "完成至少3位相关角色访谈并沉淀责任边界文档"
    if any(token in corpus for token in ("补采", "澄清", "确认", "访谈", "盘点", "梳理")):
        return "完成至少3条可追溯证据并更新结论"
    if any(token in corpus for token in ("试点", "上线", "改造", "接入", "优化", "开发", "实施")):
        return "形成验收记录并完成一次复盘"
    if field == "solutions":
        return "形成方案评审纪要并确认验收口径"
    return "形成负责人与时间表，并输出一次验收记录"


def _infer_action_owner_timeline_metric_v3(
    field: str,
    item: dict,
    evidence_pack: Optional[dict] = None,
    dimension_hint: str = "",
) -> dict:
    if not isinstance(item, dict):
        return {"owner": "", "timeline": "", "metric": ""}

    item_dimension = str(item.get("dimension", "") or "").strip()
    inferred_dimension = item_dimension or dimension_hint
    if not inferred_dimension and isinstance(evidence_pack, dict):
        inferred_dimension = _infer_item_dimension_key_v3(field, item, evidence_pack)

    text_parts = [
        str(item.get("title", "") or ""),
        str(item.get("description", "") or ""),
        str(item.get("action", "") or ""),
        str(item.get("risk", "") or ""),
        str(item.get("impact", "") or ""),
        str(item.get("mitigation", "") or ""),
    ]
    text = " ".join(part for part in text_parts if part).strip()

    owner = str(item.get("owner", "") or "").strip() or _infer_default_action_owner_v3(text, inferred_dimension)
    current_timeline = str(item.get("timeline", "") or "").strip()
    timeline = current_timeline if _is_action_timeline_specific_v3(current_timeline) else _infer_default_action_timeline_v3(text, field=field)
    current_metric = str(item.get("metric", "") or "").strip()
    if field == "actions":
        metric = current_metric if module_is_action_metric_measurable_v3(current_metric) else _infer_default_action_metric_v3(text, inferred_dimension, field=field)
    elif field == "solutions":
        metric = current_metric or _infer_default_action_metric_v3(text, inferred_dimension, field=field)
    else:
        metric = current_metric or _infer_default_action_metric_v3(text, inferred_dimension, field=field)
    return {"owner": owner, "timeline": timeline, "metric": metric}


def _should_soft_pass_not_actionable_issue_v3(issue: dict, draft: dict) -> bool:
    if not isinstance(issue, dict) or not isinstance(draft, dict):
        return False
    if str(issue.get("type", "") or "").strip().lower() != "not_actionable":
        return False

    target = str(issue.get("target", "") or "").strip()
    field, index = _extract_issue_field_index_v3(target)
    normalized_target = target.lower()
    if normalized_target == "actions":
        field = "actions"
        index = -1
    elif field not in {"solutions", "actions"} or index < 0:
        return False

    values = draft.get(field, [])
    if not isinstance(values, list) or index >= len(values):
        return False
    item = values[index]
    if not isinstance(item, dict):
        return False

    owner = str(item.get("owner", "") or "").strip()
    timeline = str(item.get("timeline", "") or "").strip()
    metric = str(item.get("metric", "") or "").strip()
    if not (owner and metric and _is_action_timeline_specific_v3(timeline)):
        if field != "actions" or target != "actions":
            return False
    else:
        return True

    message = str(issue.get("message", "") or "").strip().lower()
    if not any(token in message for token in ("长期", "全周期", "运营", "复盘", "机制", "闭环")):
        return False

    for candidate in values:
        if not isinstance(candidate, dict):
            continue
        action_text = str(candidate.get("action", "") or "").strip().lower()
        owner_text = str(candidate.get("owner", "") or "").strip()
        metric_text = str(candidate.get("metric", "") or "").strip().lower()
        timeline_text = str(candidate.get("timeline", "") or "").strip()
        bucket = module_classify_action_timeline_bucket_v3(timeline_text)
        if bucket not in {"mid", "long"} and not any(token in timeline_text for token in ("月", "季度", "半年", "年度")):
            continue
        if not (owner_text and metric_text and _is_action_timeline_specific_v3(timeline_text)):
            continue
        if any(token in action_text for token in ("机制", "复盘", "跟踪", "闭环", "运营")) or any(token in metric_text for token in ("复盘", "闭环", "机制")):
            return True
    return False


def _build_overview_blindspot_status_line_v3(dimension: str, aspect: str) -> str:
    dim_text = str(dimension or "相关维度").strip()
    aspect_text = str(aspect or "关键未覆盖点").strip()
    return f"当前仍存在待补采盲区：{dim_text}-{aspect_text}，需补充直接证据后再收敛结论。"


def _infer_analysis_key_for_blindspot_v3(dimension: str, target: str = "") -> str:
    target_text = str(target or "").strip().lower()
    if target_text.startswith("analysis."):
        return target_text.split(".", 1)[1].strip()

    normalized_dimension = _normalize_dimension_hint_v3(dimension)
    mapping = {
        "customer_needs": "customer_needs",
        "business_process": "business_flow",
        "tech_constraints": "tech_constraints",
        "project_constraints": "project_constraints",
    }
    return mapping.get(normalized_dimension, "")


def _build_analysis_blindspot_status_line_v3(dimension: str, aspect: str) -> str:
    dim_text = str(dimension or "相关维度").strip()
    aspect_text = str(aspect or "关键未覆盖点").strip()
    return f"{dim_text}中“{aspect_text}”仍属于待补采盲区，当前仅可作为风险提示，需补证后再收敛为确定结论。"


def _collect_actionability_candidate_indexes_v3(field: str, target: str, working: dict) -> list[int]:
    values = working.get(field, []) if isinstance(working, dict) else []
    if not isinstance(values, list) or field not in {"solutions", "actions"}:
        return []

    target_field, target_index = _extract_issue_field_index_v3(target)
    if target_field == field and target_index >= 0:
        return [target_index] if target_index < len(values) else []

    normalized_target = str(target or "").strip().lower()
    if normalized_target in {field, f"{field}.owner", f"{field}.timeline", f"{field}.metric"}:
        result = []
        for idx, item in enumerate(values):
            if not isinstance(item, dict):
                continue
            if not (str(item.get("owner", "") or "").strip() and str(item.get("timeline", "") or "").strip() and str(item.get("metric", "") or "").strip()):
                result.append(idx)
        return result
    return []


def _build_blindspot_pending_action_v3(dimension: str, aspect: str, evidence_pack: dict) -> dict:
    dim_text = str(dimension or "相关维度").strip()
    aspect_text = str(aspect or "关键未覆盖点").strip()
    refs = _pick_evidence_refs_for_dimension_v3(evidence_pack, dimension_hint=dim_text, limit=2)
    if not refs:
        refs = _pick_evidence_refs_for_dimension_v3(evidence_pack, dimension_hint="", limit=2)
    if not refs:
        return {}

    action_text = f"补采并确认“{aspect_text}”的责任边界，输出可执行决策记录"
    return {
        "action": action_text,
        "owner": _infer_default_action_owner_v3(action_text, dim_text),
        "timeline": _infer_default_action_timeline_v3(action_text, field="actions"),
        "metric": _infer_default_action_metric_v3(action_text, dim_text, field="actions"),
        "evidence_refs": refs,
        "evidence_binding_mode": "weak_inferred",
        "inference_origin_field": "blindspot",
        "dimension": dim_text,
    }


def _should_soft_pass_blindspot_issue_v3(
    issue: dict,
    draft: dict,
    evidence_pack: Optional[dict] = None,
    runtime_profile: str = "",
) -> bool:
    if not isinstance(issue, dict) or not isinstance(draft, dict):
        return False

    issue_type = str(issue.get("type", "") or "").strip().lower()
    if issue_type != "blindspot":
        return False

    profile = normalize_report_profile_choice(runtime_profile, fallback=REPORT_V3_PROFILE)
    if profile == "quality" and REPORT_V3_BLINDSPOT_ACTION_REQUIRED_QUALITY:
        # quality 档保持更严格，但当证据明显稀疏时允许从“阻断”降级为“补采建议”。
        if not _is_evidence_sparse_v3(evidence_pack):
            return False
    elif profile == "balanced" and REPORT_V3_BLINDSPOT_ACTION_REQUIRED_BALANCED:
        return False

    message = str(issue.get("message", "") or "").lower()
    target = str(issue.get("target", "") or "").lower()
    open_questions = draft.get("open_questions", [])
    oq_corpus = _collect_text_corpus_for_items_v3(open_questions if isinstance(open_questions, list) else [], ["question", "reason", "impact", "suggested_follow_up"])
    if not oq_corpus:
        return False

    if target.startswith("open_questions"):
        blindspots = evidence_pack.get("blindspots", []) if isinstance(evidence_pack, dict) else []
        if isinstance(blindspots, list) and blindspots:
            matched = 0
            total = 0
            for blindspot in blindspots:
                if not isinstance(blindspot, dict):
                    continue
                aspect = str(blindspot.get("aspect", "") or "").strip().lower()
                if not aspect:
                    continue
                total += 1
                if aspect in oq_corpus:
                    matched += 1
            if total > 0:
                coverage = matched / total
                if matched == total or (total >= 8 and coverage >= 0.75):
                    return True

    if target.startswith("analysis."):
        aspect = _extract_blindspot_aspect_from_text_v3(issue.get("message", ""))
        analysis = draft.get("analysis", {}) if isinstance(draft.get("analysis", {}), dict) else {}
        analysis_key = target.split(".", 1)[1].strip()
        analysis_text = str(analysis.get(analysis_key, "") or "").strip().lower()
        if aspect and aspect.lower() in analysis_text and ("待补采" in analysis_text or "待确认" in analysis_text or "盲区" in analysis_text):
            return True

    mentions_action_gap = ("action" in message or "行动" in message or "行动计划" in message or "actions" in target)
    if not mentions_action_gap:
        return False

    aspect = _extract_blindspot_aspect_from_text_v3(issue.get("message", ""))
    if aspect:
        return aspect.lower() in oq_corpus

    # 无法提取具体 aspect 时，至少保证存在盲区补问并且证据稀疏。
    return _is_evidence_sparse_v3(evidence_pack)


def _is_blindspot_cleanup_issue_v3(issue: dict) -> bool:
    """将 open_questions 去重/清晰化类问题视为样式优化，不阻断主流程。"""
    if not isinstance(issue, dict):
        return False

    issue_type = str(issue.get("type", "") or "").strip().lower()
    if issue_type != "blindspot":
        return False

    target = str(issue.get("target", "") or "").strip().lower()
    if not target.startswith("open_questions"):
        return False

    message = str(issue.get("message", "") or "").strip().lower()
    cleanup_markers = (
        "重复",
        "去重",
        "合并",
        "清晰",
        "通用",
        "泛化",
        "clarity",
        "duplicate",
        "dedup",
        "merge",
    )
    return any(marker in message for marker in cleanup_markers)


def _extract_issue_field_index_v3(target: str) -> tuple[str, int]:
    text = str(target or "").strip()
    match = re.match(r"^(needs|solutions|risks|actions|open_questions|evidence_index)\[(\d+)\]", text)
    if not match:
        return "", -1
    return match.group(1), int(match.group(2))


def _issue_target_exists_v3(target: str, draft: dict) -> bool:
    field, index = _extract_issue_field_index_v3(target)
    if not field:
        return True
    values = draft.get(field, []) if isinstance(draft, dict) else []
    if not isinstance(values, list):
        return False
    return 0 <= index < len(values)


def _normalize_review_issue_payload_v3(item: dict) -> dict:
    normalized = {
        "type": str(item.get("type", "unknown")).strip().lower() or "unknown",
        "severity": str(item.get("severity", "medium")).strip().lower() or "medium",
        "message": str(item.get("message", "")).strip(),
        "target": str(item.get("target", "unknown")).strip(),
    }
    return _normalize_review_issue_semantics_v3(normalized)


def _normalize_review_issue_semantics_v3(issue: dict) -> dict:
    if not isinstance(issue, dict):
        return {
            "type": "unknown",
            "severity": "medium",
            "message": "",
            "target": "unknown",
        }

    normalized = dict(issue)
    issue_type = str(normalized.get("type", "") or "").strip().lower()
    target = str(normalized.get("target", "") or "").strip().lower()
    message = str(normalized.get("message", "") or "").strip().lower()
    if issue_type != "no_evidence":
        return normalized

    aggregate_target = (
        target in {
            "needs/solutions/actions/risks/evidence_index",
            "needs/solutions/actions/risks",
            "overall",
            "report",
        }
        or ("/" in target and "[" not in target and "." not in target)
    )
    coverage_markers = (
        "证据覆盖率",
        "覆盖率",
        "未达到≥",
        "未达到>=",
        "门槛",
        "信息盲区",
        "多个维度",
    )
    if not aggregate_target or not any(marker in message for marker in coverage_markers):
        return normalized

    normalized["type"] = "quality_gate_evidence"
    if not target or target == "unknown":
        normalized["target"] = "needs/solutions/actions/risks/evidence_index"
    return normalized


def filter_model_review_issues_v3(
    model_issues: list,
    draft: dict,
    evidence_pack: Optional[dict] = None,
    runtime_profile: str = "",
) -> list:
    """过滤模型审稿问题：仅保留阻断型结构问题，避免模板幻觉导致误拦截。"""
    if not isinstance(model_issues, list):
        return []

    filtered = []
    for raw_item in model_issues:
        if not isinstance(raw_item, dict):
            continue
        issue = _normalize_review_issue_payload_v3(raw_item)
        issue_type = issue.get("type", "")
        message_lower = issue.get("message", "").lower()
        target = issue.get("target", "")

        if issue_type.startswith(REVIEW_GATE_MANAGED_ISSUE_PREFIXES_V3) or issue_type in REVIEW_GATE_MANAGED_ISSUE_TYPES_V3:
            continue
        if "acceptance_criteria" in message_lower:
            continue
        if issue_type == "no_evidence" and str(target).endswith(".evidence_binding_mode"):
            continue
        if issue_type == "no_evidence" and str(target).startswith("visualizations"):
            continue
        if issue_type == "blindspot" and _is_blindspot_cleanup_issue_v3(issue):
            continue
        if issue_type == "blindspot" and _should_soft_pass_blindspot_issue_v3(
            issue,
            draft,
            evidence_pack=evidence_pack,
            runtime_profile=runtime_profile,
        ):
            continue
        if issue_type == "not_actionable" and _should_soft_pass_not_actionable_issue_v3(issue, draft):
            continue
        if issue_type not in REVIEW_BLOCKING_ISSUE_TYPES_V3:
            continue
        if issue_type == "no_evidence" and str(target).startswith("open_questions"):
            continue
        if not _issue_target_exists_v3(target, draft):
            continue
        filtered.append(issue)
    return filtered


def merge_review_and_local_issues_v3(
    model_issues: list,
    local_issues: list,
    draft: dict,
    evidence_pack: Optional[dict] = None,
    runtime_profile: str = "",
) -> tuple[list, list]:
    """合并模型问题与本地校验问题，并去重。"""
    filtered_model_issues = filter_model_review_issues_v3(
        model_issues,
        draft,
        evidence_pack=evidence_pack,
        runtime_profile=runtime_profile,
    )

    merged = []
    seen_keys = set()
    for item in filtered_model_issues + (local_issues if isinstance(local_issues, list) else []):
        if not isinstance(item, dict):
            continue
        normalized = _normalize_review_issue_payload_v3(item)
        key = f"{normalized.get('type')}|{normalized.get('target')}|{normalized.get('message')}"
        if key in seen_keys:
            continue
        seen_keys.add(key)
        merged.append(normalized)
    return merged, filtered_model_issues


def _tokenize_similarity_text_v3(text: str) -> set[str]:
    source = str(text or "").strip().lower()
    if not source:
        return set()

    tokens = set(re.findall(r"[a-z0-9_]{2,}", source))
    for chunk in re.findall(r"[\u4e00-\u9fff]{2,12}", source):
        tokens.add(chunk)
        for idx in range(len(chunk) - 1):
            tokens.add(chunk[idx: idx + 2])
    return {token for token in tokens if token}


def _infer_item_dimension_key_v3(field: str, item: dict, evidence_pack: dict) -> str:
    if not isinstance(item, dict) or not isinstance(evidence_pack, dict):
        return ""

    dimension_coverage = evidence_pack.get("dimension_coverage", {})
    if not isinstance(dimension_coverage, dict):
        return ""

    explicit = str(item.get("dimension", "") or "").strip()
    if explicit in dimension_coverage:
        return explicit

    text_corpus = " ".join([
        str(item.get("title", "") or ""),
        str(item.get("description", "") or ""),
        str(item.get("risk", "") or ""),
        str(item.get("action", "") or ""),
        str(item.get("question", "") or ""),
        str(item.get("reason", "") or ""),
        str(item.get("impact", "") or ""),
    ]).lower()
    if not text_corpus:
        return ""

    best_key = ""
    best_hits = 0
    for dim_key, dim_meta in dimension_coverage.items():
        if not isinstance(dim_meta, dict):
            continue
        vocab = [
            dim_key,
            str(dim_meta.get("name", "") or ""),
            *(dim_meta.get("missing_aspects", []) if isinstance(dim_meta.get("missing_aspects", []), list) else []),
        ]
        hits = 0
        for token in vocab:
            token_text = str(token or "").strip().lower()
            if token_text and token_text in text_corpus:
                hits += 1
        if hits > best_hits:
            best_hits = hits
            best_key = dim_key
    return best_key


def infer_weak_evidence_refs_v3(
    field: str,
    item: dict,
    evidence_pack: dict,
    min_score: float = REPORT_V3_WEAK_BINDING_MIN_SCORE,
) -> dict:
    """仅对风险/行动/未决问题执行保守弱绑定，避免无证据硬结论。"""
    if not REPORT_V3_WEAK_BINDING_ENABLED:
        return {"refs": [], "score": 0.0}
    if field not in {"risks", "actions", "open_questions"}:
        return {"refs": [], "score": 0.0}
    if not isinstance(item, dict) or not isinstance(evidence_pack, dict):
        return {"refs": [], "score": 0.0}

    facts = evidence_pack.get("facts", [])
    if not isinstance(facts, list) or not facts:
        return {"refs": [], "score": 0.0}

    text_fields = {
        "risks": ["risk", "impact", "mitigation"],
        "actions": ["action", "owner", "timeline", "metric"],
        "open_questions": ["question", "reason", "impact", "suggested_follow_up"],
    }
    item_text = " ".join(str(item.get(key, "") or "") for key in text_fields.get(field, []))
    item_tokens = _tokenize_similarity_text_v3(item_text)
    if not item_tokens:
        return {"refs": [], "score": 0.0}

    preferred_dimension = _infer_item_dimension_key_v3(field, item, evidence_pack)
    quality_snapshot = evidence_pack.get("quality_snapshot", {})
    avg_quality = _safe_float((quality_snapshot or {}).get("average_quality_score", 0.0), default=0.0)
    action_strategy = _derive_action_generation_strategy_v3(evidence_pack) if field == "actions" else {}

    best = None
    for fact in facts:
        if not isinstance(fact, dict):
            continue
        q_id = str(fact.get("q_id", "") or "").upper().strip()
        if not re.fullmatch(r"Q\d+", q_id):
            continue

        fact_text = " ".join([
            str(fact.get("question", "") or ""),
            str(fact.get("answer", "") or ""),
            str(fact.get("dimension_name", "") or ""),
            str(fact.get("dimension", "") or ""),
        ])
        fact_tokens = _tokenize_similarity_text_v3(fact_text)
        if not fact_tokens:
            continue

        overlap = len(item_tokens & fact_tokens)
        if overlap <= 0:
            continue

        coverage = overlap / max(3, min(len(item_tokens), 14))
        precision = overlap / max(4, min(len(fact_tokens), 18))
        quality_score = max(0.0, min(1.0, _safe_float(fact.get("quality_score", 0.0), default=0.0)))
        dim_bonus = 0.12 if preferred_dimension and str(fact.get("dimension", "") or "") == preferred_dimension else 0.0
        hard_bonus = 0.04 if bool(fact.get("hard_triggered", False)) else 0.0
        score = 0.62 * coverage + 0.18 * precision + 0.16 * quality_score + dim_bonus + hard_bonus

        if best is None or score > best["score"]:
            best = {"score": score, "q_id": q_id}

    if not best:
        return {"refs": [], "score": 0.0}

    threshold = float(min_score or REPORT_V3_WEAK_BINDING_MIN_SCORE)
    if field == "actions":
        threshold += 0.04
        if action_strategy.get("prefer_open_questions"):
            threshold += 0.02
        if int(action_strategy.get("min_actions", 2) or 2) <= 1:
            threshold += 0.04
    if preferred_dimension:
        threshold -= 0.03
    if avg_quality <= 0.30:
        threshold += 0.02
    threshold = max(0.25, min(threshold, 0.92))

    if best["score"] + 1e-9 < threshold:
        return {"refs": [], "score": round(best["score"], 3)}

    return {"refs": [best["q_id"]], "score": round(best["score"], 3)}


def _demote_item_to_open_question_v3(field: str, item: dict) -> dict:
    title_map = {
        "needs": str(item.get("name", "") or "").strip() or "该需求项",
        "solutions": str(item.get("title", "") or "").strip() or "该方案项",
        "risks": str(item.get("risk", "") or "").strip() or "该风险项",
        "actions": str(item.get("action", "") or "").strip() or "该行动项",
    }
    title = title_map.get(field, "该结论项")
    impact_text = str(item.get("impact", "") or item.get("description", "") or "").strip()
    follow_up = (
        f"请补充“{title}”对应的直接访谈证据（原话、场景、量化口径）"
        if title
        else "请补充对应的直接访谈证据（原话、场景、量化口径）"
    )
    return {
        "question": f"“{title}”当前缺少可追溯证据，是否应作为待验证假设？",
        "reason": "该项为推断结论，当前没有可靠 evidence_refs，已自动降级为待补问问题",
        "impact": impact_text or "可能影响结论可信度与行动优先级",
        "suggested_follow_up": follow_up,
        "evidence_refs": [],
        "evidence_binding_mode": "pending_follow_up",
        "inference_origin_field": field,
    }


def _is_evidence_index_claim_orphan_v3(index_item: dict, draft: dict) -> bool:
    if not isinstance(index_item, dict) or not isinstance(draft, dict):
        return False

    refs = _normalize_evidence_refs(index_item.get("evidence_refs", []))
    if not refs:
        return True

    sibling_fields = ("needs", "solutions", "risks", "actions", "open_questions")
    shared_refs = set()
    for field in sibling_fields:
        values = draft.get(field, [])
        if not isinstance(values, list):
            continue
        for item in values:
            if not isinstance(item, dict):
                continue
            shared_refs.update(_normalize_evidence_refs(item.get("evidence_refs", [])))

    return not any(ref in shared_refs for ref in refs)


def _normalize_actionable_timelines_v3(working: dict, evidence_pack: dict) -> tuple[dict, list[str], bool]:
    if not isinstance(working, dict):
        return working, [], False

    notes = []
    changed = False
    for field in ("solutions", "actions"):
        values = working.get(field, [])
        if not isinstance(values, list):
            continue
        for idx, item in enumerate(values):
            if not isinstance(item, dict):
                continue
            title_text = str(item.get("action", "") or item.get("title", "") or "").strip()
            if not title_text:
                continue

            current_timeline = str(item.get("timeline", "") or "").strip()
            if _is_action_timeline_specific_v3(current_timeline):
                continue

            has_supporting_signal = bool(
                str(item.get("owner", "") or "").strip()
                or str(item.get("metric", "") or "").strip()
                or _normalize_evidence_refs(item.get("evidence_refs", []))
            )
            if not has_supporting_signal:
                continue

            inferred = _infer_action_owner_timeline_metric_v3(field, item, evidence_pack=evidence_pack)
            new_timeline = str(inferred.get("timeline", "") or "").strip()
            if not _is_action_timeline_specific_v3(new_timeline):
                continue

            item["timeline"] = new_timeline
            changed = True
            notes.append(f"{field}[{idx}] 规范 timeline 为 {new_timeline}")
    return working, notes, changed


def _normalize_action_metrics_v3(working: dict, evidence_pack: dict) -> tuple[dict, list[str], bool]:
    if not isinstance(working, dict):
        return working, [], False

    notes = []
    changed = False
    for field in ("solutions", "actions"):
        values = working.get(field, [])
        if not isinstance(values, list):
            continue
        for idx, item in enumerate(values):
            if not isinstance(item, dict):
                continue
            title_text = str(item.get("action", "") or item.get("title", "") or "").strip()
            if not title_text:
                continue

            current_metric = str(item.get("metric", "") or "").strip()
            if field == "actions" and module_is_action_metric_measurable_v3(current_metric):
                continue
            if field == "solutions" and current_metric:
                continue

            has_supporting_signal = bool(
                str(item.get("owner", "") or "").strip()
                or _is_action_timeline_specific_v3(str(item.get("timeline", "") or "").strip())
                or _normalize_evidence_refs(item.get("evidence_refs", []))
            )
            if not has_supporting_signal:
                continue

            inferred = _infer_action_owner_timeline_metric_v3(field, item, evidence_pack=evidence_pack)
            new_metric = str(inferred.get("metric", "") or "").strip()
            if not new_metric:
                continue

            item["metric"] = new_metric
            changed = True
            notes.append(f"{field}[{idx}] 规范 metric 为 {new_metric}")
    return working, notes, changed


def _build_long_horizon_action_v3(draft: dict, evidence_pack: dict) -> dict:
    blindspots = evidence_pack.get("blindspots", []) if isinstance(evidence_pack, dict) else []
    dimension = ""
    aspect = ""
    if isinstance(blindspots, list):
        for item in blindspots:
            if not isinstance(item, dict):
                continue
            dimension = str(item.get("dimension", "") or "").strip()
            aspect = str(item.get("aspect", "") or "").strip()
            if aspect:
                break

    if not aspect:
        open_questions = draft.get("open_questions", []) if isinstance(draft, dict) else []
        if isinstance(open_questions, list):
            for item in open_questions:
                if not isinstance(item, dict):
                    continue
                question = str(item.get("question", "") or "").strip()
                if question:
                    aspect = question[:18]
                    break

    dim_text = str(dimension or "相关维度").strip()
    aspect_text = str(aspect or "关键缺口").strip()
    refs = _pick_evidence_refs_for_dimension_v3(evidence_pack, dimension_hint=dim_text, limit=2)
    if not refs:
        refs = _pick_evidence_refs_for_dimension_v3(evidence_pack, dimension_hint="", limit=2)

    action_text = f"围绕“{aspect_text}”建立长期运营闭环，按月跟踪并组织跨角色复盘"
    return {
        "action": action_text,
        "owner": _infer_default_action_owner_v3(action_text, dim_text),
        "timeline": "季度内",
        "metric": "发布闭环机制并完成至少1次跨角色复盘，输出长期优化清单",
        "evidence_refs": refs,
        "evidence_binding_mode": "weak_inferred" if refs else "",
        "inference_origin_field": "actionability",
        "dimension": dim_text,
    }


def _reinforce_long_horizon_actions_v3(working: dict, evidence_pack: dict, issue_message: str = "") -> tuple[dict, list[str], bool]:
    if not isinstance(working, dict):
        return working, [], False

    message = str(issue_message or "").strip().lower()
    if not any(token in message for token in ("长期", "全周期", "运营", "复盘", "机制", "闭环")):
        return working, [], False

    actions = working.get("actions", [])
    if not isinstance(actions, list):
        return working, [], False

    notes = []
    changed = False
    reinforced = False
    for idx, item in enumerate(actions):
        if not isinstance(item, dict):
            continue
        timeline_text = str(item.get("timeline", "") or "").strip()
        bucket = module_classify_action_timeline_bucket_v3(timeline_text)
        if bucket not in {"mid", "long"} and not any(token in timeline_text for token in ("月", "季度", "半年", "年度")):
            continue

        action_text = str(item.get("action", "") or "").strip()
        metric_text = str(item.get("metric", "") or "").strip()
        if not any(token in action_text for token in ("机制", "复盘", "跟踪", "闭环", "运营")):
            item["action"] = f"{action_text}，并建立月度跟踪与复盘机制".strip("，")
            changed = True
        if not metric_text or not any(token in metric_text.lower() for token in ("复盘", "闭环", "机制")):
            item["metric"] = "发布闭环机制并完成至少1次跨角色复盘，输出长期优化清单"
            changed = True
        if not str(item.get("owner", "") or "").strip():
            item["owner"] = _infer_default_action_owner_v3(item.get("action", ""), str(item.get("dimension", "") or ""))
            changed = True
        if not _normalize_evidence_refs(item.get("evidence_refs", [])):
            weak_bind = infer_weak_evidence_refs_v3("actions", item, evidence_pack, min_score=REPORT_V3_WEAK_BINDING_MIN_SCORE)
            weak_refs = _normalize_evidence_refs(weak_bind.get("refs", []))
            if weak_refs:
                item["evidence_refs"] = weak_refs
                item["evidence_binding_mode"] = "weak_inferred"
                item["evidence_binding_score"] = float(weak_bind.get("score", 0.0) or 0.0)
                changed = True
        notes.append(f"actions[{idx}] 补强长期执行动作")
        reinforced = True
        break

    if not reinforced:
        action_item = _build_long_horizon_action_v3(working, evidence_pack)
        if isinstance(action_item, dict) and str(action_item.get("action", "") or "").strip():
            actions.append(action_item)
            working["actions"] = actions
            changed = True
            notes.append("补充长期运营闭环 action")

    return working, notes, changed


def _pick_strong_action_seed_refs_v3(evidence_pack: dict, limit: int = 2) -> list[str]:
    if not isinstance(evidence_pack, dict):
        return []
    facts = evidence_pack.get("facts", [])
    if not isinstance(facts, list):
        return []

    ranked = []
    for fact in facts:
        if not isinstance(fact, dict):
            continue
        q_id = str(fact.get("q_id", "") or "").upper().strip()
        if not re.fullmatch(r"Q\d+", q_id):
            continue
        evidence_class = str(fact.get("answer_evidence_class", "") or "explicit").strip().lower()
        if evidence_class in {"pending_follow_up", "none"}:
            continue
        quality_score = max(0.0, min(1.0, _safe_float(fact.get("quality_score", 0.0), default=0.0)))
        ranked.append((quality_score, q_id))

    ranked.sort(key=lambda item: (-item[0], item[1]))
    return _normalize_evidence_refs([q_id for _score, q_id in ranked[:max(1, int(limit or 1))]])


def _build_sparse_session_explicit_action_v3(working: dict, evidence_pack: dict) -> dict:
    refs = _pick_strong_action_seed_refs_v3(evidence_pack, limit=2)
    if not refs:
        return {}

    blindspots = evidence_pack.get("blindspots", []) if isinstance(evidence_pack.get("blindspots", []), list) else []
    primary_blindspot = blindspots[0] if blindspots else {}
    dim_text = str((primary_blindspot or {}).get("dimension", "") or "相关维度").strip()
    aspect_text = str((primary_blindspot or {}).get("aspect", "") or "").strip()

    needs = working.get("needs", []) if isinstance(working.get("needs", []), list) else []
    need_name = ""
    if needs and isinstance(needs[0], dict):
        need_name = str(needs[0].get("name", "") or "").strip()

    focus_text = need_name or aspect_text or "当前已确认的核心问题"
    action_text = f"围绕“{focus_text}”组织一次补采澄清，并确认责任边界与验收口径"
    metric_text = "完成补采清单，明确负责人、验收口径与下一步决策记录"
    return {
        "action": action_text,
        "owner": _infer_default_action_owner_v3(action_text, dim_text),
        "timeline": "1周内",
        "metric": metric_text,
        "evidence_refs": refs,
        "evidence_binding_mode": "strong_explicit",
        "inference_origin_field": "sparse_session_action",
        "dimension": dim_text,
    }


def _stabilize_sparse_actions_v3(working: dict, evidence_pack: dict, issues: list, runtime_profile: str = "") -> tuple[dict, list[str], bool]:
    if not isinstance(working, dict):
        return working, [], False

    action_strategy = _derive_action_generation_strategy_v3(evidence_pack)
    if not action_strategy.get("prefer_open_questions"):
        return working, [], False

    issue_types = summarize_issue_types_v3(issues)
    if "quality_gate_weak_binding" not in issue_types and "style_template_violation" not in issue_types:
        return working, [], False

    actions = working.get("actions", [])
    if not isinstance(actions, list) or not actions:
        return working, [], False

    action_minimum = max(1, int(action_strategy.get("min_actions", 2) or 2))
    open_questions = working.get("open_questions", [])
    if not isinstance(open_questions, list):
        open_questions = []

    changed = False
    notes = []
    kept_actions = []
    demoted_count = 0

    for item in actions:
        if not isinstance(item, dict):
            continue
        binding_mode = str(item.get("evidence_binding_mode", "") or "").strip().lower()
        binding_score = max(0.0, min(1.0, _safe_float(item.get("evidence_binding_score", 0.0), default=0.0)))
        refs = _normalize_evidence_refs(item.get("evidence_refs", []))
        is_strong = bool(refs) and binding_mode not in {"weak_inferred", "pending_follow_up", ""}
        if is_strong:
            kept_actions.append(item)
            continue

        should_demote = False
        if not refs:
            should_demote = True
        elif binding_mode == "weak_inferred":
            should_demote = True
            if action_minimum > 1 and binding_score >= 0.78:
                should_demote = False

        if should_demote:
            open_questions.append(_demote_item_to_open_question_v3("actions", item))
            demoted_count += 1
            changed = True
            continue

        kept_actions.append(item)

    if demoted_count > 0:
        notes.append(f"actions 收缩为待补问 {demoted_count} 条")

    if not kept_actions and action_minimum >= 1:
        fallback_action = _build_sparse_session_explicit_action_v3(working, evidence_pack)
        if fallback_action:
            kept_actions.append(fallback_action)
            changed = True
            notes.append("补充 1 条强证据补采 action")

    if not changed:
        return working, [], False

    working["actions"] = kept_actions
    working["open_questions"] = open_questions
    return working, notes, True


def _deduplicate_structured_list_v3(items: list, id_fields: list[str]) -> list:
    if not isinstance(items, list):
        return []

    deduped = []
    seen = set()
    for item in items:
        if not isinstance(item, dict):
            continue
        signature_parts = []
        for key in id_fields:
            signature_parts.append(re.sub(r"\s+", " ", str(item.get(key, "") or "").strip().lower()))
        signature = "|".join(signature_parts)
        if not signature or signature in seen:
            continue
        seen.add(signature)
        deduped.append(item)
    return deduped


def apply_deterministic_report_repairs_v3(
    draft: dict,
    evidence_pack: dict,
    issues: list,
    runtime_profile: str = "",
) -> dict:
    """
    规则化修复器（确定性）：
    1) 对 risks/actions/open_questions 的 no_evidence 尝试保守弱绑定
    2) 无法绑定的 risks/actions 自动降级为 open_questions
    3) evidence_index 中无证据条目直接清理
    4) 对盲区项做保守补全（先补 open_questions，必要时补 pending action）
    5) 在 unknown_ratio 过高时，自动补充待补采 open_questions，降低遗漏
    6) 去重，减少模型重复条目导致的误拦截
    """
    if not isinstance(draft, dict):
        return {"draft": {}, "changed": False, "notes": []}

    working = copy.deepcopy(draft)
    notes = []
    changed = False
    remove_index_map = {"needs": set(), "solutions": set(), "risks": set(), "actions": set(), "open_questions": set(), "evidence_index": set()}

    runtime_profile = normalize_report_profile_choice(runtime_profile, fallback=REPORT_V3_PROFILE)
    weak_binding_floor = REPORT_V3_WEAK_BINDING_MIN_SCORE
    if runtime_profile == "quality":
        weak_binding_floor = max(weak_binding_floor, 0.48)

    for issue in (issues if isinstance(issues, list) else []):
        if not isinstance(issue, dict):
            continue
        issue_type = str(issue.get("type", "") or "").strip().lower()
        if issue_type != "not_actionable":
            continue

        target = str(issue.get("target", "") or "")
        candidate_indexes = []
        for field_name in ("solutions", "actions"):
            for idx in _collect_actionability_candidate_indexes_v3(field_name, target, working):
                candidate_indexes.append((field_name, idx))

        for field, index in candidate_indexes:
            values = working.get(field, [])
            if not isinstance(values, list) or index >= len(values):
                continue
            item = values[index]
            if not isinstance(item, dict):
                continue

            inferred = _infer_action_owner_timeline_metric_v3(field, item, evidence_pack=evidence_pack)
            missing_before = {
                "owner": not str(item.get("owner", "") or "").strip(),
                "timeline": not str(item.get("timeline", "") or "").strip(),
                "metric": not str(item.get("metric", "") or "").strip(),
            }
            item["owner"] = str(item.get("owner", "") or "").strip() or inferred.get("owner", "")
            item["timeline"] = str(item.get("timeline", "") or "").strip() or inferred.get("timeline", "")
            item["metric"] = str(item.get("metric", "") or "").strip() or inferred.get("metric", "")

            refs = _normalize_evidence_refs(item.get("evidence_refs", []))
            if not refs:
                weak_bind = infer_weak_evidence_refs_v3(
                    "actions" if field == "actions" else "actions",
                    item,
                    evidence_pack,
                    min_score=weak_binding_floor,
                )
                weak_refs = _normalize_evidence_refs(weak_bind.get("refs", []))
                if weak_refs:
                    item["evidence_refs"] = weak_refs
                    item["evidence_binding_mode"] = "weak_inferred"
                    item["evidence_binding_score"] = float(weak_bind.get("score", 0.0) or 0.0)
                    refs = weak_refs

            if any(missing_before.values()):
                changed = True
                filled_fields = [name for name, missing in missing_before.items() if missing and str(item.get(name, "") or "").strip()]
                if filled_fields:
                    notes.append(f"{field}[{index}] 补齐 {'/'.join(filled_fields)}")
            if refs:
                notes.append(f"{field}[{index}] 保留可执行证据引用 {','.join(refs)}")

        if str(target or "").strip().lower() == "actions":
            working, long_action_notes, long_action_changed = _reinforce_long_horizon_actions_v3(
                working,
                evidence_pack,
                issue_message=str(issue.get("message", "") or ""),
            )
            if long_action_changed:
                changed = True
                notes.extend(long_action_notes)

    for issue in (issues if isinstance(issues, list) else []):
        if not isinstance(issue, dict):
            continue
        issue_type = str(issue.get("type", "") or "").strip().lower()
        if issue_type != "no_evidence":
            continue

        field, index = _extract_issue_field_index_v3(str(issue.get("target", "") or ""))
        if field not in {"needs", "solutions", "risks", "actions", "open_questions", "evidence_index"} or index < 0:
            continue

        values = working.get(field, [])
        if not isinstance(values, list) or index >= len(values):
            continue
        item = values[index]
        if not isinstance(item, dict):
            continue

        refs = _normalize_evidence_refs(item.get("evidence_refs", []))
        if refs:
            if field == "evidence_index" and _is_evidence_index_claim_orphan_v3(item, working):
                remove_index_map[field].add(index)
                changed = True
                notes.append(f"移除孤立证据索引项 {field}[{index}]")
                continue
            continue

        if field == "evidence_index":
            remove_index_map[field].add(index)
            changed = True
            notes.append(f"移除无证据索引项 {field}[{index}]")
            continue

        weak_bind = infer_weak_evidence_refs_v3(
            field,
            item,
            evidence_pack,
            min_score=weak_binding_floor,
        )
        weak_refs = _normalize_evidence_refs(weak_bind.get("refs", []))
        if weak_refs:
            item["evidence_refs"] = weak_refs
            item["evidence_binding_mode"] = "weak_inferred"
            item["evidence_binding_score"] = float(weak_bind.get("score", 0.0) or 0.0)
            changed = True
            notes.append(f"{field}[{index}] 弱绑定证据 {','.join(weak_refs)}")
            continue

        if field in {"needs", "solutions", "risks", "actions"}:
            open_questions = working.get("open_questions", [])
            if not isinstance(open_questions, list):
                open_questions = []
            open_questions.append(_demote_item_to_open_question_v3(field, item))
            working["open_questions"] = open_questions
            remove_index_map[field].add(index)
            changed = True
            notes.append(f"{field}[{index}] 降级为 open_questions")

    working, timeline_notes, timeline_changed = _normalize_actionable_timelines_v3(working, evidence_pack)
    if timeline_changed:
        changed = True
        notes.extend(timeline_notes)
    working, metric_notes, metric_changed = _normalize_action_metrics_v3(working, evidence_pack)
    if metric_changed:
        changed = True
        notes.extend(metric_notes)
    working, sparse_action_notes, sparse_action_changed = _stabilize_sparse_actions_v3(
        working,
        evidence_pack,
        issues,
        runtime_profile=runtime_profile,
    )
    if sparse_action_changed:
        changed = True
        notes.extend(sparse_action_notes)

    # 盲区规则补全：优先进入 open_questions；质量档可按配置补一条待验证行动项。
    blindspot_candidates = []
    for blindspot in (evidence_pack.get("blindspots", []) if isinstance(evidence_pack, dict) else []):
        if not isinstance(blindspot, dict):
            continue
        dimension = str(blindspot.get("dimension", "") or "").strip()
        aspect = str(blindspot.get("aspect", "") or "").strip()
        if not aspect:
            continue
        blindspot_candidates.append((dimension, aspect))

    for issue in (issues if isinstance(issues, list) else []):
        if not isinstance(issue, dict):
            continue
        if str(issue.get("type", "") or "").strip().lower() != "blindspot":
            continue
        raw_message = str(issue.get("message", "") or "").strip()
        aspect = _extract_blindspot_aspect_from_text_v3(raw_message)
        if not aspect:
            continue
        blindspot_candidates.append(("", aspect))

    blindspot_dedup = []
    blindspot_seen = set()
    for dimension, aspect in blindspot_candidates:
        sig = f"{str(dimension or '').strip().lower()}|{str(aspect or '').strip().lower()}"
        if not aspect or sig in blindspot_seen:
            continue
        blindspot_seen.add(sig)
        blindspot_dedup.append((str(dimension or "").strip(), str(aspect or "").strip()))

    if blindspot_dedup:
        open_questions = working.get("open_questions", [])
        if not isinstance(open_questions, list):
            open_questions = []
        actions = working.get("actions", [])
        if not isinstance(actions, list):
            actions = []
        overview_text = str(working.get("overview", "") or "").strip()
        analysis = working.get("analysis", {}) if isinstance(working.get("analysis", {}), dict) else {}

        blindspot_action_requested = False
        blindspot_overview_requested = False
        blindspot_analysis_targets = set()
        for issue in (issues if isinstance(issues, list) else []):
            if not isinstance(issue, dict):
                continue
            if str(issue.get("type", "") or "").strip().lower() != "blindspot":
                continue
            target = str(issue.get("target", "") or "").strip().lower()
            message = str(issue.get("message", "") or "").strip().lower()
            if "action" in target or "actions" in target or "行动" in message or "action" in message:
                blindspot_action_requested = True
            if target.startswith("overview") or "overview" in target or "概述" in message or "盲区状态" in message:
                blindspot_overview_requested = True
            if target.startswith("analysis."):
                blindspot_analysis_targets.add(target.split(".", 1)[1].strip())

        action_required_for_blindspot = (
            REPORT_V3_BLINDSPOT_ACTION_REQUIRED_QUALITY
            if runtime_profile == "quality"
            else REPORT_V3_BLINDSPOT_ACTION_REQUIRED_BALANCED
        )
        action_required_for_blindspot = action_required_for_blindspot or blindspot_action_requested
        for dimension, aspect in blindspot_dedup:
            oq_corpus = _collect_text_corpus_for_items_v3(open_questions, ["question", "reason", "impact", "suggested_follow_up"])
            action_corpus = _collect_text_corpus_for_items_v3(actions, ["action", "owner", "timeline", "metric"])
            aspect_token = aspect.lower()

            if blindspot_overview_requested and aspect_token and aspect_token not in overview_text.lower():
                status_line = _build_overview_blindspot_status_line_v3(dimension, aspect)
                overview_text = f"{overview_text}\n\n{status_line}".strip() if overview_text else status_line
                changed = True
                notes.append(f"overview 标注盲区状态: {aspect}")

            analysis_key = _infer_analysis_key_for_blindspot_v3(dimension)
            if blindspot_analysis_targets and not analysis_key:
                analysis_key = next(iter(blindspot_analysis_targets))
            if analysis_key in blindspot_analysis_targets:
                current_analysis_text = str(analysis.get(analysis_key, "") or "").strip()
                if aspect_token and aspect_token not in current_analysis_text.lower():
                    status_line = _build_analysis_blindspot_status_line_v3(dimension, aspect)
                    analysis[analysis_key] = f"{current_analysis_text}\n\n{status_line}".strip() if current_analysis_text else status_line
                    changed = True
                    notes.append(f"analysis.{analysis_key} 标注盲区状态: {aspect}")

            if aspect_token and aspect_token not in oq_corpus:
                open_questions.append(_build_blindspot_open_question_v3(dimension, aspect, evidence_pack))
                changed = True
                notes.append(f"盲区补齐 open_questions: {aspect}")

            if action_required_for_blindspot and aspect_token and aspect_token not in action_corpus:
                action_item = _build_blindspot_pending_action_v3(dimension, aspect, evidence_pack)
                blindspot_count = len(evidence_pack.get("blindspots", [])) if isinstance(evidence_pack.get("blindspots", []), list) else 0
                refs_count = len(_normalize_evidence_refs(action_item.get("evidence_refs", []))) if isinstance(action_item, dict) else 0
                allow_action = bool(action_item)
                if allow_action and runtime_profile != "quality":
                    allow_action = refs_count >= 2 and blindspot_count <= 2
                if allow_action and action_item:
                    inferred = _infer_action_owner_timeline_metric_v3("actions", action_item, evidence_pack=evidence_pack, dimension_hint=dimension)
                    action_item["owner"] = inferred.get("owner", action_item.get("owner", ""))
                    action_item["timeline"] = inferred.get("timeline", action_item.get("timeline", ""))
                    action_item["metric"] = inferred.get("metric", action_item.get("metric", ""))
                    actions.append(action_item)
                    changed = True
                    notes.append(f"盲区补齐 actionable action: {aspect}")

        working["open_questions"] = open_questions
        working["actions"] = actions
        if overview_text != str(working.get("overview", "") or "").strip():
            working["overview"] = overview_text
        if analysis is not working.get("analysis"):
            working["analysis"] = analysis

    # unknown 过高时自动补采待问，减少“信息缺口直接进结论”的风险。
    if REPORT_V3_UNKNOWNS_TO_OPEN_QUESTIONS_ENABLED and isinstance(evidence_pack, dict):
        raw_facts = evidence_pack.get("facts", [])
        raw_unknowns = evidence_pack.get("unknowns", [])
        facts_count = len(raw_facts) if isinstance(raw_facts, list) else 0
        unknown_count = len(raw_unknowns) if isinstance(raw_unknowns, list) else 0
        unknown_ratio = (unknown_count / facts_count) if facts_count > 0 else 0.0
        if unknown_ratio >= REPORT_V3_UNKNOWN_RATIO_TRIGGER and isinstance(raw_unknowns, list) and raw_unknowns:
            open_questions = working.get("open_questions", [])
            if not isinstance(open_questions, list):
                open_questions = []
            oq_corpus = _collect_text_corpus_for_items_v3(open_questions, ["question", "reason", "impact", "suggested_follow_up"])
            appended = 0
            for item in raw_unknowns:
                if appended >= REPORT_V3_UNKNOWNS_TO_OPEN_QUESTIONS_MAX_ITEMS:
                    break
                if not isinstance(item, dict):
                    continue
                q_id = str(item.get("q_id", "") or "").upper().strip()
                if not re.fullmatch(r"Q\d+", q_id):
                    continue
                reason = str(item.get("reason", "") or "").strip() or "回答存在不确定信息"
                dimension = str(item.get("dimension", "") or "").strip() or "相关维度"
                signature = f"{q_id.lower()} {reason.lower()}"
                if signature in oq_corpus:
                    continue
                open_questions.append({
                    "question": f"{dimension}在{q_id}呈现不确定信号，是否需要补采访谈以确认真实约束？",
                    "reason": reason,
                    "impact": "若不补采，报告中的优先级和行动口径可能偏离实际",
                    "suggested_follow_up": f"围绕 {q_id} 对应场景补充可量化事实（角色、频次、影响范围）",
                    "evidence_refs": [q_id],
                    "evidence_binding_mode": "pending_follow_up",
                })
                appended += 1
                changed = True
                notes.append(f"unknown补采 open_questions: {q_id}")
            working["open_questions"] = open_questions

    for field, index_set in remove_index_map.items():
        if not index_set:
            continue
        values = working.get(field, [])
        if not isinstance(values, list):
            continue
        filtered = [item for idx, item in enumerate(values) if idx not in index_set]
        if len(filtered) != len(values):
            working[field] = filtered
            changed = True

    # 统一清洗 evidence_refs：去重 + 移除无效 Q 编号。
    valid_q_refs = {
        str(fact.get("q_id", "")).upper().strip()
        for fact in (evidence_pack.get("facts", []) if isinstance(evidence_pack.get("facts", []), list) else [])
        if isinstance(fact, dict) and re.fullmatch(r"Q\d+", str(fact.get("q_id", "")).upper().strip())
    }
    for field in ["needs", "solutions", "risks", "actions", "open_questions", "evidence_index"]:
        values = working.get(field, [])
        if not isinstance(values, list):
            continue
        for item in values:
            if not isinstance(item, dict):
                continue
            refs = _normalize_evidence_refs(item.get("evidence_refs", []))
            if valid_q_refs:
                refs = [ref for ref in refs if ref in valid_q_refs]
            if refs != _normalize_evidence_refs(item.get("evidence_refs", [])):
                item["evidence_refs"] = refs
                changed = True

    # 统一去重，降低重复条目带来的伪问题。
    dedup_rules = {
        "needs": ["name", "description"],
        "solutions": ["title", "description"],
        "risks": ["risk", "impact"],
        "actions": ["action", "timeline"],
        "open_questions": ["question", "reason"],
        "evidence_index": ["claim"],
    }
    for field, keys in dedup_rules.items():
        values = working.get(field, [])
        if not isinstance(values, list):
            continue
        deduped = _deduplicate_structured_list_v3(values, keys)
        if len(deduped) != len(values):
            working[field] = deduped
            changed = True
            notes.append(f"{field} 去重 {len(values) - len(deduped)} 项")

    return {"draft": working, "changed": changed, "notes": notes[:30]}


def _collect_claim_entries_for_quality(draft: dict) -> list:
    """收集草案中的可计量结论条目。"""
    claim_entries = []
    for field in ["needs", "solutions", "risks", "actions", "open_questions", "evidence_index"]:
        values = draft.get(field, [])
        if not isinstance(values, list):
            continue
        for item in values:
            if not isinstance(item, dict):
                continue
            binding_mode = str(item.get("evidence_binding_mode", "") or "").strip().lower()
            if field == "open_questions" and binding_mode == "pending_follow_up":
                # 待补问项本质上是“尚未形成结论”的缺口，不应拉低硬性证据覆盖率。
                continue
            claim_entries.append({
                "field": field,
                "evidence_refs": _normalize_evidence_refs(item.get("evidence_refs", [])),
                "evidence_binding_mode": binding_mode,
                "owner": str(item.get("owner", "")).strip(),
                "timeline": str(item.get("timeline", "")).strip(),
                "metric": str(item.get("metric", "")).strip(),
            })
    return claim_entries


REPORT_V3_QUALITY_THRESHOLDS = {
    "evidence_coverage": 0.9,
    "consistency": 0.8,
    "actionability": 0.8,
    "expression_structure": 0.82,
    "table_readiness": 0.78,
    "action_acceptance": 0.75,
    "milestone_coverage": 0.65,
    "max_weak_binding_ratio": 0.35,
}


def _profile_quality_gate_thresholds_v3(profile: str, base_thresholds: Optional[dict] = None) -> dict:
    """按档位返回质量门禁阈值。quality 更严格，balanced 适度放宽。"""
    thresholds = dict(REPORT_V3_QUALITY_THRESHOLDS)
    if isinstance(base_thresholds, dict):
        thresholds.update(base_thresholds)

    normalized_profile = normalize_report_profile_choice(profile, fallback="balanced")
    if normalized_profile == "quality":
        return thresholds

    # balanced 档适度放宽表达与模板门禁，避免小样本访谈被过度拦截。
    relaxed = dict(thresholds)
    relaxed["expression_structure"] = min(float(relaxed.get("expression_structure", 0.82) or 0.82), 0.72)
    relaxed["table_readiness"] = min(float(relaxed.get("table_readiness", 0.78) or 0.78), 0.68)
    relaxed["action_acceptance"] = min(float(relaxed.get("action_acceptance", 0.75) or 0.75), 0.65)
    relaxed["milestone_coverage"] = min(float(relaxed.get("milestone_coverage", 0.65) or 0.65), 0.45)
    relaxed["max_weak_binding_ratio"] = max(float(relaxed.get("max_weak_binding_ratio", 0.35) or 0.35), 0.45)
    return relaxed


def _adapt_quality_gate_thresholds_by_evidence_v3(limit: dict, quality_meta: dict) -> dict:
    """根据证据可靠性动态收敛/放宽部分表达类门禁。"""
    adapted = dict(limit)
    evidence_context = quality_meta.get("evidence_context", {}) if isinstance(quality_meta, dict) else {}
    if not isinstance(evidence_context, dict):
        return adapted

    unknown_ratio = max(0.0, min(1.0, _safe_float(evidence_context.get("unknown_ratio", 0.0), default=0.0)))
    avg_quality = max(0.0, min(1.0, _safe_float(evidence_context.get("average_quality_score", 0.0), default=0.0)))
    facts_count = max(0, int(evidence_context.get("facts_count", 0) or 0))
    runtime_profile = normalize_report_profile_choice(
        str((quality_meta or {}).get("runtime_profile", "") or ""),
        fallback="balanced",
    )
    claim_total = max(0, int((quality_meta or {}).get("claim_total", 0) or 0))
    rich_option_count = max(0, int((quality_meta or {}).get("rich_option_count", 0) or 0))
    pending_follow_up_count = max(0, int((quality_meta or {}).get("pending_follow_up_count", 0) or 0))
    weak_binding_ratio = max(0.0, min(1.0, _safe_float((quality_meta or {}).get("weak_binding_ratio", 0.0), default=0.0)))
    rich_option_ratio = (rich_option_count / claim_total) if claim_total > 0 else 0.0
    pending_follow_up_ratio = (pending_follow_up_count / claim_total) if claim_total > 0 else 0.0
    blindspots_count = max(0, int((evidence_context or {}).get("blindspots_count", 0) or 0))

    if facts_count <= 0:
        return adapted

    # 证据较稀疏时，适度放宽 evidence_coverage，避免“待补问项”把主流程整体卡死；
    # 一致性门禁仍保持刚性。
    tension = 0.0
    if unknown_ratio > 0.60:
        tension += min(0.12, (unknown_ratio - 0.60) * 0.30)
    if avg_quality < 0.32:
        tension += min(0.08, (0.32 - avg_quality) * 0.45)
    tension = max(0.0, min(tension, 0.18))

    if tension > 0.0:
        current_evidence_limit = float(adapted.get("evidence_coverage", 0.9) or 0.9)
        adapted["evidence_coverage"] = max(0.82, current_evidence_limit - min(0.06, tension * 0.70))
        for key in ("actionability", "expression_structure", "table_readiness", "action_acceptance", "milestone_coverage"):
            current = float(adapted.get(key, 0.0) or 0.0)
            adapted[key] = max(0.45, current - tension)
        adapted["max_weak_binding_ratio"] = min(0.60, max(float(adapted.get("max_weak_binding_ratio", 0.35) or 0.35), 0.35 + tension))

    # rich_option 比例高且弱绑定低时，适度放宽 balanced 档证据门槛；
    # 这类会话的证据往往是“高信息量选项回答”，不应继续按纯弱证据对待。
    if (
        runtime_profile == "balanced"
        and rich_option_ratio >= 0.5
        and weak_binding_ratio <= 0.12
        and avg_quality >= 0.5
        and unknown_ratio <= 0.25
    ):
        adapted["evidence_coverage"] = min(float(adapted.get("evidence_coverage", 0.9) or 0.9), 0.78)
    if (
        runtime_profile == "balanced"
        and rich_option_ratio >= 0.75
        and weak_binding_ratio <= 0.10
        and avg_quality >= 0.55
        and unknown_ratio <= 0.12
    ):
        adapted["evidence_coverage"] = min(float(adapted.get("evidence_coverage", 0.9) or 0.9), 0.73)

    # 高盲区 / 高待补采会话不应继续按普通报告要求 90% 硬卡。
    # 这类输入更接近“待补采型报告”，重点是显式暴露缺口，而不是强行伪造强证据。
    if (
        runtime_profile == "balanced"
        and blindspots_count >= 10
        and pending_follow_up_ratio >= 0.25
        and unknown_ratio >= 0.30
        and avg_quality >= 0.40
        and weak_binding_ratio <= 0.12
    ):
        adapted["evidence_coverage"] = min(float(adapted.get("evidence_coverage", 0.9) or 0.9), 0.52)

    return adapted


def _get_weak_binding_field_limits_v3(runtime_profile: str, quality_meta: Optional[dict] = None) -> dict:
    normalized_profile = normalize_report_profile_choice(runtime_profile, fallback="balanced")
    if normalized_profile == "quality":
        limits = {
            "actions": 0.25,
            "solutions": 0.35,
            "risks": 0.55,
        }
    else:
        limits = {
            "actions": 0.35,
            "solutions": 0.45,
            "risks": 0.70,
        }

    evidence_context = quality_meta.get("evidence_context", {}) if isinstance(quality_meta, dict) else {}
    unknown_ratio = max(0.0, min(1.0, _safe_float((evidence_context or {}).get("unknown_ratio", 0.0), default=0.0)))
    avg_quality = max(0.0, min(1.0, _safe_float((evidence_context or {}).get("average_quality_score", 0.0), default=0.0)))
    if unknown_ratio >= 0.65 or avg_quality <= 0.32:
        limits["risks"] = min(0.80, limits["risks"] + 0.10)
        limits["solutions"] = min(0.60, limits["solutions"] + 0.05)
        limits["actions"] = min(0.45, limits["actions"] + 0.03)
    return limits


def build_quality_gate_issues_v3(quality_meta: dict, thresholds: Optional[dict] = None) -> list:
    """根据质量阈值构建门禁问题列表。"""
    if not isinstance(quality_meta, dict):
        return [{
            "type": "quality_gate_missing",
            "severity": "high",
            "message": "缺少质量评分结果，无法通过质量门禁",
            "target": "quality_meta",
        }]

    runtime_profile = normalize_report_profile_choice(
        str(quality_meta.get("runtime_profile", "") or ""),
        fallback="balanced",
    )
    limit = _profile_quality_gate_thresholds_v3(runtime_profile, base_thresholds=thresholds)
    limit = _adapt_quality_gate_thresholds_by_evidence_v3(limit, quality_meta)

    checks = [
        ("evidence_coverage", "quality_gate_evidence", "证据覆盖率", "needs/solutions/actions/risks/evidence_index"),
        ("consistency", "quality_gate_consistency", "冲突解释完成度", "risks/open_questions"),
        ("actionability", "quality_gate_actionability", "可执行建议占比", "solutions/actions"),
        ("expression_structure", "quality_gate_expression", "表达结构完整度", "overview/analysis/needs/solutions/risks/actions"),
        ("table_readiness", "quality_gate_table", "表格化可读性", "needs/solutions/risks/actions"),
        ("action_acceptance", "quality_gate_acceptance", "行动验收口径完备度", "actions.metric"),
        ("milestone_coverage", "quality_gate_milestone", "行动里程碑覆盖度", "actions.timeline"),
    ]

    issues = []
    for key, issue_type, label, target in checks:
        current = float(quality_meta.get(key, 0) or 0)
        required = float(limit.get(key, 0) or 0)
        if current + 1e-9 < required:
            issues.append({
                "type": issue_type,
                "severity": "high",
                "message": f"{label}低于门槛（当前{current:.1%}，要求≥{required:.1%}）",
                "target": target,
            })

    weak_binding_ratio = max(0.0, min(1.0, _safe_float(quality_meta.get("weak_binding_ratio", 0.0), default=0.0)))
    weak_binding_limit = max(0.0, min(1.0, _safe_float(limit.get("max_weak_binding_ratio", 0.35), default=0.35)))
    weak_binding_ratio_by_field = quality_meta.get("weak_binding_ratio_by_field", {})
    field_limits = _get_weak_binding_field_limits_v3(runtime_profile, quality_meta)
    weak_binding_field_issues = []
    if isinstance(weak_binding_ratio_by_field, dict):
        field_display_names = {
            "actions": "行动项",
            "solutions": "方案建议",
            "risks": "风险项",
        }
        for field, field_limit in field_limits.items():
            current_ratio = max(0.0, min(1.0, _safe_float(weak_binding_ratio_by_field.get(field, 0.0), default=0.0)))
            if current_ratio > field_limit + 1e-9:
                weak_binding_field_issues.append({
                    "type": "quality_gate_weak_binding",
                    "severity": "high" if runtime_profile == "quality" else "medium",
                    "message": f"{field_display_names.get(field, field)}弱证据绑定占比过高（当前{current_ratio:.1%}，允许≤{field_limit:.1%}）",
                    "target": field,
                })

    if weak_binding_field_issues:
        issues.extend(weak_binding_field_issues)
    elif weak_binding_ratio > weak_binding_limit + 1e-9:
        issues.append({
            "type": "quality_gate_weak_binding",
            "severity": "high" if runtime_profile == "quality" else "medium",
            "message": f"弱证据绑定占比过高（当前{weak_binding_ratio:.1%}，允许≤{weak_binding_limit:.1%}）",
            "target": "solutions/risks/actions",
        })

    template_minimums = quality_meta.get("template_minimums", {})
    list_counts = quality_meta.get("list_counts", {})
    if isinstance(template_minimums, dict) and isinstance(list_counts, dict):
        display_names = {
            "needs": "核心需求",
            "solutions": "方案建议",
            "risks": "风险项",
            "actions": "行动项",
            "open_questions": "未决问题",
        }
        deficits = []
        for key, label in display_names.items():
            required = int(template_minimums.get(key, 0) or 0)
            current = int(list_counts.get(key, 0) or 0)
            if required > 0 and current < required:
                deficits.append(f"{label}≥{required}（当前{current}）")

        if deficits:
            severity = "high" if runtime_profile == "quality" else "medium"
            issues.append({
                "type": "style_template_violation",
                "severity": severity,
                "message": "风格模板未达标：" + "，".join(deficits),
                "target": "needs/solutions/risks/actions/open_questions",
            })
    return issues


