@app.route('/api/report-templates/validate', methods=['POST'])
def validate_report_template_schema():
    data = request.get_json() or {}
    schema_input = data.get("schema")
    sections_input = data.get("sections")
    normalized_schema, issues = normalize_custom_report_schema(schema_input, fallback_sections=sections_input)
    if issues:
        return jsonify({
            "success": False,
            "error": "模板结构校验失败",
            "details": issues,
            "schema": normalized_schema,
        }), 400
    return jsonify({"success": True, "schema": normalized_schema})


@app.route('/api/report-templates/preview', methods=['POST'])
def preview_report_template_schema():
    data = request.get_json() or {}
    schema_input = data.get("schema")
    sections_input = data.get("sections")
    normalized_schema, issues = normalize_custom_report_schema(schema_input, fallback_sections=sections_input)
    if issues:
        return jsonify({
            "success": False,
            "error": "模板结构校验失败",
            "details": issues,
            "schema": normalized_schema,
        }), 400

    draft = data.get("draft")
    if not isinstance(draft, dict):
        draft = build_custom_template_preview_draft()
    quality_meta = data.get("quality_meta")
    if not isinstance(quality_meta, dict):
        quality_meta = {}

    session_stub = {
        "topic": str(data.get("topic") or "自定义模板预览"),
        "scenario_config": {
            "report": {
                "type": "standard",
                "template": REPORT_TEMPLATE_CUSTOM_V1,
                "schema": normalized_schema,
            }
        },
        "dimensions": {},
        "interview_log": [],
    }
    markdown = render_report_from_draft_custom_v1(session_stub, draft, quality_meta)

    return jsonify({
        "success": True,
        "schema": normalized_schema,
        "preview_markdown": markdown,
    })


# ============ 场景 API ============

def _normalize_user_id_for_scenarios(raw_user_id: object) -> Optional[int]:
    try:
        user_id = int(raw_user_id)
    except (TypeError, ValueError):
        return None
    return user_id if user_id > 0 else None


def _scenario_owner_user_id(scenario: dict) -> int:
    if not isinstance(scenario, dict):
        return 0
    try:
        return int(scenario.get("owner_user_id") or 0)
    except (TypeError, ValueError):
        return 0


def _is_scenario_accessible_to_user(
    scenario: dict,
    user_id: Optional[int] = None,
    expected_scope: Optional[str] = None,
) -> bool:
    if not isinstance(scenario, dict):
        return False
    if bool(scenario.get("builtin", False)):
        return True

    user_id_int = _normalize_user_id_for_scenarios(user_id)
    if user_id_int is None:
        return False

    owner_user_id = _scenario_owner_user_id(scenario)
    if owner_user_id <= 0 or owner_user_id != user_id_int:
        return False

    return is_instance_scope_visible(scenario.get(INSTANCE_SCOPE_FIELD), expected_scope=expected_scope)


def get_accessible_scenarios_for_user(user_id: Optional[int] = None) -> list[dict]:
    expected_scope = get_active_instance_scope_key()
    refresh_custom_scenarios = getattr(scenario_loader, "refresh_custom_scenarios", None)
    if callable(refresh_custom_scenarios):
        try:
            refresh_custom_scenarios()
        except Exception as exc:
            if ENABLE_DEBUG_LOG:
                print(f"⚠️ 刷新自定义场景缓存失败: {exc}")
    scenarios = scenario_loader.get_all_scenarios()
    return [
        scenario
        for scenario in scenarios
        if _is_scenario_accessible_to_user(scenario, user_id=user_id, expected_scope=expected_scope)
    ]


def get_accessible_scenario_or_none(scenario_id: str, user_id: Optional[int] = None) -> Optional[dict]:
    expected_scope = get_active_instance_scope_key()
    scenario = scenario_loader.get_scenario(scenario_id)
    if not _is_scenario_accessible_to_user(scenario, user_id=user_id, expected_scope=expected_scope):
        refresh_custom_scenarios = getattr(scenario_loader, "refresh_custom_scenarios", None)
        if callable(refresh_custom_scenarios) and str(scenario_id or "").startswith("custom-"):
            try:
                refresh_custom_scenarios()
                scenario = scenario_loader.get_scenario(scenario_id)
            except Exception as exc:
                if ENABLE_DEBUG_LOG:
                    print(f"⚠️ 刷新自定义场景缓存失败: {exc}")
        if not _is_scenario_accessible_to_user(scenario, user_id=user_id, expected_scope=expected_scope):
            return None
    return scenario


def strip_internal_scenario_fields(scenario: dict) -> dict:
    payload = copy.deepcopy(scenario or {})
    payload.pop("owner_user_id", None)
    payload.pop(INSTANCE_SCOPE_FIELD, None)
    meta = payload.get("meta")
    if isinstance(meta, dict):
        meta.pop("owner_user_id", None)
        meta.pop(INSTANCE_SCOPE_FIELD, None)
    return payload


def match_accessible_scenarios_by_keywords(topic: str, scenarios: list[dict]) -> dict:
    topic_lower = str(topic or "").lower()
    scores = {}

    for scenario in scenarios:
        if not isinstance(scenario, dict):
            continue
        scenario_id = str(scenario.get("id") or "").strip()
        if not scenario_id:
            continue
        for keyword in scenario.get("keywords", []) or []:
            keyword_lower = str(keyword or "").strip().lower()
            if keyword_lower and keyword_lower in topic_lower:
                scores[scenario_id] = scores.get(scenario_id, 0) + 1

    if not scores:
        default_scenario = next((item for item in scenarios if item.get("id") == "product-requirement"), None)
        if not default_scenario and scenarios:
            default_scenario = scenarios[0]
        fallback_id = str((default_scenario or {}).get("id") or "product-requirement")
        return {
            "scenario_id": fallback_id,
            "confidence": 0.3,
            "matched_keywords": [],
            "alternatives": [],
        }

    sorted_scenarios = sorted(scores.items(), key=lambda item: item[1], reverse=True)
    best_id, best_score = sorted_scenarios[0]
    scenario = next((item for item in scenarios if item.get("id") == best_id), {})
    total_keywords = len(scenario.get("keywords", []) or [])
    confidence = min(0.9, 0.4 + (best_score / max(total_keywords, 1)) * 0.5)
    matched_keywords = [
        keyword
        for keyword in scenario.get("keywords", []) or []
        if str(keyword or "").strip().lower() in topic_lower
    ]
    alternatives = [
        {"scenario_id": scenario_id, "score": score}
        for scenario_id, score in sorted_scenarios[1:4]
    ]
    return {
        "scenario_id": best_id,
        "confidence": round(confidence, 2),
        "matched_keywords": matched_keywords,
        "alternatives": alternatives,
    }


@app.route('/api/scenarios', methods=['GET'])
def list_scenarios():
    """获取所有场景列表"""
    scenarios = get_accessible_scenarios_for_user(get_current_user_id_or_none())
    # 返回简化的场景信息
    return jsonify([
        {
            "id": s.get("id"),
            "name": s.get("name"),
            "name_en": s.get("name_en"),
            "description": s.get("description"),
            "icon": s.get("icon"),
            "builtin": s.get("builtin", True),
            "custom": s.get("custom", False),
            "dimensions": [
                {
                    "id": d.get("id"),
                    "name": d.get("name"),
                    "description": d.get("description")
                }
                for d in s.get("dimensions", [])
            ],
            "report_type": s.get("report", {}).get("type", "standard"),
            "report_template": normalize_report_template_name(
                s.get("report", {}).get("template", ""),
                report_type=s.get("report", {}).get("type", "standard"),
            ),
            "has_custom_report_schema": isinstance(s.get("report", {}).get("schema"), dict),
            "has_solution_schema": bool(get_scenario_solution_compiled_schema(s).get("sections")),
            "solution_mode": (
                str((s.get("solution", {}) if isinstance(s.get("solution", {}), dict) else {}).get("mode") or "auto").strip().lower()
                or "auto"
            ),
            "solution_sections_count": len(get_scenario_solution_compiled_schema(s).get("sections", [])),
            "scenario_source": "builtin" if s.get("builtin", True) else "user_defined",
        }
        for s in scenarios
    ])


@app.route('/api/scenarios/<scenario_id>', methods=['GET'])
def get_scenario(scenario_id):
    """获取场景详情"""
    scenario = get_accessible_scenario_or_none(scenario_id, get_current_user_id_or_none())
    if not scenario:
        return jsonify({"error": "场景不存在"}), 404
    payload = strip_internal_scenario_fields(scenario)
    payload["compiled_solution_schema"] = get_scenario_solution_compiled_schema(payload)
    meta = payload.get("meta", {}) if isinstance(payload.get("meta", {}), dict) else {}
    meta.setdefault("source", "builtin" if payload.get("builtin", True) else "user_defined")
    payload["meta"] = meta
    return jsonify(payload)


@app.route('/api/scenarios/generate', methods=['POST'])
def generate_scenario_with_ai():
    """AI 自动生成场景配置"""
    ai_client = resolve_ai_client(call_type="scenario_generate")
    if not ai_client:
        return jsonify({"error": "AI 服务不可用"}), 503

    data = request.get_json()
    if not data:
        return jsonify({"error": "无效的请求数据"}), 400

    user_description = data.get("user_description", "").strip()
    if not user_description:
        return jsonify({"error": "请输入场景描述"}), 400

    if len(user_description) < 10:
        return jsonify({"error": "描述太短，请至少输入10个字"}), 400

    if len(user_description) > 500:
        return jsonify({"error": "描述不能超过500字"}), 400

    def _build_prompt(strict_json: bool = False) -> str:
        strict_notice = ""
        if strict_json:
            strict_notice = """

## 额外要求
- 只输出单个 JSON 对象
- 不要使用 markdown 代码块
- 不要输出说明文字、标题或备注
"""
        return f'''你是一个专业的访谈场景设计师。用户将描述他们想要进行的访谈或调研目标，你需要设计一个完整的访谈场景配置。

## 用户描述
{user_description}

## 设计要求
1. 场景名称：简洁明了，4-10个字
2. 场景描述：说明场景适用范围，20-50字
3. 关键词：5-10个用于自动匹配的关键词
4. 维度设计：3-5个维度（根据访谈复杂度调整）
   - 每个维度需要有清晰的名称（2-6字）
   - 维度描述说明该维度关注的内容（10-30字）
   - 每个维度包含3-5个关键点（key_aspects）
   - min_questions 固定为 2，max_questions 固定为 4

## 设计原则
- 维度之间应该互补，共同覆盖用户关心的所有方面
- 维度顺序应该符合认知逻辑（如从具体到抽象，从核心到外围）
- 关键点应该具体可问，便于AI生成访谈问题
- 如果用户描述涉及评估/评分类场景，可考虑在维度中加入评分相关的关键点

## 参考：现有场景示例
- 产品需求：客户需求、业务流程、技术约束、项目约束
- 用户研究：用户背景、使用场景、痛点期望、行为模式
- 竞品分析：市场定位、功能对比、用户评价、差异化机会

## 输出格式
请严格按照以下JSON格式输出，不要包含其他文字：
```json
{{
  "name": "场景名称",
  "description": "场景描述",
  "dimensions": [
    {{
      "id": "dim_1",
      "name": "维度名称",
      "description": "维度描述",
      "key_aspects": ["关键点1", "关键点2", "关键点3", "关键点4"],
      "min_questions": 2,
      "max_questions": 4
    }}
  ],
  "explanation": "设计思路说明（1-2句话，解释为什么这样设计维度）"
}}
```{strict_notice}'''

    try:
        generated = None
        ai_explanation = ""
        last_error = None
        generation_mode = "ai"
        for attempt_index, strict_json in enumerate((False, True), start=1):
            try:
                response = ai_client.messages.create(
                    model=resolve_model_name(call_type="scenario_generate"),
                    max_tokens=1500,
                    timeout=18.0 if strict_json else 24.0,
                    messages=[{"role": "user", "content": _build_prompt(strict_json=strict_json)}]
                )

                raw_text = extract_message_text(response)
                if not raw_text:
                    raise ValueError("模型响应中未包含场景配置文本")

                parsed = parse_generated_scenario_response(raw_text)
                normalized_generated = normalize_generated_scenario_payload(parsed or {})
                if not isinstance(normalized_generated, dict):
                    raise ValueError("AI 场景结构不完整")

                ai_explanation = str(normalized_generated.pop("explanation", "") or "").strip()
                generated = normalized_generated
                break
            except Exception as exc:
                last_error = exc
                if ENABLE_DEBUG_LOG:
                    print(f"⚠️ AI 生成场景第{attempt_index}次解析失败: {exc}")

        if not isinstance(generated, dict):
            fallback_generated = _build_generated_scenario_local_fallback(user_description)
            if not isinstance(fallback_generated, dict):
                raise ValueError(str(last_error or "AI 场景生成失败"))
            generated = fallback_generated
            ai_explanation = str(fallback_generated.get("explanation") or "").strip()
            generation_mode = "local_fallback"
            print(f"⚠️ AI 场景生成失败，已切换本地草案兜底: {last_error or 'unknown'}")

        # 添加默认的 report / solution 配置
        generated["report"] = {"type": "standard", "template": "default"}
        generated["solution"] = {
            "version": SOLUTION_SCHEMA_VERSION,
            "mode": "auto",
        }
        generated["compiled_solution_schema"] = get_scenario_solution_compiled_schema(generated)

        return jsonify({
            "success": True,
            "generated_scenario": generated,
            "ai_explanation": ai_explanation,
            "generation_mode": generation_mode,
        })

    except ValueError as e:
        print(f"⚠️ AI 生成场景 JSON 解析失败: {e}")
        return jsonify({"error": "AI 返回格式异常，请重试"}), 500
    except Exception as e:
        print(f"⚠️ AI 生成场景失败: {e}")
        return jsonify({"error": f"生成失败: {str(e)[:100]}"}), 500


@app.route('/api/scenarios/custom', methods=['POST'])
def create_custom_scenario():
    """创建自定义场景"""
    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    data = request.get_json()
    if not data:
        return jsonify({"error": "无效的请求数据"}), 400

    name = data.get("name", "").strip()
    if not name:
        return jsonify({"error": "场景名称不能为空"}), 400

    dimensions = data.get("dimensions", [])
    if not dimensions or len(dimensions) < 1:
        return jsonify({"error": "至少需要 1 个维度"}), 400
    if len(dimensions) > 8:
        return jsonify({"error": "最多支持 8 个维度"}), 400

    # 验证维度数据
    for i, dim in enumerate(dimensions):
        if not dim.get("name", "").strip():
            return jsonify({"error": f"第 {i+1} 个维度名称不能为空"}), 400
        # 自动生成维度 ID
        if not dim.get("id"):
            dim["id"] = f"dim_{i+1}"
        # 确保有必要字段
        dim.setdefault("description", "")
        dim.setdefault("key_aspects", [])
        dim.setdefault("min_questions", 2)
        dim.setdefault("max_questions", 4)

    report_payload = data.get("report", {"type": "standard", "template": "default"})
    if not isinstance(report_payload, dict):
        return jsonify({"error": "report 配置格式无效"}), 400

    report_type = str(report_payload.get("type") or "standard").strip().lower()
    if report_type not in {"standard", "assessment"}:
        report_type = "standard"
    report_template = normalize_report_template_name(report_payload.get("template", ""), report_type=report_type)
    if report_template not in REPORT_TEMPLATE_ALLOWED:
        return jsonify({"error": "report.template 不支持"}), 400

    normalized_report = {"type": report_type}
    if report_template == REPORT_TEMPLATE_STANDARD_V1:
        normalized_report["template"] = "default"
    elif report_template == REPORT_TEMPLATE_ASSESSMENT_V1:
        normalized_report["template"] = "assessment"
    else:
        normalized_report["template"] = REPORT_TEMPLATE_CUSTOM_V1
        schema_input = report_payload.get("schema")
        normalized_schema, schema_issues = normalize_custom_report_schema(
            schema_input,
            fallback_sections=report_payload.get("sections"),
        )
        if schema_issues:
            return jsonify({"error": "report.schema 校验失败", "details": schema_issues}), 400
        normalized_report["schema"] = normalized_schema

    solution_payload = data.get("solution", {})
    if solution_payload is None:
        solution_payload = {}
    if solution_payload and not isinstance(solution_payload, dict):
        return jsonify({"error": "solution 配置格式无效"}), 400

    scenario = {
        "name": name,
        "description": data.get("description", "").strip(),
        "icon": data.get("icon", "clipboard-list"),
        "dimensions": dimensions,
        "owner_user_id": int(user_id),
        INSTANCE_SCOPE_FIELD: get_active_instance_scope_key(),
        "report": normalized_report,
        "meta": {
            "source": "user_defined",
        },
    }
    normalized_solution, solution_issues = normalize_solution_config(solution_payload, scenario=scenario)
    if solution_issues and str(normalized_solution.get("mode") or "") in {"schema", "dsl"}:
        return jsonify({"error": "solution 配置校验失败", "details": solution_issues}), 400
    scenario["solution"] = normalized_solution

    scenario_id = scenario_loader.save_custom_scenario(scenario)
    saved_scenario = scenario_loader.get_scenario(scenario_id) or {}
    response_scenario = strip_internal_scenario_fields(saved_scenario)
    response_scenario["compiled_solution_schema"] = get_scenario_solution_compiled_schema(response_scenario)
    meta = response_scenario.get("meta", {}) if isinstance(response_scenario.get("meta", {}), dict) else {}
    meta.setdefault("source", "user_defined")
    response_scenario["meta"] = meta

    return jsonify({
        "success": True,
        "scenario_id": scenario_id,
        "scenario": response_scenario,
    })


@app.route('/api/scenarios/custom/<scenario_id>', methods=['DELETE'])
def delete_custom_scenario(scenario_id):
    """删除自定义场景"""
    if not scenario_id.startswith("custom-"):
        return jsonify({"error": "只能删除自定义场景"}), 400

    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    scenario = get_accessible_scenario_or_none(scenario_id, user_id)
    if not scenario or scenario.get("builtin", False):
        return jsonify({"error": "场景不存在或无法删除"}), 404

    success = scenario_loader.delete_custom_scenario(scenario_id)
    if not success:
        return jsonify({"error": "场景不存在或无法删除"}), 404

    return jsonify({"success": True})


@app.route('/api/scenarios/recognize', methods=['POST'])
def recognize_scenario():
    """根据主题和描述智能识别最匹配的访谈场景"""
    data = request.get_json()
    if not data:
        return jsonify({"error": "无效的请求数据"}), 400

    topic = data.get("topic", "")
    description = data.get("description", "")
    if not topic:
        return jsonify({"error": "主题不能为空"}), 400

    # 仅在当前用户可访问的场景中做识别，避免泄露他人的自定义场景。
    user_id = get_current_user_id_or_none()
    all_scenarios = get_accessible_scenarios_for_user(user_id)
    if not all_scenarios:
        fallback_scenario = scenario_loader.get_default_scenario()
        if isinstance(fallback_scenario, dict):
            all_scenarios = [fallback_scenario]

    scenario_list_text = "\n".join(
        f"- id: {s['id']}, 名称: {s['name']}, 说明: {s.get('description', '')}"
        for s in all_scenarios
    )

    user_input = f"访谈主题：{topic}"
    if description:
        user_input += f"\n主题描述：{description}"

    prompt = f"""你是一个访谈场景分类器。根据用户的访谈主题和描述，从以下场景中选择最匹配的一个。

可选场景：
{scenario_list_text}

{user_input}

请严格按照以下 JSON 格式返回（不要包含其他文字）：
{{"scenario_id": "最匹配的场景id", "confidence": 0.0到1.0的置信度, "reason": "一句话理由"}}"""

    valid_scenario_ids = {s["id"] for s in all_scenarios}

    # 优先使用 AI 识别，失败时回退到关键词匹配
    ai_result = None
    ai_last_error = None
    scenario_client = resolve_ai_client(call_type="scenario_recognize")
    if scenario_client:
        attempts = [
            {
                "max_tokens": 220,
                "timeout": 10.0,
                "extra_instruction": "",
            },
            {
                "max_tokens": 480,
                "timeout": 18.0,
                "extra_instruction": "只输出一行 JSON，不要 markdown 代码块，不要额外解释，不要换行。",
            },
        ]

        for idx, attempt in enumerate(attempts, start=1):
            try:
                attempt_prompt = prompt
                if attempt["extra_instruction"]:
                    attempt_prompt = f"{prompt}\n\n【额外要求】{attempt['extra_instruction']}"

                response = scenario_client.messages.create(
                    model=resolve_model_name(call_type="scenario_recognize"),
                    max_tokens=attempt["max_tokens"],
                    timeout=attempt["timeout"],
                    messages=[{"role": "user", "content": attempt_prompt}]
                )

                raw = extract_message_text(response)
                if not raw:
                    raise ValueError("模型响应中未包含场景识别文本")

                parsed = parse_scenario_recognition_response(raw, valid_scenario_ids)
                if parsed:
                    ai_result = parsed
                    break

                raise ValueError(f"无法从响应提取有效场景结果，响应前120字: {raw[:120]}")
            except Exception as e:
                ai_last_error = e
                if ENABLE_DEBUG_LOG:
                    print(f"⚠️  AI 场景识别第{idx}次失败: {e}")

        if not ai_result and ai_last_error:
            print(f"⚠️  AI 场景识别失败，回退到关键词匹配: {ai_last_error}")

    if ai_result and ai_result.get("scenario_id") in valid_scenario_ids:
        best_id = ai_result["scenario_id"]
        confidence = min(1.0, max(0.0, float(ai_result.get("confidence", 0.8))))
        reason = ai_result.get("reason", "")
    else:
        # 回退：关键词匹配
        kw_result = match_accessible_scenarios_by_keywords(topic, all_scenarios)
        best_id = kw_result["scenario_id"]
        confidence = kw_result["confidence"]
        reason = ""

    recommended_scenario = get_accessible_scenario_or_none(best_id, user_id)
    if not recommended_scenario and all_scenarios:
        recommended_scenario = next((item for item in all_scenarios if item.get("id") == best_id), all_scenarios[0])

    return jsonify({
        "recommended": {
            "id": best_id,
            "name": recommended_scenario.get("name") if recommended_scenario else best_id,
            "description": recommended_scenario.get("description") if recommended_scenario else "",
            "icon": recommended_scenario.get("icon") if recommended_scenario else "clipboard-list",
            "dimensions_count": len(recommended_scenario.get("dimensions", [])) if recommended_scenario else 4
        },
        "confidence": confidence,
        "reason": reason
    })


# ============ 认证 API ============

def ensure_user_for_phone(phone: str) -> tuple[Optional[sqlite3.Row], bool]:
    normalized_phone = normalize_phone_number(phone)
    existing = query_user_by_account(normalized_phone)
    if existing:
        return existing, False

    now_iso = datetime.now(timezone.utc).isoformat()
    random_password_hash = generate_password_hash(secrets.token_urlsafe(32), method="pbkdf2:sha256")
    try:
        with get_auth_db_connection() as conn:
            cursor = conn.execute(
                """
                INSERT INTO users (email, phone, password_hash, created_at, updated_at)
                VALUES (?, ?, ?, ?, ?)
                """,
                (None, normalized_phone, random_password_hash, now_iso, now_iso),
            )
            conn.commit()
            user_id = int(cursor.lastrowid)
    except sqlite3.IntegrityError:
        existing_after_conflict = query_user_by_account(normalized_phone)
        return existing_after_conflict, False

    return query_user_by_id(user_id), True


@app.route('/api/auth/sms/send-code', methods=['POST'])
def auth_send_sms_code():
    data = request.get_json() or {}
    raw_phone = str(data.get("phone") or data.get("account") or "").strip()
    scene = normalize_sms_scene(data.get("scene") or "login")
    unavailable_reason = get_sms_login_unavailable_reason(scene)
    if unavailable_reason:
        return jsonify({"error": unavailable_reason}), 503

    phone, phone_error = normalize_account(raw_phone)
    if phone_error:
        return jsonify({"error": phone_error}), 400

    if scene == "bind":
        current_user = get_current_user()
        if not current_user:
            return jsonify({"error": "请先登录"}), 401

    ok, error_message, payload = issue_sms_code(phone, scene, request_ip=get_request_ip())
    if not ok:
        status_code = 429 if (payload and payload.get("retry_after")) else 400
        response_body = {"error": error_message or "验证码发送失败"}
        if payload:
            response_body.update(payload)
        return jsonify(response_body), status_code

    response_body = {
        "success": True,
        "message": "验证码已发送",
    }
    if payload:
        response_body.update(payload)
    return jsonify(response_body)


@app.route('/api/auth/login/code', methods=['POST'])
@app.route('/api/auth/recover/login', methods=['POST'])
def auth_login_with_code():
    data = request.get_json() or {}
    raw_phone = str(data.get("phone") or data.get("account") or "").strip()
    code = str(data.get("code") or data.get("sms_code") or "").strip()
    scene = normalize_sms_scene(data.get("scene") or "login")
    if scene not in {"login", "recover"}:
        scene = "login"
    unavailable_reason = get_sms_login_unavailable_reason(scene)
    if unavailable_reason:
        return jsonify({"error": unavailable_reason}), 503

    phone, phone_error = normalize_account(raw_phone)
    if phone_error:
        return jsonify({"error": phone_error}), 400
    if not code:
        return jsonify({"error": "请输入验证码"}), 400

    verified, verify_error = verify_sms_code(phone, scene, code, consume=True)
    if not verified:
        status_code = 401 if "错误" in verify_error else 400
        if "次数过多" in verify_error:
            status_code = 429
        return jsonify({"error": verify_error or "验证码校验失败"}), status_code

    user_row, created = ensure_user_for_phone(phone)
    if not user_row:
        return jsonify({"error": "登录失败，请稍后重试"}), 500

    login_user(user_row)
    return jsonify({
        "success": True,
        "created": bool(created),
        "user": build_user_payload(user_row),
    })


