@app.route('/api/sessions/<session_id>/next-question', methods=['POST'])
def get_next_question(session_id):
    """获取下一个问题（AI 生成）"""
    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401
    request_started_at = _time.perf_counter()
    question_generation_queue_slot_acquired = False
    question_generation_slot_acquired = False
    question_runtime_durations = {
        "session_load_ms": 0.0,
        "prefetch_wait_ms": 0.0,
        "queue_wait_ms": 0.0,
        "prompt_build_ms": 0.0,
        "ai_call_ms": 0.0,
        "parse_repair_ms": 0.0,
        "postprocess_ms": 0.0,
    }
    question_mode_metrics = {}

    def _elapsed_ms(started_at: float) -> float:
        return max(0.0, (_time.perf_counter() - float(started_at or _time.perf_counter())) * 1000.0)

    def _record_question_runtime(outcome: str, runtime_profile: str = "", tier_used: str = "", selection_reason: str = "") -> None:
        payload = dict(question_runtime_durations)
        payload["total_ms"] = round(_elapsed_ms(request_started_at), 2)
        record_question_generation_runtime_sample(
            durations=payload,
            outcome=outcome,
            runtime_profile=runtime_profile,
            tier_used=tier_used,
            selection_reason=selection_reason,
            mode_metrics=question_mode_metrics,
        )

    session_load_started_at = _time.perf_counter()
    loaded = load_session_for_user(session_id, user_id)
    question_runtime_durations["session_load_ms"] = round(_elapsed_ms(session_load_started_at), 2)
    if len(loaded) == 3:
        _file, error_msg, status_code = loaded
        return jsonify({"error": error_msg}), status_code

    session_file, session = loaded
    data = request.get_json() or {}
    default_dim = get_dimension_order_for_session(session)[0] if get_dimension_order_for_session(session) else "customer_needs"
    dimension = data.get("dimension", default_dim)
    prefer_prefetch = bool(data.get("prefer_prefetch", False))
    session_signature = get_file_signature(session_file)
    question_cache_key = _build_question_result_cache_key(session_id, dimension, session_signature)
    cached_dim_logs = [log for log in session.get("interview_log", []) if log.get("dimension") == dimension]

    def _is_duplicate_cached_question(payload: dict, source: str) -> bool:
        duplicate_log = find_similar_interview_question_log(cached_dim_logs, payload.get("question") if isinstance(payload, dict) else "")
        if not duplicate_log:
            return False
        if ENABLE_DEBUG_LOG:
            matched_question = duplicate_log.get("question", "")
            print(f"⚠️ 丢弃重复缓存问题: source={source}, matched={matched_question}")
        return True

    def _is_low_quality_visible_question(payload: dict, source: str) -> bool:
        quality_gate = evaluate_visible_question_quality_gate(
            payload if isinstance(payload, dict) else {},
            session=session,
            dimension=dimension,
            source=source,
        )
        if quality_gate.get("passed"):
            return False
        if ENABLE_DEBUG_LOG:
            print(f"⚠️ 丢弃低质可见问题: source={source}, reasons={quality_gate.get('reasons')}")
        return True

    def _should_discard_cached_question(payload: dict, source: str) -> bool:
        return (
            _is_duplicate_cached_question(payload, source)
            or _is_low_quality_visible_question(payload, source)
        )

    report_resume_question = (
        build_report_follow_up_resume_question(session, dimension)
        or build_report_low_signal_resume_question(session, dimension)
    )
    if report_resume_question:
        _record_question_runtime(
            "completed",
            runtime_profile="report_readiness_resume",
            tier_used="rule:report_readiness",
            selection_reason="pending_report_follow_up",
        )
        return jsonify(report_resume_question)

    cached_question_payload = _get_question_result_cache(question_cache_key)
    if isinstance(cached_question_payload, dict):
        if _should_discard_cached_question(cached_question_payload, "question_result_cache"):
            _delete_question_result_cache(question_cache_key)
        else:
            if ENABLE_DEBUG_LOG:
                print(f"📦 命中问题结果缓存: session={session_id}, dimension={dimension}")
            _record_cache_hit_metric("question_result_cache_hit")
            cached_question_payload["cached"] = True
            return jsonify(cached_question_payload)

    prefetch_wait_seconds = QUESTION_SUBMIT_PREFETCH_WAIT_SECONDS if prefer_prefetch else QUESTION_PREFETCH_INFLIGHT_WAIT_SECONDS
    prefetch_wait_started_at = _time.perf_counter()
    waited_prefetch = _wait_for_question_prefetch_inflight(question_cache_key, prefetch_wait_seconds)
    question_runtime_durations["prefetch_wait_ms"] = round(_elapsed_ms(prefetch_wait_started_at), 2)
    if waited_prefetch:
        cached_question_payload = _get_question_result_cache(question_cache_key)
        if isinstance(cached_question_payload, dict):
            if _should_discard_cached_question(cached_question_payload, "waited_question_result_cache"):
                _delete_question_result_cache(question_cache_key)
            else:
                if ENABLE_DEBUG_LOG:
                    print(f"📦 等待后命中问题结果缓存: session={session_id}, dimension={dimension}")
                _record_cache_hit_metric("question_result_cache_hit")
                cached_question_payload["cached"] = True
                return jsonify(cached_question_payload)

    # ========== 步骤5: 检查预生成缓存 ==========
    prefetched = get_prefetch_result(session_id, dimension, session_signature=session_signature)
    if prefetched:
        if ENABLE_DEBUG_LOG:
            print(f"🎯 预生成缓存命中: session={session_id}, dimension={dimension}")
        _record_cache_hit_metric("question_prefetch_cache_hit")

        # 先检查维度是否已完成（即使有缓存也要检查）
        dim_data = session.get("dimensions", {}).get(dimension, {})
        dim_coverage = dim_data.get("coverage", 0)
        user_completed = dim_data.get("user_completed", False)
        if dim_coverage >= 100 or user_completed:
            # 维度已完成，忽略缓存，返回完成状态
            all_dim_logs = [log for log in session.get("interview_log", []) if log.get("dimension") == dimension]
            formal_questions_count = len([log for log in all_dim_logs if not log.get("is_follow_up", False)])
            dim_follow_ups = len([log for log in all_dim_logs if log.get("is_follow_up", False)])
            completion_reason = dim_data.get("completion_reason") or ("user_completed" if user_completed else "auto_completed")
            quality_warning = bool(dim_data.get("quality_warning", False))
            return jsonify({
                "dimension": dimension,
                "completed": True,
                "completion_reason": completion_reason,
                "quality_warning": quality_warning,
                "decision_meta": {
                    "mode": get_mode_identifier(session),
                    "follow_up_round": get_follow_up_round_for_dimension_logs(all_dim_logs),
                    "remaining_question_follow_up_budget": max(
                        0,
                        get_interview_mode_config(session).get("max_questions_per_formal", 1)
                        - get_follow_up_round_for_dimension_logs(all_dim_logs)
                    ),
                    "hard_triggered": False,
                    "missing_aspects": get_dimension_missing_aspects(session, dimension),
                },
                "stats": {
                    "formal_questions": formal_questions_count,
                    "follow_ups": dim_follow_ups,
                    "saturation": 1.0
                }
            })

        # 对预生成结果也做 is_follow_up 校验
        all_dim_logs = [log for log in session.get("interview_log", []) if log.get("dimension") == dimension]
        if prefetched.get("is_follow_up", False) and all_dim_logs:
            last_log = all_dim_logs[-1]
            eval_result = evaluate_answer_depth(
                question=last_log.get("question", ""),
                answer=last_log.get("answer", ""),
                dimension=dimension,
                options=last_log.get("options", []),
                is_follow_up=last_log.get("is_follow_up", False),
                multi_select=bool(last_log.get("multi_select", False)),
                answer_mode=last_log.get("answer_mode", ""),
                requires_rationale=bool(last_log.get("requires_rationale", False)),
                evidence_intent=last_log.get("evidence_intent", ""),
            )
            preflight_plan = plan_mid_interview_preflight(
                session,
                dimension,
                ledger=refresh_session_evidence_ledger(session),
                rule_based_result=eval_result,
            )
            comprehensive_check = should_follow_up_comprehensive(
                session=session,
                dimension=dimension,
                rule_based_result=eval_result,
                preflight_plan=preflight_plan,
            )
            if not comprehensive_check["should_follow_up"]:
                if ENABLE_DEBUG_LOG:
                    print(f"⚠️ 预生成缓存 is_follow_up=true 但后端决策不允许，强制覆盖为 false")
                prefetched["is_follow_up"] = False
                prefetched["follow_up_reason"] = None

        prefetched_meta = dict(prefetched.get("decision_meta", {}) or {})
        prefetched_meta.update({
            "mode": get_mode_identifier(session),
            "follow_up_round": get_follow_up_round_for_dimension_logs(all_dim_logs),
            "remaining_question_follow_up_budget": max(
                0,
                get_interview_mode_config(session).get("max_questions_per_formal", 1)
                - get_follow_up_round_for_dimension_logs(all_dim_logs)
            ),
            "hard_triggered": False,
            "missing_aspects": get_dimension_missing_aspects(session, dimension),
        })

        if _should_discard_cached_question(prefetched, "prefetch_cache"):
            _delete_question_result_cache(question_cache_key)
        else:
            prefetched["decision_meta"] = prefetched_meta

            prefetched["prefetched"] = True
            _set_question_result_cache(question_cache_key, prefetched)
            return jsonify(prefetched)

    # 检查是否有 Claude API
    if not resolve_ai_client(call_type="question"):
        if ENABLE_DEBUG_LOG:
            print(f"ℹ️ AI 未启用，使用 fallback 题库: session={session_id}, dimension={dimension}")
        fallback = get_fallback_question(session, dimension)
        _record_question_generation_fallback("ai_disabled")
        return jsonify(fallback)

    # 获取当前维度的所有记录
    all_dim_logs = [log for log in session.get("interview_log", []) if log.get("dimension") == dimension]

    # 计算正式问题数量（排除追问）
    formal_questions_count = len([log for log in all_dim_logs if not log.get("is_follow_up", False)])

    # 获取访谈模式配置
    mode_config = get_interview_mode_config(session)

    # 获取当前维度状态
    dim_data = session.get("dimensions", {}).get(dimension, {})
    dim_coverage = dim_data.get("coverage", 0)
    user_completed = dim_data.get("user_completed", False)

    # 维度已完成（用户手动完成或自动完成）
    if dim_coverage >= 100 or user_completed:
        dim_follow_ups = len([log for log in all_dim_logs if log.get("is_follow_up", False)])
        completion_reason = dim_data.get("completion_reason") or ("user_completed" if user_completed else "auto_completed")
        quality_warning = bool(dim_data.get("quality_warning", False))
        return jsonify({
            "dimension": dimension,
            "completed": True,
            "completion_reason": completion_reason,
            "quality_warning": quality_warning,
            "decision_meta": {
                "mode": get_mode_identifier(session),
                "follow_up_round": get_follow_up_round_for_dimension_logs(all_dim_logs),
                "remaining_question_follow_up_budget": max(0, mode_config.get("max_questions_per_formal", 1) - get_follow_up_round_for_dimension_logs(all_dim_logs)),
                "hard_triggered": False,
                "missing_aspects": get_dimension_missing_aspects(session, dimension),
            },
            "stats": {
                "formal_questions": formal_questions_count,
                "follow_ups": dim_follow_ups,
                "saturation": 1.0
            }
        })

    completion = evaluate_dimension_completion_v2(session, dimension)
    if completion.get("can_complete"):
        # 自动完成写回时重新锁定并读取最新会话，避免覆盖并发写入。
        with locked_session_for_user(session_id, user_id) as latest_loaded:
            if len(latest_loaded) == 3:
                _file, error_msg, status_code = latest_loaded
                return jsonify({"error": error_msg}), status_code

            latest_session_file, latest_session = latest_loaded
            latest_dim_state = latest_session.setdefault("dimensions", {}).setdefault(dimension, {})
            latest_dim_state["coverage"] = 100
            latest_dim_state["auto_completed"] = True
            latest_dim_state["completion_reason"] = completion.get("reason") or "quality_gate_passed"
            latest_dim_state["quality_warning"] = bool(completion.get("quality_warning", False))
            latest_session["updated_at"] = get_utc_now()
            save_session_json_and_sync(latest_session_file, latest_session)
            session = latest_session

        dim_follow_ups = len([log for log in all_dim_logs if log.get("is_follow_up", False)])
        snapshot = completion.get("snapshot", {})
        return jsonify({
            "dimension": dimension,
            "completed": True,
            "completion_reason": latest_dim_state.get("completion_reason"),
            "quality_warning": bool(latest_dim_state.get("quality_warning", False)),
            "decision_meta": {
                "mode": get_mode_identifier(session),
                "follow_up_round": snapshot.get("follow_up_round", get_follow_up_round_for_dimension_logs(all_dim_logs)),
                "remaining_question_follow_up_budget": max(0, mode_config.get("max_questions_per_formal", 1) - snapshot.get("follow_up_round", 0)),
                "hard_triggered": bool(snapshot.get("pending_forced_follow_up", False)),
                "missing_aspects": snapshot.get("missing_aspects", []),
            },
            "stats": {
                "formal_questions": formal_questions_count,
                "follow_ups": dim_follow_ups,
                "saturation": snapshot.get("saturation", 0)
            }
        })

    if not try_enter_question_generation_queue():
        return build_overload_response(
            "question_generation",
            message="问题生成链路繁忙，请稍后重试",
            retry_after_seconds=QUESTION_GENERATION_RETRY_AFTER_SECONDS,
        )
    question_generation_queue_slot_acquired = True
    acquired_generation_slot, queue_wait_ms = try_acquire_question_generation_slot_from_queue(
        QUESTION_GENERATION_QUEUE_WAIT_SECONDS,
    )
    question_runtime_durations["queue_wait_ms"] = round(queue_wait_ms, 2)
    if not acquired_generation_slot:
        return build_overload_response(
            "question_generation",
            message="问题生成队列繁忙，请稍后重试",
            retry_after_seconds=QUESTION_GENERATION_RETRY_AFTER_SECONDS,
        )
    question_generation_slot_acquired = True

    try:
        # 调用 Claude 生成问题
        # 判断是否会有搜索（用于设置正确的阶段数）
        has_search = should_search(session.get("topic", ""), dimension, session)

        # 阶段1: 分析回答
        update_thinking_status(session_id, "analyzing", has_search)

        prompt_build_started_at = _time.perf_counter()
        prepared_runtime = _prepare_question_generation_runtime(
            session,
            dimension,
            all_dim_logs,
            session_id=session_id,
            session_signature=session_signature,
            base_call_type="question",
            allow_fast_path=True,
        )
        prompt = prepared_runtime["full_prompt"]
        truncated_docs = prepared_runtime["truncated_docs"]
        fast_truncated_docs = prepared_runtime.get("fast_truncated_docs")
        decision_meta = prepared_runtime["decision_meta"]
        runtime_profile = prepared_runtime["runtime_profile"]
        fast_prompt = prepared_runtime["fast_prompt"]
        formal_questions_for_metrics = max(0, int((decision_meta or {}).get("formal_questions_count", 0) or 0))
        dimension_follow_up_for_metrics = max(0, int((decision_meta or {}).get("dimension_follow_up_count", 0) or 0))
        question_mode_metrics = {
            "interview_mode": runtime_profile.get("interview_mode", get_mode_identifier(session)),
            "high_evidence": runtime_profile.get("evidence_intent") == "high",
            "search_triggered": bool((decision_meta or {}).get("has_search", False)),
            "follow_up_per_formal": (
                round(dimension_follow_up_for_metrics / formal_questions_for_metrics, 4)
                if formal_questions_for_metrics > 0 else 0.0
            ),
            "formal_questions_per_dimension": formal_questions_for_metrics,
            "ai_call_ms": 0.0,
            "ai_recommendation": False,
        }
        question_runtime_durations["prompt_build_ms"] = round(_elapsed_ms(prompt_build_started_at), 2)

        # 日志：记录 prompt 长度（便于监控和调优）
        if ENABLE_DEBUG_LOG:
            ref_docs_count = len(session.get("reference_materials", session.get("reference_docs", []) + session.get("research_docs", [])))
            print(
                "📊 访谈 Prompt 统计："
                f"full={len(prompt)}字符,fast={len(fast_prompt)}字符,参考资料={ref_docs_count}个"
            )
            if truncated_docs:
                print(f"⚠️  文档截断：{len(truncated_docs)}个文档被截断")

        # 阶段3: 生成问题
        update_thinking_status(session_id, "generating", has_search)

        ai_call_started_at = _time.perf_counter()
        response, result, tier_used = generate_question_with_tiered_strategy(
            prompt,
            truncated_docs=truncated_docs,
            fast_truncated_docs=fast_truncated_docs,
            debug=ENABLE_DEBUG_LOG,
            base_call_type="question",
            allow_fast_path=bool(runtime_profile.get("allow_fast_path", True)),
            fast_prompt=fast_prompt,
            runtime_profile=runtime_profile,
        )
        question_runtime_durations["ai_call_ms"] = round(_elapsed_ms(ai_call_started_at), 2)
        question_mode_metrics["ai_call_ms"] = question_runtime_durations["ai_call_ms"]
        parse_repair_started_at = _time.perf_counter()
        if ENABLE_DEBUG_LOG:
            print(f"⚙️ 问题生成通道: {tier_used}")

        if not response:
            clear_thinking_status(session_id)
            fallback = get_fallback_question(session, dimension)
            fallback["detail"] = "AI 服务暂时不可用，已切换为备用题目"
            _record_question_generation_fallback("ai_unavailable")
            question_runtime_durations["parse_repair_ms"] = round(_elapsed_ms(parse_repair_started_at), 2)
            _record_question_runtime(
                "failed",
                runtime_profile=runtime_profile.get("profile_name", ""),
                tier_used=tier_used,
                selection_reason=runtime_profile.get("selection_reason", ""),
            )
            return jsonify(fallback)

        if result:
            selected_lane = tier_used.split(":", 1)[1] if ":" in tier_used else ""
            decision_meta = dict(decision_meta or {})
            decision_meta["tier_used"] = tier_used
            decision_meta["selected_lane"] = selected_lane
            result["dimension"] = dimension
            result["ai_generated"] = True
            result["decision_meta"] = decision_meta
            result["question_generation_tier"] = tier_used
            result["question_selected_lane"] = selected_lane
            result["question_runtime_profile"] = runtime_profile.get("profile_name", "")
            question_mode_metrics["ai_recommendation"] = bool(result.get("ai_recommendation"))
            # 兜底：避免同维度重复问题（最多自动重试一次）
            duplicate_log = find_similar_interview_question_log(all_dim_logs, result.get("question"))
            if duplicate_log:
                if ENABLE_DEBUG_LOG:
                    print("⚠️ 检测到重复问题，自动重试一次")
                retry_runtime_profile = dict(runtime_profile)
                retry_runtime_profile["allow_fast_path"] = False
                decision_meta["duplicate_guard_triggered"] = True
                decision_meta["duplicate_guard_matched_question"] = duplicate_log.get("question", "")
                retry_response, retry_result, retry_tier = generate_question_with_tiered_strategy(
                    prompt,
                    truncated_docs=truncated_docs,
                    fast_truncated_docs=fast_truncated_docs,
                    debug=ENABLE_DEBUG_LOG,
                    base_call_type="question_retry",
                    allow_fast_path=False,
                    fast_prompt=prompt,
                    runtime_profile=retry_runtime_profile,
                )
                if ENABLE_DEBUG_LOG:
                    print(f"⚙️ 重复问题重试通道: {retry_tier}")
                retry_duplicate_log = find_similar_interview_question_log(all_dim_logs, retry_result.get("question") if retry_result else "")
                if retry_result and not retry_duplicate_log:
                    tier_used = retry_tier
                    response = retry_response
                    selected_lane = retry_tier.split(":", 1)[1] if ":" in retry_tier else ""
                    decision_meta["tier_used"] = retry_tier
                    decision_meta["selected_lane"] = selected_lane
                    decision_meta["duplicate_guard_retry_tier"] = retry_tier
                    retry_result["dimension"] = dimension
                    retry_result["ai_generated"] = True
                    retry_result["decision_meta"] = decision_meta
                    retry_result["question_generation_tier"] = retry_tier
                    retry_result["question_selected_lane"] = selected_lane
                    retry_result["question_runtime_profile"] = runtime_profile.get("profile_name", "")
                    retry_result["duplicate_guard_triggered"] = True
                    result = retry_result
                    question_mode_metrics["ai_recommendation"] = bool(result.get("ai_recommendation"))
                else:
                    clear_thinking_status(session_id)
                    fallback = get_fallback_question(session, dimension)
                    fallback["detail"] = "AI 连续生成了重复问题，已切换为备用题目"
                    _record_question_generation_fallback("repeat_retry_failed")
                    question_runtime_durations["parse_repair_ms"] = round(_elapsed_ms(parse_repair_started_at), 2)
                    _record_question_runtime(
                        "failed",
                        runtime_profile=runtime_profile.get("profile_name", ""),
                        tier_used=tier_used,
                        selection_reason=runtime_profile.get("selection_reason", ""),
                    )
                    return jsonify(fallback)

            quality_gate = evaluate_visible_question_quality_gate(
                result,
                session=session,
                dimension=dimension,
                source="ai_generation",
            )
            if not quality_gate.get("passed"):
                if ENABLE_DEBUG_LOG:
                    print(f"⚠️ AI 生成问题未通过质量闸门，升档 full 重试: reasons={quality_gate.get('reasons')}")
                retry_runtime_profile = dict(runtime_profile)
                retry_runtime_profile["allow_fast_path"] = False
                decision_meta["quality_gate_triggered"] = True
                decision_meta["quality_gate_reasons"] = list(quality_gate.get("reasons") or [])
                retry_response, retry_result, retry_tier = generate_question_with_tiered_strategy(
                    prompt,
                    truncated_docs=truncated_docs,
                    fast_truncated_docs=fast_truncated_docs,
                    debug=ENABLE_DEBUG_LOG,
                    base_call_type="question_quality_retry",
                    allow_fast_path=False,
                    fast_prompt=prompt,
                    runtime_profile=retry_runtime_profile,
                )
                if ENABLE_DEBUG_LOG:
                    print(f"⚙️ 质量闸门重试通道: {retry_tier}")
                retry_duplicate_log = find_similar_interview_question_log(all_dim_logs, retry_result.get("question") if retry_result else "")
                retry_quality_gate = evaluate_visible_question_quality_gate(
                    retry_result if isinstance(retry_result, dict) else {},
                    session=session,
                    dimension=dimension,
                    source="ai_generation_quality_retry",
                )
                if retry_result and not retry_duplicate_log and retry_quality_gate.get("passed"):
                    tier_used = retry_tier
                    response = retry_response
                    selected_lane = retry_tier.split(":", 1)[1] if ":" in retry_tier else ""
                    decision_meta["tier_used"] = retry_tier
                    decision_meta["selected_lane"] = selected_lane
                    decision_meta["quality_gate_retry_tier"] = retry_tier
                    decision_meta["quality_gate_retry_reasons"] = list(quality_gate.get("reasons") or [])
                    retry_result["dimension"] = dimension
                    retry_result["ai_generated"] = True
                    retry_result["decision_meta"] = decision_meta
                    retry_result["question_generation_tier"] = retry_tier
                    retry_result["question_selected_lane"] = selected_lane
                    retry_result["question_runtime_profile"] = runtime_profile.get("profile_name", "")
                    retry_result["question_quality_retry_triggered"] = True
                    retry_result["question_quality_retry_reasons"] = list(quality_gate.get("reasons") or [])
                    result = retry_result
                    question_mode_metrics["ai_recommendation"] = bool(result.get("ai_recommendation"))
                else:
                    clear_thinking_status(session_id)
                    fallback = get_fallback_question(session, dimension)
                    fallback["detail"] = "AI 生成的问题质量不足，已切换为备用题目"
                    _record_question_generation_fallback("quality_gate_failed")
                    question_runtime_durations["parse_repair_ms"] = round(_elapsed_ms(parse_repair_started_at), 2)
                    _record_question_runtime(
                        "failed",
                        runtime_profile=runtime_profile.get("profile_name", ""),
                        tier_used=tier_used,
                        selection_reason=runtime_profile.get("selection_reason", ""),
                    )
                    return jsonify(fallback)

            # ========== 后端强制校验 is_follow_up ==========
            # 防止 AI 绕过追问预算控制，自行将问题标记为追问
            if result.get("is_follow_up", False):
                # 重新计算追问决策
                last_log = all_dim_logs[-1] if all_dim_logs else None
                if last_log:
                    eval_result = evaluate_answer_depth(
                        question=last_log.get("question", ""),
                        answer=last_log.get("answer", ""),
                        dimension=dimension,
                        options=last_log.get("options", []),
                        is_follow_up=last_log.get("is_follow_up", False),
                        multi_select=bool(last_log.get("multi_select", False)),
                        answer_mode=last_log.get("answer_mode", ""),
                        requires_rationale=bool(last_log.get("requires_rationale", False)),
                        evidence_intent=last_log.get("evidence_intent", ""),
                    )
                    preflight_plan = plan_mid_interview_preflight(
                        session,
                        dimension,
                        ledger=refresh_session_evidence_ledger(session),
                        rule_based_result=eval_result,
                    )
                    comprehensive_check = should_follow_up_comprehensive(
                        session=session,
                        dimension=dimension,
                        rule_based_result=eval_result,
                        preflight_plan=preflight_plan,
                    )
                    if not comprehensive_check["should_follow_up"]:
                        if ENABLE_DEBUG_LOG:
                            print(f"⚠️ AI 返回 is_follow_up=true 但后端决策不允许追问，强制覆盖为 false (原因: {comprehensive_check['reason']})")
                        result["is_follow_up"] = False
                        result["follow_up_reason"] = None

            # 清除思考状态
            clear_thinking_status(session_id)
            # ========== 步骤5: 触发预生成（如果需要）==========
            postprocess_started_at = _time.perf_counter()
            trigger_prefetch_if_needed(session, dimension, session_signature=session_signature)
            _set_question_result_cache(question_cache_key, result)
            record_question_generation_event("ai_success", reason=tier_used)
            question_runtime_durations["parse_repair_ms"] = round(_elapsed_ms(parse_repair_started_at), 2)
            question_runtime_durations["postprocess_ms"] = round(_elapsed_ms(postprocess_started_at), 2)
            _record_question_runtime(
                "completed",
                runtime_profile=runtime_profile.get("profile_name", ""),
                tier_used=tier_used,
                selection_reason=runtime_profile.get("selection_reason", ""),
            )
            return jsonify(result)

        clear_thinking_status(session_id)
        repaired_result = repair_generated_question_result_from_response(
            response,
            session=session,
            dimension=dimension,
            fallback_contract=runtime_profile,
            debug=ENABLE_DEBUG_LOG,
        )
        if repaired_result:
            selected_lane = tier_used.split(":", 1)[1] if ":" in tier_used else ""
            repaired_result["dimension"] = dimension
            repaired_result["ai_generated"] = True
            repaired_result["decision_meta"] = dict(decision_meta or {})
            repaired_result["question_generation_tier"] = tier_used
            repaired_result["question_selected_lane"] = selected_lane
            repaired_result["question_runtime_profile"] = runtime_profile.get("profile_name", "")
            question_mode_metrics["ai_recommendation"] = bool(repaired_result.get("ai_recommendation"))
            repair_quality_gate = evaluate_visible_question_quality_gate(
                repaired_result,
                session=session,
                dimension=dimension,
                source="ai_generation_repair",
            )
            if not repair_quality_gate.get("passed"):
                fallback = get_fallback_question(session, dimension)
                fallback["detail"] = "AI 修复后的问题质量不足，已切换为备用题目"
                _record_question_generation_fallback("quality_gate_repair_failed")
                question_runtime_durations["parse_repair_ms"] = round(_elapsed_ms(parse_repair_started_at), 2)
                _record_question_runtime(
                    "failed",
                    runtime_profile=runtime_profile.get("profile_name", ""),
                    tier_used=f"{tier_used}:repair",
                    selection_reason=runtime_profile.get("selection_reason", ""),
                )
                return jsonify(fallback)
            postprocess_started_at = _time.perf_counter()
            trigger_prefetch_if_needed(session, dimension, session_signature=session_signature)
            _set_question_result_cache(question_cache_key, repaired_result)
            record_question_generation_event("ai_success", reason=f"{tier_used}:repair")
            question_runtime_durations["parse_repair_ms"] = round(_elapsed_ms(parse_repair_started_at), 2)
            question_runtime_durations["postprocess_ms"] = round(_elapsed_ms(postprocess_started_at), 2)
            _record_question_runtime(
                "completed",
                runtime_profile=runtime_profile.get("profile_name", ""),
                tier_used=f"{tier_used}:repair",
                selection_reason=runtime_profile.get("selection_reason", ""),
            )
            return jsonify(repaired_result)

        fallback = get_fallback_question(session, dimension)
        if fallback.get("question") or fallback.get("completed"):
            fallback["detail"] = "AI 返回内容无法稳定解析，已切换为备用题目"
            _record_question_generation_fallback("parse_invalid")
            question_runtime_durations["parse_repair_ms"] = round(_elapsed_ms(parse_repair_started_at), 2)
            _record_question_runtime(
                "failed",
                runtime_profile=runtime_profile.get("profile_name", ""),
                tier_used=tier_used,
                selection_reason=runtime_profile.get("selection_reason", ""),
            )
            return jsonify(fallback)

        question_runtime_durations["parse_repair_ms"] = round(_elapsed_ms(parse_repair_started_at), 2)
        _record_question_runtime(
            "failed",
            runtime_profile=runtime_profile.get("profile_name", ""),
            tier_used=tier_used,
            selection_reason=runtime_profile.get("selection_reason", ""),
        )
        return jsonify({
            "error": "AI 响应格式错误",
            "detail": "AI 返回的内容无法解析为有效的 JSON 格式。请点击「重试」按钮重新生成问题。"
        }), 503

    except Exception as e:
        clear_thinking_status(session_id)
        print(f"生成问题时发生异常: {e}")
        error_msg = str(e)
        fallback = get_fallback_question(session, dimension)
        if fallback.get("question") or fallback.get("completed"):
            fallback["detail"] = "AI 生成过程中发生异常，已切换为备用题目"
            _record_question_generation_fallback("exception")
            _record_question_runtime(
                "failed",
                selection_reason="exception",
            )
            return jsonify(fallback)

        # 根据异常类型提供更具体的错误信息
        if "connection" in error_msg.lower() or "network" in error_msg.lower():
            _record_question_runtime(
                "failed",
                selection_reason="exception:connection",
            )
            return jsonify({
                "error": "网络连接失败",
                "detail": "无法连接到 AI 服务，请检查网络连接"
            }), 503
        elif "timeout" in error_msg.lower():
            _record_question_runtime(
                "failed",
                selection_reason="exception:timeout",
            )
            return jsonify({
                "error": "请求超时",
                "detail": "AI 服务响应超时，请稍后重试"
            }), 503
        elif "authentication" in error_msg.lower() or "api key" in error_msg.lower():
            _record_question_runtime(
                "failed",
                selection_reason="exception:auth",
            )
            return jsonify({
                "error": "API 认证失败",
                "detail": "API Key 无效或已过期，请联系管理员"
            }), 503
        elif "rate limit" in error_msg.lower():
            _record_question_runtime(
                "failed",
                selection_reason="exception:rate_limit",
            )
            return jsonify({
                "error": "请求频率超限",
                "detail": "AI 服务请求过于频繁，请稍后再试"
            }), 503
        else:
            _record_question_runtime(
                "failed",
                selection_reason="exception:unknown",
            )
            return jsonify({
                "error": "生成问题失败",
                "detail": f"发生未知错误: {error_msg}"
            }), 503
    finally:
        if question_generation_slot_acquired:
            try:
                QUESTION_GENERATION_SEMAPHORE.release()
            except ValueError:
                pass
        if question_generation_queue_slot_acquired:
            release_question_generation_queue_slot()


def get_fallback_question(session: dict, dimension: str) -> dict:
    """获取备用问题（无 AI 时使用）"""
    fallback_questions = {
        "customer_needs": [
            {"question": "您希望通过这个项目解决哪些核心问题？", "options": ["提升工作效率", "降低运营成本", "改善用户体验", "增强数据分析能力"], "multi_select": True},
            {"question": "主要的用户群体有哪些？", "options": ["内部员工", "外部客户", "合作伙伴", "管理层"], "multi_select": True},
            {"question": "用户最期望获得的核心价值是什么？", "options": ["节省时间", "减少错误", "获取洞察", "提升协作"], "multi_select": False},
        ],
        "business_process": [
            {"question": "当前业务流程中需要优化的环节有哪些？", "options": ["数据录入", "审批流程", "报表生成", "跨部门协作"], "multi_select": True},
            {"question": "关键业务流程涉及哪些部门？", "options": ["销售部门", "技术部门", "财务部门", "运营部门"], "multi_select": True},
            {"question": "流程中最关键的决策节点是什么？", "options": ["审批节点", "分配节点", "验收节点", "结算节点"], "multi_select": False},
        ],
        "tech_constraints": [
            {"question": "期望的系统部署方式是？", "options": ["公有云部署", "私有云部署", "混合云部署", "本地部署"], "multi_select": False},
            {"question": "需要与哪些现有系统集成？", "options": ["ERP系统", "CRM系统", "OA办公系统", "财务系统"], "multi_select": True},
            {"question": "对系统安全性的要求是？", "options": ["等保二级", "等保三级", "基础安全即可", "需要详细评估"], "multi_select": False},
        ],
        "project_constraints": [
            {"question": "项目的预期预算范围是？", "options": ["10万以内", "10-50万", "50-100万", "100万以上"], "multi_select": False},
            {"question": "期望的上线时间是？", "options": ["1个月内", "1-3个月", "3-6个月", "6个月以上"], "multi_select": False},
            {"question": "项目团队的资源情况如何？", "options": ["有专职团队", "兼职参与", "完全外包", "需要评估"], "multi_select": False},
        ]
    }

    # 获取该维度已回答的正式问题数
    answered = len([
        log for log in session.get("interview_log", [])
        if log.get("dimension") == dimension and not log.get("is_follow_up", False)
    ])
    questions = fallback_questions.get(dimension, [])

    if answered < len(questions):
        q = questions[answered]
        return {
            "question": q["question"],
            "options": q["options"],
            "multi_select": q.get("multi_select", False),
            "question_multi_select": q.get("multi_select", False),
            "dimension": dimension,
            "ai_generated": False,
            "is_follow_up": False,
            "ai_recommendation": None
        }

    dim_info = get_dimension_info_for_session(session).get(dimension, {})
    mode_config = get_interview_mode_config(session)
    max_formal = max(
        1,
        int(mode_config.get("max_formal_questions_per_dim", mode_config.get("formal_questions_per_dim", 3)) or 3),
    )
    if answered < max_formal:
        dim_name = str(dim_info.get("name") or dimension or "当前维度").strip()
        key_aspects = get_dimension_fallback_options(session, dimension, limit=4)
        focus = key_aspects[min(answered, max(0, len(key_aspects) - 1))] if key_aspects else f"{dim_name}重点"
        question_templates = [
            f"关于{dim_name}，当前最需要优先确认的是哪一项？",
            f"如果先聚焦{dim_name}，您认为最关键的判断点是什么？",
            f"围绕{focus}，哪项更符合您的当前情况？",
            f"为便于推进{dim_name}，接下来最应补充哪类信息？",
        ]
        return {
            "question": question_templates[min(answered, len(question_templates) - 1)],
            "options": key_aspects[:4] if key_aspects else [f"{dim_name}现状", f"{dim_name}目标", f"{dim_name}约束", "需要进一步确认"],
            "multi_select": answered == 0,
            "question_multi_select": answered == 0,
            "dimension": dimension,
            "ai_generated": False,
            "is_follow_up": False,
            "ai_recommendation": None,
            "fallback_generated": True,
        }

    # 维度已完成
    return {
        "question": None,
        "dimension": dimension,
        "completed": True,
        "ai_recommendation": None
    }


OTHER_RESOLUTION_MODES = {"reference", "mixed", "custom"}


def normalize_ai_recommendation_payload(payload, interview_mode: str = DEFAULT_INTERVIEW_MODE) -> Optional[dict]:
    """规范化当前题 AI 推荐，便于写入 interview_log 并在撤销时恢复。"""
    if payload is None:
        return None
    if not isinstance(payload, dict):
        raise ValueError("ai_recommendation必须是对象")

    normalized_mode = normalize_interview_mode_key(interview_mode, fallback=DEFAULT_INTERVIEW_MODE)

    recommended_options = []
    seen_options = set()
    raw_options = payload.get("recommended_options")
    if isinstance(raw_options, list):
        for item in raw_options:
            normalized_item = str(item or "").strip()
            if not normalized_item or normalized_item in seen_options:
                continue
            recommended_options.append(normalized_item[:200])
            seen_options.add(normalized_item)
    elif isinstance(payload.get("recommended_option"), str):
        normalized_item = str(payload.get("recommended_option") or "").strip()
        if normalized_item:
            recommended_options = [normalized_item[:200]]

    summary = str(payload.get("summary", "") or "").strip()
    confidence = normalize_ai_recommendation_confidence(payload.get("confidence", ""))

    reasons = []
    raw_reasons = payload.get("reasons")
    if isinstance(raw_reasons, list):
        for reason in raw_reasons[:4]:
            if not isinstance(reason, dict):
                continue
            text = str(reason.get("text", "") or "").strip()
            if not text:
                continue
            evidence_values = []
            raw_evidence = reason.get("evidence")
            if isinstance(raw_evidence, list):
                for item in raw_evidence[:4]:
                    normalized_item = str(item or "").strip()
                    if normalized_item:
                        evidence_values.append(normalized_item[:120])
            reason_payload = {"text": text[:240]}
            if evidence_values:
                reason_payload["evidence"] = evidence_values
            reasons.append(reason_payload)

    if not recommended_options and not summary and not reasons:
        return None

    min_confidence_by_mode = {
        "quick": AI_RECOMMENDATION_MIN_CONFIDENCE_QUICK,
        "standard": AI_RECOMMENDATION_MIN_CONFIDENCE_STANDARD,
        "deep": AI_RECOMMENDATION_MIN_CONFIDENCE_DEEP,
    }
    if not recommended_options:
        return None
    if not ai_recommendation_confidence_meets_threshold(
        confidence,
        min_confidence_by_mode.get(normalized_mode, AI_RECOMMENDATION_MIN_CONFIDENCE_STANDARD),
    ):
        return None
    if normalized_mode == "deep" and AI_RECOMMENDATION_REQUIRE_EVIDENCE_DEEP:
        evidence_backed_reasons = [
            reason for reason in reasons
            if isinstance(reason, dict)
            and len(list(reason.get("evidence") or [])) > 0
        ]
        if len(evidence_backed_reasons) < 2:
            return None
        reasons = evidence_backed_reasons[:3]

    normalized = {
        "recommended_options": recommended_options,
        "summary": summary[:240],
        "reasons": reasons,
    }
    if confidence:
        normalized["confidence"] = confidence
    return normalized


def normalize_other_resolution_payload(
    payload,
    option_list: list[str],
    *,
    other_selected: bool,
    other_answer_text: str,
) -> Optional[dict]:
    """标准化“其他”选项的解析结果元数据。"""
    if payload is None or not other_selected:
        return None
    if not isinstance(payload, dict):
        raise ValueError("other_resolution必须是对象")

    mode = str(payload.get("mode", "") or "").strip().lower()
    if mode not in OTHER_RESOLUTION_MODES:
        raise ValueError("other_resolution.mode无效")

    raw_matched_options = payload.get("matched_options", [])
    if raw_matched_options is None:
        raw_matched_options = []
    if not isinstance(raw_matched_options, list):
        raise ValueError("other_resolution.matched_options必须是列表")

    allowed_options = {
        str(item or "").strip()
        for item in option_list
        if str(item or "").strip()
    }
    matched_options = []
    seen_options = set()
    for item in raw_matched_options:
        if not isinstance(item, str):
            raise ValueError("other_resolution.matched_options必须全部为字符串")
        normalized_item = item.strip()
        if not normalized_item:
            continue
        if allowed_options and normalized_item not in allowed_options:
            raise ValueError("other_resolution.matched_options包含无效选项")
        if normalized_item in seen_options:
            continue
        matched_options.append(normalized_item)
        seen_options.add(normalized_item)

    source_text = payload.get("source_text", other_answer_text)
    custom_text = payload.get("custom_text", "")
    if source_text is None:
        source_text = other_answer_text
    if custom_text is None:
        custom_text = ""
    if not isinstance(source_text, str):
        raise ValueError("other_resolution.source_text必须是字符串")
    if not isinstance(custom_text, str):
        raise ValueError("other_resolution.custom_text必须是字符串")

    source_text = source_text.strip()
    custom_text = custom_text.strip()
    if len(source_text) > 2000:
        raise ValueError("other_resolution.source_text长度不能超过2000字符")
    if len(custom_text) > 2000:
        raise ValueError("other_resolution.custom_text长度不能超过2000字符")

    if mode == "reference" and not matched_options:
        raise ValueError("other_resolution.reference需要至少一个matched_options")
    if mode == "mixed" and (not matched_options or not custom_text):
        raise ValueError("other_resolution.mixed需要matched_options和custom_text")
    if mode == "custom" and matched_options:
        raise ValueError("other_resolution.custom不能包含matched_options")

    return {
        "mode": mode,
        "matched_options": matched_options,
        "custom_text": custom_text,
        "source_text": source_text,
    }


def extract_other_resolution(log: dict, option_list: list[str]) -> Optional[dict]:
    """读取已持久化的“其他”选项语义数据；历史数据缺失时返回 None。"""
    if not isinstance(log, dict):
        return None

    raw_value = log.get("other_resolution")
    if not isinstance(raw_value, dict):
        return None

    mode = str(raw_value.get("mode", "") or "").strip().lower()
    if mode not in OTHER_RESOLUTION_MODES:
        return None

    matched_options = []
    seen_options = set()
    allowed_options = {
        str(item or "").strip()
        for item in option_list
        if str(item or "").strip()
    }
    raw_matched_options = raw_value.get("matched_options", [])
    if isinstance(raw_matched_options, list):
        for item in raw_matched_options:
            normalized_item = str(item or "").strip()
            if not normalized_item:
                continue
            if allowed_options and normalized_item not in allowed_options:
                continue
            if normalized_item in seen_options:
                continue
            matched_options.append(normalized_item)
            seen_options.add(normalized_item)

    custom_text = str(raw_value.get("custom_text", "") or "").strip()
    source_text = str(raw_value.get("source_text", "") or "").strip()

    if mode == "reference" and not matched_options:
        return None
    if mode == "mixed" and (not matched_options or not custom_text):
        return None
    if mode == "custom" and matched_options:
        return None

    return {
        "mode": mode,
        "matched_options": matched_options,
        "custom_text": custom_text,
        "source_text": source_text,
    }


@app.route('/api/sessions/<session_id>/interview-assistant-chat', methods=['POST'])
def interview_assistant_chat(session_id):
    """当前题内 AI 助手；辅助解释不进入正式访谈记录。"""
    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    loaded = load_session_for_user(session_id, user_id)
    if len(loaded) == 3:
        _file, error_msg, status_code = loaded
        return jsonify({"error": error_msg}), status_code

    _session_file, session = loaded
    data = request.get_json() or {}
    try:
        chat_payload = normalize_interview_assistant_chat_payload(data, session)
    except ValueError as exc:
        return jsonify({"error": str(exc)}), 400

    if not resolve_ai_client(call_type="summary_interview_chat"):
        return jsonify({"error": "AI 助手暂时不可用"}), 503

    now_iso = get_utc_now()
    try:
        reply = generate_interview_assistant_chat_reply(
            session,
            chat_payload,
            call_ai=call_claude,
            now_iso=now_iso,
            get_dimension_info_for_session=get_dimension_info_for_session,
            select_reference_material_context=select_reference_material_context,
            reference_context_chunk_limit=REFERENCE_MATERIAL_CONTEXT_CHUNK_LIMIT,
        )
    except Exception as exc:
        if ENABLE_DEBUG_LOG:
            print(f"⚠️ 题内助手生成失败: {exc}")
        return jsonify({"error": "AI 助手暂时不可用"}), 502

    with locked_session_for_user(session_id, user_id) as latest_loaded:
        if len(latest_loaded) == 3:
            _file, error_msg, status_code = latest_loaded
            return jsonify({"error": error_msg}), status_code

        latest_session_file, latest_session = latest_loaded
        append_interview_assistant_chat_exchange(
            latest_session,
            chat_payload,
            reply,
            now_iso=now_iso,
        )
        latest_session["updated_at"] = now_iso
        save_session_json_and_sync(latest_session_file, latest_session)
    return jsonify(reply)


@app.route('/api/sessions/<session_id>/submit-answer', methods=['POST'])
@with_session_write_lock
def submit_answer(session_id):
    """提交回答"""
    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    loaded = load_session_for_user(session_id, user_id)
    if len(loaded) == 3:
        _file, error_msg, status_code = loaded
        return jsonify({"error": error_msg}), status_code

    session_file, session = loaded

    # 验证请求数据
    data = request.get_json()
    if not data:
        return jsonify({"error": "无效的请求数据"}), 400

    question = data.get("question")
    answer = data.get("answer")
    dimension = data.get("dimension")
    options = data.get("options", [])
    multi_select = data.get("multi_select", False)
    question_multi_select = data.get("question_multi_select", multi_select)
    selection_escalated_from_single = data.get("selection_escalated_from_single", False)
    other_selected = data.get("other_selected", False)
    other_answer_text = data.get("other_answer_text", "")
    other_resolution_payload = data.get("other_resolution")
    is_follow_up = data.get("is_follow_up", False)
    answer_mode = data.get("answer_mode", "")
    requires_rationale = data.get("requires_rationale", False)
    evidence_intent = data.get("evidence_intent", "")
    rationale_text = data.get("rationale_text", "")
    question_generation_tier = data.get("question_generation_tier", "")
    question_selected_lane = data.get("question_selected_lane", "")
    question_runtime_profile = data.get("question_runtime_profile", "")
    question_hedge_triggered = data.get("question_hedge_triggered", False)
    question_fallback_triggered = data.get("question_fallback_triggered", False)
    ai_recommendation_payload = data.get("ai_recommendation")
    preflight_intervened = data.get("preflight_intervened", False)
    preflight_fingerprint = data.get("preflight_fingerprint", "")
    preflight_planner_mode = data.get("preflight_planner_mode", "")
    preflight_probe_slots = data.get("preflight_probe_slots", [])

    # 验证必需参数
    if not question or not isinstance(question, str):
        return jsonify({"error": "问题不能为空"}), 400
    if not answer or not isinstance(answer, str):
        return jsonify({"error": "答案不能为空"}), 400
    if len(answer) > 5000:
        return jsonify({"error": "答案长度不能超过5000字符"}), 400
    if not dimension or dimension not in session.get("dimensions", {}):
        return jsonify({"error": "无效的维度"}), 400
    if not isinstance(options, list):
        return jsonify({"error": "选项必须是列表"}), 400
    if not isinstance(multi_select, bool):
        return jsonify({"error": "multi_select必须是布尔值"}), 400
    if not isinstance(question_multi_select, bool):
        return jsonify({"error": "question_multi_select必须是布尔值"}), 400
    if not isinstance(selection_escalated_from_single, bool):
        return jsonify({"error": "selection_escalated_from_single必须是布尔值"}), 400
    if not isinstance(other_selected, bool):
        return jsonify({"error": "other_selected必须是布尔值"}), 400
    if other_answer_text is None:
        other_answer_text = ""
    if not isinstance(other_answer_text, str):
        return jsonify({"error": "other_answer_text必须是字符串"}), 400
    if len(other_answer_text) > 2000:
        return jsonify({"error": "自定义答案长度不能超过2000字符"}), 400
    if not isinstance(is_follow_up, bool):
        return jsonify({"error": "is_follow_up必须是布尔值"}), 400
    if rationale_text is None:
        rationale_text = ""
    if not isinstance(rationale_text, str):
        return jsonify({"error": "rationale_text必须是字符串"}), 400
    if len(rationale_text) > 3000:
        return jsonify({"error": "原因说明长度不能超过3000字符"}), 400
    if not isinstance(requires_rationale, bool):
        return jsonify({"error": "requires_rationale必须是布尔值"}), 400
    if not isinstance(question_generation_tier, str):
        return jsonify({"error": "question_generation_tier必须是字符串"}), 400
    if not isinstance(question_selected_lane, str):
        return jsonify({"error": "question_selected_lane必须是字符串"}), 400
    if not isinstance(question_runtime_profile, str):
        return jsonify({"error": "question_runtime_profile必须是字符串"}), 400
    if not isinstance(question_hedge_triggered, bool):
        return jsonify({"error": "question_hedge_triggered必须是布尔值"}), 400
    if not isinstance(question_fallback_triggered, bool):
        return jsonify({"error": "question_fallback_triggered必须是布尔值"}), 400
    if not isinstance(preflight_intervened, bool):
        return jsonify({"error": "preflight_intervened必须是布尔值"}), 400
    if not isinstance(preflight_fingerprint, str):
        return jsonify({"error": "preflight_fingerprint必须是字符串"}), 400
    if not isinstance(preflight_planner_mode, str):
        return jsonify({"error": "preflight_planner_mode必须是字符串"}), 400
    if preflight_probe_slots is None:
        preflight_probe_slots = []
    if not isinstance(preflight_probe_slots, list):
        return jsonify({"error": "preflight_probe_slots必须是列表"}), 400
    answer_mode = normalize_question_answer_mode(answer_mode, fallback="pick_with_reason" if requires_rationale else "pick_only")
    requires_rationale = bool(requires_rationale or answer_mode == "pick_with_reason")
    evidence_intent = normalize_question_evidence_intent(
        evidence_intent,
        fallback="high" if requires_rationale else ("medium" if answer_mode == "pick_with_reason" else "low"),
    )

    try:
        other_resolution = normalize_other_resolution_payload(
            other_resolution_payload,
            options,
            other_selected=other_selected,
            other_answer_text=other_answer_text,
        )
    except ValueError as exc:
        return jsonify({"error": str(exc)}), 400

    try:
        ai_recommendation = normalize_ai_recommendation_payload(
            ai_recommendation_payload,
            interview_mode=get_mode_identifier(session),
        )
    except ValueError as exc:
        return jsonify({"error": str(exc)}), 400

    idempotent_payload = _build_submit_answer_idempotency_payload(
        question=question,
        answer=answer,
        dimension=dimension,
        options=options,
        multi_select=multi_select,
        question_multi_select=question_multi_select,
        selection_escalated_from_single=selection_escalated_from_single,
        other_selected=other_selected,
        other_answer_text=other_answer_text,
        other_resolution=other_resolution,
        is_follow_up=is_follow_up,
        answer_mode=answer_mode,
        requires_rationale=requires_rationale,
        evidence_intent=evidence_intent,
        rationale_text=rationale_text,
        question_generation_tier=question_generation_tier,
        question_selected_lane=question_selected_lane,
        question_runtime_profile=question_runtime_profile,
        question_hedge_triggered=question_hedge_triggered,
        question_fallback_triggered=question_fallback_triggered,
        ai_recommendation=ai_recommendation,
        preflight_intervened=preflight_intervened,
        preflight_fingerprint=preflight_fingerprint,
        preflight_planner_mode=preflight_planner_mode,
        preflight_probe_slots=preflight_probe_slots,
    )
    if _is_recent_duplicate_submit_answer(session, idempotent_payload):
        deduplicated_session = dict(session)
        deduplicated_session["deduplicated"] = True
        return jsonify(deduplicated_session)

    # 使用增强版评估函数判断回答是否需要追问
    eval_result = evaluate_answer_depth(
        question=question,
        answer=answer,
        dimension=dimension,
        options=options,
        is_follow_up=is_follow_up,
        multi_select=multi_select,
        answer_mode=answer_mode,
        requires_rationale=requires_rationale,
        evidence_intent=evidence_intent,
    )
    needs_follow_up = eval_result["needs_follow_up"]
    follow_up_signals = eval_result["signals"]

    dim_logs_before = [log for log in session.get("interview_log", []) if log.get("dimension") == dimension]
    follow_up_round = get_follow_up_round_for_dimension_logs(dim_logs_before)
    if not is_follow_up:
        follow_up_round = 0
    else:
        follow_up_round += 1

    quality_result = evaluate_answer_quality(
        eval_result=eval_result,
        answer=answer,
        is_follow_up=is_follow_up,
        follow_up_round=follow_up_round,
    )

    if ENABLE_DEBUG_LOG and (needs_follow_up or eval_result["suggest_ai_eval"]):
        print(f"📝 回答评估: signals={follow_up_signals}, needs_follow_up={needs_follow_up}")

    # 添加到访谈记录
    log_entry = {
        "timestamp": get_utc_now(),
        "question": question,
        "answer": answer,
        "dimension": dimension,
        "options": options,
        "multi_select": multi_select,
        "question_multi_select": question_multi_select,
        "selection_escalated_from_single": selection_escalated_from_single,
        "other_selected": other_selected,
        "other_answer_text": other_answer_text,
        "other_resolution": other_resolution,
        "is_follow_up": is_follow_up,
        "answer_mode": answer_mode,
        "requires_rationale": requires_rationale,
        "evidence_intent": evidence_intent,
        "rationale_text": rationale_text.strip(),
        "question_generation_tier": str(question_generation_tier or "").strip(),
        "question_selected_lane": str(question_selected_lane or "").strip(),
        "question_runtime_profile": str(question_runtime_profile or "").strip(),
        "question_hedge_triggered": bool(question_hedge_triggered),
        "question_fallback_triggered": bool(question_fallback_triggered),
        "ai_recommendation": ai_recommendation,
        "preflight_intervened": bool(preflight_intervened),
        "preflight_fingerprint": str(preflight_fingerprint or "").strip(),
        "preflight_planner_mode": str(preflight_planner_mode or "").strip(),
        "preflight_probe_slots": [
            str(item or "").strip()
            for item in preflight_probe_slots
            if str(item or "").strip()
        ][:EVIDENCE_LEDGER_MAX_FOCUS_SLOTS],
        "needs_follow_up": needs_follow_up,
        "follow_up_signals": follow_up_signals,  # 记录检测到的信号
        "quality_score": quality_result["quality_score"],
        "quality_signals": quality_result["quality_signals"],
        "hard_triggered": quality_result["hard_triggered"],
        "follow_up_round": follow_up_round,
        "answer_evidence_class": classify_answer_evidence_class_v3(
            follow_up_signals,
            quality_result["quality_score"],
            evidence_intent,
        ),
    }
    session["interview_log"].append(log_entry)
    refresh_session_evidence_ledger(session)

    # 更新维度数据（只有正式问题才添加到维度需求列表）
    if dimension and dimension in session["dimensions"] and not is_follow_up:
        session["dimensions"][dimension]["items"].append({
            "name": answer,
            "description": question,
            "priority": "中"
        })

    # 计算覆盖度（只统计正式问题，追问不计入）
    if dimension and dimension in session["dimensions"]:
        session["dimensions"][dimension]["coverage"] = calculate_dimension_coverage(session, dimension)

    # 评估场景：为每次回答进行 AI 评分
    is_assessment = session.get("scenario_config", {}).get("report", {}).get("type") == "assessment"
    if is_assessment and dimension and dimension in session["dimensions"]:
        score = score_assessment_answer(session, dimension, question, answer)
        if score is not None:
            # 记录本次回答的评分
            log_entry["score"] = score
            # 更新维度的综合评分（取该维度所有评分的平均值）
            dim_scores = [
                log.get("score") for log in session["interview_log"]
                if log.get("dimension") == dimension and log.get("score") is not None
            ]
            if dim_scores:
                session["dimensions"][dimension]["score"] = round(sum(dim_scores) / len(dim_scores), 2)
            if ENABLE_DEBUG_LOG:
                print(f"📊 评估评分: {dimension} = {score}分，维度均分 = {session['dimensions'][dimension].get('score')}")

    session["updated_at"] = get_utc_now()
    session_signature = save_session_json_and_sync(session_file, session)

    try:
        trigger_current_dimension_prefetch(session, dimension, session_signature=session_signature)
    except Exception as e:
        print(f"⚠️ 当前维度预生成触发失败: {e}")

    # 异步更新上下文摘要（超过阈值且满足节流时触发）
    if len(session.get("interview_log", [])) >= SUMMARY_THRESHOLD:
        schedule_context_summary_update_async(session_id)

    return jsonify(session)


@app.route('/api/sessions/<session_id>/undo-answer', methods=['POST'])
@with_session_write_lock
def undo_answer(session_id):
    """撤销最后一个回答"""
    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    loaded = load_session_for_user(session_id, user_id)
    if len(loaded) == 3:
        _file, error_msg, status_code = loaded
        return jsonify({"error": error_msg}), status_code

    session_file, session = loaded

    # 检查是否有回答可以撤销
    if not session.get("interview_log") or len(session["interview_log"]) == 0:
        return jsonify({"error": "没有可撤销的回答"}), 400

    # 删除最后一个回答
    last_log = session["interview_log"].pop()
    dimension = last_log.get("dimension")
    was_follow_up = last_log.get("is_follow_up", False)

    # 更新维度数据（只有正式问题才影响维度 items）
    if dimension and dimension in session["dimensions"]:
        # 只有删除的是正式问题时，才从 items 中删除
        if not was_follow_up and session["dimensions"][dimension]["items"]:
            session["dimensions"][dimension]["items"].pop()

        # 重新计算覆盖度（只统计正式问题）
        session["dimensions"][dimension]["coverage"] = calculate_dimension_coverage(session, dimension)

    refresh_session_evidence_ledger(session)
    session["updated_at"] = get_utc_now()
    save_session_json_and_sync(session_file, session)

    return jsonify(session)


@app.route('/api/sessions/<session_id>/skip-follow-up', methods=['POST'])
@with_session_write_lock
def skip_follow_up(session_id):
    """
    用户主动跳过当前问题的追问
    标记最后一个正式问题的回答为"不需要追问"
    """
    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    loaded = load_session_for_user(session_id, user_id)
    if len(loaded) == 3:
        _file, error_msg, status_code = loaded
        return jsonify({"error": error_msg}), status_code

    session_file, session = loaded
    data = request.get_json() or {}
    dimension = data.get("dimension")

    # 验证 dimension
    if not dimension or dimension not in session.get("dimensions", {}):
        return jsonify({"error": "无效的维度"}), 400

    interview_log = session.get("interview_log", [])
    if not interview_log:
        return jsonify({"error": "没有可跳过的问题"}), 400

    # 找到当前维度的最后一个正式问题
    dim_logs = [log for log in interview_log if log.get("dimension") == dimension]
    formal_logs = [log for log in dim_logs if not log.get("is_follow_up", False)]

    if not formal_logs:
        return jsonify({"error": "没有可跳过的正式问题"}), 400

    # 标记最后一个正式问题不需要追问
    last_formal = formal_logs[-1]
    last_formal["needs_follow_up"] = False
    last_formal["user_skip_follow_up"] = True  # 标记为用户主动跳过
    refresh_session_evidence_ledger(session)

    session["updated_at"] = get_utc_now()
    save_session_json_and_sync(session_file, session)

    if ENABLE_DEBUG_LOG:
        print(f"⏭️ 用户跳过追问: dimension={dimension}")

    return jsonify({"success": True, "message": "已跳过追问"})


@app.route('/api/sessions/<session_id>/complete-dimension', methods=['POST'])
@with_session_write_lock
def complete_dimension(session_id):
    """
    用户主动完成当前维度
    将当前维度标记为已完成（覆盖度设为100%）
    """
    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    loaded = load_session_for_user(session_id, user_id)
    if len(loaded) == 3:
        _file, error_msg, status_code = loaded
        return jsonify({"error": error_msg}), status_code

    session_file, session = loaded
    data = request.get_json() or {}
    dimension = data.get("dimension")

    # 验证维度有效性
    if not dimension or dimension not in session.get("dimensions", {}):
        return jsonify({"error": "无效的维度"}), 400

    # 检查覆盖度是否已达到至少 50%
    current_coverage = session["dimensions"][dimension]["coverage"]
    if current_coverage < 50:
        return jsonify({
            "error": "无法完成维度",
            "detail": "当前维度覆盖度不足50%，建议至少回答一半问题后再跳过"
        }), 400

    # 标记所有该维度的回答为不需要追问
    for log in session.get("interview_log", []):
        if log.get("dimension") == dimension and not log.get("is_follow_up", False):
            log["needs_follow_up"] = False

    # 将维度覆盖度设为 100%
    session["dimensions"][dimension]["coverage"] = 100
    session["dimensions"][dimension]["user_completed"] = True  # 标记为用户主动完成
    session["dimensions"][dimension]["auto_completed"] = False
    session["dimensions"][dimension]["completion_reason"] = "user_completed"
    session["dimensions"][dimension]["quality_warning"] = False

    refresh_session_evidence_ledger(session)
    session["updated_at"] = get_utc_now()
    save_session_json_and_sync(session_file, session)

    if ENABLE_DEBUG_LOG:
        print(f"⏭️ 用户完成维度: dimension={dimension}, coverage={current_coverage}%")

    session_dim_info = get_dimension_info_for_session(session)
    dim_name = session_dim_info.get(dimension, {}).get('name', dimension)
    return jsonify({"success": True, "message": f"{dim_name}维度已完成"})


# ============ 文档上传 API ============

REFERENCE_MATERIAL_CONTENT_LIMIT = 10000
REFERENCE_MATERIAL_PREVIEW_LIMIT = 300
REFERENCE_MATERIAL_CHUNK_SIZE = max(800, _cfg_int("REFERENCE_MATERIAL_CHUNK_SIZE", 1800))
REFERENCE_MATERIAL_CHUNK_OVERLAP = max(0, _cfg_int("REFERENCE_MATERIAL_CHUNK_OVERLAP", 160))
if REFERENCE_MATERIAL_CHUNK_OVERLAP >= REFERENCE_MATERIAL_CHUNK_SIZE:
    REFERENCE_MATERIAL_CHUNK_OVERLAP = max(0, REFERENCE_MATERIAL_CHUNK_SIZE // 10)
REFERENCE_MATERIAL_CONTEXT_CHUNK_LIMIT = max(1, _cfg_int("REFERENCE_MATERIAL_CONTEXT_CHUNK_LIMIT", 4))
REFERENCE_MATERIAL_INLINE_CHUNK_PREVIEW_LIMIT = max(20, _cfg_int("REFERENCE_MATERIAL_INLINE_CHUNK_PREVIEW_LIMIT", 120))


def _compact_reference_material_preview(content: str, limit: int = REFERENCE_MATERIAL_PREVIEW_LIMIT) -> str:
    text = re.sub(r"\s+", " ", str(content or "")).strip()
    if len(text) <= limit:
        return text
    return text[: max(0, limit - 3)].rstrip() + "..."


def _safe_reference_material_segment(value: str, fallback: str = "item") -> str:
    text = re.sub(r"[^A-Za-z0-9_.-]+", "-", str(value or "").strip()).strip(".-")
    if not text:
        text = fallback
    return text[:96]


def _reference_material_storage_dir(session_id: str, doc_id: str) -> Path:
    session_segment = _safe_reference_material_segment(session_id, "session")
    doc_segment = _safe_reference_material_segment(doc_id, "doc")
    target = (REFERENCE_MATERIALS_DIR / session_segment / doc_segment).resolve()
    if not is_path_under(target, REFERENCE_MATERIALS_DIR):
        raise ValueError("参考资料归档路径无效")
    return target


def _relative_data_ref(path: Path) -> str:
    try:
        return str(Path(path).resolve().relative_to(DATA_DIR.resolve()))
    except Exception:
        return ""


def _resolve_data_ref(ref: str) -> Path:
    normalized = str(ref or "").strip()
    if not normalized:
        raise ValueError("数据引用为空")
    target = (DATA_DIR / normalized).resolve()
    if not is_path_under(target, DATA_DIR):
        raise ValueError("数据引用路径无效")
    return target


def _build_reference_material_chunks(content: str) -> list[dict]:
    text = str(content or "")
    if not text.strip():
        return []
    chunk_size = REFERENCE_MATERIAL_CHUNK_SIZE
    overlap = min(REFERENCE_MATERIAL_CHUNK_OVERLAP, max(0, chunk_size // 3))
    chunks = []
    start = 0
    text_length = len(text)
    while start < text_length:
        hard_end = min(text_length, start + chunk_size)
        end = hard_end
        if hard_end < text_length:
            split_floor = start + max(200, chunk_size // 2)
            paragraph_split = text.rfind("\n\n", split_floor, hard_end)
            line_split = text.rfind("\n", split_floor, hard_end)
            split_at = max(paragraph_split, line_split)
            if split_at > start:
                end = min(text_length, split_at + 1)
        chunk_text = text[start:end].strip()
        if chunk_text:
            chunks.append({
                "chunk_id": f"chunk-{len(chunks) + 1:04d}",
                "index": len(chunks),
                "start": start,
                "end": end,
                "text": chunk_text,
                "preview": _compact_reference_material_preview(
                    chunk_text,
                    REFERENCE_MATERIAL_INLINE_CHUNK_PREVIEW_LIMIT,
                ),
            })
        if end >= text_length:
            break
        next_start = max(end - overlap, start + 1)
        if next_start <= start:
            next_start = end
        start = next_start
    return chunks


def save_reference_material_fulltext_artifacts(
    *,
    session_id: str,
    doc_id: str,
    filename: str,
    content: str,
    ext: str,
) -> dict:
    text = str(content or "")
    if not text.strip():
        return {}
    target_dir = _reference_material_storage_dir(session_id, doc_id)
    target_dir.mkdir(parents=True, exist_ok=True)
    full_text_path = target_dir / "full_content.md"
    chunks_path = target_dir / "chunks.json"
    content_sha256 = hashlib.sha256(text.encode("utf-8")).hexdigest()
    chunks = _build_reference_material_chunks(text)
    full_text_path.write_text(text, encoding="utf-8")
    chunks_path.write_text(json.dumps({
        "version": 1,
        "doc_id": doc_id,
        "name": filename,
        "type": ext,
        "content_sha256": content_sha256,
        "chunk_size": REFERENCE_MATERIAL_CHUNK_SIZE,
        "chunk_overlap": REFERENCE_MATERIAL_CHUNK_OVERLAP,
        "chunks": chunks,
    }, ensure_ascii=False), encoding="utf-8")
    inline_chunks = [
        {
            "chunk_id": chunk.get("chunk_id"),
            "index": chunk.get("index"),
            "start": chunk.get("start"),
            "end": chunk.get("end"),
            "preview": chunk.get("preview"),
        }
        for chunk in chunks[:REFERENCE_MATERIAL_CONTEXT_CHUNK_LIMIT]
    ]
    return {
        "full_content_ref": _relative_data_ref(full_text_path),
        "chunk_manifest_ref": _relative_data_ref(chunks_path),
        "full_content_sha256": content_sha256,
        "chunk_count": len(chunks),
        "chunk_index_version": 1,
        "chunk_previews": inline_chunks,
    }


def load_reference_material_chunks(doc: dict) -> list[dict]:
    if not isinstance(doc, dict):
        return []
    manifest_ref = str(doc.get("chunk_manifest_ref") or "").strip()
    if not manifest_ref:
        return []
    try:
        manifest_path = _resolve_data_ref(manifest_ref)
        payload = json.loads(manifest_path.read_text(encoding="utf-8"))
    except Exception as exc:
        if ENABLE_DEBUG_LOG:
            print(f"⚠️  读取参考资料分块失败: {exc}")
        return []
    chunks = payload.get("chunks", []) if isinstance(payload, dict) else []
    return [chunk for chunk in chunks if isinstance(chunk, dict) and str(chunk.get("text") or "").strip()]


def _tokenize_reference_material_query(query_text: str) -> list[str]:
    normalized = str(query_text or "").lower()
    raw_terms = re.findall(r"[a-z0-9_]{2,}|[\u4e00-\u9fff]{2,}", normalized)
    terms = []
    for term in raw_terms:
        compact = term.strip()
        if compact and compact not in terms:
            terms.append(compact)
        if re.fullmatch(r"[\u4e00-\u9fff]{6,}", compact):
            for size in (4, 3):
                for index in range(0, max(0, len(compact) - size + 1)):
                    gram = compact[index:index + size]
                    if gram and gram not in terms:
                        terms.append(gram)
    return terms[:80]


def select_reference_material_context(
    doc: dict,
    *,
    query_text: str = "",
    max_chars: int = 0,
    chunk_limit: int = 0,
) -> tuple[str, dict]:
    chunks = load_reference_material_chunks(doc)
    limit = max(1, int(max_chars or MAX_DOC_LENGTH))
    if not chunks:
        content = str((doc or {}).get("content") or "")
        return content[:limit], {
            "mode": "stored_content",
            "selected_chunks": [],
            "chunk_count": 0,
        }

    terms = _tokenize_reference_material_query(query_text)
    scored = []
    for chunk in chunks:
        text = str(chunk.get("text") or "")
        lowered = text.lower()
        score = sum(lowered.count(term) for term in terms)
        scored.append((score, int(chunk.get("index", 0) or 0), chunk))

    selected = []
    max_chunks = max(1, int(chunk_limit or REFERENCE_MATERIAL_CONTEXT_CHUNK_LIMIT))
    positive_scored = [item for item in scored if item[0] > 0]
    if positive_scored:
        for _score, _index, chunk in sorted(positive_scored, key=lambda item: (-item[0], item[1])):
            selected.append(chunk)
            if len(selected) >= max_chunks:
                break
        selected.sort(key=lambda item: int(item.get("index", 0) or 0))
    else:
        candidate_indexes = [0]
        if len(chunks) > 2:
            candidate_indexes.append(len(chunks) // 2)
        if len(chunks) > 1:
            candidate_indexes.append(len(chunks) - 1)
        for index in candidate_indexes:
            chunk = chunks[index]
            if chunk not in selected:
                selected.append(chunk)
            if len(selected) >= max_chunks:
                break

    parts = []
    used = 0
    selected_meta = []
    for chunk in selected:
        text = str(chunk.get("text") or "").strip()
        if not text:
            continue
        prefix = f"[片段 {int(chunk.get('index', 0) or 0) + 1}/{len(chunks)}]\n"
        available = limit - used - len(prefix)
        if available <= 0:
            break
        clipped = text[:available]
        parts.append(prefix + clipped)
        used += len(prefix) + len(clipped)
        selected_meta.append({
            "chunk_id": chunk.get("chunk_id"),
            "index": chunk.get("index"),
            "start": chunk.get("start"),
            "end": chunk.get("end"),
        })
        if used >= limit:
            break

    return "\n\n".join(parts).strip(), {
        "mode": "chunk_selection",
        "selected_chunks": selected_meta,
        "chunk_count": len(chunks),
        "query_terms": terms[:12],
    }


def _build_reference_material_parse_meta(content: str, ext: str) -> dict:
    text = str(content or "").strip()
    upper_ext = str(ext or "").lstrip(".").upper()
    parse_status = "parsed"
    parse_error = ""
    context_ready = bool(text)

    failure_prefix = f"[{upper_ext} 解析失败:"
    if upper_ext and text.startswith(failure_prefix):
        parse_status = "failed"
        parse_error = text.strip("[]")
        context_ready = False
    elif upper_ext and text.startswith(f"[{upper_ext} 文件:") and "转换脚本不存在" in text:
        parse_status = "failed"
        parse_error = "转换脚本不存在"
        context_ready = False
    elif text.startswith("[图片:") and any(marker in text for marker in (
        "视觉功能已禁用",
        "视觉 API 未配置",
        "文件过大:",
        "描述生成失败:",
        "API 错误:",
        "API 超时",
        "处理失败:",
    )):
        parse_status = "degraded"
        parse_error = text
        context_ready = False

    stored_chars = min(len(text), REFERENCE_MATERIAL_CONTENT_LIMIT)
    return {
        "parse_status": parse_status,
        "parse_error": parse_error,
        "original_size": 0,
        "extracted_chars": len(text),
        "stored_chars": stored_chars,
        "is_truncated": len(text) > REFERENCE_MATERIAL_CONTENT_LIMIT,
        "context_ready": bool(context_ready),
        "preview": _compact_reference_material_preview(text),
    }


@app.route('/api/sessions/<session_id>/documents', methods=['POST'])
def upload_document(session_id):
    """上传参考文档"""
    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    loaded = load_session_for_user(session_id, user_id)
    if len(loaded) == 3:
        _file, error_msg, status_code = loaded
        return jsonify({"error": error_msg}), status_code

    session_file, session = loaded

    if 'file' not in request.files:
        return jsonify({"error": "未找到文件"}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "文件名为空"}), 400

    # 验证文件大小（最大10MB）
    MAX_FILE_SIZE = 10 * 1024 * 1024  # 10MB
    file.seek(0, 2)  # 移动到文件末尾
    file_size = file.tell()
    file.seek(0)  # 重置文件指针
    if file_size > MAX_FILE_SIZE:
        return jsonify({"error": f"文件大小超过限制（最大{MAX_FILE_SIZE // 1024 // 1024}MB）"}), 400

    original_filename = Path(file.filename or "").name.strip()
    if not original_filename:
        return jsonify({"error": "文件名无效"}), 400

    display_filename = sanitize_filename(original_filename)
    if not display_filename:
        return jsonify({"error": "文件名无效"}), 400

    safe_filename = secure_filename(display_filename)
    if not safe_filename:
        fallback_ext = Path(display_filename).suffix.lower()
        safe_filename = f"upload{fallback_ext or '.txt'}"

    ext = Path(display_filename).suffix.lower()
    supported_image_types = {str(item).lower() for item in SUPPORTED_IMAGE_TYPES}
    allowed_upload_types = supported_image_types | {'.md', '.txt', '.pdf', '.docx', '.xlsx', '.pptx'}
    if ext not in allowed_upload_types:
        return jsonify({"error": f"不支持的文件类型: {ext or '未知'}"}), 400

    temp_stem = secure_filename(Path(safe_filename).stem)[:80] or "upload"
    temp_filename = f"{temp_stem}-{secrets.token_hex(8)}{ext}"
    filepath = (TEMP_DIR / temp_filename).resolve()
    if not is_path_under(filepath, TEMP_DIR):
        return jsonify({"error": "文件保存路径无效"}), 400

    file.save(str(filepath))
    filename = display_filename

    # 读取文件内容
    content = ""

    try:
        # 图片处理
        if ext in supported_image_types:
            content = describe_image_with_vision(filepath, filename)
        elif ext in ['.md', '.txt']:
            content = filepath.read_text(encoding="utf-8")
            if not content or not content.strip():
                return jsonify({"error": "文件内容为空"}), 400
        elif ext in ['.pdf', '.docx', '.xlsx', '.pptx']:
            # 先查 PostgreSQL 转换缓存，未命中再调用转换脚本
            import subprocess
            source_hash = _compute_file_sha256(filepath)
            converted_cache_key = build_converted_cache_key(source_hash, ext)
            cached_markdown = get_converted_cache_content(converted_cache_key)
            if cached_markdown.strip():
                content = cached_markdown
                if ENABLE_DEBUG_LOG:
                    print(f"📋 命中转换缓存: ext={ext}, hash={source_hash[:12]}")
            else:
                convert_script = SKILL_DIR / "scripts" / "convert_doc.py"
                if convert_script.exists():
                    try:
                        result = subprocess.run(
                            ["uv", "run", str(convert_script), "convert", str(filepath)],
                            capture_output=True,
                            text=True,
                            cwd=str(SKILL_DIR),
                            timeout=DOCUMENT_CONVERT_TIMEOUT_SECONDS,
                        )
                        if result.returncode == 0:
                            converted_file = CONVERTED_DIR / f"{filepath.stem}.md"
                            if converted_file.exists():
                                content = converted_file.read_text(encoding="utf-8")
                                if content.strip():
                                    save_converted_cache_content(
                                        converted_cache_key,
                                        content,
                                        source_ext=ext,
                                        source_hash=source_hash,
                                    )
                                if _use_postgres_shared_meta_storage():
                                    try:
                                        converted_file.unlink()
                                    except Exception:
                                        pass
                            else:
                                content = f"[{ext.upper()[1:]} 解析失败: 未找到转换后的文件]"
                        else:
                            error_msg = result.stderr[:200] if result.stderr else "未知错误"
                            content = f"[{ext.upper()[1:]} 解析失败: {error_msg}]"
                    except subprocess.TimeoutExpired:
                        content = f"[{ext.upper()[1:]} 解析失败: 转换超时（>{DOCUMENT_CONVERT_TIMEOUT_SECONDS}s）]"
                    except Exception as e:
                        print(f"转换文档失败: {e}")
                        content = f"[{ext.upper()[1:]} 解析失败: {str(e)[:200]}]"
                else:
                    content = f"[{ext.upper()[1:]} 文件: {filename}] (转换脚本不存在)"
    except UnicodeDecodeError as e:
        return jsonify({"error": f"文件编码错误: {str(e)}"}), 400
    except Exception as e:
        return jsonify({"error": f"文件处理失败: {str(e)}"}), 500

    if not content or not content.strip():
        return jsonify({"error": "文件解析后内容为空"}), 400

    upload_archive = {}
    upload_archive_warning = ""
    if is_object_storage_enabled():
        try:
            upload_archive = upload_file_to_object_storage(
                filepath,
                object_key=build_object_storage_key(
                    "uploads",
                    "sessions",
                    session_id,
                    filename=display_filename,
                ),
                content_type=str(file.content_type or _guess_content_type(display_filename)),
                metadata={
                    "session_id": session_id,
                    "owner_user_id": str(user_id),
                    "original_filename": display_filename,
                },
            )
        except Exception as exc:
            upload_archive_warning = f"文件归档到对象存储失败，已保留解析结果: {exc}"
            if ENABLE_DEBUG_LOG:
                print(f"⚠️ {upload_archive_warning}")

    # 读取内容完成后再短暂加锁写回，避免文档转换阻塞整个会话。
    with locked_session_for_user(session_id, user_id) as latest_loaded:
        if len(latest_loaded) == 3:
            _file, error_msg, status_code = latest_loaded
            return jsonify({"error": error_msg}), status_code

        latest_session_file, latest_session = latest_loaded
        latest_session = migrate_session_docs(latest_session)
        stored_content = content[:REFERENCE_MATERIAL_CONTENT_LIMIT]
        parse_meta = _build_reference_material_parse_meta(content, ext)
        parse_meta["original_size"] = int(file_size or 0)
        uploaded_document = {
            "name": filename,
            "type": ext,
            "content": stored_content,
            "source": "upload",  # 用户上传
            "uploaded_at": get_utc_now(),
            **parse_meta,
        }
        if upload_archive:
            uploaded_document.update({
                "storage_backend": upload_archive.get("storage_backend"),
                "object_key": upload_archive.get("object_key"),
                "bucket": upload_archive.get("bucket"),
                "content_type": upload_archive.get("content_type"),
            })
        if upload_archive_warning:
            uploaded_document["archive_warning"] = upload_archive_warning
        uploaded_document["doc_id"] = build_reference_material_doc_id(
            uploaded_document,
            index=len(latest_session["reference_materials"]),
        )
        if parse_meta.get("context_ready"):
            try:
                uploaded_document.update(save_reference_material_fulltext_artifacts(
                    session_id=session_id,
                    doc_id=uploaded_document["doc_id"],
                    filename=filename,
                    content=content,
                    ext=ext,
                ))
            except Exception as exc:
                uploaded_document["full_content_warning"] = f"全文索引保存失败，已保留兼容摘录: {exc}"
                if ENABLE_DEBUG_LOG:
                    print(f"⚠️  {uploaded_document['full_content_warning']}")
        latest_session["reference_materials"].append(uploaded_document)
        latest_session["updated_at"] = get_utc_now()
        save_session_json_and_sync(latest_session_file, latest_session)

    return jsonify({
        "success": True,
        "filename": filename,
        "content_length": len(content),
        "uploaded_document": copy.deepcopy(uploaded_document),
        "archive_warning": upload_archive_warning,
    })


@app.route('/api/sessions/<session_id>/documents/<path:doc_name>', methods=['DELETE'])
@with_session_write_lock
def delete_document(session_id, doc_name):
    """删除参考资料（软删除）"""
    # 路径遍历防护
    if '..' in doc_name or doc_name.startswith('/'):
        return jsonify({"error": "无效的文档名"}), 400

    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    loaded = load_session_for_user(session_id, user_id)
    if len(loaded) == 3:
        _file, error_msg, status_code = loaded
        return jsonify({"error": error_msg}), status_code

    session_file, session = loaded
    # 数据迁移：兼容旧会话
    session = migrate_session_docs(session)
    doc_id = str(request.args.get("doc_id") or "").strip()

    # 查找并删除文档
    original_count = len(session["reference_materials"])
    session["reference_materials"] = [
        doc for doc in session["reference_materials"]
        if not (
            (doc_id and str(doc.get("doc_id") or "").strip() == doc_id)
            or (not doc_id and doc["name"] == doc_name)
        )
    ]

    if len(session["reference_materials"]) == original_count:
        return jsonify({"error": "文档不存在"}), 404

    session["updated_at"] = get_utc_now()
    save_session_json_and_sync(session_file, session)

    # 软删除：记录到删除日志，文件保留在 temp/converted 目录
    mark_doc_as_deleted(session_id, doc_name, doc_id=doc_id)

    return jsonify({
        "success": True,
        "deleted": doc_name,
        "deleted_doc_id": doc_id,
        "message": "文档已从列表中移除（文件已存档）"
    })


# ============ 重新访谈 API ============

@app.route('/api/sessions/<session_id>/restart-interview', methods=['POST'])
@with_session_write_lock
def restart_interview(session_id):
    """重新访谈：将当前访谈记录保存为参考资料，然后重置访谈状态"""
    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    loaded = load_session_for_user(session_id, user_id)
    if len(loaded) == 3:
        _file, error_msg, status_code = loaded
        return jsonify({"error": error_msg}), status_code

    session_file, session = loaded
    # 数据迁移：兼容旧会话
    session = migrate_session_docs(session)

    # 整理当前访谈记录为 markdown 格式
    interview_log = session.get("interview_log", [])
    if not interview_log:
        return jsonify({"error": "没有访谈记录可以保存"}), 400

    # 生成访谈记录文档内容
    research_content = f"""# 访谈记录 - {session.get('topic', '未命名访谈')}

生成时间: {get_utc_now()}

"""

    if session.get("description"):
        # 清理描述中的特殊字符
        desc = session['description'].replace('\n', ' ').replace('\r', '')
        research_content += f"主题描述: {desc}\n\n"

    research_content += "## 访谈记录\n\n"

    # 按维度整理访谈记录
    restart_dim_info = get_dimension_info_for_session(session)
    for dim_key, dim_info in restart_dim_info.items():
        dim_logs = [log for log in interview_log if log.get("dimension") == dim_key]
        if dim_logs:
            research_content += f"### {dim_info['name']}\n\n"
            for log in dim_logs:
                # 清理文本中的特殊字符，避免影响 JSON 解析
                question = log.get('question', '').replace('**', '').replace('`', '')
                answer = log.get('answer', '').replace('**', '').replace('`', '')

                research_content += f"问题：{question}\n\n"
                research_content += f"回答：{answer}\n\n"

                if log.get('follow_up_question'):
                    follow_q = log['follow_up_question'].replace('**', '').replace('`', '')
                    follow_a = log.get('follow_up_answer', '').replace('**', '').replace('`', '')
                    research_content += f"追问: {follow_q}\n\n"
                    research_content += f"回答: {follow_a}\n\n"
                research_content += "---\n\n"

    # 添加到参考资料列表
    doc_name = f"访谈记录-{get_utc_now().replace(':', '-').replace(' ', '_')}.md"

    # 限制内容长度，避免过长导致 AI prompt 问题
    max_length = 2000
    if len(research_content) > max_length:
        research_content = research_content[:max_length] + "\n\n...(内容过长已截断)"

    restart_doc = {
        "name": doc_name,
        "type": ".md",
        "content": research_content,
        "source": "auto",  # 系统自动生成
        "uploaded_at": get_utc_now(),
    }
    restart_doc["doc_id"] = build_reference_material_doc_id(
        restart_doc,
        index=len(session["reference_materials"]),
    )
    session["reference_materials"].append(restart_doc)

    # 重置访谈状态 - 从场景配置动态创建维度
    session["interview_log"] = []
    reset_dim_info = get_dimension_info_for_session(session)
    session["dimensions"] = {
        dim_key: {"coverage": 0, "items": [], "score": None}
        for dim_key in reset_dim_info
    }
    session["status"] = "in_progress"  # 重置状态为进行中
    session["updated_at"] = get_utc_now()

    # 保存会话
    save_session_json_and_sync(session_file, session)

    return jsonify({
        "success": True,
        "message": "已保存当前访谈内容并重置访谈",
        "research_doc_name": doc_name
    })


# ============ 报告生成 API ============

V3_FAILOVER_FIXABLE_SINGLE_ISSUE_TYPES = {
    "blindspot",
    "style_template_violation",
    "quality_gate_expression",
    "quality_gate_table",
    "quality_gate_milestone",
    "quality_gate_actionability",
    "quality_gate_acceptance",
}

V3_FAILOVER_DETERMINISTIC_ISSUE_TYPES = {
    "blindspot",
    "no_evidence",
    "not_actionable",
    "style_template_violation",
    "quality_gate_evidence",
    "quality_gate_weak_binding",
    "quality_gate_expression",
    "quality_gate_table",
    "quality_gate_milestone",
    "quality_gate_actionability",
    "quality_gate_acceptance",
}

V3_RELEASE_CONSERVATIVE_SOFT_PASS_ISSUE_TYPES = {
    "style_template_violation",
    "quality_gate_expression",
    "quality_gate_acceptance",
    "quality_gate_weak_binding",
}


def _extract_v3_issue_types_for_failover(v3_result: Optional[dict]) -> list[str]:
    if not isinstance(v3_result, dict):
        return []
    return summarize_issue_types_v3(v3_result.get("review_issues", []))


def _is_v3_deterministic_issue_bucket(issue_types: list[str], final_issue_count: int) -> bool:
    if not REPORT_V3_FAILOVER_ON_DETERMINISTIC_BUCKET:
        return False
    if final_issue_count <= 0 or final_issue_count > REPORT_V3_FAILOVER_DETERMINISTIC_MAX_ISSUES:
        return False
    if not issue_types:
        return False
    return all(str(issue_type or "").strip().lower() in V3_FAILOVER_DETERMINISTIC_ISSUE_TYPES for issue_type in issue_types)


def should_retry_v3_with_failover(v3_result: Optional[dict]) -> bool:
    """判断 V3 失败后是否值得切备用网关再试一次。"""
    if not isinstance(v3_result, dict):
        return True

    reason = str(v3_result.get("reason", "") or "").strip().lower()
    error = str(v3_result.get("error", "") or "").strip().lower()
    issue_types = _extract_v3_issue_types_for_failover(v3_result)
    try:
        final_issue_count = int(v3_result.get("final_issue_count", len(v3_result.get("review_issues", []) or [])) or 0)
    except Exception:
        final_issue_count = len(v3_result.get("review_issues", []) or [])

    if reason in {"review_gate_failed", "quality_gate_failed", "review_not_passed_or_quality_gate_failed"}:
        if (
            REPORT_V3_FAILOVER_ON_SINGLE_ISSUE
            and final_issue_count == 1
            and len(issue_types) == 1
            and issue_types[0] in V3_FAILOVER_FIXABLE_SINGLE_ISSUE_TYPES
        ):
            return True
        return _is_v3_deterministic_issue_bucket(issue_types, final_issue_count)

    # 质量门禁未通过属于内容质量问题，切网关通常无收益
    if reason == "release_conservative_short_circuit":
        return False
    if reason in {"draft_generation_failed", "review_generation_failed", "exception", "v3_pipeline_returned_empty"}:
        return True

    network_hints = (
        "timeout",
        "timed out",
        "connection",
        "gateway",
        "504",
        "502",
        "503",
        "429",
        "rate limit",
    )
    if any(hint in error for hint in network_hints):
        return True

    # 解析失败通常与网关输出风格相关（例如返回额外说明/包装文本），
    # 在备用网关上重试一次通常有收益。
    if reason in {"draft_parse_failed", "review_parse_failed"}:
        return True

    return False


def can_release_conservative_soft_pass_v3(quality_gate_issues: list, quality_meta: Optional[dict], runtime_cfg: Optional[dict]) -> bool:
    """发布保守档下，仅存在软性表达/模板问题时允许直接放行，避免再次进入 legacy fallback。"""
    if not isinstance(runtime_cfg, dict) or not bool(runtime_cfg.get("release_conservative_mode", False)):
        return False
    issue_types = summarize_issue_types_v3(quality_gate_issues)
    if not issue_types or len(issue_types) > 4:
        return False
    if not all(issue_type in V3_RELEASE_CONSERVATIVE_SOFT_PASS_ISSUE_TYPES for issue_type in issue_types):
        return False
    if not isinstance(quality_meta, dict):
        return False

    evidence_coverage = max(0.0, min(1.0, _safe_float(quality_meta.get("evidence_coverage", 0.0), default=0.0)))
    actionability = max(0.0, min(1.0, _safe_float(quality_meta.get("actionability", 0.0), default=0.0)))
    table_readiness = max(0.0, min(1.0, _safe_float(quality_meta.get("table_readiness", 0.0), default=0.0)))
    if evidence_coverage < 0.45:
        return False
    if actionability < 0.35:
        return False
    if table_readiness < 0.40:
        return False
    return True


V3_BALANCED_LOW_EVIDENCE_SOFT_PASS_ISSUE_TYPES = {
    "quality_gate_evidence",
    "quality_gate_expression",
    "quality_gate_table",
    "quality_gate_acceptance",
    "quality_gate_milestone",
    "style_template_violation",
}


def can_balanced_low_evidence_soft_pass_v3(
    quality_gate_issues: list,
    quality_meta: Optional[dict],
    runtime_cfg: Optional[dict],
) -> bool:
    """balanced 档下，允许对低证据但已有事实支撑的报告做保守放行。"""
    if not isinstance(quality_meta, dict):
        return False

    runtime_profile = normalize_report_profile_choice(
        str(quality_meta.get("runtime_profile", "") or ""),
        fallback=str((runtime_cfg or {}).get("profile", "") or REPORT_V3_PROFILE),
    )
    if runtime_profile != "balanced":
        return False

    issue_types = summarize_issue_types_v3(quality_gate_issues)
    if not issue_types or len(quality_gate_issues or []) > 5:
        return False
    weak_binding_issue_present = "quality_gate_weak_binding" in issue_types
    allowed_issue_types = set(V3_BALANCED_LOW_EVIDENCE_SOFT_PASS_ISSUE_TYPES)
    if weak_binding_issue_present:
        allowed_issue_types.add("quality_gate_weak_binding")
    if not all(issue_type in allowed_issue_types for issue_type in issue_types):
        return False

    overall = max(0.0, min(1.0, _safe_float(quality_meta.get("overall", 0.0), default=0.0)))
    evidence_coverage = max(0.0, min(1.0, _safe_float(quality_meta.get("evidence_coverage", 0.0), default=0.0)))
    consistency = max(0.0, min(1.0, _safe_float(quality_meta.get("consistency", 0.0), default=0.0)))
    actionability = max(0.0, min(1.0, _safe_float(quality_meta.get("actionability", 0.0), default=0.0)))
    table_readiness = max(0.0, min(1.0, _safe_float(quality_meta.get("table_readiness", 0.0), default=0.0)))
    weak_binding_ratio = max(0.0, min(1.0, _safe_float(quality_meta.get("weak_binding_ratio", 0.0), default=0.0)))
    weak_binding_ratio_by_field = quality_meta.get("weak_binding_ratio_by_field", {}) if isinstance(quality_meta.get("weak_binding_ratio_by_field", {}), dict) else {}
    action_weak_binding_ratio = max(0.0, min(1.0, _safe_float(weak_binding_ratio_by_field.get("actions", 0.0), default=0.0)))
    solutions_weak_binding_ratio = max(0.0, min(1.0, _safe_float(weak_binding_ratio_by_field.get("solutions", 0.0), default=0.0)))
    risks_weak_binding_ratio = max(0.0, min(1.0, _safe_float(weak_binding_ratio_by_field.get("risks", 0.0), default=0.0)))
    review_issue_count = max(0, int(quality_meta.get("review_issue_count", len(quality_gate_issues or [])) or 0))
    pending_follow_up_count = max(0, int(quality_meta.get("pending_follow_up_count", 0) or 0))
    evidence_context = quality_meta.get("evidence_context", {}) if isinstance(quality_meta.get("evidence_context", {}), dict) else {}
    facts_count = max(0, int(evidence_context.get("facts_count", 0) or 0))
    blindspots_count = max(0, int(evidence_context.get("blindspots_count", 0) or 0))
    unknown_ratio = max(0.0, min(1.0, _safe_float(evidence_context.get("unknown_ratio", 0.0), default=0.0)))
    avg_quality_score = max(0.0, min(1.0, _safe_float(evidence_context.get("average_quality_score", 0.0), default=0.0)))

    if overall < 0.45:
        return False
    if consistency < 0.95:
        return False
    if actionability < 0.35:
        return False
    if table_readiness < 0.40:
        return False
    if review_issue_count > 8:
        return False
    if facts_count >= 2:
        if weak_binding_issue_present:
            if "quality_gate_evidence" not in issue_types:
                return False
            if facts_count < 3:
                return False
            if evidence_coverage < 0.78:
                return False
            if overall < 0.52:
                return False
            if actionability < 0.45:
                return False
            if table_readiness < 0.50:
                return False
            if weak_binding_ratio > 0.22:
                return False
            if action_weak_binding_ratio > 0.50:
                return False
            if solutions_weak_binding_ratio > 0.20:
                return False
            if risks_weak_binding_ratio > 0.30:
                return False
            if pending_follow_up_count > 0:
                return False
            if blindspots_count < 8:
                return False
            if unknown_ratio > 0.10:
                return False
            if avg_quality_score < 0.60:
                return False
            if review_issue_count > 4:
                return False
        if blindspots_count < 8 and pending_follow_up_count < 1 and "quality_gate_evidence" not in issue_types:
            return False
        return True

    # 对 quick/balanced 小样本场景，允许“单事实但高信号”报告软放行：
    # 必须是显式证据、未知比例极低、弱绑定极低，且主要问题集中在证据/表达/里程碑类缺口。
    if facts_count != 1:
        return False
    if "quality_gate_evidence" not in issue_types:
        return False
    if evidence_coverage < 0.75:
        return False
    if weak_binding_ratio > 0.05:
        return False
    if pending_follow_up_count > 0:
        return False
    if blindspots_count < 10:
        return False
    if unknown_ratio > 0.10:
        return False
    if avg_quality_score < 0.55:
        return False
    if review_issue_count > 6:
        return False
    return True


def resolve_quality_gate_soft_pass_v3(
    quality_gate_issues: list,
    quality_meta: Optional[dict],
    runtime_cfg: Optional[dict],
) -> Optional[dict]:
    """统一计算 V3 质量门禁的软放行结果。"""
    if not isinstance(quality_meta, dict):
        return None

    issue_types = summarize_issue_types_v3(quality_gate_issues)
    if can_release_conservative_soft_pass_v3(quality_gate_issues, quality_meta, runtime_cfg):
        return {
            "kind": "release_conservative_soft_pass",
            "issue_types": issue_types,
            "quality_meta_updates": {
                "release_conservative_soft_pass": True,
                "release_conservative_soft_issue_types": issue_types,
            },
        }

    if can_balanced_low_evidence_soft_pass_v3(quality_gate_issues, quality_meta, runtime_cfg):
        evidence_context = quality_meta.get("evidence_context", {}) if isinstance(quality_meta.get("evidence_context", {}), dict) else {}
        facts_count = max(0, int(evidence_context.get("facts_count", 0) or 0))
        soft_pass_variant = "single_fact_high_signal"
        if facts_count != 1:
            soft_pass_variant = (
                "multi_fact_light_weak_binding"
                if "quality_gate_weak_binding" in issue_types
                else "multi_fact_sparse"
            )
        return {
            "kind": "balanced_low_evidence_soft_pass",
            "issue_types": issue_types,
            "quality_meta_updates": {
                "balanced_low_evidence_soft_pass": True,
                "balanced_low_evidence_issue_types": issue_types,
                "balanced_low_evidence_soft_pass_variant": soft_pass_variant,
            },
        }

    return None


def get_release_conservative_report_short_circuit_meta(runtime_cfg: Optional[dict], preferred_lane: str = "report") -> dict:
    """发布保守档下，根据 draft 超时/熔断状态决定是否直接跳过 V3。"""
    if not isinstance(runtime_cfg, dict):
        return {"triggered": False}
    if not bool(runtime_cfg.get("release_conservative_mode", False)):
        return {"triggered": False}
    if not REPORT_V3_RELEASE_SHORT_CIRCUIT_ENABLED:
        return {"triggered": False}

    preferred = str(preferred_lane or "report").strip().lower() or "report"
    draft_snapshot = get_gateway_circuit_snapshot("report_draft")
    report_snapshot = get_gateway_circuit_snapshot(preferred if preferred in {"report", "report_draft"} else "report")
    draft_cooldown = bool(is_gateway_lane_in_cooldown("report_draft") or is_gateway_lane_in_cooldown("report"))

    timeout_threshold = int(REPORT_V3_RELEASE_SHORT_CIRCUIT_TIMEOUT_THRESHOLD or 2)
    consecutive_timeout_count = 0
    timeout_lane = ""
    for lane_name, snapshot in (("report_draft", draft_snapshot), (preferred, report_snapshot)):
        if not isinstance(snapshot, dict):
            continue
        if str(snapshot.get("last_error_type", "") or "").strip().lower() != "timeout":
            continue
        fail_count = int(snapshot.get("fail_count", 0) or 0)
        if fail_count > consecutive_timeout_count:
            consecutive_timeout_count = fail_count
            timeout_lane = lane_name

    reason = ""
    message = ""
    if draft_cooldown:
        reason = "gateway_circuit_open"
        cooldown_remaining = max(
            float(draft_snapshot.get("cooldown_remaining_seconds", 0.0) or 0.0),
            float(report_snapshot.get("cooldown_remaining_seconds", 0.0) or 0.0),
        )
        message = f"检测到报告网关熔断冷却，直接回退标准报告生成（剩余约 {int(max(1.0, round(cooldown_remaining)))} 秒）"
    elif consecutive_timeout_count >= timeout_threshold:
        reason = "consecutive_draft_timeout"
        message = (
            f"检测到报告草案最近连续超时 {consecutive_timeout_count} 次，"
            "发布保守档直接回退标准报告生成"
        )

    return {
        "triggered": bool(reason),
        "reason": reason,
        "message": message,
        "timeout_threshold": timeout_threshold,
        "consecutive_timeout_count": consecutive_timeout_count,
        "timeout_lane": timeout_lane,
        "preferred_lane": preferred,
        "draft_snapshot": draft_snapshot if isinstance(draft_snapshot, dict) else {},
        "report_snapshot": report_snapshot if isinstance(report_snapshot, dict) else {},
    }


def describe_v3_failure_reason(reason: str) -> str:
    """将 V3 失败原因转换为更可读的中文标签。"""
    normalized = str(reason or "").strip().lower()
    reason_text_map = {
        "draft_generation_failed": "草案生成超时/空响应",
        "release_conservative_short_circuit": "发布保守档命中快速短路",
        "draft_parse_failed": "草案结构化解析失败",
        "review_generation_failed": "审稿生成超时/空响应",
        "review_parse_failed": "审稿结构化解析失败",
        "review_gate_failed": "审稿门禁未通过",
        "quality_gate_failed": "质量门禁未通过",
        "review_not_passed_or_quality_gate_failed": "审稿或质量门禁未通过",
        "exception": "流水线异常",
        "v3_pipeline_returned_empty": "流水线返回为空",
    }
    return reason_text_map.get(normalized, "流水线未通过")


def choose_v3_failure_log_icon(reason: str) -> str:
    """按失败类型选择日志级别图标，避免将可预期回退全部标成告警。"""
    normalized = str(reason or "").strip().lower()
    if normalized in {
        "release_conservative_short_circuit",
        "draft_parse_failed",
        "review_parse_failed",
        "review_gate_failed",
        "quality_gate_failed",
        "review_not_passed_or_quality_gate_failed",
    }:
        return "ℹ️"
    return "⚠️"


def format_v3_phase_lanes_for_log(phase_lanes: Optional[dict]) -> str:
    if not isinstance(phase_lanes, dict):
        return "-"
    draft_lane = str(phase_lanes.get("draft", "") or "").strip() or "-"
    review_lane = str(phase_lanes.get("review", "") or "").strip() or "-"
    return f"draft={draft_lane},review={review_lane}"


def build_v3_failure_log_context(v3_failure: Optional[dict]) -> str:
    if not isinstance(v3_failure, dict):
        return "reason=v3_pipeline_returned_empty,profile=-,parse_stage=-,lane=-,phase_lanes=-,error=-"

    reason = str(v3_failure.get("reason", "v3_pipeline_returned_empty") or "v3_pipeline_returned_empty").strip()
    profile = str(v3_failure.get("profile", "") or "").strip() or "-"
    parse_stage = str(v3_failure.get("parse_stage", "") or "").strip() or "-"
    lane = str(v3_failure.get("lane", "") or "").strip() or "-"
    phase_lanes = format_v3_phase_lanes_for_log(v3_failure.get("phase_lanes", {}))
    raw_error = str(v3_failure.get("error", "") or "").strip()
    error = summarize_error_for_log(raw_error, limit=160) if raw_error else "-"
    salvage_attempted = bool(v3_failure.get("salvage_attempted", False))
    salvage_success = bool(v3_failure.get("salvage_success", False))
    salvage_note = str(v3_failure.get("salvage_note", "") or "").strip()
    salvage_error = str(v3_failure.get("salvage_error", "") or "").strip()
    final_issue_types = summarize_issue_types_v3(v3_failure.get("review_issues", []))
    if not final_issue_types:
        final_issue_types = [str(item).strip().lower() for item in (v3_failure.get("final_issue_types", []) or []) if str(item).strip()]
    salvage_issue_types = [str(item).strip().lower() for item in (v3_failure.get("salvage_issue_types", []) or []) if str(item).strip()]
    final_issue_types_text = "|".join(final_issue_types[:8]) if final_issue_types else "-"
    salvage_issue_types_text = "|".join(salvage_issue_types[:8]) if salvage_issue_types else "-"
    try:
        final_issue_count = int(v3_failure.get("final_issue_count", len(v3_failure.get("review_issues", []) or [])) or 0)
    except Exception:
        final_issue_count = len(v3_failure.get("review_issues", []) or [])
    try:
        salvage_quality_issue_count = int(v3_failure.get("salvage_quality_issue_count", 0) or 0)
    except Exception:
        salvage_quality_issue_count = 0

    if salvage_note:
        salvage_note = summarize_error_for_log(salvage_note, limit=120)
    if salvage_error:
        salvage_error = summarize_error_for_log(salvage_error, limit=120)
    exception_stage = str(v3_failure.get("exception_stage", "") or "").strip() or "-"
    exception_kind = str(v3_failure.get("exception_kind", "") or "").strip() or "-"

    return (
        f"reason={reason},profile={profile},parse_stage={parse_stage},lane={lane},phase_lanes={phase_lanes},"
        f"error={error},final_issue_count={final_issue_count},final_issue_types={final_issue_types_text},"
        f"exception_stage={exception_stage},exception_kind={exception_kind},"
        f"salvage_attempted={salvage_attempted},salvage_success={salvage_success},"
        f"salvage_quality_issue_count={salvage_quality_issue_count},"
        f"salvage_issue_types={salvage_issue_types_text},"
        f"salvage_note={salvage_note or '-'},salvage_error={salvage_error or '-'}"
    )


def attempt_salvage_v3_review_failure(session: dict, v3_result: Optional[dict]) -> dict:
    """
    在审稿阶段失败时尝试直接复用现有草案：
    - 针对 review_generation_failed / review_parse_failed
    - 可选覆盖 review_gate_failed / quality_gate_failed（启用保守规则修复）
    - 若草案通过质量门禁，则直接产出，减少不必要回退和告警
    """
    outcome = {
        "attempted": False,
        "success": False,
        "reason": str((v3_result or {}).get("reason", "") or "").strip().lower() if isinstance(v3_result, dict) else "",
        "note": "",
        "error": "",
        "quality_gate_issue_count": 0,
        "review_issues": [],
        "quality_gate_issues": [],
        "quality_gate_issue_types": [],
        "profile": str((v3_result or {}).get("profile", "") or "").strip() if isinstance(v3_result, dict) else "",
        "phase_lanes": (v3_result.get("phase_lanes", {}) if isinstance(v3_result, dict) and isinstance(v3_result.get("phase_lanes", {}), dict) else {}),
        "evidence_pack": (v3_result.get("evidence_pack", {}) if isinstance(v3_result, dict) and isinstance(v3_result.get("evidence_pack", {}), dict) else {}),
    }

    if not isinstance(session, dict) or not isinstance(v3_result, dict):
        return outcome

    salvage_reasons = {"review_generation_failed", "review_parse_failed"}
    if REPORT_V3_SALVAGE_ON_QUALITY_GATE_FAILURE:
        salvage_reasons.update({
            "review_gate_failed",
            "quality_gate_failed",
            "review_not_passed_or_quality_gate_failed",
        })

    if outcome["reason"] not in salvage_reasons:
        return outcome

    outcome["attempted"] = True
    draft_snapshot = v3_result.get("draft_snapshot", {})
    evidence_pack = outcome["evidence_pack"]
    if not isinstance(draft_snapshot, dict) or not draft_snapshot:
        outcome["note"] = "missing_draft_snapshot"
        return outcome
    if not isinstance(evidence_pack, dict) or not evidence_pack:
        outcome["note"] = "missing_evidence_pack"
        return outcome

    try:
        sanitized_draft, local_issues = validate_report_draft_v3(draft_snapshot, evidence_pack)
        review_issues_raw = v3_result.get("review_issues", []) if isinstance(v3_result.get("review_issues", []), list) else []
        repair_seed_issues = list(review_issues_raw) + list(local_issues)
        salvage_repair = apply_deterministic_report_repairs_v3(
            sanitized_draft,
            evidence_pack,
            repair_seed_issues,
            runtime_profile=outcome.get("profile", REPORT_V3_PROFILE),
        )
        if salvage_repair.get("changed"):
            sanitized_draft, local_issues = validate_report_draft_v3(
                salvage_repair.get("draft", sanitized_draft),
                evidence_pack,
            )

        merged_issues, _filtered_model_issues = merge_review_and_local_issues_v3(
            review_issues_raw,
            local_issues,
            sanitized_draft,
            evidence_pack=evidence_pack,
            runtime_profile=outcome.get("profile", REPORT_V3_PROFILE),
        )

        quality_meta = compute_report_quality_meta_v3(sanitized_draft, evidence_pack, merged_issues)
        if isinstance(quality_meta, dict):
            quality_meta["runtime_profile"] = normalize_report_profile_choice(outcome.get("profile", ""), fallback=REPORT_V3_PROFILE)
        quality_gate_issues = build_quality_gate_issues_v3(quality_meta)
        outcome["quality_gate_issue_count"] = len(quality_gate_issues)
        outcome["quality_gate_issue_types"] = summarize_issue_types_v3(quality_gate_issues)
        if quality_gate_issues:
            runtime_cfg = get_report_v3_runtime_config(outcome.get("profile", REPORT_V3_PROFILE))
            soft_pass = resolve_quality_gate_soft_pass_v3(quality_gate_issues, quality_meta, runtime_cfg)
            if not soft_pass:
                outcome["note"] = "quality_gate_blocked"
                outcome["quality_gate_issues"] = quality_gate_issues[:60]
                outcome["review_issues"] = quality_gate_issues[:60]
                return outcome
            if isinstance(quality_meta, dict):
                quality_meta.update(soft_pass.get("quality_meta_updates", {}))
            outcome["note"] = str(soft_pass.get("kind", "") or "quality_gate_soft_pass")

        report_content = render_report_from_draft_v3(session, sanitized_draft, quality_meta)
        if not report_content:
            outcome["note"] = "render_empty"
            return outcome

        outcome["success"] = True
        if not outcome["note"]:
            outcome["note"] = "quality_gate_passed"
        outcome["draft_snapshot"] = copy.deepcopy(sanitized_draft)
        outcome["quality_meta"] = quality_meta if isinstance(quality_meta, dict) else {}
        outcome["report_content"] = report_content
        outcome["report_template"] = resolve_report_template_for_session(session, evidence_pack=evidence_pack)
        outcome["report_type"] = str(evidence_pack.get("report_type", "standard") or "standard").strip().lower() or "standard"
        outcome["review_issues"] = (quality_gate_issues or merged_issues)[:60]
        outcome["quality_gate_issues"] = quality_gate_issues[:60]
        return outcome
    except Exception as exc:
        outcome["error"] = summarize_error_for_log(exc, limit=200)
        return outcome


def is_unusable_legacy_report_content(content: Optional[str]) -> bool:
    """检测标准回退报告是否为无效的工具确认话术。"""
    return run_report_generation_runtime_with_bindings(
        _sync_report_generation_runtime_bindings(),
        module_is_unusable_legacy_report_content,
        content,
    )


def strip_report_leading_assistant_preamble(content: str) -> str:
    """移除模型在报告正文前输出的寒暄式前言。"""
    text = str(content or "")
    if not text.strip():
        return text

    lines = text.splitlines()
    heading_index = -1
    for index, line in enumerate(lines[:20]):
        if re.match(r"^\s{0,3}#{1,3}\s+\S+", line):
            heading_index = index
            break
    if heading_index <= 0:
        return text

    prefix = "\n".join(lines[:heading_index]).strip()
    if not prefix:
        return text

    prefix_compact = re.sub(r"\s+", "", prefix)
    preamble_markers = [
        "好的",
        "当然",
        "以下是",
        "我将根据",
        "作为一名",
        "为您生成",
        "生成一份专业的访谈报告",
    ]
    report_markers = [
        "访谈报告",
        "需求分析",
        "根据您提供",
        "访谈记录",
    ]
    has_preamble_marker = any(marker in prefix_compact for marker in preamble_markers)
    has_report_marker = any(marker in prefix_compact for marker in report_markers)
    only_preamble_lines = all(
        not re.match(r"^\s{0,3}(?:[-*+]|\d+[.、]|\|)", line)
        and not re.match(r"^\s{0,3}```", line)
        for line in lines[:heading_index]
        if line.strip() and not re.match(r"^\s{0,3}-\s*-+\s*$", line)
    )
    if not (has_preamble_marker and has_report_marker and only_preamble_lines):
        return text

    cleaned_lines = lines[heading_index:]
    while cleaned_lines and not cleaned_lines[0].strip():
        cleaned_lines = cleaned_lines[1:]
    return "\n".join(cleaned_lines).strip() + ("\n" if text.endswith("\n") else "")


def normalize_report_time_fields(content: str, generated_at: Optional[datetime] = None) -> str:
    """标准化报告中的时间字段，避免模型产出过期/幻觉时间。"""
    text = strip_report_leading_assistant_preamble(str(content or ""))
    if not text.strip():
        return text

    temporal_fields = build_report_temporal_fields(generated_at=generated_at)
    interview_date = temporal_fields["interview_date"]
    generated_datetime_cn = temporal_fields["generated_datetime_cn"]
    report_id = temporal_fields["report_id"]

    lines = text.splitlines()
    if not lines:
        return text
    # 仅处理报告头部，避免误改正文提及的历史时间。
    head_limit = min(len(lines), 80)
    head_text = "\n".join(lines[:head_limit])
    tail_text = "\n".join(lines[head_limit:])

    normalized_head = head_text

    # 表格字段统一
    normalized_head = re.sub(
        r"(?im)^(\|\s*报告生成时间\s*\|)\s*[^|\n]*\|",
        rf"\g<1> {generated_datetime_cn} |",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)^(\|\s*生成日期\s*\|)\s*[^|\n]*\|",
        rf"\g<1> {generated_datetime_cn} |",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)^(\|\s*访谈日期\s*\|)\s*[^|\n]*\|",
        rf"\g<1> {interview_date} |",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)^(\|\s*访谈时间\s*\|)\s*[^|\n]*\|",
        rf"\g<1> {interview_date} |",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)^(\|\s*报告编号\s*\|)\s*[^|\n]*\|",
        rf"\g<1> {report_id} |",
        normalized_head,
    )

    # 独立行字段统一
    normalized_head = re.sub(
        r"(?im)^(\*\*报告生成时间\*\*\s*[:：]\s*)[^\n]+$",
        rf"\g<1>{generated_datetime_cn}",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)^(\s*报告生成时间\s*[:：]\s*)[^\n]+$",
        rf"\g<1>{generated_datetime_cn}",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)^(\*\*生成日期\*\*\s*[:：]\s*)[^\n]+$",
        rf"\g<1>{generated_datetime_cn}",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)^(\s*生成日期\s*[:：]\s*)[^\n]+$",
        rf"\g<1>{generated_datetime_cn}",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)^(\*\*访谈日期\*\*\s*[:：]\s*)[^\n]+$",
        rf"\g<1>{interview_date}",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)^(\s*访谈日期\s*[:：]\s*)[^\n]+$",
        rf"\g<1>{interview_date}",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)^(\s*访谈时间\s*[:：]\s*)[^\n]+$",
        rf"\g<1>{interview_date}",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)^(\*\*报告编号\*\*\s*[:：]\s*)[^\n]+$",
        rf"\g<1>{report_id}",
        normalized_head,
    )

    # 兼容 Markdown 列表项（-/*/+）和可选加粗标签字段，防止模型输出年份幻觉值残留。
    line_field_rules = [
        ("报告生成时间", generated_datetime_cn),
        ("生成日期", generated_datetime_cn),
        ("访谈日期", interview_date),
        ("访谈时间", interview_date),
        ("报告编号", report_id),
    ]
    for label, target_value in line_field_rules:
        normalized_head = re.sub(
            rf"(?im)^(\s*(?:[-*+•·]\s+)(?:\*\*)?{label}(?:\*\*)?\s*[:：]\s*)[^\n]+$",
            rf"\g<1>{target_value}",
            normalized_head,
        )

    # 行内复合字段（如：报告编号：xxx 访谈主题：yyy 生成日期：zzz）统一
    normalized_head = re.sub(
        r"(?im)(报告编号\s*[:：]\s*)([A-Za-z0-9][A-Za-z0-9_\-]*)",
        rf"\g<1>{report_id}",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)(生成日期\s*[:：]\s*)([^\n]*)$",
        rf"\g<1>{generated_datetime_cn}",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)(报告生成时间\s*[:：]\s*)([^\n]*)$",
        rf"\g<1>{generated_datetime_cn}",
        normalized_head,
    )
    normalized_head = re.sub(
        r"(?im)(访谈时间\s*[:：]\s*)([^\n]*)$",
        rf"\g<1>{interview_date}",
        normalized_head,
    )

    if tail_text:
        return f"{normalized_head}\n{tail_text}"
    return normalized_head


def can_use_v3_failover_lane() -> bool:
    """是否具备可用且独立的备用网关 lane。"""
    primary_client, _, _ = resolve_ai_client_with_lane(
        call_type="report_v3_review_round_1",
        preferred_lane="report",
        respect_circuit_breaker=False,
    )
    target_client, _, _ = resolve_ai_client_with_lane(
        call_type="report_v3_review_round_1",
        preferred_lane=REPORT_V3_FAILOVER_LANE,
        respect_circuit_breaker=False,
    )
    if not target_client or not primary_client:
        return False

    # 两侧复用同一客户端时，切换 lane 没有意义
    return target_client is not primary_client


