    """归类 V3 流水线异常类型，便于区分运行异常与内容门禁问题。"""
    return run_report_generation_runtime_with_bindings(
        _sync_report_generation_runtime_bindings(),
        module_classify_v3_pipeline_exception,
        exc,
    )


