def _has_follow_up_answer_after_formal_log(interview_log: list, formal_index: int, dimension: str) -> bool:
    """判断某条正式问题后、下一条同维度正式问题前，是否已存在有效追问回答。"""
    if not isinstance(interview_log, list):
        return False

    normalized_dimension = str(dimension or "").strip()
    for idx in range(int(formal_index) + 1, len(interview_log)):
        log = interview_log[idx]
        if not isinstance(log, dict):
            continue
        if str(log.get("dimension", "") or "").strip() != normalized_dimension:
            continue
        if not bool(log.get("is_follow_up", False)):
            return False
        if str(log.get("answer", "") or "").strip():
            return True
    return False


def build_report_follow_up_blockers(session: dict) -> list[dict]:
    """quick 模式下，收集生成报告前仍需要补充的关键追问。"""
    if not isinstance(session, dict):
        return []
    if get_mode_identifier(session) != "quick":
        return []

    interview_log = session.get("interview_log", [])
    if not isinstance(interview_log, list) or not interview_log:
        return []

    dim_info_map = get_dimension_info_for_session(session)
    blockers = []
    for index, log in enumerate(interview_log):
        if not isinstance(log, dict):
            continue
        if bool(log.get("is_follow_up", False)):
            continue
        if not bool(log.get("needs_follow_up", False)):
            continue
        if bool(log.get("user_skip_follow_up", False)):
            continue

        requires_rationale = bool(log.get("requires_rationale", False))
        evidence_intent = normalize_question_evidence_intent(log.get("evidence_intent", ""), fallback="")
        if not (requires_rationale or evidence_intent == "high"):
            continue

        dimension = str(log.get("dimension", "") or "").strip()
        if _has_follow_up_answer_after_formal_log(interview_log, index, dimension):
            continue

        dimension_name = dimension
        dim_info = dim_info_map.get(dimension, {}) if isinstance(dim_info_map, dict) else {}
        if isinstance(dim_info, dict):
            dimension_name = str(dim_info.get("name", "") or dim_info.get("title", "") or dimension).strip() or dimension

        blockers.append({
            "log_index": index,
            "dimension": dimension,
            "dimension_name": dimension_name,
            "question": str(log.get("question", "") or "").strip(),
            "follow_up_signals": [
                str(item or "").strip()
                for item in (log.get("follow_up_signals", []) or [])
                if str(item or "").strip()
            ],
            "answer_mode": normalize_question_answer_mode(log.get("answer_mode", ""), fallback="pick_only"),
            "evidence_intent": evidence_intent,
        })

    return blockers


def build_report_follow_up_blocker(session: dict) -> Optional[dict]:
    """quick 模式下，阻止带关键待补问的会话直接生成报告。"""
    blockers = build_report_follow_up_blockers(session)
    if not blockers:
        return None

    blocker = dict(blockers[0])
    blocker_count = len(blockers)
    blocker["blocker_count"] = blocker_count
    blocker["message"] = (
        f"还有 {blocker_count} 个关键信息未补充："
        f"“{blocker.get('question', '当前问题')}”当前只完成了选项式回答，缺少理由或场景说明。"
        "请先补 1 句原因、场景或依据，再生成报告。"
    )
    return blocker


def build_report_follow_up_resume_question(session: dict, dimension: str) -> Optional[dict]:
    """将报告生成门禁中的待补项转换为可继续回答的追问题。"""
    normalized_dimension = str(dimension or "").strip()
    if not normalized_dimension:
        return None
    blocker = next(
        (
            item for item in build_report_follow_up_blockers(session)
            if str(item.get("dimension") or "").strip() == normalized_dimension
        ),
        None,
    )
    if not blocker:
        return None

    source_question = str(blocker.get("question") or "当前问题").strip() or "当前问题"
    return {
        "dimension": normalized_dimension,
        "question": f"请补充说明：{source_question}。可以直接写一个具体原因、场景或依据。",
        "options": [],
        "multi_select": False,
        "question_multi_select": False,
        "is_follow_up": True,
        "follow_up_reason": "生成报告前需要补充该题的理由、场景或依据。",
        "answer_mode": "pick_with_reason",
        "requires_rationale": True,
        "evidence_intent": str(blocker.get("evidence_intent") or "high"),
        "ai_generated": False,
        "report_readiness_resume": True,
        "decision_meta": {
            "mode": get_mode_identifier(session),
            "report_readiness_blocker": True,
            "source_question": source_question,
            "source_log_index": blocker.get("log_index"),
            "follow_up_signals": blocker.get("follow_up_signals") or [],
        },
    }


def build_report_low_signal_blocker(session: dict) -> Optional[dict]:
    """quick 模式下，阻止“全低信号正式回答”直接进入报告生成。"""
    if not isinstance(session, dict):
        return None
    if get_mode_identifier(session) != "quick":
        return None

    interview_log = session.get("interview_log", [])
    if not isinstance(interview_log, list) or not interview_log:
        return None

    formal_logs = []
    answered_follow_ups = 0
    for log in interview_log:
        if not isinstance(log, dict):
            continue
        answer_text = str(log.get("answer", "") or "").strip()
        if not answer_text:
            continue
        if bool(log.get("is_follow_up", False)):
            answered_follow_ups += 1
            continue
        formal_logs.append(log)

    if len(formal_logs) < 3:
        return None
    if answered_follow_ups > 0:
        return None

    low_signal_formals = []
    for log in formal_logs:
        answer_mode = normalize_question_answer_mode(log.get("answer_mode", ""), fallback="pick_only")
        requires_rationale = bool(log.get("requires_rationale", False) or answer_mode == "pick_with_reason")
        evidence_intent = normalize_question_evidence_intent(
            log.get("evidence_intent", ""),
            fallback="high" if requires_rationale else ("medium" if answer_mode == "pick_with_reason" else "low"),
        )
        answer_evidence_class = str(
            log.get("answer_evidence_class")
            or classify_answer_evidence_class_v3(
                log.get("follow_up_signals", []) if isinstance(log.get("follow_up_signals", []), list) else [],
                log.get("quality_score", 0.0),
                evidence_intent,
            )
        ).strip().lower()

        is_low_signal = (
            answer_mode == "pick_only"
            and not requires_rationale
            and evidence_intent == "low"
            and answer_evidence_class in {"explicit", "weak_inferred"}
        )
        if not is_low_signal:
            return None

        low_signal_formals.append({
            "question": str(log.get("question", "") or "").strip(),
            "dimension": str(log.get("dimension", "") or "").strip(),
            "answer_mode": answer_mode,
            "evidence_intent": evidence_intent,
            "answer_evidence_class": answer_evidence_class,
        })

    latest = low_signal_formals[-1] if low_signal_formals else {}
    return {
        "formal_count": len(formal_logs),
        "answered_follow_up_count": answered_follow_ups,
        "question": str(latest.get("question", "") or "").strip(),
        "dimension": str(latest.get("dimension", "") or "").strip(),
        "answer_mode": str(latest.get("answer_mode", "") or "pick_only"),
        "evidence_intent": str(latest.get("evidence_intent", "") or "low"),
        "answer_evidence_class": str(latest.get("answer_evidence_class", "") or ""),
        "message": (
            f"当前已完成 {len(formal_logs)} 条正式回答，但都还是低信号选项式输入。"
            "请先补至少 1 条带原因、场景或依据的回答，再生成报告；否则很容易直接回退到标准报告。"
        ),
    }


def build_report_low_signal_resume_question(session: dict, dimension: str) -> Optional[dict]:
    """将低信号报告门禁转换为可继续回答的补充题。"""
    normalized_dimension = str(dimension or "").strip()
    if not normalized_dimension:
        return None
    blocker = build_report_low_signal_blocker(session)
    if not blocker or str(blocker.get("dimension") or "").strip() != normalized_dimension:
        return None

    source_question = str(blocker.get("question") or "当前问题").strip() or "当前问题"
    return {
        "dimension": normalized_dimension,
        "question": f"请围绕“{source_question}”补充一个具体原因、真实场景或判断依据。",
        "options": [],
        "multi_select": False,
        "question_multi_select": False,
        "is_follow_up": True,
        "follow_up_reason": "当前回答整体信息量偏弱，生成报告前需要补充一条更具体的依据。",
        "answer_mode": "pick_with_reason",
        "requires_rationale": True,
        "evidence_intent": "high",
        "ai_generated": False,
        "report_readiness_resume": True,
        "decision_meta": {
            "mode": get_mode_identifier(session),
            "report_readiness_blocker": True,
            "low_signal_resume": True,
            "source_question": source_question,
            "answer_evidence_class": blocker.get("answer_evidence_class"),
        },
    }


def build_report_readiness_payload(session: dict, report_profile: str = "balanced") -> dict:
    """生成报告前预检结果，供前端提前引导用户继续补答。"""
    normalized_profile = normalize_report_profile_choice(report_profile, fallback="balanced")

    follow_up_blocker = build_report_follow_up_blocker(session)
    if follow_up_blocker:
        message = follow_up_blocker.get("message", "仍有待补充的关键信息，请先完成追问再生成报告")
        return {
            "ready": False,
            "can_generate": False,
            "message": message,
            "error": message,
            "error_code": "follow_up_required_before_report",
            "follow_up_required": True,
            "follow_up_blocker": follow_up_blocker,
            "report_profile": normalized_profile,
        }

    low_signal_blocker = build_report_low_signal_blocker(session)
    if low_signal_blocker:
        message = low_signal_blocker.get("message", "当前回答信号偏弱，请先补充高信息量回答再生成报告")
        return {
            "ready": False,
            "can_generate": False,
            "message": message,
            "error": message,
            "error_code": "high_signal_answer_required_before_report",
            "high_signal_answer_required": True,
            "evidence_signal_blocker": low_signal_blocker,
            "report_profile": normalized_profile,
        }

    return {
        "ready": True,
        "can_generate": True,
        "message": "",
        "report_profile": normalized_profile,
    }


@app.route('/api/sessions/<session_id>/report-readiness', methods=['POST'])
def get_report_readiness(session_id):
    """生成报告前预检，不启动报告任务。"""
    user_row = get_current_user()
    if not user_row:
        return jsonify({"error": "请先登录"}), 401
    user_id = int(user_row["id"])

    loaded = load_session_for_user(session_id, user_id)
    if len(loaded) == 3:
        _file, error_msg, status_code = loaded
        return jsonify({"error": error_msg}), status_code
    _session_file, session = loaded

    data = request.get_json(silent=True) or {}
    raw_report_profile = str(data.get("report_profile", "") or "").strip().lower()
    if raw_report_profile and raw_report_profile not in {"balanced", "quality"}:
        return jsonify({"error": "report_profile 仅支持 balanced 或 quality"}), 400

    requested_profile = normalize_report_profile_choice(raw_report_profile, fallback="balanced")
    return jsonify(build_report_readiness_payload(session, requested_profile))


@app.route('/api/sessions/<session_id>/generate-report', methods=['POST'])
def generate_report(session_id):
    """异步生成访谈报告。"""
    user_row = get_current_user()
    if not user_row:
        return jsonify({"error": "请先登录"}), 401
    user_id = int(user_row["id"])

    level_context = build_user_level_context_for_user(user_row)
    if not user_has_level_capability(user_row, "report.generate", level_context=level_context):
        return build_level_capability_denied_response(user_row, "report.generate", level_context=level_context)

    loaded = load_session_for_user(session_id, user_id)
    if len(loaded) == 3:
        _file, error_msg, status_code = loaded
        return jsonify({"error": error_msg}), status_code
    _session_file, session = loaded

    data = request.get_json(silent=True) or {}
    action = "regenerate" if data.get("action") == "regenerate" else "generate"
    source_report_name = normalize_solution_report_filename(data.get("source_report_name", ""))
    raw_report_profile = str(data.get("report_profile", "") or "").strip().lower()
    if raw_report_profile and raw_report_profile not in {"balanced", "quality"}:
        return jsonify({"error": "report_profile 仅支持 balanced 或 quality"}), 400
    requested_profile = normalize_report_profile_choice(raw_report_profile, fallback="")
    allowed_report_profiles = level_context.get("allowed_report_profiles") or ["balanced"]
    report_profile = get_default_report_profile_for_level(
        level_context.get("level", {}).get("key"),
        requested_profile or "balanced",
    )
    if requested_profile == "quality" and "quality" not in allowed_report_profiles:
        return build_level_capability_denied_response(
            user_row,
            "report.profile.quality",
            level_context=level_context,
        )
    if report_profile == "quality" and not user_has_level_capability(
        user_row,
        "report.profile.quality",
        level_context=level_context,
    ):
        return build_level_capability_denied_response(
            user_row,
            "report.profile.quality",
            level_context=level_context,
        )

    readiness_payload = build_report_readiness_payload(session, report_profile)
    if not bool(readiness_payload.get("ready")):
        return jsonify(readiness_payload), 409

    current_record = get_report_generation_record(session_id) or {}
    worker_alive = is_report_generation_worker_alive(session_id)
    if bool(current_record.get("active")) or worker_alive:
        if worker_alive and not bool(current_record.get("active")):
            current_state = str(current_record.get("state") or "").strip()
            if current_state not in {"completed", "failed", "cancelled"}:
                update_report_generation_status(
                    session_id,
                    "queued",
                    message="报告任务正在处理中...",
                    detail_key="queue_wait",
                    next_hint="等待执行槽位释放后将自动开始",
                )
        queue_snapshot = get_report_generation_worker_snapshot(include_positions=True)
        sync_report_generation_queue_metadata(session_id, snapshot=queue_snapshot)
        current_record = get_report_generation_record(session_id) or current_record
        payload = build_report_generation_payload(current_record)
        payload.update({
            "success": True,
            "already_running": True,
            "action": current_record.get("action", action),
            "report_profile": normalize_report_profile_choice(current_record.get("report_profile", ""), fallback=report_profile),
            "queue": {
                "running": int(queue_snapshot.get("running", 0) or 0),
                "pending": int(queue_snapshot.get("pending", 0) or 0),
                "max_workers": int(queue_snapshot.get("max_workers", REPORT_GENERATION_MAX_WORKERS) or REPORT_GENERATION_MAX_WORKERS),
                "max_pending": int(queue_snapshot.get("max_pending", REPORT_GENERATION_MAX_PENDING) or REPORT_GENERATION_MAX_PENDING),
            },
        })
        return jsonify(payload), 202

    if not report_generation_slots.acquire(blocking=False):
        record_report_generation_queue_event("rejected")
        queue_snapshot = get_report_generation_worker_snapshot(include_positions=False)
        response = jsonify({
            "error": "报告生成队列繁忙，请稍后重试",
            "retry_after_seconds": REPORT_GENERATION_QUEUE_RETRY_AFTER_SECONDS,
            "queue": {
                "running": int(queue_snapshot.get("running", 0) or 0),
                "pending": int(queue_snapshot.get("pending", 0) or 0),
                "max_workers": int(queue_snapshot.get("max_workers", REPORT_GENERATION_MAX_WORKERS) or REPORT_GENERATION_MAX_WORKERS),
                "max_pending": int(queue_snapshot.get("max_pending", REPORT_GENERATION_MAX_PENDING) or REPORT_GENERATION_MAX_PENDING),
            },
        })
        response.status_code = 429
        response.headers["Retry-After"] = str(REPORT_GENERATION_QUEUE_RETRY_AFTER_SECONDS)
        return response

    request_id = secrets.token_hex(12)
    set_report_generation_metadata(session_id, {
        "request_id": request_id,
        "action": action,
        "started_at": get_utc_now(),
        "completed_at": "",
        "report_name": "",
        "report_path": "",
        "ai_generated": None,
        "v3_enabled": None,
        "report_profile": report_profile,
        "source_report_name": source_report_name,
        "report_variant_label": "精审版" if report_profile == "quality" else "普通版",
        "report_quality_meta": {},
        "error": "",
        "queue_position": 0,
        "queue_pending": 0,
        "queue_running": 0,
    })
    update_report_generation_status(
        session_id,
        "queued",
        detail_key="queue_wait",
        next_hint="等待执行槽位释放后将自动开始",
    )

    try:
        worker = report_generation_executor.submit(
            run_report_generation_job,
            session_id,
            user_id,
            request_id,
            report_profile,
            action,
            source_report_name,
        )
    except Exception as exc:
        release_report_generation_slot()
        error_detail = str(exc)[:200] or "未知错误"
        update_report_generation_status(session_id, "failed", message=f"报告任务提交失败：{error_detail}", active=False)
        set_report_generation_metadata(session_id, {
            "request_id": request_id,
            "error": error_detail,
            "completed_at": get_utc_now(),
        })
        return jsonify({"error": f"报告任务提交失败：{error_detail}"}), 500

    register_report_generation_worker(session_id, worker)
    record_report_generation_queue_event("submitted")
    queue_snapshot = get_report_generation_worker_snapshot(include_positions=True)
    sync_report_generation_queue_metadata(session_id, snapshot=queue_snapshot)

    payload = build_report_generation_payload(get_report_generation_record(session_id))
    payload.update({
        "success": True,
        "already_running": False,
        "action": action,
        "report_profile": report_profile,
        "queue": {
            "running": int(queue_snapshot.get("running", 0) or 0),
            "pending": int(queue_snapshot.get("pending", 0) or 0),
            "max_workers": int(queue_snapshot.get("max_workers", REPORT_GENERATION_MAX_WORKERS) or REPORT_GENERATION_MAX_WORKERS),
            "max_pending": int(queue_snapshot.get("max_pending", REPORT_GENERATION_MAX_PENDING) or REPORT_GENERATION_MAX_PENDING),
        },
    })
    return jsonify(payload), 202


def resolve_selected_options(log: dict, option_list: list[str]) -> set[str]:
    """解析用户实际勾选的选项（兼容单选、多选、其他输入引用选项）。"""
    if not isinstance(log, dict) or not option_list:
        return set()

    answer_text = str(log.get("answer", "") or "").strip()
    answer_tokens = {
        token.strip()
        for token in re.split(r"[；;]\s*", answer_text)
        if token and token.strip()
    }
    if not answer_tokens and answer_text:
        answer_tokens.add(answer_text)

    other_resolution = extract_other_resolution(log, option_list)
    if other_resolution and other_resolution.get("custom_text"):
        answer_tokens.discard(other_resolution["custom_text"])

    selected_options = {option for option in option_list if option in answer_tokens}
    if other_resolution:
        selected_options.update(other_resolution.get("matched_options", []))

    return selected_options


def render_appendix_answer_block(log: dict) -> str:
    """将附录回答渲染为“全选项 + 勾选态 + 语义化其他输入”格式。"""
    if not isinstance(log, dict):
        text = str(log or "").strip()
        safe_text = html.escape(text or "（未填写）")
        return f"<div><strong>回答：</strong></div>\n<div>☑ {safe_text}</div>"

    answer_text = str(log.get("answer", "") or "").strip()
    option_list = []
    options = log.get("options")
    if isinstance(options, list):
        option_list = [str(item or "").strip() for item in options if str(item or "").strip()]

    other_resolution = extract_other_resolution(log, option_list)
    selected_options = resolve_selected_options(log, option_list)

    answer_lines = []
    if option_list:
        for option in option_list:
            mark = "☑" if option in selected_options else "☐"
            answer_lines.append(f"{mark} {option}")
    else:
        answer_lines.append(f"☑ {answer_text or '（未填写）'}")

    other_selected = bool(log.get("other_selected"))
    other_input = str(log.get("other_answer_text", "") or "").strip()
    if other_resolution:
        if other_resolution["mode"] == "mixed" and other_resolution["custom_text"]:
            answer_lines.append(f"☑ 其他补充说明：{other_resolution['custom_text']}")
        elif other_resolution["mode"] == "custom":
            free_text = other_resolution["source_text"] or other_input
            if free_text:
                answer_lines.append(f"☑ 其他（自由输入）：{free_text}")
    elif other_selected and other_input:
        answer_lines.append(f"☑ 其他（自由输入）：{other_input}")

    # 附录位于 <details> HTML 区块内，Markdown 换行在部分渲染器中会失效。
    # 这里直接输出块级 HTML，确保选项稳定按“自上而下”逐行展示。
    if answer_lines:
        rendered_lines = "\n".join(f"<div>{html.escape(line)}</div>" for line in answer_lines)
        return f"<div><strong>回答：</strong></div>\n{rendered_lines}"

    return "<div><strong>回答：</strong></div>\n<div>☑ （未填写）</div>"


def generate_interview_appendix(session: dict) -> str:
    """生成完整的访谈记录附录"""
    interview_log = session.get("interview_log", [])
    if not interview_log:
        return ""

    appendix = "\n\n---\n\n## 附录：完整访谈记录\n\n"
    appendix += "<details>\n"
    appendix += f"<summary>本次访谈共收集了 {len(interview_log)} 个问题的回答</summary>\n\n"

    appendix_dim_info = get_dimension_info_for_session(session)
    total_questions = len(interview_log)
    for i, log in enumerate(interview_log, 1):
        dim_name = appendix_dim_info.get(log.get('dimension', ''), {}).get('name', '未分类')
        question = str(log.get('question', '') or '').strip() or '（未记录问题）'
        answer_block = render_appendix_answer_block(log)
        appendix += f"**【{dim_name}】问题 {i}：{question}**\n\n"
        appendix += f"{answer_block}\n\n"
        if i < total_questions:
            appendix += "---\n\n"

    appendix += "</details>\n\n"

    return appendix


def generate_simple_report(session: dict) -> str:
    """生成简单报告（无 AI 时使用）"""
    topic = session.get("topic", "未命名项目")
    interview_log = session.get("interview_log", [])
    now = datetime.now()
    temporal_fields = build_report_temporal_fields(now)

    content = f"""# {topic} 访谈报告

**访谈日期**: {temporal_fields['interview_date']}
**生成日期**: {temporal_fields['generated_datetime_cn']}
**报告编号**: {temporal_fields['report_id']}

---

## 1. 访谈概述

本次访谈主题为「{topic}」，共收集了 {len(interview_log)} 个问题的回答。

## 2. 需求摘要

"""

    simple_dim_info = get_dimension_info_for_session(session)
    for dim_key, dim_info in simple_dim_info.items():
        content += f"### {dim_info['name']}\n\n"
        logs = [log for log in interview_log if log.get("dimension") == dim_key]
        if logs:
            for log in logs:
                content += f"- **{log['answer']}** - {log['question']}\n"
        else:
            content += "*暂无数据*\n"
        content += "\n"

    # 使用统一的附录生成函数，确保格式一致
    content += generate_interview_appendix(session)

    content += """
*此报告由 Intus 见真生成*
"""

    return content


# ============ Refly 集成 ============

def get_presentation_provider() -> str:
    if PAPER2SLIDES_API_URL:
        return "paper2slides"
    return "refly"


def is_paper2slides_configured() -> bool:
    return bool(PAPER2SLIDES_API_URL)


def get_paper2slides_client() -> Paper2SlidesClient:
    return Paper2SlidesClient(
        PAPER2SLIDES_API_URL,
        api_token=PAPER2SLIDES_API_TOKEN,
        timeout=PAPER2SLIDES_TIMEOUT,
    )


def is_presentation_service_configured() -> bool:
    if get_presentation_provider() == "paper2slides":
        return is_paper2slides_configured()
    return is_refly_configured()


def is_refly_configured() -> bool:
    return bool(REFLY_API_URL and REFLY_API_KEY and REFLY_WORKFLOW_ID and REFLY_INPUT_FIELD)


def build_refly_payload(report_content: str, file_keys: Optional[list] = None) -> dict:
    variables = {REFLY_INPUT_FIELD: report_content}
    if file_keys:
        variables[REFLY_FILES_FIELD] = file_keys
    return {"variables": variables}


def get_refly_base_url() -> str:
    return (REFLY_API_URL or "").rstrip("/")


def get_refly_run_url() -> str:
    base = get_refly_base_url()
    if not base:
        return base
    return f"{base}/openapi/workflow/{REFLY_WORKFLOW_ID}/run"


def get_refly_upload_url() -> str:
    base = get_refly_base_url()
    if not base:
        return base
    return f"{base}/openapi/files/upload"


def get_refly_status_url(execution_id: str) -> str:
    base = get_refly_base_url()
    if not base:
        return base
    return f"{base}/openapi/workflow/{execution_id}/status"


def get_refly_output_url(execution_id: str) -> str:
    base = get_refly_base_url()
    if not base:
        return base
    return f"{base}/openapi/workflow/{execution_id}/output"


def get_refly_execution_status(status_response: dict) -> str:
    if not isinstance(status_response, dict):
        return ""
    payload = status_response.get("payload") or status_response.get("data") or status_response
    data = payload.get("data") if isinstance(payload, dict) else {}
    status = ""
    if isinstance(data, dict):
        status = data.get("status") or ""
    return status or ""


def get_refly_abort_url(execution_id: str) -> str:
    base = get_refly_base_url()
    if not base:
        return base
    return f"{base}/openapi/workflow/{execution_id}/abort"


def upload_refly_file(file_path: Path) -> dict:
    url = get_refly_upload_url()
    headers = {
        "Authorization": f"Bearer {REFLY_API_KEY}"
    }
    if ENABLE_DEBUG_LOG:
        print(f"📤 Refly 上传文件: {url}")
    with open(file_path, "rb") as file_handle:
        files = {"files": (file_path.name, file_handle)}
        response = requests.post(url, headers=headers, files=files, timeout=REFLY_TIMEOUT)
    response.raise_for_status()
    try:
        return response.json()
    except ValueError:
        return {"raw": response.text}


def extract_refly_file_keys(upload_response: dict) -> list:
    if not isinstance(upload_response, dict):
        return []
    files = (
        upload_response.get("data", {}).get("files")
        or upload_response.get("files")
        or []
    )
    keys = []
    if isinstance(files, list):
        for item in files:
            if isinstance(item, dict):
                key = item.get("fileKey") or item.get("file_key") or item.get("key")
                if key:
                    keys.append(key)
    return keys


def run_refly_workflow(report_content: str, file_keys: Optional[list] = None) -> dict:
    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {REFLY_API_KEY}"
    }
    url = get_refly_run_url()
    payload = build_refly_payload(report_content, file_keys=file_keys)

    if ENABLE_DEBUG_LOG:
        print(f"📤 Refly 运行工作流: {url}")

    response = requests.post(url, json=payload, headers=headers, timeout=REFLY_TIMEOUT)
    response.raise_for_status()
    try:
        return response.json()
    except ValueError:
        return {"raw": response.text}


def _paper2slides_stage_output(status_payload: dict) -> list[dict]:
    stage_titles = {
        "rag": "解析与索引资料",
        "summary": "提炼内容摘要",
        "plan": "规划演示结构",
        "generate": "生成演示文稿",
    }
    stages = status_payload.get("stages") if isinstance(status_payload, dict) else {}
    if not isinstance(stages, dict):
        stages = {}

    def normalize_status(value: object) -> str:
        raw = str(value or "").strip().lower()
        if raw == "completed":
            return "finished"
        if raw == "running":
            return "running"
        if raw == "failed":
            return "failed"
        return "pending"

    output = []
    for key, title in stage_titles.items():
        output.append({
            "title": title,
            "status": normalize_status(stages.get(key)),
        })
    return output


def build_paper2slides_status_payload(status_payload: dict, result_payload: Optional[dict] = None) -> dict:
    data = {
        "status": str(status_payload.get("status") or "pending"),
        "output": _paper2slides_stage_output(status_payload),
    }
    for key in ("progress", "generated_pages", "total_pages", "page_progress", "output_dir", "pdf_exists"):
        value = status_payload.get(key)
        if value is not None:
            data[key] = value
    return {
        "data": data,
        "paper2slides_status": status_payload,
        "paper2slides_result": result_payload or {},
    }


def extract_paper2slides_failure_detail(status_payload: Optional[dict], result_payload: Optional[dict] = None) -> dict:
    raw_error = ""
    if isinstance(status_payload, dict):
        raw_error = str(status_payload.get("error") or "").strip()
    if not raw_error and isinstance(result_payload, dict):
        raw_error = str(result_payload.get("error") or "").strip()

    upstream_message = ""
    upstream_type = ""
    upstream_code = ""

    detail_text = raw_error
    if " - " in raw_error:
        _prefix, _sep, maybe_payload = raw_error.partition(" - ")
        if maybe_payload.strip().startswith("{"):
            detail_text = maybe_payload.strip()

    if detail_text.startswith("{"):
        try:
            parsed = ast.literal_eval(detail_text)
        except Exception:
            parsed = None
        if isinstance(parsed, dict):
            error_payload = parsed.get("error") if isinstance(parsed.get("error"), dict) else parsed
            if isinstance(error_payload, dict):
                upstream_message = str(error_payload.get("message") or "").strip()
                upstream_type = str(error_payload.get("type") or "").strip()
                upstream_code = str(error_payload.get("code") or "").strip()

    status_code = ""
    match = re.search(r"error code:\s*(\d+)", raw_error, flags=re.IGNORECASE)
    if match:
        status_code = match.group(1)

    lowered = raw_error.lower()
    if (
        upstream_type == "insufficient_quota"
        or upstream_code == "insufficient_quota"
        or status_code == "402"
        or "insufficient_quota" in lowered
        or "used up your points" in lowered
    ):
        return {
            "message": "演示文稿生成失败：模型额度不足，请补充可用额度后重试",
            "error_code": "paper2slides_insufficient_quota",
            "raw_error": raw_error,
            "upstream_message": upstream_message,
            "upstream_type": upstream_type or upstream_code,
            "upstream_status_code": status_code,
        }

    if upstream_message:
        return {
            "message": f"演示文稿生成失败：{upstream_message}",
            "error_code": "paper2slides_generation_failed",
            "raw_error": raw_error,
            "upstream_message": upstream_message,
            "upstream_type": upstream_type or upstream_code,
            "upstream_status_code": status_code,
        }

    fallback_message = raw_error or "Paper2Slides 未返回可用演示文稿产物"
    return {
        "message": f"演示文稿生成失败：{fallback_message}",
        "error_code": "paper2slides_generation_failed",
        "raw_error": raw_error,
        "upstream_message": upstream_message,
        "upstream_type": upstream_type or upstream_code,
        "upstream_status_code": status_code,
    }


def build_paper2slides_failure_response(
    filename: str,
    execution_id: str,
    status_payload: dict,
    result_payload: Optional[dict] = None,
) -> tuple[dict, int]:
    failure_detail = extract_paper2slides_failure_detail(status_payload, result_payload)
    record_presentation_execution(
        filename,
        execution_id,
        metadata={
            "provider": "paper2slides",
            "paper2slides_job_id": execution_id,
            "last_error": failure_detail.get("raw_error") or "",
            "failed_at": datetime.now().isoformat(),
        },
    )
    clear_presentation_execution(filename)
    return {
        "processing": False,
        "failed": True,
        "execution_id": execution_id,
        "error": failure_detail.get("message") or "演示文稿生成失败",
        "error_code": failure_detail.get("error_code") or "paper2slides_generation_failed",
        "paper2slides_error": failure_detail.get("raw_error") or "",
        "paper2slides_status": status_payload,
        "paper2slides_result": result_payload or {},
    }, 502


def send_report_to_paper2slides_service(filename: str, report_file: Path, report_content: str) -> tuple[dict, int]:
    client = get_paper2slides_client()
    if not client.is_configured():
        return {"error": "Paper2Slides 服务未配置"}, 400

    report_title = report_content.strip().splitlines()[0].lstrip("#").strip() if report_content else ""
    materialized_report_file = _materialize_report_file_for_local_use(filename, report_content)
    try:
        create_response = client.create_presentation(
            materialized_report_file,
            profile=PAPER2SLIDES_PROFILE,
            content=PAPER2SLIDES_CONTENT_TYPE,
            output_type=PAPER2SLIDES_OUTPUT_TYPE,
            style=PAPER2SLIDES_STYLE,
            style_prompt="",
            length=PAPER2SLIDES_SLIDES_LENGTH,
            fast_mode=PAPER2SLIDES_FAST_MODE,
        )
    finally:
        if materialized_report_file != report_file:
            materialized_report_file.unlink(missing_ok=True)

    job_id = str(create_response.get("job_id") or "").strip()
    if not job_id:
        return {
            "error": "Paper2Slides 服务未返回 job_id",
            "paper2slides_response": create_response,
        }, 502

    owner = get_execution_owner_report(job_id)
    if owner and owner != filename:
        return {
            "error": "生成任务归属冲突，请重试",
            "mismatch": True,
            "owner_report": owner,
            "execution_id": job_id,
        }, 409

    record_presentation_execution(filename, job_id, metadata={
        "provider": "paper2slides",
        "paper2slides_job_id": job_id,
    })

    return {
        "message": "已提交生成任务",
        "report_filename": filename,
        "report_title": report_title,
        "execution_id": job_id,
        "paper2slides_response": create_response,
        "processing": True,
    }, 202


def check_paper2slides_status(filename: str, execution_id: str) -> tuple[dict, int]:
    client = get_paper2slides_client()
    status_payload = client.get_status(execution_id)
    result_payload, ready = client.get_result(execution_id)
    normalized_status = str(status_payload.get("status") or "").strip().lower()
    status_bridge_payload = build_paper2slides_status_payload(status_payload, result_payload)
    progress_fields = {
        key: status_payload.get(key)
        for key in ("progress", "generated_pages", "total_pages", "page_progress")
        if status_payload.get(key) is not None
    }

    if normalized_status == "failed":
        return build_paper2slides_failure_response(
            filename,
            execution_id,
            status_payload,
            result_payload,
        )

    if not ready:
        record_presentation_execution(filename, execution_id, metadata={
            "provider": "paper2slides",
            "paper2slides_job_id": execution_id,
        })
        return {
            "processing": True,
            "execution_id": execution_id,
            "refly_status": status_bridge_payload,
            "refly_response": status_bridge_payload,
            "paper2slides_status": status_payload,
            "paper2slides_result": result_payload or {},
            **progress_fields,
        }, 200

    pdf_url = select_primary_artifact_url(result_payload or {})
    if not pdf_url:
        return build_paper2slides_failure_response(
            filename,
            execution_id,
            status_payload,
            result_payload,
        )
    if pdf_url.startswith("/"):
        pdf_url = urljoin(f"{PAPER2SLIDES_API_URL.rstrip('/')}/", pdf_url.lstrip("/"))

    record_presentation_file(
        filename,
        None,
        pdf_url=pdf_url,
        metadata={
            "filename": build_presentation_pdf_filename(filename),
            "provider": "paper2slides",
            "paper2slides_job_id": execution_id,
        },
    )
    return {
        "execution_id": execution_id,
        "pdf_url": pdf_url,
        "refly_status": status_bridge_payload,
        "refly_response": status_bridge_payload,
        "paper2slides_status": status_payload,
        "paper2slides_result": result_payload or {},
        **progress_fields,
    }, 200


def poll_refly_execution(execution_id: str) -> dict:
    headers = {
        "Authorization": f"Bearer {REFLY_API_KEY}"
    }
    status_url = get_refly_status_url(execution_id)
    deadline = _time.time() + REFLY_POLL_TIMEOUT
    last_payload = {}
    status = "executing"

    if ENABLE_DEBUG_LOG:
        print(f"🔁 Refly 轮询状态: {status_url}")

    while _time.time() < deadline and status == "executing":
        _time.sleep(REFLY_POLL_INTERVAL)
        response = requests.get(status_url, headers=headers, timeout=REFLY_TIMEOUT)
        response.raise_for_status()
        try:
            last_payload = response.json()
        except ValueError:
            last_payload = {"raw": response.text}
        status = (
            last_payload.get("data", {}).get("status")
            or last_payload.get("status")
            or status
        )

    return {
        "status": status,
        "payload": last_payload
    }


def fetch_refly_status_once(execution_id: str) -> dict:
    headers = {
        "Authorization": f"Bearer {REFLY_API_KEY}"
    }
    status_url = get_refly_status_url(execution_id)
    response = requests.get(status_url, headers=headers, timeout=REFLY_TIMEOUT)
    response.raise_for_status()
    try:
        payload = response.json()
    except ValueError:
        payload = {"raw": response.text}
    status = payload.get("data", {}).get("status") or payload.get("status") or "executing"
    return {
        "status": status,
        "payload": payload
    }


def fetch_refly_output(execution_id: str) -> dict:
    headers = {
        "Authorization": f"Bearer {REFLY_API_KEY}"
    }
    output_url = get_refly_output_url(execution_id)

    if ENABLE_DEBUG_LOG:
        print(f"📥 Refly 获取结果: {output_url}")

    response = requests.get(output_url, headers=headers, timeout=REFLY_TIMEOUT)
    response.raise_for_status()
    try:
        return response.json()
    except ValueError:
        return {"raw": response.text}


def has_pdf_or_result_file(payload) -> bool:
    if not isinstance(payload, dict):
        return False
    data = payload.get("data") if isinstance(payload.get("data"), dict) else {}
    files = data.get("files") if isinstance(data.get("files"), list) else []
    for item in files:
        if not isinstance(item, dict):
            continue
        name = (item.get("name") or "").lower()
        file_type = (item.get("type") or "").lower()
        url = (item.get("url") or "").lower()
        if name.endswith(".pdf") or name.endswith("result_info.json"):
            return True
        if url.endswith(".pdf") or url.endswith("result_info.json"):
            return True
        if "pdf" in file_type:
            return True
    return False


def wait_for_refly_output_ready(execution_id: str) -> dict:
    deadline = _time.time() + REFLY_POLL_TIMEOUT
    last_output = {}
    last_status = "executing"
    while _time.time() < deadline:
        try:
            status_payload = fetch_refly_status_once(execution_id)
            last_status = status_payload.get("status") or last_status
        except Exception:
            pass
        if last_status != "executing":
            break
        _time.sleep(REFLY_POLL_INTERVAL)
    try:
        last_output = fetch_refly_output(execution_id)
    except Exception:
        last_output = last_output or {}
    if has_pdf_or_result_file(last_output):
        return last_output
    return last_output


def extract_refly_url(payload) -> Optional[str]:
    if isinstance(payload, dict):
        for key in ("presentation_url", "url", "share_url", "shareUrl", "preview_url", "previewUrl"):
            value = payload.get(key)
            if isinstance(value, str) and value.startswith("http"):
                return value
        for value in payload.values():
            found = extract_refly_url(value)
            if found:
                return found
    elif isinstance(payload, list):
        for value in payload:
            found = extract_refly_url(value)
            if found:
                return found
    elif isinstance(payload, str) and payload.startswith("http"):
        return payload
    return None


def extract_pdf_filename(payload) -> Optional[str]:
    if isinstance(payload, dict):
        if isinstance(payload.get("pdf_filename"), str):
            return payload.get("pdf_filename")
        for value in payload.values():
            found = extract_pdf_filename(value)
            if found:
                return found
    elif isinstance(payload, list):
        for value in payload:
            found = extract_pdf_filename(value)
            if found:
                return found
    return None


def extract_refly_file_id(payload) -> Optional[str]:
    urls = collect_refly_urls(payload, [])
    for url in urls:
        match = re.search(r"/drive/file/(?:content|public)/([^/]+)/", url)
        if match:
            return match.group(1)
    return None


def build_pdf_url_from_result_info(payload) -> Optional[str]:
    pdf_filename = extract_pdf_filename(payload)
    file_id = extract_refly_file_id(payload)
    if not pdf_filename or not file_id:
        return None
    base = get_refly_base_url()
    if not base:
        return None
    return f"{base}/drive/file/content/{file_id}/{quote(pdf_filename)}"


def collect_refly_urls(payload, urls: Optional[list] = None) -> list:
    if urls is None:
        urls = []
    if not payload:
        return urls
    if isinstance(payload, str):
        if payload.startswith("http"):
            urls.append(payload)
        return urls
    if isinstance(payload, list):
        for item in payload:
            collect_refly_urls(item, urls)
        return urls
    if isinstance(payload, dict):
        for value in payload.values():
            collect_refly_urls(value, urls)
    return urls


def extract_pdf_url_from_output(payload) -> Optional[str]:
    if not isinstance(payload, dict):
        return None
    data = payload.get("data") if isinstance(payload.get("data"), dict) else {}
    files = data.get("files") if isinstance(data.get("files"), list) else []
    for item in files:
        if not isinstance(item, dict):
            continue
        url = item.get("url")
        name = (item.get("name") or "").lower()
        file_type = (item.get("type") or "").lower()
        if isinstance(url, str) and url.startswith("http"):
            if url.lower().endswith(".pdf") or name.endswith(".pdf") or "pdf" in file_type:
                return url

    outputs = data.get("output") if isinstance(data.get("output"), list) else []
    for node in outputs:
        if not isinstance(node, dict):
            continue
        messages = node.get("messages") if isinstance(node.get("messages"), list) else []
        for msg in messages:
            if not isinstance(msg, dict):
                continue
            content = msg.get("content")
            if isinstance(content, str):
                match = re.search(r"https?://\\S+?\\.pdf", content)
                if match:
                    return match.group(0)

    for url in collect_refly_urls(payload, []):
        if isinstance(url, str) and url.lower().endswith(".pdf"):
            return url
    return None


def fetch_result_info_json(payload) -> Optional[dict]:
    if not isinstance(payload, dict):
        return None
    data = payload.get("data") if isinstance(payload.get("data"), dict) else {}
    files = data.get("files") if isinstance(data.get("files"), list) else []
    result_url = None
    for item in files:
        if not isinstance(item, dict):
            continue
        name = (item.get("name") or "").lower()
        url = item.get("url")
        if name.endswith("result_info.json") and isinstance(url, str) and url.startswith("http"):
            result_url = url
            break
    if not result_url:
        return None

    headers = {}
    try:
        base_host = urlparse(get_refly_base_url()).netloc
        url_host = urlparse(result_url).netloc
        if base_host and url_host.endswith(base_host):
            headers["Authorization"] = f"Bearer {REFLY_API_KEY}"
    except Exception:
        headers = {}

    try:
        response = requests.get(result_url, headers=headers, timeout=REFLY_TIMEOUT)
        response.raise_for_status()
        return response.json()
    except Exception:
        return None


def build_pdf_url_from_result_info_file(payload) -> Optional[str]:
    result_info = fetch_result_info_json(payload)
    if not isinstance(result_info, dict):
        return None
    pdf_filename = result_info.get("pdf_filename")
    if not isinstance(pdf_filename, str) or not pdf_filename:
        return None
    file_id = extract_refly_file_id(payload)
    if not file_id:
        return None
    base = get_refly_base_url()
    if not base:
        return None
    return f"{base}/drive/file/content/{file_id}/{quote(pdf_filename)}"


def get_refly_file_candidates(output_response: dict) -> list:
    files = []
    if isinstance(output_response, dict):
        files = (
            output_response.get("data", {}).get("files")
            or output_response.get("files")
            or []
        )
    if not isinstance(files, list):
        return []
    candidates = []
    for item in files:
        if not isinstance(item, dict):
            continue
        url = item.get("url")
        name = item.get("name") or item.get("fileName") or item.get("filename") or ""
        if isinstance(url, str) and url.startswith("http"):
            candidates.append({"url": url, "name": name})
    return candidates


def score_refly_url(url: str, name: str = "") -> int:
    lower_url = (url or "").lower()
    lower_name = (name or "").lower()
    target = lower_name or lower_url
    match = re.search(r"\.[a-z0-9]+(?=$|\?)", target)
    ext = match.group(0) if match else ""
    score = 0

    if any(key in lower_url for key in ("share", "preview", "presentation")):
        score += 80
    if "slide" in lower_url:
        score += 10

    if ext == ".pptx":
        score += 100
    elif ext == ".pdf":
        score += 90
    elif ext in (".ppt", ".key"):
        score += 80
    elif ext in (".html", ".htm"):
        score += 70
    elif ext in (".png", ".jpg", ".jpeg"):
        score += 50
    elif ext == ".json":
        score -= 10

    return score


def select_best_refly_candidate(output_response: dict, presentation_url: Optional[str]) -> Optional[dict]:
    candidates = []

    def add_candidate(url: Optional[str], name: str = ""):
        if not isinstance(url, str) or not url.startswith("http"):
            return
        candidates.append({"url": url, "name": name or ""})

    if isinstance(presentation_url, str) and presentation_url.startswith("http"):
        if not presentation_url.lower().endswith(".json"):
            return {"url": presentation_url, "name": "presentation_url"}
        add_candidate(presentation_url, "presentation_url")

    for item in get_refly_file_candidates(output_response):
        add_candidate(item.get("url"), item.get("name", ""))

    for url in collect_refly_urls(output_response, []):
        add_candidate(url, "")

    if not candidates:
        return None

    deduped = {}
    for item in candidates:
        deduped.setdefault(item["url"], item)

    sorted_candidates = sorted(
        deduped.values(),
        key=lambda item: score_refly_url(item.get("url", ""), item.get("name", "")),
        reverse=True,
    )
    return sorted_candidates[0] if sorted_candidates else None


def get_downloads_dir() -> Path:
    env_dir = os.environ.get("DOWNLOADS_DIR", "").strip()
    if env_dir:
        return Path(env_dir).expanduser().resolve()
    home = Path.home()
    candidates = [home / "Downloads", home / "下载"]
    for candidate in candidates:
        if candidate.exists() and candidate.is_dir():
            return candidate
    return candidates[0]


def sanitize_filename(name: str) -> str:
    safe = Path(name).name if name else ""
    safe = safe.strip().strip(".")
    if not safe:
        return "presentation"
    for ch in ('/', '\\', ':', '*', '?', '"', '<', '>', '|'):
        safe = safe.replace(ch, "_")
    return safe


def build_presentation_pdf_filename(report_filename: str, record: Optional[dict] = None) -> str:
    """Build a user-facing PDF filename from the report title."""
    candidates: list[str] = []
    report_content = _load_report_content(report_filename)
    for line in report_content.splitlines():
        stripped = line.strip()
        if not stripped:
            continue
        if stripped.startswith("#"):
            title = stripped.lstrip("#").strip()
            if title:
                candidates.append(title)
            break
        candidates.append(stripped)
        break

    if record:
        existing_name = str(record.get("filename") or "").strip()
        if existing_name and existing_name.lower() != "slides.pdf":
            candidates.append(Path(existing_name).stem)

    fallback_stem = Path(normalize_presentation_report_filename(report_filename) or "presentation").stem
    candidates.append(fallback_stem)

    for candidate in candidates:
        safe_name = sanitize_filename(re.sub(r"\s+", " ", str(candidate or "").strip()))
        if safe_name:
            if safe_name.lower().endswith(".pdf"):
                return safe_name
            return f"{safe_name}.pdf"
    return "presentation.pdf"


def ensure_unique_path(directory: Path, filename: str) -> Path:
    path = directory / filename
    if not path.exists():
        return path
    stem = path.stem
    suffix = path.suffix
    counter = 1
    while True:
        candidate = directory / f"{stem}-{counter}{suffix}"
        if not candidate.exists():
            return candidate
        counter += 1


def infer_extension(content_type: str) -> str:
    if not content_type:
        return ""
    lower = content_type.lower()
    if "presentationml" in lower or "pptx" in lower:
        return ".pptx"
    if "ms-powerpoint" in lower:
        return ".ppt"
    if "pdf" in lower:
        return ".pdf"
    if "html" in lower:
        return ".html"
    if "json" in lower:
        return ".json"
    if "png" in lower:
        return ".png"
    if "jpeg" in lower or "jpg" in lower:
        return ".jpg"
    return ""


def build_download_filename(url: str, name: str, content_type: str) -> str:
    raw_name = name or ""
    if raw_name:
        raw_name = sanitize_filename(raw_name)
    if not raw_name:
        parsed = urlparse(url)
        raw_name = sanitize_filename(unquote(Path(parsed.path).name))

    ext = ""
    if raw_name:
        ext_match = re.search(r"\.[a-z0-9]+$", raw_name.lower())
        ext = ext_match.group(0) if ext_match else ""
    if not ext:
        ext = infer_extension(content_type)
    if not raw_name:
        raw_name = "presentation"
    if ext and not raw_name.lower().endswith(ext):
        raw_name = f"{raw_name}{ext}"
    return raw_name


def download_presentation_file(url: str, name: str = "") -> Optional[dict]:
    headers = {}
    try:
        base_host = urlparse(get_refly_base_url()).netloc
        url_host = urlparse(url).netloc
        if base_host and url_host.endswith(base_host):
            headers["Authorization"] = f"Bearer {REFLY_API_KEY}"
    except Exception:
        headers = {}

    response = requests.get(url, headers=headers, stream=True, timeout=REFLY_TIMEOUT)
    response.raise_for_status()
    content_type = response.headers.get("Content-Type", "")
    filename = build_download_filename(url, name, content_type)
    chunks = []
    size = 0
    for chunk in response.iter_content(chunk_size=1024 * 256):
        if not chunk:
            continue
        chunks.append(chunk)
        size += len(chunk)
    response.close()
    content = b"".join(chunks)

    if is_object_storage_enabled():
        uploaded = upload_bytes_to_object_storage(
            content,
            object_key=build_object_storage_key("presentations", filename=filename),
            content_type=content_type or _guess_content_type(filename),
            metadata={
                "source_url": url,
                "instance_scope_key": get_active_instance_scope_key(),
            },
        )
        uploaded["url"] = url
        uploaded["filename"] = filename
        uploaded["size"] = size
        return uploaded

    downloads_dir = get_downloads_dir()
    downloads_dir.mkdir(parents=True, exist_ok=True)
    file_path = ensure_unique_path(downloads_dir, filename)
    file_path.write_bytes(content)
    return {
        "url": url,
        "path": str(file_path),
        "filename": file_path.name,
        "size": size,
        "content_type": content_type or _guess_content_type(file_path.name),
    }


@app.route('/api/reports/<path:filename>/presentation', methods=['GET'])
def get_report_presentation(filename):
    user_row = get_current_user()
    if not user_row:
        return jsonify({"error": "请先登录"}), 401
    user_id = int(user_row["id"])
    level_context = build_user_level_context_for_user(user_row)
    if not user_has_level_capability(user_row, "presentation.generate", level_context=level_context):
        return build_level_capability_denied_response(user_row, "presentation.generate", level_context=level_context)

    filename = normalize_presentation_report_filename(filename)
    if not filename:
        return jsonify({"error": "演示文稿不存在"}), 404

    _report_file, owner_error = enforce_report_owner_or_404(filename, user_id)
    if owner_error:
        response, status_code = owner_error
        return response, status_code

    record = get_presentation_record(filename)
    if not record:
        return jsonify({"error": "演示文稿不存在"}), 404
    pdf_url = str(record.get("pdf_url") or "").strip()
    if pdf_url:
        try:
            response = requests.get(pdf_url, timeout=60)
            response.raise_for_status()
            pdf_name = build_presentation_pdf_filename(filename, record)
            return send_file(
                BytesIO(response.content),
                mimetype="application/pdf",
                as_attachment=False,
                download_name=pdf_name,
            )
        except Exception as exc:
            if ENABLE_DEBUG_LOG:
                print(f"⚠️ 演示文稿 PDF 代理失败: {exc}")
            return jsonify({"error": "演示文稿不存在"}), 404
    object_key = str(record.get("object_key") or "").strip()
    if object_key:
        try:
            content, meta = download_object_storage_bytes(object_key)
        except Exception:
            return jsonify({"error": "演示文稿不存在"}), 404
        return send_file(
            BytesIO(content),
            mimetype=str(record.get("content_type") or meta.get("content_type") or "application/octet-stream"),
            as_attachment=False,
            download_name=str(record.get("filename") or Path(object_key).name or "presentation"),
        )

    path_str = str(record.get("path") or "").strip()
    if not path_str:
        return jsonify({"error": "演示文稿不存在"}), 404
    file_path = Path(path_str)
    if not file_path.exists():
        return jsonify({"error": "演示文稿不存在"}), 404
    downloads_dir = get_downloads_dir()
    if not is_path_under(file_path, downloads_dir):
        return jsonify({"error": "演示文稿位置无效"}), 403
    return send_from_directory(
        directory=file_path.parent,
        path=file_path.name,
        as_attachment=False,
        download_name=record.get("filename") or file_path.name
    )


@app.route('/api/reports/<path:filename>/presentation/status', methods=['GET'])
def get_report_presentation_status(filename):
    user_row = get_current_user()
    if not user_row:
        return jsonify({"error": "请先登录"}), 401
    user_id = int(user_row["id"])
    level_context = build_user_level_context_for_user(user_row)
    if not user_has_level_capability(user_row, "presentation.generate", level_context=level_context):
        return build_level_capability_denied_response(user_row, "presentation.generate", level_context=level_context)

    filename = normalize_presentation_report_filename(filename)
    if not filename:
        return jsonify({"exists": False})

    _report_file, owner_error = enforce_report_owner_or_404(filename, user_id)
    if owner_error:
        return jsonify({"exists": False})

    record = get_presentation_record(filename)
    if not record:
        return jsonify({"exists": False})

    pdf_url = record.get("pdf_url")
    is_paper2slides_record = str(record.get("provider") or "").strip() == "paper2slides"
    execution_id = str(record.get("execution_id") or "").strip()
    if is_paper2slides_record and not execution_id:
        execution_id = str(record.get("paper2slides_job_id") or "").strip()
    stopped_at = record.get("stopped_at")

    if execution_id:
        owner = get_execution_owner_report(execution_id)
        if owner and owner != filename:
            if ENABLE_DEBUG_LOG:
                print(f"⚠️ 清理跨报告 execution_id: execution_id={execution_id}, owner={owner}, filename={filename}")
            clear_presentation_execution(filename)
            execution_id = ""

    if execution_id and stopped_at:
        clear_presentation_execution(filename)
        execution_id = ""

    object_key = str(record.get("object_key") or "").strip()
    path_str = str(record.get("path") or "").strip()
    file_exists = False
    if object_key:
        file_exists = object_storage_key_exists(object_key)
    elif path_str:
        file_path = Path(path_str)
        downloads_dir = get_downloads_dir()
        if file_path.exists() and is_path_under(file_path, downloads_dir):
            file_exists = True

    processing = bool(execution_id and not pdf_url and not stopped_at)
    if is_paper2slides_record and execution_id and not pdf_url and not stopped_at:
        try:
            payload, _status_code = check_paper2slides_status(filename, execution_id)
            pdf_url = payload.get("pdf_url") or ""
            processing = bool(payload.get("processing")) and not pdf_url
            if payload.get("failed"):
                processing = False
        except Exception:
            processing = True
        return jsonify({
            "exists": bool(pdf_url),
            "pdf_url": pdf_url,
            "presentation_local_url": "",
            "execution_id": "" if pdf_url else execution_id,
            "processing": processing,
            "stopped": False,
            "progress": payload.get("progress"),
            "generated_pages": payload.get("generated_pages"),
            "total_pages": payload.get("total_pages"),
            "page_progress": payload.get("page_progress"),
            "paper2slides_status": payload.get("paper2slides_status") or {},
        })

    if processing:
        try:
            output_response = fetch_refly_output(execution_id)
            pdf_url = (
                extract_pdf_url_from_output(output_response)
                or build_pdf_url_from_result_info_file(output_response)
                or build_pdf_url_from_result_info(output_response)
            )
            if pdf_url:
                record_presentation_file(filename, None, pdf_url=pdf_url)
                processing = False
        except Exception:
            pass

    return jsonify({
        "exists": bool(pdf_url or file_exists),
        "pdf_url": pdf_url,
        "presentation_local_url": f"/api/reports/{quote(filename)}/presentation" if file_exists else "",
        "execution_id": execution_id,
        "processing": processing,
        "stopped": bool(stopped_at)
    })


@app.route('/api/reports/<path:filename>/presentation/link', methods=['GET'])
def get_report_presentation_link(filename):
    user_row = get_current_user()
    if not user_row:
        return jsonify({"error": "请先登录"}), 401
    user_id = int(user_row["id"])
    level_context = build_user_level_context_for_user(user_row)
    if not user_has_level_capability(user_row, "presentation.generate", level_context=level_context):
        return build_level_capability_denied_response(user_row, "presentation.generate", level_context=level_context)

    filename = normalize_presentation_report_filename(filename)
    if not filename:
        return jsonify({"error": "演示文稿不存在"}), 404

    _report_file, owner_error = enforce_report_owner_or_404(filename, user_id)
    if owner_error:
        response, status_code = owner_error
        return response, status_code

    record = get_presentation_record(filename)
    if not record:
        return jsonify({"error": "演示文稿不存在"}), 404
    pdf_url = str(record.get("pdf_url") or "").strip()
    if not pdf_url and not record.get("path") and not record.get("object_key"):
        return jsonify({"error": "演示文稿不存在"}), 404
    object_key = str(record.get("object_key") or "").strip()
    path_str = str(record.get("path") or "").strip()
    if object_key and object_storage_key_exists(object_key):
        return redirect(f"/api/reports/{quote(filename)}/presentation", code=302)
    if path_str:
        file_path = Path(path_str)
        downloads_dir = get_downloads_dir()
        if file_path.exists() and is_path_under(file_path, downloads_dir):
            return redirect(f"/api/reports/{quote(filename)}/presentation", code=302)
    if pdf_url:
        return redirect(pdf_url, code=302)
    return redirect(f"/api/reports/{quote(filename)}/presentation", code=302)


# ============ 报告 API ============

def extract_appendix_markdown_from_report(content: str) -> str:
    report_text = str(content or "")
    marker = "## 附录：完整访谈记录"
    appendix_index = report_text.find(marker)
    if appendix_index < 0:
        return ""

    appendix = report_text[appendix_index:].strip()
    appendix = re.sub(r"^\s*\*\*生成方式\*\*:[^\n]*\n?", "", appendix, flags=re.MULTILINE)
    return appendix.strip()


def normalize_appendix_line_for_pdf(raw_line: str) -> str:
    line = html.unescape(str(raw_line or ""))
    if not line:
        return ""

    summary_match = re.match(r"^\s*<summary[^>]*>\s*(.*?)\s*</summary>\s*$", line, flags=re.IGNORECASE)
    if summary_match:
        line = f"### {summary_match.group(1).strip()}"

    line = re.sub(r"</?details[^>]*>", "", line, flags=re.IGNORECASE)
    line = re.sub(r"<br\s*/?>", " ", line, flags=re.IGNORECASE)
    line = re.sub(r"<[^>]+>", "", line)
    line = re.sub(r"\s+", " ", line).strip()
    line = line.replace("☑", "[√]").replace("☐", "[ ]")
    return line


def wrap_pdf_text(text: str, font_name: str, font_size: float, max_width: float) -> list[str]:
    content = str(text or "")
    if not content:
        return [""]

    wrapped: list[str] = []
    current = ""
    for ch in content:
        candidate = f"{current}{ch}"
        if current and pdfmetrics.stringWidth(candidate, font_name, font_size) > max_width:
            wrapped.append(current)
            current = ch
        else:
            current = candidate

    if current:
        wrapped.append(current)

    return wrapped or [""]


def resolve_appendix_cjk_font_path() -> str:
    candidates = [
        # macOS
        "/System/Library/Fonts/PingFang.ttc",
        "/System/Library/Fonts/STHeiti Light.ttc",
        "/Library/Fonts/Arial Unicode.ttf",
        # Linux
        "/usr/share/fonts/opentype/noto/NotoSansCJK-Regular.ttc",
        "/usr/share/fonts/opentype/noto/NotoSansCJKSC-Regular.otf",
        "/usr/share/fonts/truetype/noto/NotoSansCJK-Regular.ttc",
        "/usr/share/fonts/truetype/wqy/wqy-microhei.ttc",
        # Windows
        "C:/Windows/Fonts/msyh.ttc",
        "C:/Windows/Fonts/simhei.ttf",
    ]
    for path in candidates:
        try:
            if Path(path).is_file():
                return path
        except Exception:
            continue
    return ""


def wrap_pil_text(draw: "ImageDraw.ImageDraw", text: str, font: "ImageFont.FreeTypeFont", max_width: int) -> list[str]:
    content = str(text or "")
    if not content:
        return [""]

    lines: list[str] = []
    current = ""
    for ch in content:
        candidate = f"{current}{ch}"
        width = draw.textlength(candidate, font=font)
        if current and width > max_width:
            lines.append(current)
            current = ch
        else:
            current = candidate

    if current:
        lines.append(current)
    return lines or [""]


def render_appendix_pages_as_images(appendix_markdown: str) -> list["Image.Image"]:
    if not PIL_AVAILABLE:
        return []

    page_width = 1240
    page_height = 1754
    margin_x = 86
    margin_y = 92
    max_width = page_width - margin_x * 2

    font_path = resolve_appendix_cjk_font_path()

    def load_font(size: int) -> "ImageFont.ImageFont":
        if font_path:
            try:
                return ImageFont.truetype(font_path, size=size)
            except Exception:
                pass
        return ImageFont.load_default()

    font_body = load_font(25)
    font_h3 = load_font(26)
    font_h2 = load_font(28)
    font_h1 = load_font(32)

    pages: list[Image.Image] = []
    image = Image.new("RGB", (page_width, page_height), "#FFFFFF")
    draw = ImageDraw.Draw(image)
    y = margin_y

    def new_page() -> None:
        nonlocal image, draw, y
        pages.append(image)
        image = Image.new("RGB", (page_width, page_height), "#FFFFFF")
        draw = ImageDraw.Draw(image)
        y = margin_y

    def ensure_space(height_needed: int) -> None:
        nonlocal y
        if y + height_needed <= page_height - margin_y:
            return
        new_page()

    for raw_line in str(appendix_markdown or "").splitlines():
        line = normalize_appendix_line_for_pdf(raw_line)
        if not line:
            y += 18
            continue

        text = line
        font = font_body
        line_height = 37
        spacing_after = 8

        if line.startswith("# "):
            text = line[2:].strip()
            font = font_h1
            line_height = 46
            spacing_after = 18
        elif line.startswith("## "):
            text = line[3:].strip()
            font = font_h2
            line_height = 40
            spacing_after = 16
        elif line.startswith("### "):
            text = line[4:].strip()
            font = font_h3
            line_height = 38
            spacing_after = 14
        elif line.startswith("- "):
            text = f"• {line[2:].strip()}"
            font = font_body
            line_height = 37
            spacing_after = 6

        wrapped_lines = wrap_pil_text(draw, text, font, max_width)
        ensure_space(len(wrapped_lines) * line_height + spacing_after)

        for segment in wrapped_lines:
            draw.text((margin_x, y), segment, fill="#111827", font=font)
            y += line_height
        y += spacing_after

    pages.append(image)
    return pages


def build_appendix_pdf_bytes_via_images(appendix_markdown: str) -> bytes:
    if not (REPORTLAB_AVAILABLE and PIL_AVAILABLE):
        raise RuntimeError("图像渲染依赖不可用")

    pages = render_appendix_pages_as_images(appendix_markdown)
    if not pages:
        raise RuntimeError("未生成有效图像页")

    buffer = BytesIO()
    pdf = report_canvas.Canvas(buffer, pagesize=A4, pageCompression=1)
    pdf_page_width, pdf_page_height = A4

    for page in pages:
        img_buffer = BytesIO()
        page.save(img_buffer, format="PNG")
        img_buffer.seek(0)
        pdf.drawImage(ImageReader(img_buffer), 0, 0, width=pdf_page_width, height=pdf_page_height, preserveAspectRatio=False, mask="auto")
        pdf.showPage()

    pdf.save()
    buffer.seek(0)
    return buffer.read()


def build_appendix_pdf_bytes(appendix_markdown: str) -> bytes:
    if not REPORTLAB_AVAILABLE:
        raise RuntimeError("reportlab 不可用")

    font_name = "STSong-Light"
    if font_name not in pdfmetrics.getRegisteredFontNames():
        pdfmetrics.registerFont(UnicodeCIDFont(font_name))

    buffer = BytesIO()
    pdf = report_canvas.Canvas(buffer, pagesize=A4, pageCompression=1)

    page_width, page_height = A4
    margin_x = 18 * mm
    margin_top = 18 * mm
    margin_bottom = 16 * mm
    max_width = page_width - margin_x * 2
    y = page_height - margin_top

    def ensure_space(height_needed: float) -> None:
        nonlocal y
        if y - height_needed < margin_bottom:
            pdf.showPage()
            y = page_height - margin_top

    for raw_line in str(appendix_markdown or "").splitlines():
        line = normalize_appendix_line_for_pdf(raw_line)
        if not line:
            ensure_space(8)
            y -= 8
            continue

        text = line
        font_size = 10.5
        line_height = 16
        spacing_after = 2

        if line.startswith("# "):
            text = line[2:].strip()
            font_size = 16
            line_height = 23
            spacing_after = 7
        elif line.startswith("## "):
            text = line[3:].strip()
            font_size = 14
            line_height = 21
            spacing_after = 6
        elif line.startswith("### "):
            text = line[4:].strip()
            font_size = 12.5
            line_height = 19
            spacing_after = 4
        elif line.startswith("- "):
            text = f"• {line[2:].strip()}"
            font_size = 10.5
            line_height = 16
            spacing_after = 2

        wrapped_lines = wrap_pdf_text(text, font_name, font_size, max_width)
        ensure_space(len(wrapped_lines) * line_height + spacing_after)

        pdf.setFont(font_name, font_size)
        for segment in wrapped_lines:
            pdf.drawString(margin_x, y, segment)
            y -= line_height
        y -= spacing_after

    pdf.save()
    buffer.seek(0)
    return buffer.read()


def load_reports_for_user_from_files(user_id_int: int) -> list[dict]:
    deleted = get_deleted_reports()
    owner_map = load_report_owners()
    expected_scope = get_active_instance_scope_key()
    binding_map = collect_direct_bound_report_metadata_from_sessions()
    reports = []
    for report_name, owner_id in owner_map.items():
        if owner_id != int(user_id_int):
            continue
        if not is_instance_scope_visible(get_report_scope_key(report_name), expected_scope=expected_scope):
            continue
        if report_name in deleted:
            continue
        if not isinstance(report_name, str) or not report_name.endswith(".md"):
            continue
        if not _report_exists(report_name):
            continue
        signature = _get_report_store_signature(report_name) or (0, 0)
        generated_at = _get_report_generated_at(report_name)
        reports.append(
            build_report_list_item(
                report_name,
                int(signature[1]),
                generated_at.isoformat() if isinstance(generated_at, datetime) else "",
                binding_metadata=binding_map.get(report_name),
            )
        )

    reports.sort(key=lambda x: x["created_at"], reverse=True)
    return reports


SOLUTION_DIMENSION_META = {
    "客户需求": {"badge": "需求聚焦", "summary": "围绕真实痛点定义目标、样本与优先级。"},
    "业务流程": {"badge": "关键触点", "summary": "锁定用户触达路径、界面节点与干预时机。"},
    "技术约束": {"badge": "技术底线", "summary": "明确合规、脱敏、性能与集成边界。"},
    "项目约束": {"badge": "交付边界", "summary": "平衡周期、预算、样本与落地节奏。"},
}


def normalize_solution_report_filename(report_filename: Optional[str]) -> str:
    return normalize_presentation_report_filename(report_filename)


def clean_solution_text(value: object, max_len: int = 0) -> str:
    text = html.unescape(str(value or ""))
    text = re.sub(r"<[^>]+>", " ", text)
    text = re.sub(r"\[([^\]]+)\]\([^\)]+\)", r"\1", text)
    text = re.sub(r"(?m)^\s{0,3}#{1,6}\s*", "", text)
    text = re.sub(r"(?m)^\s*[-*+]\s+", "", text)
    text = text.replace("**", "").replace("__", "").replace("`", "")
    text = re.sub(r"\s+", " ", text).strip(" \t\r\n-—|:：；;，。,.")
    if max_len and len(text) > max_len:
        text = text[:max_len].rstrip("，。,.;；：:!?？！ ")
    return text


def split_markdown_sections(content: str, heading_prefix: str) -> list[tuple[str, str]]:
    sections: list[tuple[str, str]] = []
    current_title = ""
    current_lines: list[str] = []
    for raw_line in str(content or "").splitlines():
        line = raw_line.rstrip("\n")
        if line.startswith(heading_prefix):
            if current_title:
                sections.append((clean_solution_text(current_title), "\n".join(current_lines).strip()))
            current_title = line[len(heading_prefix):].strip()
            current_lines = []
            continue
        if current_title:
            current_lines.append(line)
    if current_title:
        sections.append((clean_solution_text(current_title), "\n".join(current_lines).strip()))
    return sections


def parse_solution_bullet_item(raw_line: str) -> dict:
    text = str(raw_line or "").strip()
    if text.startswith("- "):
        text = text[2:].strip()
    match = re.match(r"^\*\*(.+?)\*\*\s*-\s*(.+)$", text)
    if match:
        return {
            "answer": clean_solution_text(match.group(1), max_len=88),
            "detail": clean_solution_text(match.group(2), max_len=180),
        }
    return {
        "answer": clean_solution_text(text, max_len=88),
        "detail": "",
    }


def dedupe_solution_items(items: list[dict], max_items: int = 8) -> list[dict]:
    seen = set()
    results = []
    for item in items:
        if not isinstance(item, dict):
            continue
        answer = clean_solution_text(item.get("answer", ""), max_len=88)
        detail = clean_solution_text(item.get("detail", ""), max_len=180)
        if not answer:
            continue
        key = answer.lower()
        if key in seen:
            continue
        seen.add(key)
        results.append({"answer": answer, "detail": detail})
        if len(results) >= max_items:
            break
    return results


def dedupe_solution_texts(values: list[object], max_items: int = 6, max_len: int = 24) -> list[str]:
    seen = set()
    results: list[str] = []
    for value in values:
        text = clean_solution_text(value, max_len=max_len)
        if not text:
            continue
        key = text.lower()
        if key in seen:
            continue
        seen.add(key)
        results.append(text)
        if len(results) >= max_items:
            break
    return results


def get_solution_item_answer(items: list[dict], index: int, fallback: str = "") -> str:
    if 0 <= index < len(items):
        return clean_solution_text(items[index].get("answer", ""), max_len=88)
    return clean_solution_text(fallback, max_len=88)


def get_solution_item_detail(items: list[dict], index: int, fallback: str = "") -> str:
    if 0 <= index < len(items):
        return clean_solution_text(items[index].get("detail", ""), max_len=180)
    return clean_solution_text(fallback, max_len=180)


def compact_solution_term(value: object, max_len: int = 0) -> str:
    text = clean_solution_text(value)
    text = re.sub(r"（[^）]*）", "", text)
    text = re.sub(r"\([^\)]*\)", "", text)
    text = re.split(r"[：:]", text, maxsplit=1)[0]
    text = re.sub(r"\s+", " ", text).strip(" \t\r\n-—|:：；;，。,.")

    if max_len and len(text) > max_len and "后的" in text:
        tail = text.rsplit("后的", 1)[-1].strip()
        if 1 < len(tail) < len(text):
            text = tail

    if max_len and len(text) > max_len and "的" in text:
        tail = text.rsplit("的", 1)[-1].strip()
        if 1 < len(tail) <= max_len:
            text = tail

    if max_len and len(text) > max_len:
        text = text[:max_len].rstrip("，。,.;；：:!?？！ ")
    return text or clean_solution_text(value, max_len=max_len)


def normalize_solution_meta_label(value: object, fallback: str = "访谈信息") -> str:
    text = clean_solution_text(value, max_len=28)
    text = re.sub(r"^\d+(?:\.\d+)*\s*", "", text)
    return text or fallback


def build_solution_overview_meta(
    overview_section: str,
    scene: str,
    pain_point: str,
    entry_point: str,
    tech_constraint: str,
    project_constraint: str,
) -> list[dict]:
    _ = overview_section
    candidates = [
        ("聚焦场景", scene or "待明确", 18),
        ("核心目标", pain_point or "待明确", 16),
        ("推进切口", entry_point or "待明确", 14),
        ("交付边界", project_constraint or tech_constraint or "待明确", 16),
    ]
    items: list[dict] = []
    for label, value, limit in candidates:
        normalized = compact_solution_term(value, max_len=limit)
        if not normalized:
            continue
        items.append({"label": label, "value": normalized})
    return items


def build_solution_overview_text(
    report_title: str,
    scene: str,
    pain_point: str,
    entry_point: str,
    tech_constraint: str,
    project_constraint: str,
    overview_meta: list[dict],
) -> str:
    _ = tech_constraint
    _ = project_constraint
    _ = overview_meta
    scene_brief = compact_solution_term(scene or report_title, max_len=16)
    pain_brief = compact_solution_term(pain_point or "核心问题", max_len=14)
    entry_brief = compact_solution_term(entry_point or "关键触点", max_len=12)
    return f"聚焦「{scene_brief}」，先解决「{pain_brief}」，从「{entry_brief}」启动首轮试点。"


def extract_solution_requirements(summary_content: str) -> dict[str, list[dict]]:
    groups: dict[str, list[dict]] = {}
    for title, body in split_markdown_sections(summary_content, "### "):
        parsed_items = []
        for raw_line in body.splitlines():
            line = raw_line.strip()
            if not line.startswith("- "):
                continue
            parsed_items.append(parse_solution_bullet_item(line))
        if parsed_items:
            groups[clean_solution_text(title, max_len=32)] = dedupe_solution_items(parsed_items, max_items=10)
    return groups


def extract_solution_overview_facts(overview_content: str) -> dict[str, str]:
    facts: dict[str, str] = {}
    for raw_line in str(overview_content or "").splitlines():
        line = raw_line.strip()
        if not line.startswith("- "):
            continue

        match = re.match(r"^- \*\*(.+?)\*\*\s*-\s*(.+)$", line)
        if match:
            label = normalize_solution_meta_label(match.group(1))
            value = clean_solution_text(match.group(2), max_len=180)
        else:
            body = line[2:].strip()
            parts = re.split(r"\s*[：:-]\s*", body, maxsplit=1)
            if len(parts) != 2:
                continue
            label = normalize_solution_meta_label(parts[0])
            value = clean_solution_text(parts[1], max_len=180)

        if label and value and label not in facts:
            facts[label] = value
    return facts


def extract_solution_overview_topic(overview_content: str) -> str:
    text = clean_solution_text(overview_content, max_len=180)
    match = re.search(r'本次访谈主题为[「"]?(.+?)[」"]?[，。,]', text)
    if match:
        return clean_solution_text(match.group(1), max_len=60)
    return ""


def simplify_solution_subject(value: object, max_len: int = 0) -> str:
    text = clean_solution_text(value)
    if not text:
        return ""

    text = text.replace("Intus", "").replace("见真", "").strip()
    original = text
    patterns = [
        r"(产品)?需求调研报告$",
        r"需求调研报告$",
        r"调研报告$",
        r"访谈报告$",
        r"报告$",
        r"(产品)?需求调研$",
        r"需求调研$",
        r"专题调研$",
        r"调研$",
    ]

    for pattern in patterns:
        candidate = re.sub(pattern, "", text).strip(" \t\r\n-—|:：；;，。,.《》「」")
        if len(candidate) >= 2:
            text = candidate
            break

    return compact_solution_term(text or original, max_len=max_len)


def is_solution_generic_subject(value: object) -> bool:
    text = clean_solution_text(value)
    if not text:
        return True
    if "报告" in text or "调研" in text:
        return True
    if "访谈" in text and len(text) >= 8:
        return True
    return False


def infer_solution_metrics(report_title: str, report_text: str) -> list[dict]:
    combined = f"{report_title}\n{report_text}"

    def contains_any(keywords: list[str]) -> bool:
        return any(keyword in combined for keyword in keywords)

    metrics = [
        {
            "label": "调研效率",
            "value": "65-80%" if contains_any(["效率", "自动化", "人工", "回收", "耗时"]) else "35-50%",
            "note": "用于衡量访谈组织与整理效率的预估改善幅度",
        },
        {
            "label": "有效洞察率",
            "value": "40-60%" if contains_any(["洞察", "归因", "真实痛点", "敷衍", "无效"]) else "25-40%",
            "note": "用于衡量高价值回答与根因识别的预估提升",
        },
        {
            "label": "风险识别",
            "value": "20-35%" if contains_any(["风控", "安全", "误拦截", "合规", "隐私", "脱敏"]) else "15-25%",
            "note": "用于衡量高风险场景识别与拦截误伤校准",
        },
        {
            "label": "试点周期",
            "value": "4-8周" if contains_any(["2-3个月", "短周期", "试点", "投放"]) else "3-6周",
            "note": "从方案对齐到首轮验证的建议节奏",
        },
    ]
    return metrics


def infer_solution_risk_guardrail(answer: str) -> str:
    text = str(answer or "")
    if any(keyword in text for keyword in ["隐私", "合规", "脱敏", "加密"]):
        return "先冻结脱敏规则、留痕范围与本地处理边界，再推进采集。"
    if any(keyword in text for keyword in ["招募", "投放", "样本", "触发"]):
        return "先验证样本获取路径，再扩大投放，避免低质样本稀释结论。"
    if any(keyword in text for keyword in ["复现", "模拟器", "录屏", "UI"]):
        return "采用分层复现策略，优先低保真验证，再投入高仿真开发。"
    if any(keyword in text for keyword in ["周期", "预算", "资源"]):
        return "把试点范围、验收口径和资源上限前置锁定，避免中途扩张。"
    return "通过试点范围、验收门槛和里程碑复盘控制执行风险。"


def build_solution_focus_cards(
    customer_items: list[dict],
    process_items: list[dict],
    scene: str,
    entry_point: str,
) -> list[dict]:
    return [
        {
            "title": "场景切口",
            "summary": get_solution_item_answer(customer_items, 5, fallback=scene or "围绕高价值场景优先切入"),
            "detail": get_solution_item_detail(customer_items, 5, fallback="把业务场景进一步收窄到可验证切口。"),
        },
        {
            "title": "用户心理",
            "summary": get_solution_item_answer(
                customer_items,
                8,
                fallback=get_solution_item_answer(customer_items, 7, fallback="补齐用户心理与替代方案决策链路"),
            ),
            "detail": get_solution_item_detail(customer_items, 8, fallback="优先还原用户在关键触点的决策与情绪机制。"),
        },
        {
            "title": "流程触点",
            "summary": get_solution_item_answer(process_items, 2, fallback=entry_point or "补齐触发节点与操作路径"),
            "detail": get_solution_item_detail(process_items, 2, fallback="把触点、时机和交互阻塞点映射到方案动作。"),
        },
    ]


def build_solution_dimension_cards(requirement_groups: dict[str, list[dict]]) -> list[dict]:
    cards: list[dict] = []
    for name in ["客户需求", "业务流程", "技术约束", "项目约束"]:
        items = requirement_groups.get(name, [])
        meta = SOLUTION_DIMENSION_META.get(name, {"badge": "业务板块", "summary": "结合访谈内容补齐该板块。"})
        points = dedupe_solution_texts([item.get("answer", "") for item in items] or [meta["summary"]], max_items=4, max_len=44)
        cards.append({
            "name": name,
            "badge": meta["badge"],
            "summary": get_solution_item_answer(items, 0, fallback=meta["summary"]),
            "points": points,
        })
    return cards


