def get_solution_sidecar_path(report_name: str) -> Path:
    normalized = normalize_solution_report_filename(report_name)
    safe_name = Path(str(normalized or "report.md")).name or "report.md"
    return REPORTS_DIR / f"{safe_name}{SOLUTION_SIDECAR_SUFFIX}"


def get_solution_payload_cache_path(report_name: str) -> Path:
    normalized = normalize_solution_report_filename(report_name)
    safe_name = Path(str(normalized or "report.md")).name or "report.md"
    return REPORTS_DIR / f"{safe_name}{SOLUTION_PAYLOAD_CACHE_SUFFIX}"


def read_solution_sidecar(report_name: str) -> dict:
    return _load_report_artifact_payload(
        "report_solution_sidecars",
        report_name,
        get_solution_sidecar_path(report_name),
    )


def _collect_direct_bound_report_names(session: dict) -> list[str]:
    if not isinstance(session, dict):
        return []

    candidates = []
    current_report_name = str(session.get("current_report_name") or "").strip()
    if current_report_name:
        candidates.append(current_report_name)

    current_report_path = str(session.get("current_report_path") or "").strip()
    if current_report_path:
        derived_name = Path(current_report_path).name.strip()
        if derived_name and derived_name not in candidates:
            candidates.append(derived_name)

    last_report_name = normalize_solution_report_filename(session.get("last_report_name", ""))
    if last_report_name and last_report_name not in candidates:
        candidates.append(last_report_name)
    return candidates


def find_direct_bound_session_for_report(report_name: str, owner_user_id: int) -> Optional[dict]:
    expected_scope = get_active_instance_scope_key()
    normalized_report_name = normalize_solution_report_filename(report_name)
    if not normalized_report_name:
        return None

    for _session_file, session_data in _iter_session_payload_entries():
        if not isinstance(session_data, dict):
            continue
        if not ensure_session_owner(session_data, owner_user_id):
            continue
        if not is_instance_scope_visible(get_session_instance_scope_key(session_data), expected_scope=expected_scope):
            continue
        if normalized_report_name in _collect_direct_bound_report_names(session_data):
            return session_data
    return None


def build_report_binding_metadata(report_name: str, binding_metadata: Optional[dict] = None) -> dict:
    normalized_report_name = normalize_solution_report_filename(report_name)
    metadata = empty_report_binding_metadata()
    if not normalized_report_name:
        return metadata

    sidecar = read_solution_sidecar(normalized_report_name)
    if isinstance(sidecar, dict) and sidecar:
        normalized_snapshot = _normalize_solution_snapshot(sidecar)
        metadata.update(normalize_report_binding_metadata({
            "session_id": normalized_snapshot.get("session_id", ""),
            "topic": normalized_snapshot.get("topic", ""),
            "scenario_name": normalized_snapshot.get("scenario_name", ""),
            "report_template": normalized_snapshot.get("report_template", ""),
            "report_type": normalized_snapshot.get("report_type", ""),
            "report_profile": normalized_snapshot.get("report_profile", ""),
            "source_report_name": normalized_snapshot.get("source_report_name", ""),
            "report_variant_label": normalized_snapshot.get("report_variant_label", ""),
        }))

    fallback_metadata = normalize_report_binding_metadata(binding_metadata)
    for key, value in fallback_metadata.items():
        if value and not metadata.get(key):
            metadata[key] = value
    return metadata


def build_report_list_item(report_name: str, size: int, created_at: str, binding_metadata: Optional[dict] = None) -> dict:
    path = str((REPORTS_DIR / report_name).resolve())
    payload = {
        "name": report_name,
        "path": path,
        "size": int(size or 0),
        "created_at": str(created_at or ""),
    }
    payload.update(build_report_binding_metadata(report_name, binding_metadata=binding_metadata))
    return payload


def write_solution_sidecar(report_name: str, snapshot: dict) -> None:
    if not isinstance(snapshot, dict) or not snapshot:
        return
    payload = copy.deepcopy(snapshot)
    payload["version"] = SOLUTION_SNAPSHOT_VERSION
    payload["report_name"] = report_name
    _save_report_artifact_payload(
        "report_solution_sidecars",
        report_name,
        payload,
        get_solution_sidecar_path(report_name),
    )
    delete_solution_payload_cache(report_name)
    try:
        sync_report_index_for_filename(report_name)
    except Exception as exc:
        if ENABLE_DEBUG_LOG:
            _safe_log(f"⚠️ 写入 solution sidecar 后同步报告索引失败: report={report_name}, error={exc}")


def _solution_payload_cache_source_hash(
    report_name: str,
    *,
    source_mode: str,
    snapshot: Optional[dict] = None,
    report_content: str = "",
) -> str:
    normalized_report_name = normalize_solution_report_filename(report_name)
    if isinstance(snapshot, dict) and snapshot:
        cache_source = copy.deepcopy(_normalize_solution_snapshot(snapshot))
        if isinstance(cache_source, dict):
            cache_source.pop("solution_snapshot", None)
    else:
        cache_source = {
            "report_name": normalized_report_name,
            "report_content": normalize_report_time_fields(str(report_content or "")),
        }
    digest_payload = {
        "cache_version": SOLUTION_PAYLOAD_CACHE_VERSION,
        "source_mode": str(source_mode or "").strip(),
        "source": cache_source,
    }
    return hashlib.sha1(
        json.dumps(digest_payload, ensure_ascii=False, sort_keys=True).encode("utf-8")
    ).hexdigest()


def read_solution_payload_cache(
    report_name: str,
    *,
    expected_source_mode: str,
    expected_source_hash: str,
) -> dict:
    payload = _load_report_artifact_payload(
        "report_solution_payload_caches",
        report_name,
        get_solution_payload_cache_path(report_name),
    )
    if not isinstance(payload, dict):
        return {}
    if str(payload.get("cache_version") or "") != SOLUTION_PAYLOAD_CACHE_VERSION:
        return {}
    if str(payload.get("source_mode") or "") != str(expected_source_mode or ""):
        return {}
    if str(payload.get("source_hash") or "") != str(expected_source_hash or ""):
        return {}
    cached_payload = payload.get("payload", {})
    return copy.deepcopy(cached_payload) if isinstance(cached_payload, dict) else {}


def write_solution_payload_cache(
    report_name: str,
    payload: dict,
    *,
    source_mode: str,
    source_hash: str,
) -> None:
    if not isinstance(payload, dict) or not payload:
        return
    cache_payload = {
        "cache_version": SOLUTION_PAYLOAD_CACHE_VERSION,
        "report_name": normalize_solution_report_filename(report_name),
        "source_mode": str(source_mode or "").strip(),
        "source_hash": str(source_hash or "").strip(),
        "generated_at": get_utc_now(),
        "payload": copy.deepcopy(payload),
    }
    _save_report_artifact_payload(
        "report_solution_payload_caches",
        report_name,
        cache_payload,
        get_solution_payload_cache_path(report_name),
    )


def delete_solution_payload_cache(report_name: str) -> None:
    _delete_report_artifact_payload(
        "report_solution_payload_caches",
        report_name,
        get_solution_payload_cache_path(report_name),
    )


def delete_solution_sidecar(report_name: str) -> None:
    _delete_report_artifact_payload(
        "report_solution_sidecars",
        report_name,
        get_solution_sidecar_path(report_name),
    )
    delete_solution_payload_cache(report_name)


def _solution_report_title_from_content(report_content: str) -> str:
    report_title = "访谈报告"
    for raw_line in str(report_content or "").splitlines():
        line = raw_line.strip()
        if line.startswith("# "):
            report_title = clean_solution_text(line[2:].replace("访谈报告", ""), max_len=60) or "访谈报告"
            break
    return report_title


def _solution_find_section_body(sections: list[tuple[str, str]], keywords: list[str]) -> str:
    for title, body in sections:
        normalized_title = clean_solution_text(title, max_len=80)
        if any(keyword in normalized_title for keyword in keywords):
            return body
    return ""


def _solution_strip_markdown_tables(text: str) -> str:
    lines = []
    for raw_line in str(text or "").splitlines():
        line = raw_line.rstrip()
        if line.strip().startswith("|"):
            continue
        lines.append(line)
    return "\n".join(lines).strip()


def _parse_solution_markdown_table(table_body: str) -> list[dict]:
    lines = [line.strip() for line in str(table_body or "").splitlines() if line.strip().startswith("|")]
    if len(lines) < 2:
        return []

    headers = [clean_solution_text(cell, max_len=48) for cell in lines[0].strip().strip("|").split("|")]
    if not headers:
        return []

    rows = []
    for raw_line in lines[2:]:
        if re.match(r"^\|\s*[:\- ]+\|", raw_line):
            continue
        cells = [clean_solution_text(cell, max_len=240) for cell in raw_line.strip().strip("|").split("|")]
        if not any(cell and cell != "-" for cell in cells):
            continue
        while len(cells) < len(headers):
            cells.append("")
        rows.append({headers[idx]: cells[idx] for idx in range(len(headers))})
    return rows


def _solution_extract_markdown_table_blocks(text: str) -> list[str]:
    blocks = []
    current_lines = []
    for raw_line in str(text or "").splitlines():
        line = raw_line.strip()
        if line.startswith("|"):
            current_lines.append(line)
            continue
        if len(current_lines) >= 2:
            blocks.append("\n".join(current_lines))
        current_lines = []
    if len(current_lines) >= 2:
        blocks.append("\n".join(current_lines))
    return blocks


def _solution_parse_table_from_sections(sections: list[tuple[str, str]], keywords: list[str], fallback_body: str = "") -> list[dict]:
    candidate_bodies = []
    for title, body in sections:
        normalized_title = clean_solution_text(title, max_len=80)
        if any(keyword in normalized_title for keyword in keywords):
            candidate_bodies.append(body)
    if fallback_body:
        candidate_bodies.append(fallback_body)

    seen = set()
    for body in candidate_bodies:
        body_text = str(body or "")
        key = clean_solution_text(body_text, max_len=0)
        if key in seen:
            continue
        seen.add(key)
        for block in _solution_extract_markdown_table_blocks(body_text):
            rows = _parse_solution_markdown_table(block)
            if rows:
                return rows
    return []


def _normalize_solution_refs(value) -> list[str]:
    if isinstance(value, list):
        raw_items = value
    elif isinstance(value, str):
        raw_items = re.split(r"[、,，;；/\s]+", value)
    else:
        raw_items = []

    refs = []
    seen = set()
    for raw_item in raw_items:
        text = clean_solution_text(raw_item, max_len=16).upper()
        if not text or not re.fullmatch(r"Q\d+", text):
            continue
        if text in seen:
            continue
        seen.add(text)
        refs.append(text)
    return refs


