def build_solution_runtime_snapshot(snapshot: dict) -> dict:
    normalized = _normalize_solution_snapshot(snapshot)
    context = _solution_context_from_snapshot(normalized)
    draft = normalized["draft"]
    needs = draft.get("needs", [])
    solutions = draft.get("solutions", [])
    risks = draft.get("risks", [])
    actions = draft.get("actions", [])
    analysis = draft.get("analysis", {})

    decision_cards = [
        {
            "eyebrow": "主判断",
            "title": "当前判断",
            "summary": context.get("pain_point", "核心议题"),
            "detail": context.get("summary", "当前报告已经沉淀出足够清晰的推进判断。"),
        },
        {
            "eyebrow": "优先切口",
            "title": "优先切口",
            "summary": context.get("entry_point", "首轮动作"),
            "detail": _solution_join_meta([
                actions[0].get("timeline", "") if actions else "",
                solutions[0].get("metric", "") if solutions else "",
            ]) or "优先从最靠近业务闭环的动作进入。",
        },
        {
            "eyebrow": "边界条件",
            "title": "成立边界",
            "summary": context.get("constraint", "交付边界"),
            "detail": clean_solution_text(
                analysis.get("project_constraints", "") or analysis.get("tech_constraints", ""),
                max_len=140,
            ) or "需要先锁定资源、合规与交付边界。",
        },
    ]
    analysis_blocks = [
        text
        for text in [
            analysis.get("customer_needs", ""),
            analysis.get("business_flow", ""),
            analysis.get("tech_constraints", ""),
            analysis.get("project_constraints", ""),
        ]
        if clean_solution_text(text, max_len=200)
    ]

    return {
        "version": "v2",
        "context": {
            "subject": context.get("subject", "访谈结论"),
            "summary": context.get("summary", ""),
            "pain_point": context.get("pain_point", ""),
            "entry_point": context.get("entry_point", ""),
            "constraint": context.get("constraint", ""),
        },
        "decision_frame": {
            "why_now": context.get("summary", ""),
            "why_this_path": context.get("entry_point", ""),
            "must_lock": context.get("constraint", ""),
        },
        "derived": {
            "executive_summary": context.get("summary", ""),
            "primary_decision": context.get("pain_point", ""),
            "primary_workstream": context.get("entry_point", ""),
            "decision_cards": decision_cards,
            "current_state_cards": _solution_need_cards(needs, limit=6),
            "target_blueprint_cards": _solution_solution_cards(solutions, limit=6),
            "solution_compare_table": _solution_table_payload_from_items("solutions", solutions),
            "workstream_cards": _solution_solution_cards(solutions, limit=6),
            "milestones": _solution_action_timeline(actions, limit=6),
            "action_checklist": _solution_action_checklist(actions, limit=6),
            "risk_cards": _solution_risk_cards(risks, limit=6),
            "analysis_blocks": analysis_blocks[:4],
            "open_questions_table": _solution_table_payload_from_items("open_questions", draft.get("open_questions", [])),
            "needs_table": _solution_table_payload_from_items("needs", needs),
            "solutions_table": _solution_table_payload_from_items("solutions", solutions),
            "actions_table": _solution_table_payload_from_items("actions", actions),
            "risks_table": _solution_table_payload_from_items("risks", risks),
        },
        "raw": {
            "draft": copy.deepcopy(draft),
            "quality": {
                "quality_meta": copy.deepcopy(normalized.get("quality_meta", {})),
                "quality_snapshot": copy.deepcopy(normalized.get("quality_snapshot", {})),
            },
            "evidence_summary": {
                "overall_coverage": float(normalized.get("overall_coverage", 0.0) or 0.0),
                "has_structured_evidence": bool(normalized.get("has_structured_evidence", False)),
            },
        },
    }


def _proposal_unique_refs(values, limit: int = 8) -> list[str]:
    refs = []
    seen = set()
    raw_values = values if isinstance(values, list) else [values]
    for value in raw_values:
        if isinstance(value, dict):
            candidates = value.get("evidence_refs", [])
        else:
            candidates = value
        for ref in _normalize_solution_refs(candidates):
            if ref in seen:
                continue
            seen.add(ref)
            refs.append(ref)
            if len(refs) >= limit:
                return refs
    return refs


def _proposal_compact_sentences(values, max_items: int = 4, max_len: int = 120) -> list[str]:
    items = []
    seen = set()
    raw_values = values if isinstance(values, list) else [values]
    for value in raw_values:
        if isinstance(value, dict):
            texts = [
                value.get("title", ""),
                value.get("summary", ""),
                value.get("detail", ""),
                value.get("description", ""),
            ]
        else:
            texts = [value]
        for raw_text in texts:
            text = _proposal_business_sentence(raw_text, max_len=max_len) or clean_solution_text(raw_text, max_len=max_len)
            if not text:
                continue
            key = re.sub(r"\s+", "", text.lower())
            if key in seen:
                continue
            seen.add(key)
            items.append(text)
            if len(items) >= max_items:
                return items
    return items


def _proposal_sentence_from_parts(parts: list[str], fallback: str, max_len: int = 140) -> str:
    text = clean_solution_text("，".join([part for part in parts if clean_solution_text(part, max_len=max_len)]), max_len=max_len)
    return text or clean_solution_text(fallback, max_len=max_len)


def _proposal_text_fingerprint(value) -> str:
    text = clean_solution_text(value, max_len=0).lower()
    if not text:
        return ""
    for source, target in _PROPOSAL_FOCUS_REPLACEMENTS:
        text = text.replace(source.lower(), target.lower())
    for source, target in _PROPOSAL_SENTENCE_REPLACEMENTS:
        text = text.replace(source.lower(), target.lower())
    for source, target in (
        ("为什么当前先做", ""),
        ("为什么现在做", ""),
        ("为什么选", ""),
        ("推荐路径", ""),
        ("推荐结论", ""),
        ("当前建议", ""),
        ("最终建议", ""),
        ("当前更适合", ""),
        ("围绕", ""),
        ("先把", ""),
        ("先做", ""),
        ("优先", ""),
        ("试点", ""),
        ("首轮", ""),
        ("跑通", ""),
        ("锁定", ""),
        ("拉通", ""),
        ("推进", ""),
        ("做透", ""),
        ("完成", ""),
        ("进入", ""),
        ("阶段", ""),
    ):
        text = text.replace(source, target)
    text = re.sub(r"[「」\"'“”‘’、，。；：:！!？?\s]", "", text)
    return text


def _proposal_pick_unique_copy(candidates, seen: set[str], max_len: int = 120) -> str:
    values = candidates if isinstance(candidates, list) else [candidates]
    fallback = ""
    for value in values:
        text = clean_solution_text(value, max_len=max_len)
        if text and not fallback:
            fallback = text
        key = _proposal_text_fingerprint(text)
        if not text:
            continue
        if key and key in seen:
            continue
        if key:
            seen.add(key)
        return text
    return fallback


def _proposal_text_equivalent(left, right) -> bool:
    left_key = _proposal_text_fingerprint(left)
    right_key = _proposal_text_fingerprint(right)
    return bool(left_key and right_key and left_key == right_key)


def _proposal_distinct_copy(value, context=None, max_len: int = 120) -> str:
    text = clean_solution_text(value, max_len=max_len)
    if not text:
        return ""
    peers = context if isinstance(context, list) else [context]
    for peer in peers:
        if _proposal_text_equivalent(text, peer):
            return ""
    return text


def _proposal_dedupe_string_list(values, context=None, limit: int = 0, max_len: int = 64) -> list[str]:
    items = values if isinstance(values, list) else [values]
    seen = {
        _proposal_text_fingerprint(item)
        for item in (context if isinstance(context, list) else [context])
        if _proposal_text_fingerprint(item)
    }
    result = []
    for item in items:
        text = clean_solution_text(item, max_len=max_len)
        key = _proposal_text_fingerprint(text)
        if not text or not key or key in seen:
            continue
        seen.add(key)
        result.append(text)
        if limit > 0 and len(result) >= limit:
            break
    return result


def _proposal_normalize_metric_entries(metrics, context=None, limit: int = 0) -> list[dict]:
    seen = {
        _proposal_text_fingerprint(item)
        for item in (context if isinstance(context, list) else [context])
        if _proposal_text_fingerprint(item)
    }
    result = []
    for item in (metrics if isinstance(metrics, list) else [metrics]):
        if not isinstance(item, dict):
            continue
        label = clean_solution_text(item.get("label", "") or item.get("metric", "") or "指标", max_len=20)
        value = clean_solution_text(item.get("value", "") or item.get("target", ""), max_len=40)
        note = clean_solution_text(item.get("note", ""), max_len=48)
        value_key = _proposal_text_fingerprint(value)
        note_key = _proposal_text_fingerprint(note)
        pair_key = _proposal_text_fingerprint(f"{label} {value}")
        if note_key and (note_key == value_key or note_key in seen):
            note = ""
        if not value or not pair_key or pair_key in seen:
            continue
        seen.add(pair_key)
        if value_key:
            seen.add(value_key)
        if note_key and note:
            seen.add(note_key)
        result.append({
            "metric": label,
            "target": value,
            "note": note,
        })
        if limit > 0 and len(result) >= limit:
            break
    return result


def _proposal_normalize_card_entries(cards, context=None, limit: int = 0, title_max_len: int = 28, desc_max_len: int = 88) -> list[dict]:
    seen = {
        _proposal_text_fingerprint(item)
        for item in (context if isinstance(context, list) else [context])
        if _proposal_text_fingerprint(item)
    }
    result = []
    for item in (cards if isinstance(cards, list) else [cards]):
        if not isinstance(item, dict):
            continue
        tag = clean_solution_text(item.get("tag", ""), max_len=16)
        title = clean_solution_text(item.get("title", ""), max_len=title_max_len)
        desc = clean_solution_text(
            item.get("desc", "") or item.get("detail", "") or item.get("description", "") or item.get("summary", ""),
            max_len=desc_max_len,
        )
        meta = clean_solution_text(item.get("meta", ""), max_len=48)
        title_key = _proposal_text_fingerprint(title)
        desc_key = _proposal_text_fingerprint(desc)
        if title_key and desc_key and title_key == desc_key:
            desc = ""
            desc_key = ""
        if title_key and title_key in seen:
            if desc_key and desc_key not in seen and tag and not _proposal_text_equivalent(tag, desc):
                title = tag
                title_key = _proposal_text_fingerprint(title)
                tag = ""
            else:
                title = ""
                title_key = ""
        if desc_key and desc_key in seen:
            desc = ""
            desc_key = ""
        if tag and title and _proposal_text_equivalent(tag, title):
            tag = ""
        if not title and desc:
            title = clean_solution_text(tag or "补充信息", max_len=title_max_len)
            title_key = _proposal_text_fingerprint(title)
            tag = ""
        merged_key = _proposal_text_fingerprint(f"{title} {desc}")
        if not title or not merged_key or merged_key in seen:
            continue
        seen.add(merged_key)
        if title_key:
            seen.add(title_key)
        if desc_key:
            seen.add(desc_key)
        result.append({
            "title": title,
            "desc": desc,
            "tag": tag,
            "meta": meta,
        })
        if limit > 0 and len(result) >= limit:
            break
    return result


