@app.route('/api/public/solutions/<share_token>', methods=['GET'])
def get_public_solution_by_share_token(share_token):
    record = get_solution_share_record(share_token)
    if not record:
        return jsonify({"error": "分享链接不存在或已失效"}), 404

    report_name = normalize_solution_report_filename(record.get("report_name"))
    if not report_name:
        return jsonify({"error": "分享链接不存在或已失效"}), 404

    if not _report_exists(report_name):
        return jsonify({"error": "分享链接不存在或已失效"}), 404

    try:
        owner_user_id = int(record.get("owner_user_id", 0))
    except (TypeError, ValueError):
        owner_user_id = 0
    if owner_user_id <= 0 or get_report_owner_id(report_name) != owner_user_id:
        return jsonify({"error": "分享链接不存在或已失效"}), 404
    if report_name in get_deleted_reports():
        return jsonify({"error": "分享链接不存在或已失效"}), 404

    content = _load_report_content(report_name)
    generated_at = _get_report_generated_at(report_name)
    content = normalize_report_time_fields(content, generated_at=generated_at)
    payload = copy.deepcopy(build_solution_payload_from_report(
        report_name,
        content,
        allow_ai_enhancement=False,
        owner_user_id=owner_user_id,
    ))
    payload["share_mode"] = "public"
    payload["report_name"] = ""
    payload["viewer_capabilities"] = {
        "solution_share": False,
    }

    response = jsonify(payload)
    response.headers["Cache-Control"] = "no-store, max-age=0"
    response.headers["Pragma"] = "no-cache"
    response.headers["X-Robots-Tag"] = "noindex, nofollow, noarchive"
    return response


@app.route('/api/reports/<path:filename>/appendix/pdf', methods=['GET'])
def export_report_appendix_pdf(filename):
    user_row = get_current_user()
    if not user_row:
        return jsonify({"error": "请先登录"}), 401
    user_id = int(user_row["id"])
    level_context = build_user_level_context_for_user(user_row)
    if not user_has_level_capability(user_row, "report.export.appendix", level_context=level_context):
        return build_level_capability_denied_response(user_row, "report.export.appendix", level_context=level_context)

    report_file, owner_error = enforce_report_owner_or_404(filename, user_id)
    if owner_error:
        response, status_code = owner_error
        return response, status_code

    if not REPORTLAB_AVAILABLE:
        return jsonify({"error": "服务端 PDF 导出能力不可用"}), 503

    report_content = _load_report_content(filename)
    appendix_markdown = extract_appendix_markdown_from_report(report_content)
    if not appendix_markdown:
        return jsonify({"error": "未找到附录内容"}), 404

    try:
        # 优先走图像渲染，规避部分 PDF 阅读器对 CJK 字体兼容导致的空白问题
        if PIL_AVAILABLE:
            pdf_bytes = build_appendix_pdf_bytes_via_images(appendix_markdown)
        else:
            pdf_bytes = build_appendix_pdf_bytes(appendix_markdown)
    except Exception as exc:
        print(f"⚠️ 附录 PDF 图像渲染失败，回退文本渲染: {exc}")
        try:
            pdf_bytes = build_appendix_pdf_bytes(appendix_markdown)
        except Exception as text_exc:
            print(f"⚠️ 附录 PDF 生成失败: {text_exc}")
            return jsonify({"error": "附录 PDF 生成失败"}), 500

    download_name = f"{Path(filename).stem}-完整访谈记录.pdf"
    return send_file(
        BytesIO(pdf_bytes),
        mimetype="application/pdf",
        as_attachment=True,
        download_name=download_name,
    )


@app.route('/api/reports/<path:filename>/refly', methods=['POST'])
def send_report_to_refly(filename):
    """将报告发送到演示文稿服务生成演示文稿"""
    user_row = get_current_user()
    if not user_row:
        return jsonify({"error": "请先登录"}), 401
    if not is_presentation_feature_enabled():
        return build_presentation_feature_disabled_response()
    user_id = int(user_row["id"])
    level_context = build_user_level_context_for_user(user_row)
    if not user_has_level_capability(user_row, "presentation.generate", level_context=level_context):
        return build_level_capability_denied_response(user_row, "presentation.generate", level_context=level_context)

    filename = normalize_presentation_report_filename(filename)
    if not filename:
        return jsonify({"error": "报告文件名无效"}), 400

    report_file, owner_error = enforce_report_owner_or_404(filename, user_id)
    if owner_error:
        response, status_code = owner_error
        return response, status_code

    if not is_presentation_service_configured():
        return jsonify({"error": "演示文稿服务未配置"}), 400

    current_record = get_presentation_record(filename) or {}
    current_execution_id = str(current_record.get("execution_id") or "").strip()
    if (
        get_presentation_provider() == "paper2slides"
        and current_execution_id
        and str(current_record.get("provider") or "").strip() == "paper2slides"
        and not is_presentation_execution_stopped(filename, current_execution_id)
    ):
        try:
            payload, status_code = check_paper2slides_status(filename, current_execution_id)
            if payload.get("processing"):
                return jsonify(payload), status_code
            if not payload.get("failed") and not payload.get("pdf_url"):
                return jsonify({
                    "processing": True,
                    "execution_id": current_execution_id,
                    "message": "已有演示文稿生成任务正在运行",
                }), 202
        except requests.RequestException:
            return jsonify({
                "processing": True,
                "execution_id": current_execution_id,
                "message": "已有演示文稿生成任务正在运行，请稍后查看状态",
            }), 202

    clear_presentation_stopped(filename)
    execution_id = ""

    try:
        report_content = _load_report_content(filename)
        if get_presentation_provider() == "paper2slides":
            payload, status_code = send_report_to_paper2slides_service(filename, report_file, report_content)
            return jsonify(payload), status_code

        report_title = report_content.strip().splitlines()[0].lstrip("#").strip() if report_content else ""
        materialized_report_file = _materialize_report_file_for_local_use(filename, report_content)
        try:
            upload_response = upload_refly_file(materialized_report_file)
        finally:
            if materialized_report_file != report_file:
                materialized_report_file.unlink(missing_ok=True)
        file_keys = extract_refly_file_keys(upload_response)
        run_response = run_refly_workflow(report_content, file_keys=file_keys)
        execution_id = (
            run_response.get("data", {}).get("executionId")
            or run_response.get("executionId")
        )
        if not execution_id:
            return jsonify({
                "error": "服务未返回 executionId",
                "refly_upload": upload_response,
                "refly_response": run_response
            }), 502

        owner = get_execution_owner_report(execution_id)
        if owner and owner != filename:
            if ENABLE_DEBUG_LOG:
                print(f"⚠️ 拦截跨报告 execution_id 复用: execution_id={execution_id}, owner={owner}, filename={filename}")
            return jsonify({
                "error": "生成任务归属冲突，请重试",
                "mismatch": True,
                "owner_report": owner,
                "execution_id": execution_id
            }), 409

        if is_presentation_execution_stopped(filename, execution_id):
            try:
                url = get_refly_abort_url(execution_id)
                headers = {"Authorization": f"Bearer {REFLY_API_KEY}"}
                requests.post(url, headers=headers, timeout=REFLY_TIMEOUT)
            except Exception:
                pass
            return jsonify({
                "processing": False,
                "execution_id": "",
                "stopped": True,
                "message": "演示文稿生成已停止"
            })

        record_presentation_execution(filename, execution_id)

        status_response = poll_refly_execution(execution_id)
        output_response = wait_for_refly_output_ready(execution_id)
        pdf_url = (
            extract_pdf_url_from_output(output_response)
            or build_pdf_url_from_result_info_file(output_response)
            or build_pdf_url_from_result_info(output_response)
        )
        if not pdf_url:
            if is_presentation_execution_stopped(filename, execution_id):
                return jsonify({
                    "processing": False,
                    "execution_id": "",
                    "stopped": True,
                    "message": "演示文稿生成已停止"
                })
            record_presentation_execution(filename, execution_id)
            return jsonify({
                "message": "演示文稿仍在生成中，请稍后重试",
                "execution_id": execution_id,
                "refly_status": status_response,
                "refly_response": output_response,
                "processing": True
            })

        if is_presentation_execution_stopped(filename, execution_id):
            return jsonify({
                "processing": False,
                "execution_id": "",
                "stopped": True,
                "message": "演示文稿生成已停止"
            })

        presentation_url = pdf_url
        download_info = None
        presentation_local_url = None
        try:
            candidate = select_best_refly_candidate(output_response, presentation_url)
            if candidate:
                download_info = download_presentation_file(candidate["url"], candidate.get("name", ""))
        except Exception as download_exc:
            if ENABLE_DEBUG_LOG:
                print(f"⚠️ 下载演示文稿失败: {download_exc}")

        if download_info or pdf_url:
            record_presentation_file(filename, download_info, pdf_url=pdf_url)
            if download_info:
                presentation_local_url = f"/api/reports/{quote(filename)}/presentation"

        response_payload = {
            "message": "已提交生成任务",
            "report_filename": filename,
            "report_title": report_title,
            "execution_id": execution_id,
            "refly_upload": upload_response,
            "refly_status": status_response,
            "refly_response": output_response,
            "presentation_url": presentation_url
        }
        if pdf_url:
            response_payload["pdf_url"] = pdf_url
        if download_info:
            response_payload.update({
                "download_url": download_info.get("url"),
                "download_path": download_info.get("path"),
                "download_filename": download_info.get("filename"),
                "download_size": download_info.get("size"),
                "presentation_local_url": presentation_local_url
            })

        return jsonify(response_payload)
    except requests.HTTPError as exc:
        if ENABLE_DEBUG_LOG:
            try:
                detail = exc.response.text
            except Exception:
                detail = str(exc)
            print(f"⚠️ 演示文稿服务 HTTP 错误: {detail}")
        return jsonify({"error": "演示文稿服务请求失败"}), 502
    except requests.exceptions.Timeout:
        if not execution_id:
            return jsonify({"error": "演示文稿服务超时，请稍后重试"}), 504
        stopped = is_presentation_execution_stopped(filename, execution_id)
        if execution_id and not stopped:
            record_presentation_execution(filename, execution_id)
        return jsonify({
            "processing": not stopped,
            "execution_id": "" if stopped else execution_id,
            "stopped": stopped,
            "message": "演示文稿生成已停止" if stopped else "演示文稿仍在生成中，请稍后重试"
        }), 202
    except requests.exceptions.SSLError:
        if not execution_id:
            return jsonify({"error": "演示文稿服务证书校验失败"}), 502
        stopped = is_presentation_execution_stopped(filename, execution_id)
        if execution_id and not stopped:
            record_presentation_execution(filename, execution_id)
        return jsonify({
            "processing": not stopped,
            "execution_id": "" if stopped else execution_id,
            "stopped": stopped,
            "message": "演示文稿生成已停止" if stopped else "演示文稿仍在生成中，请稍后重试"
        }), 202
    except requests.RequestException as exc:
        if ENABLE_DEBUG_LOG:
            print(f"⚠️ 演示文稿服务请求异常: {exc}")
        if not execution_id:
            return jsonify({"error": "演示文稿服务不可用，请稍后重试"}), 502
        stopped = is_presentation_execution_stopped(filename, execution_id)
        if execution_id and not stopped:
            record_presentation_execution(filename, execution_id)
        return jsonify({
            "processing": not stopped,
            "execution_id": "" if stopped else execution_id,
            "stopped": stopped,
            "message": "演示文稿生成已停止" if stopped else "演示文稿仍在生成中，请稍后重试"
        }), 202
    except Exception as exc:
        return jsonify({"error": f"提交生成任务失败: {str(exc)}"}), 500


@app.route('/api/reports/<path:filename>/refly/status', methods=['GET'])
def check_refly_status(filename):
    user_row = get_current_user()
    if not user_row:
        return jsonify({"error": "请先登录"}), 401
    if not is_presentation_feature_enabled():
        return build_presentation_feature_disabled_response()
    user_id = int(user_row["id"])
    level_context = build_user_level_context_for_user(user_row)
    if not user_has_level_capability(user_row, "presentation.generate", level_context=level_context):
        return build_level_capability_denied_response(user_row, "presentation.generate", level_context=level_context)

    filename = normalize_presentation_report_filename(filename)
    if not filename:
        return jsonify({"error": "filename 缺失"}), 400

    _report_file, owner_error = enforce_report_owner_or_404(filename, user_id)
    if owner_error:
        response, status_code = owner_error
        return response, status_code

    execution_id = request.args.get("execution_id", "").strip()
    if not execution_id:
        return jsonify({"error": "execution_id 缺失"}), 400

    current_record = get_presentation_record(filename) or {}
    stopped_at = current_record.get("stopped_at")
    stopped_execution_id = str(current_record.get("stopped_execution_id") or "").strip()
    if stopped_at and (not stopped_execution_id or stopped_execution_id == execution_id):
        return jsonify({
            "processing": False,
            "execution_id": "",
            "stopped": True,
            "message": "演示文稿生成已停止"
        })

    owner = get_execution_owner_report(execution_id)
    if owner and owner != filename:
        if ENABLE_DEBUG_LOG:
            print(f"⚠️ 拦截跨报告状态查询: execution_id={execution_id}, owner={owner}, filename={filename}")
        return jsonify({
            "processing": False,
            "execution_id": execution_id,
            "mismatch": True,
            "owner_report": owner,
            "message": "execution_id 与报告不匹配"
        }), 409
    if str(current_record.get("provider") or "").strip() == "paper2slides":
        try:
            payload, status_code = check_paper2slides_status(filename, execution_id)
            return jsonify(payload), status_code
        except requests.exceptions.Timeout:
            stopped = is_presentation_execution_stopped(filename, execution_id)
            return jsonify({
                "processing": not stopped,
                "execution_id": "" if stopped else execution_id,
                "stopped": stopped,
                "message": "演示文稿生成已停止" if stopped else "演示文稿仍在生成中，请稍后重试"
            })
        except requests.RequestException as exc:
            if ENABLE_DEBUG_LOG:
                print(f"⚠️ Paper2Slides 服务请求异常: {exc}")
            stopped = is_presentation_execution_stopped(filename, execution_id)
            return jsonify({
                "processing": not stopped,
                "execution_id": "" if stopped else execution_id,
                "stopped": stopped,
                "message": "演示文稿生成已停止" if stopped else "演示文稿仍在生成中，请稍后重试"
            })
    try:
        status_response = fetch_refly_status_once(execution_id)
        output_response = fetch_refly_output(execution_id)
        pdf_url = (
            extract_pdf_url_from_output(output_response)
            or build_pdf_url_from_result_info_file(output_response)
            or build_pdf_url_from_result_info(output_response)
        )
        if not pdf_url:
            latest_record = get_presentation_record(filename) or {}
            latest_stopped_at = latest_record.get("stopped_at")
            latest_stopped_execution_id = str(latest_record.get("stopped_execution_id") or "").strip()
            if latest_stopped_at and (not latest_stopped_execution_id or latest_stopped_execution_id == execution_id):
                return jsonify({
                    "processing": False,
                    "execution_id": "",
                    "stopped": True,
                    "message": "演示文稿生成已停止"
                })
            record_presentation_execution(filename, execution_id)
            return jsonify({
                "processing": True,
                "execution_id": execution_id,
                "refly_status": status_response,
                "refly_response": output_response
            })
        record_presentation_file(filename, None, pdf_url=pdf_url)
        return jsonify({
            "execution_id": execution_id,
            "pdf_url": pdf_url
        })
    except requests.exceptions.Timeout:
        stopped = is_presentation_execution_stopped(filename, execution_id)
        return jsonify({
            "processing": not stopped,
            "execution_id": "" if stopped else execution_id,
            "stopped": stopped,
            "message": "演示文稿生成已停止" if stopped else "演示文稿仍在生成中，请稍后重试"
        })
    except requests.exceptions.SSLError:
        stopped = is_presentation_execution_stopped(filename, execution_id)
        return jsonify({
            "processing": not stopped,
            "execution_id": "" if stopped else execution_id,
            "stopped": stopped,
            "message": "演示文稿生成已停止" if stopped else "演示文稿仍在生成中，请稍后重试"
        })
    except requests.RequestException as exc:
        if ENABLE_DEBUG_LOG:
            print(f"⚠️ 演示文稿服务请求异常: {exc}")
        stopped = is_presentation_execution_stopped(filename, execution_id)
        return jsonify({
            "processing": not stopped,
            "execution_id": "" if stopped else execution_id,
            "stopped": stopped,
            "message": "演示文稿生成已停止" if stopped else "演示文稿仍在生成中，请稍后重试"
        })
    except Exception as exc:
        return jsonify({"error": f"查询生成状态失败: {str(exc)}"}), 500


@app.route('/api/reports/<path:filename>/presentation/abort', methods=['POST'])
def abort_report_presentation(filename):
    user_row = get_current_user()
    if not user_row:
        return jsonify({"error": "请先登录"}), 401
    if not is_presentation_feature_enabled():
        return build_presentation_feature_disabled_response()
    user_id = int(user_row["id"])
    level_context = build_user_level_context_for_user(user_row)
    if not user_has_level_capability(user_row, "presentation.generate", level_context=level_context):
        return build_level_capability_denied_response(user_row, "presentation.generate", level_context=level_context)

    filename = normalize_presentation_report_filename(filename)
    if not filename:
        return jsonify({"error": "filename 缺失"}), 400

    _report_file, owner_error = enforce_report_owner_or_404(filename, user_id)
    if owner_error:
        response, status_code = owner_error
        return response, status_code

    execution_id = request.args.get("execution_id", "").strip()
    if not execution_id:
        record = get_presentation_record(filename) or {}
        execution_id = str(record.get("execution_id") or "").strip()
    if not execution_id:
        mark_presentation_stopped(filename)
        return jsonify({"success": True, "execution_id": ""})
    try:
        record = get_presentation_record(filename) or {}
        if str(record.get("provider") or "").strip() == "paper2slides":
            try:
                get_paper2slides_client().cancel(execution_id)
            except requests.RequestException as exc:
                if ENABLE_DEBUG_LOG:
                    print(f"⚠️ Paper2Slides 中止失败: {exc}")
            mark_presentation_stopped(filename, execution_id=execution_id)
            return jsonify({"success": True, "execution_id": execution_id})

        url = get_refly_abort_url(execution_id)
        headers = {"Authorization": f"Bearer {REFLY_API_KEY}"}
        response = requests.post(url, headers=headers, timeout=REFLY_TIMEOUT)
        response.raise_for_status()
        mark_presentation_stopped(filename, execution_id=execution_id)
        return jsonify({"success": True, "execution_id": execution_id})
    except requests.RequestException as exc:
        if ENABLE_DEBUG_LOG:
            print(f"⚠️ 演示文稿中止失败: {exc}")
        mark_presentation_stopped(filename, execution_id=execution_id)
        return jsonify({"success": True, "execution_id": execution_id, "warning": "中止请求失败，已本地标记停止"})


@app.route('/api/reports/<path:filename>', methods=['DELETE'])
def delete_report(filename):
    """删除报告（仅标记为已删除，保留文件存档）"""
    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    report_file, owner_error = enforce_report_owner_or_404(filename, user_id)
    if owner_error:
        response, status_code = owner_error
        return response, status_code

    try:
        # 只标记为已删除，不真正删除文件
        mark_report_as_deleted(filename)
        delete_solution_sidecar(filename)
        delete_solution_shares_for_report(filename)
        return jsonify({
            "message": "报告已从列表中移除（文件已存档）",
            "name": filename
        })
    except Exception as e:
        return jsonify({"error": f"标记删除失败: {str(e)}"}), 500


@app.route('/api/reports/batch-delete', methods=['POST'])
def batch_delete_reports():
    """批量删除报告（软删除）。"""
    user_id = get_current_user_id_or_none()
    if not user_id:
        return jsonify({"error": "请先登录"}), 401

    data = request.get_json(silent=True) or {}
    report_names = unique_non_empty_strings(data.get("report_names", []))

    if not report_names:
        return jsonify({"error": "report_names 不能为空"}), 400

    deleted_reports = []
    skipped_reports = []
    missing_reports = []

    for report_name in report_names:
        report_file, owner_error = enforce_report_owner_or_404(report_name, user_id)
        if owner_error:
            if report_file is None and not _report_exists(report_name):
                missing_reports.append(report_name)
            else:
                skipped_reports.append({"name": report_name, "reason": "无权限或报告不存在"})
            continue

        try:
            mark_report_as_deleted(report_name)
            delete_solution_sidecar(report_name)
            delete_solution_shares_for_report(report_name)
            deleted_reports.append(report_name)
        except Exception as exc:
            skipped_reports.append({"name": report_name, "reason": f"标记删除失败: {str(exc)}"})

    return jsonify({
        "success": True,
        "requested": len(report_names),
        "deleted_reports": deleted_reports,
        "skipped_reports": skipped_reports,
        "missing_reports": missing_reports
    })


# ============ 状态 API ============

@app.route('/api/status', methods=['GET'])
def get_status():
    """获取服务状态"""
    wechat_enabled = bool(WECHAT_LOGIN_ENABLED and WECHAT_APP_ID and WECHAT_APP_SECRET)
    sms_enabled = is_sms_login_available("login")
    license_enforcement_state = get_license_enforcement_state()
    presentation_feature_state = get_presentation_feature_state()
    current_user = get_current_user()
    if not current_user:
        level_context = build_user_level_context_for_user(None)
        return jsonify({
            "status": "running",
            "authenticated": False,
            "wechat_login_enabled": wechat_enabled,
            "sms_login_enabled": sms_enabled,
            "sms_provider": SMS_PROVIDER,
            "sms_code_length": SMS_CODE_LENGTH,
            "sms_cooldown_seconds": SMS_SEND_COOLDOWN_SECONDS,
            "license_enforcement_enabled": bool(license_enforcement_state.get("enabled")),
            "license_enforcement_source": str(license_enforcement_state.get("source") or "env_default"),
            "presentation_feature_enabled": bool(presentation_feature_state.get("enabled")),
            "presentation_feature_source": str(presentation_feature_state.get("source") or "env_default"),
            "report_profile_default": level_context.get("report_profile_default") or "balanced",
            "report_profile_options": level_context.get("allowed_report_profiles") or ["balanced"],
            **level_context,
        })

    question_available = resolve_ai_client(call_type="question") is not None
    report_draft_available = resolve_ai_client(call_type="report_v3_draft", preferred_lane="report") is not None
    report_review_available = resolve_ai_client(call_type="report_v3_review_round_1", preferred_lane="report") is not None
    report_available = report_draft_available or report_review_available or resolve_ai_client(call_type="report") is not None
    ai_available = question_available or report_available
    mode_names = ["quick", "standard", "deep"]
    mode_configs_effective = {
        mode: get_interview_mode_display_config(mode)
        for mode in mode_names
    }
    license_payload = build_license_status_payload_for_user(current_user)
    level_context = {
        "level": license_payload.get("level") or build_user_level_payload("experience"),
        "capabilities": license_payload.get("capabilities") or build_user_capabilities_for_level("experience"),
        "allowed_report_profiles": license_payload.get("allowed_report_profiles") or ["balanced"],
        "report_profile_default": license_payload.get("report_profile_default") or "balanced",
        "allowed_interview_modes": license_payload.get("allowed_interview_modes") or ["quick"],
        "interview_mode_default": license_payload.get("interview_mode_default") or "quick",
        "interview_mode_requirements": license_payload.get("interview_mode_requirements") or build_interview_mode_requirements(),
    }
    return jsonify({
        "status": "running",
        "authenticated": True,
        "user": build_user_payload(current_user),
        "wechat_login_enabled": wechat_enabled,
        "sms_login_enabled": sms_enabled,
        "sms_provider": SMS_PROVIDER,
        "sms_code_length": SMS_CODE_LENGTH,
        "sms_cooldown_seconds": SMS_SEND_COOLDOWN_SECONDS,
        "license_enforcement_enabled": bool(license_enforcement_state.get("enabled")),
        "license_enforcement_source": str(license_enforcement_state.get("source") or "env_default"),
        "presentation_feature_enabled": bool(presentation_feature_state.get("enabled")),
        "presentation_feature_source": str(presentation_feature_state.get("source") or "env_default"),
        "license": license_payload,
        "ai_available": ai_available,
        "question_ai_available": question_available,
        "report_ai_available": report_available,
        "report_draft_ai_available": report_draft_available,
        "report_review_ai_available": report_review_available,
        "report_profile_default": level_context.get("report_profile_default") or "balanced",
        "report_profile_options": level_context.get("allowed_report_profiles") or ["balanced"],
        **level_context,
        "interview_depth_v2": {
            "enabled": True,
            "modes": mode_names,
            "deep_mode_skip_followup_confirm": DEEP_MODE_SKIP_FOLLOWUP_CONFIRM,
            "mode_configs": mode_configs_effective,
        }
    })


